INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(1, 'Marinated Steak Kabobs', '1 cup Onion, chopped\r\n1/2 cup Vegetable oil\r\n1/2 cup Lemon juice\r\n1/4 cup Soy sauce\r\n1 tablespoon Worcesteshire sauce\r\n1 teaspoon Mustard, prepared\r\n1 pound Sirloin steak, cut in 2&quot;cubes\r\n1 large Green pepper, cut in 1&quot;pieces\r\n2 medium Onions, quartered\r\n2 medium Tomatoes, quartered\r\n1 cup Apple Wood Chips', 'Saute onion in oil; remove from heat. Stir in lemon juice, soy sauce, Worcestershire sauce, and mustard; pour over meat and vegetables. Cover and marinate overnight in refrigerator. Remove meat and vegetables from marinade, reserving marinade. Alternate meat and vegetables on skewers.\r\n\r\nSoak Apple Wood Chips in water for 30 minutes. Prepare fire in grill. When the grill is up up temperature, add wood chips; let them start smoking. Grill kabobs 5 minutes on each side over coals or until desired degree of doneness, brushing frequently with marinade.', '', 17),
(2, 'Bourbon Steak', '1-1/2 pounds steak\r\n1 teaspoon. sugar\r\n1/4 cup bourbon\r\n2 tablespoons soy sauce\r\n2 tablespoons water\r\n1 garlic clove, crushed\r\n1 cup Apple Wood Chips', 'Mix all ingredients (except chips) together, place in ziplock bag and marinate steak 4 hours or over night. Soak wood chips in water for 30 minutes, and add to hot coals just before commencing to grill. Grill steak to desired doneness. This recipe is good with any cut of steak you like.', '', 17),
(3, 'Baja Pizza Pouch (Calzones)', '1 pound bulk hot pork sausage\r\n1/2 pound lean ground beef\r\n1 can refried beans\r\n1 teaspoon ground cumin\r\n1/4 teaspoon garlic powder\r\n1 package hot roll mix\r\n1 can crushed italian tomatoes\r\n2 cups monterey jack cheese -- shred\r\n1 cup cheddar cheese -- shredded\r\nbutter -- melted\r\n1 cup guacamole', 'Heat large skillet over medium heat until hot. Crumble pork sausage and ground beef into skillet. Cook, stirring to separate meat, until no pink remains. Drain off fat. Add beans, cumin, and garlic powder; heat through. Oil two baking sheets. Preheat oven to 400 F. Prepare hot roll mix. Divide dough into 8 pieces. Form each piece into a ball. On lightly floured surface roll each ball into 7 inch circle. Place on prepared baking sheets. Spread 1/2 c meat mix on 1/2 of each dough circle to within 1/2 inch form edge. Layer each calzone with 2 T crushed tomatoes, 1/4 c\r\n\r\nMonterey Jack cheese and 2 T cheddar. Moisten edges of dough with water and fold over to enclose filling. Press edges firmly together with fork. Brush with melted butter. Cut slit in each calzone to allow steam to escape. Bake 18 to 20 minutes or until golden brown. Serve with guacamole, if desired.', '', 2),
(4, 'Cheese Pizza', 'Pizza Crust -- (recipe follows)\r\n1 (8 ounce) can pizza sauce\r\n1 (4 ounce) can sliced mushrooms -- drained OR 1 (4 ounce) can chopped green chiles -- drained\r\n3 cups shredded Mozzarella, Cheddar or Monterey\r\nJack cheese (12 ounces)\r\n1/4 cup grated Parmesan or Romano cheese\r\n\r\nPIZZA CRUST\r\n1 package regular or quick active dry yeast\r\n1 cup warm water (105? to 115?)\r\n2 1/2 cups all-purpose flour*\r\n2 tablespoons olive or vegetable oil\r\n1/2 teaspoon salt\r\nOlive or vegetable oil\r\nCornmeal', 'Prepare Pizza Crust. Spread pizza sauce over partially baked crusts. \r\n\r\nSprinkle with mushrooms and cheeses. Bake pizzas at 425? about 10 minutes, until cheese is melted and pizzas are bubbly.\r\n\r\nMeat Pizza: Cook 1 pound ground beef, bulk Italian sausage or ground turkey, 1 teaspoon Italian seasoning and 2 cloves garlic, finely chopped, in 10-inch medium skillet over medium heat, stirring occasionally, until beef is brown; drain. Sprinkle beef mixture over pizza sauce. Decrease Mozzarella cheese to 2 cups.\r\n\r\nPIZZA CRUST:\r\nDissolve yeast in warm water in medium bowl. Stir in flour, 2 tablespoons oil and the salt. Beat vigorously 20 strokes. Cover and let rest 20 minutes. Move oven rack to lowest position. Heat oven to 425?. Grease 2 cookie sheets or 12-inch pizza pans with oil. Sprinkle with cornmeal.\r\n\r\nDivide dough in half; pat each half onto 11-inch circle on cookie sheet with floured fingers. Prick dough thoroughly with fork. Bake about 10 minutes or until crust just begins to brown.', '', 2),
(5, 'CORIANDER FISH (BHARIA MACHLI)', '8 cloves Garlic\r\n3 Hot chilies (optional) (or cayenne)\r\n1&quot; piece Ginger\r\n1 medium bunch Coriander\r\n1 Tbsp Coriander seeds\r\n1 tsp Brown sugar\r\n1 tsp Turmeric\r\n1/2 tsp Black mustard\r\n1/2 tsp Fenugreek seeds\r\n1 Tbsp Salt\r\n1/2 cup Lemon juice\r\n1/2 cup Vegetable oil\r\n2 cup Chopped onion\r\n1 cup Chopped tomato\r\n1/2 tsp Garam Masala', 'Preheat oven to 400 deg F. Wash and pat fish dry. Sprinkle 1 t salt inside and set aside. Blend garlic, chili, ginger, 1/2 the coriander, coriander seeds, brown sugar, turmeric, mustard seeds, fenugreek seeds, salt and lemon juice until it all becomes a smooth paste (Add some water if needed).\r\n\r\nFry onions until they are soft and golden brown. Add the blended Masala and cook until most of the liquid is gone, and it starts to leave the sides of the pan. Add the tomatoes and Garam Masala. Fry for 2 minutes more and remove.\r\n\r\nCoat one side of fish, stuff 1 1/2 cups inside. Close opening, spread the rest of the Masala over it. Cover tightly and bake for about 25 minutes. Grill for 1 -2 minutes in the broiler, and sprinkle on the remaining coriander. Serve.', '', 21),
(6, 'PRAWN (SHRIMP) CURRY', '1/2 kg = 1.1 lb. Prawns\r\n2 Onions diced into small pieces\r\n1/4&quot; Cinnamon stick\r\n1/4 tsp Chili powder\r\n1/2 tsp Dhania powder\r\n1/4 tsp Garlic powder\r\n1/2 tsp ginger powder\r\n1 bunch Fresh coriander\r\n1 tsp Salt\r\n1/4 tsp Turmeric powder\r\n1 tblsp Oil', 'Clean the prawns and squeeze out the water. Add chili, dhania, garlic, ginger, turmeric powder, salt and mix well. Boil prawns on low heat. Add 1 teaspoon of oil to the boiling prawns.\r\n\r\nWhen water evaporates and the prawns are dry remove from the stove. Heat the oil and put in the cinnamon. Add prawns and fry for 2 minutes. Add onions and fry until they turn brown. Sprinkle on coriander leaves, remove from the heat and serve.', '', 21),
(7, 'Parmesan Chicken Wraps', '4 large whole wheat or plain flour tortillas 4\r\n1 tbsp butter 15 mL\r\n1 lb boneless skinless chicken, cut in thin strips 500 g\r\n3 cloves garlic, minced 3\r\n1 tsp dried basil 5 mL\r\n2 tbsp all-purpose flour 30 mL\r\n1 cup Milk 250 mL\r\n1/3 cup freshly grated Parmesan cheese 75 mL\r\n1/2 tsp hot pepper sauce (optional) 2 mL\r\n1/4 tsp pepper 1 mL\r\n2 fresh tomatoes, chopped (or 1-1/2 cups/375 mL drained canned diced tomatoes) 2\r\n1/4 cup chopped fresh basil (optional) 50 mL\r\n\r\n', 'PUT ALL TOGETHER', 'Wraps make a fun change from regular dinner fare. Each member of the family can add different toppings to customize their own wrap, such as lettuce, bacon bits, sweet peppers, olives or shredded cheese.\r\n', 54),
(71, 'vegetable salad', '1/2 cup vegetable oil\r\n1 (10 oz) can of tomato juice\r\n1 tsp. powder prepared mustard\r\n1 tsp. worshestershire sauce', 'Blanch 1 cup sliced carrots\r\n       1 cup raw sliced onions\r\n       1 green pepper sliced\r\n       1/2 cup celery\r\n       1/2 cup broccoli\r\n\r\nMix    1/2 cup white vinegar\r\n       1/2 cup sugar\r\n\r\n       ', 'Marinate for 24 hrs in the fridge', 55),
(72, 'Carrot Salad', '2 pds cooked slice carrots (boiled 5 minutes)\r\n2 slice raw onions\r\ngreen peppers slice or dice (to taste)', 'Blend \r\n1/2 cup white vinegar\r\n1/2 cup sugar (white)\r\n1/2 cup vegetable oil\r\n1 (10oz) can tomato soup\r\n1 tsp prepared mustard\r\n1 tsp worcestershire sauce.\r\nMix with carrots onions and green peppers.\r\n', '', 55),
(73, 'Macaroni Salad with Italian Dressing', 'Cook 2 cups of pasta (macaroni or spirals)\r\nThen add:\r\n1/2 cup red peppers or green\r\n1/2 cup red onions or spanish\r\n2 cups of vegetables (brocolli, califlower, carrots) vegetables have to be steamed a few minutes or cooked in microwave until crunchy.\r\nAdd to taste ham or chicken.\r\nthen add: 1 cup italian dressing (bottle)\r\n1 cup of parmesan cheese (optional)', 'MIX ALL', '', 55),
(70, 'Lazy Daisy Oatmeal Cake ', '1-1/2 cups boiling water\r\n1 cup oatmeal\r\n1/2 cup soft butter\r\n1 cup white sugar\r\n1 cup brown sugar\r\n1 tsp vanilla\r\n2 eggs\r\n1-1/3 cups flour\r\n1 tsp baking soda\r\n1/2 tsp salt\r\n3/4 tsp cinnamon\r\n1/4 tsp nutmeg\r\n\r\nFrosting......\r\n1/4 cup melted butter\r\n1/2 cup brown sugar\r\n3 tbsp cream\r\n1/2 cup pecans\r\n3/4 cup coconut\r\n \r\n', '9x9 pan 350 50-55 minutes Pour boiling water over oatmeal, cover and let stand for 20 minutes. Beat butter until it\'s creamy and gradually add in sugar and beat til stiff. Blend in vanilla and eggs. Add oatmeal and mix well. Add dry ingredients.\r\nFrosting.....\r\nMix all ingredients together in pot and mix over medium heat until boiling. Spread over warm cake.', 'Auntie Joanne gave me this recipe. It is a nice heavy cake. If I don\'t have cream for the icing I have used carnation milk or just plain milk.  \r\n', 45),
(69, 'Ultimate Chocolate Cake', ' butter and flour to coat cake pan\r\n\r\n400 grams semi sweek chocolate\r\n1 cup whipping cream\r\n2 tbsp Kirsch\r\n2 tbsp Grand Marnier\r\n1 tsp ground cinnamon\r\n6 large eggs\r\n1/2 brown sugar', '350 approx. 1 hour\r\n\r\nButter a 23 cm cake pan. Place wax paper on top and flour.\r\n\r\nWarm a large basin by filling with boiling water.\r\n\r\nMelt the chocolate. Set aside. Whisk the cream until soft peaks and stir in Kirsch, Grand Marnier and cinnamon.\r\n\r\nBreak the egss into the heated basig and add the sugar. Beat until thick and fluffy. Add the melted chocolate a little at a time. Once this mixture is cooled add the cream. Pour into the tin. Put the tin in a baking dish and add boiling water half way up the sides. Bake for 1 hour or until set on the outside and soft in the center.\r\n\r\n', 'This is a great rich chocolate cake with no flour in it. Serve it with a little whipped cream and fresh fruit, I like raspberries with it. To dress it up sift a little icing sugar on the plate and put a slice of cake on top.\r\n \r\n', 45),
(74, 'Taco Dip also called Pizza Dip', 'Do like you do a pizza\r\nBottom:\r\nMix together 1 large pkg of cream cheese and large container of sour cream.\r\nTop with:\r\ndiced green peppers\r\nred peppers\r\ngreen onions (stem)\r\ntomotoes (optional)\r\nshredded salad\r\nthen top with shredded cheddar.', 'MIX', '', 56),
(75, 'Strawberry Dip', '1 lrg pkg cream cheese (soften)\r\n15 oz frozen strawberries or fresh (fresh is better).\r\n1/2 pint of whipping cream or one enveloppe of dream whip (prepared)\r\n', 'Mix all together, then add 2 jars of cream marshmallow and whip until well mixed.\r\nServe with fresh fruitss', 'To prevent your apples from getting brown dip in lemon.', 56),
(12, 'Manacotte', '18 Manocotte Shell\r\n1 1/2 pound ground beef\r\n2 tbsp oil.\r\n3 slice bread crumbled\r\n2/3 cup milk\r\n1 egg beaten\r\n1 onion\r\n2 cups grated mozorella\r\n1/2 tsp salt\r\ndash pepper\r\n1 can spaghetti sauce\r\n2 cups grated mozorella', 'Brown ground meat, onion &amp; oil.  Drain fat.\r\nCombine bread &amp; milk, stand for 2 minutes,  add cook meat and remaining ingredients, except for spaghetti sauce and 2 cups of mozorella cheese.\r\ncook 6 manocotte shell at a time in four quart of water and add a pinch of salt.\r\nPut some spaghetti sauce in bottom of pan, fill manacotte shell with meat mixture, then cover with spaghetti sauce and cheese.  Cover pan and cook for 445 minutes.', 'I got this recipe from a girl at work.  I tried it and it was a great success.', 57),
(13, 'Oatmeal Cookies', '3/4 cup butter\r\n1/2 cup brown sugar\r\n1/2 cup granulated sugar\r\n1 egg\r\n1/2 tsp vanilla\r\n1 1/2 c flour\r\n1 tsp baking soda\r\n3 cups Quaker Oats, uncooked\r\n1 c raisins', 'Beat together butter and sugars until light and creamy. Add egg and vanilla.  Combine flour, baking soda, raising.  Add uncooked oatmeal from measuring cup tablespoon full; mix well.  Drop by rounded tablespoon on cookie pan ungreased.  Bake 10 to 15 minutes in oven 350 degrees.  Makes 4 1/2 dozen. Cool on rack or cutting board.', '', 58),
(14, 'Apple Crisp', '10 cups thinly sliced apples\r\n1 cup white sugar\r\n1 tabl flour\r\n1 tsp cinnamon\r\n1/2 cup water\r\n1 cup quick-cooking oats\r\n1 cup flour\r\n1 cup brown sugar\r\n1/4 tsp baking powder\r\n1/4 tsp baking soda\r\n1/2 cup butter, melted\r\n', 'preheat oven to 350 degrees F (175 degree C.)\r\nPlaced the sliced apples in a 9x13 inch pan.  Mix the white sugar, 1 tablespoon flour and cinnamon together, and sprinke over apples. Pour water evenly over all.\r\nCombine the oats, 1 cup flour, brown sugar, baking powder, baking soda and melted butter together. Crumble evenly over the apple mixture.  Bake at 350 degrees F for about 45 minutes.', 'A simple desert that\'s great with ice cream.  Prep time: approx. 30 minutes.. Cook time: Approx. 45 minutes.', 40),
(15, 'banana muffins', 'Bowl 1\r\n1/2 cup of margarine\r\n1 cup white sugar\r\n2 eggs (beat them)\r\n3 bananas (mash them)\r\n\r\nBowl 2\r\n2 cups white flour\r\n1 tabl of baking soda\r\n1/2 tabl of baking powder\r\n1/2 tabl of salt\r\n1 cup of nuts (or chocolate chips)', 'Mix both bowls together, put in oven at 350f for 20 minutes.  makes 24 muffin\r\n', '', 59),
(16, 'Pineapple Surprise', '1 1/2 cup milk  375 ml\r\n1 package banana instant pudding mix\r\n1 cup frozen whipped topping (reg or light) thawed.  250 ml\r\n1 14 oz(398 ml) can crushed pineapple, drained\r\n2 bananas, sliced thinly\r\n1/4 cup Graham cracker crumbs    60ml', 'Pour the milk into a medium bowl and add the pudding mix.\r\nBeat with a electric mixer or a whisk until thickened (about two minutes)\r\nFold in the frozen whipped topping and pineapple until well blended.\r\nAdd the sliced bananas and Grahamm cracker crumbs to the pudding mixture.  Save some bananas and crumbs for the top.\r\nPut in fridge until ready to serve.', 'I use Jello Vanilla instant (light)instead.', 40),
(17, 'cheesy chicken and rice bake', '1 can (10 3/4) Campbell\'s Cream of Chicken Soup (Regular or 98% Fat Free)\r\n1 1/3 cups water\r\n3/4 cup uncooked regular long-grain white rice\r\n1/2 tsp onion powder\r\n1/4 tsp. ground black pepper\r\n1 1/2lb, skinless boneless chicken breast halves (about 4-6)\r\n1 cup shredded Cheddar cheese (4 oz)', 'Mix soup, water, rice, onion powder and black pepper in 2-qt, shallow baking dish.\r\nTop with chicken. Sprinkle chicken with additional pepper.\r\nCover and bake at 375 F for 45 min. or until chicken is no longer pink and rice is done.\r\nUncover.  Sprinkle cheese over chicken.', 'Get YOur Veggies:  Stir 2 cups of fresh, canned or frozen vegetables into soup mixture before topping with chicken.', 54),
(655, 'Muffins aux bananes', '225 g (1 1/2 tasse) de farine de blÃ© entier \r\n\r\n\r\n5 ml (1 c. Ã  thÃ©) de poudre Ã  pÃ¢te \r\n\r\n\r\n2,5 ml (1/2 c. Ã  thÃ©) de bicarbonate de soude \r\n\r\n\r\n1 ml (1/4 c. Ã  thÃ©) de sel \r\n\r\n\r\n5 ml (1 c. Ã  thÃ©) de cannelle moulue \r\n\r\n\r\n2,5 ml (1/2 c. Ã  thÃ©) de piment de la JamaÃ¯que moulu (facultatif) \r\n\r\n\r\n3 bananes trÃ¨s mÃ»res (voir note) \r\n\r\n\r\n105 g (1/2 tasse) de cassonade \r\n\r\n\r\n2 oeufs \r\n\r\n\r\n60 ml (1/4 tasse) de yogourt nature 2 % \r\n\r\n\r\n75 ml (1/3 tasse) dâhuile vÃ©gÃ©tale\r\n', 'Placer la grille au centre du four. PrÃ©chauffer le four Ã  180 Â°C (350 Â°F). Chemiser un moule Ã  muffins Ã  12 cavitÃ©s de caissettes en silicone ou en papier. \r\n\r\n\r\nDans un bol, mÃ©langer la farine, la poudre Ã  pÃ¢te, le bicarbonate, le sel, la cannelle et le piment de la JamaÃ¯que, si dÃ©sirÃ©. \r\n\r\n\r\nDans un autre bol, Ã©craser grossiÃ¨rement les bananes Ã  lâaide dâune fourchette. Ajouter la cassonade, les oeufs, le yogourt et lâhuile. MÃ©langer au fouet. Incorporer les ingrÃ©dients secs en mÃ©langeant dÃ©licatement Ã  la spatule jusquâÃ  ce que le mÃ©lange soit tout juste humectÃ©. RÃ©partir la pÃ¢te dans le moule. \r\n\r\n\r\nCuire au four de 22 Ã  25 minutes ou jusquâÃ  ce quâun cure&#8209;dents insÃ©rÃ© au centre des muffins en ressorte propre. Laisser tiÃ©dir. DÃ©mouler et laisser refroidir sur une grille.\r\n', 'Ricardo', 59),
(19, 'Whole-Grain Toast Triangles with Hummus', 'Prep/Cook Time: 15 min.\r\n1 	tbsp. sesame seeds\r\n1 	can (15 1/2 oz.) chickpeas (garbanzo beans), rinsed and drained\r\n2 	tbsp. lemon juice\r\n2 	cloves garlic, minced\r\n8 	slices Pepperidge FarmÂ® German Dark Wheat Natural Whole Grain Bread, toasted\r\n\r\n \r\n\r\n\r\n', 'HEAT nonstick skillet over medium heat. Add sesame seeds. Cook and stir 1 min. or until toasted. Remove from heat.\r\n\r\nPLACE chick peas, lemon juice, garlic and toasted sesame seeds in food processor. Cover and pulse until smooth, adding about 1/4 cup water to make creamy consistency.\r\n\r\nCUT toasted bread into triangles. Serve with chick pea mixture.  Serves 8.\r\n\r\n \r\n\r\n\r\n\r\n', 'Nutritional Values Per Serving: Calories 156, Total Fat 2g, Saturated Fat 0g, Cholesterol 0mg, Sodium 226mg, Total Carbohydrate 25g, Dietary Fiber 6g, Protein 7g, Vitamin A 0%DV, Vitamin C 4%DV, Calcium 5%DV, Iron 13%DV', 60),
(20, 'Potato Latkes', '4 medium potatoes, about 1 1/2 pounds\r\n3 tablespoon olive oil\r\n2 large eggs, slightly beaten\r\n2 cloves garlic (optional)\r\n1/2 teaspoon salt\r\n2 tablespoon cooking oil\r\n1/4 - 1/2 cups non-dairy sour cream\r\n\r\n', '1. Peel and finely shred potatoes. In a mixing bowl combine potatoes with olive oil, eggs,garlic (if desired), and salt. Using 1/3 cup mixture for each latke, press mixture into patties about the size of the palm of your hand, squeezing out excess liquid.\r\n2. In a large skillet heat oil over medium-high heat. Carefully slide patties into hot oil.\r\n3. Cook over medium-high heat about 2 minutes or until latkes are golden brown, turning once.\r\n4. Repeat with remaining batter. Add cooking additional oil during cooking, as needed.\r\n5. If necessary, reduce heat to medium to prevent overbrowning. Drain on paper towels and keep warm. Serve with non-dairy sour cream, if desired. Makes about 10 latkes. (Nutrition information is given per latke plus 1 teaspoon non-dairy sour cream.)\r\n', 'Presented by:\r\nTotal Time:30 min\r\nCarbs:Carbohydrate 12g\r\n\r\nTasty Potato Latkes - 10 Servings \r\nLatkes are one treat that has become closely associated with Hanukkah. It becomes a family production with the kids shredding the potatoes, Mom mixing all the recipe ingredients together, and Dad forming and frying the latkes. Remember, you don\'t have to celebrate Hanukkah to enjoy a crisp and tasty potato pancake.\r\n', 61),
(21, 'ZUCCHINI OVEN CHIPS ', '1/4 C dry breadcrumbs\r\n1/4 C (1 oz) grated fresh parmesan cheese\r\n1/4 tsp seasoned salt\r\n1/4 tsp garlic powder\r\n1/8 tsp black pepper\r\n2 Tbsp fat-free milk\r\n2 1/2 C (1/4&quot; thick) slices zucchini (about 2 small)\r\nCooking spray\r\n\r\nMakes approx. 4 servings, 3/4 Cup = 1 Point\r\n\r\ncblessum on 6/4/2006  \r\n  \r\n \r\n     Have a Skinny Week! \r\n', 'Preheat oven to 425. Combine first 5 ingredients in medium bowl, stirring with whisk. Place milk in shallow bowl. Dip zucchini slices in milk &amp; dredge in breadcrumb mixture. Place coated slices on ovenproof wire rack coated with cooking spray. Bake for 30 minutes or until browned.\r\n\r\n', 'Appetizer  Makes approx. 4 servings, 3/4 Cup = 1 Point\r\n', 22),
(22, ' ANOTHER APPLE TURNOVER', '&lt;p&gt;2 Granny Smith apples 2 Cans Reduced-Fat crescent rolls 3/4 C Splenda 2 tsp cinnamon 1 (12 oz) can Diet Mt. Dew&lt;/p&gt;', '&lt;p&gt;Preheat oven to 350 &amp; spray 9X13 pan. Cut each apple into 8 peeled slices. Roll 1 slice of apple into each crescent. Roll &amp; place into pan. Mix splenda &amp; cinnamon &amp; sprinkle over rolls. Pour can of Mt. Dew over that &amp; bake for 45 minutes. (peaches &amp; Diet 7-up is good)&lt;/p&gt;', '&lt;p&gt;16 servings at 2 Points each&lt;/p&gt;', 40),
(23, 'APPLESAUCE JELLO ', '1 C boiling water\r\n1 box sugar-free Jello\r\n1 C unsweetened applesauce, canned\r\n1 Tbsp vinegar\r\n\r\n\r\n\r\n \r\n', 'Dissolve Jello into boiling water. Mix in applesauce &amp; vinegar. Stir well &amp; chill until set. Makes 4 servings.\r\n\r\n', '4 servings at 1/2 Point each', 40),
(24, 'SKINNY CHOCOLATE CAKE ', '1 pkg chocolate cake mix\r\n1 C water\r\n1/3 C fat-free salad dressing or mayo\r\n3 egg whites or 6 Tbsp egg substitute\r\n\r\n', 'Combine ingredients. Spray 9X13 pan &amp; cook at 350 for 30-35 minutes. Use a touch of Cool Whip Free on top.\r\n\r\n', '1/12th of cake = 4 Points and 1/16th = 3 Points \r\n', 45),
(25, 'STUFFED PEPPER SOUP ', '1 lb lean ground beef, browned\r\n3-4 peppers chopped (green, red, yellow, etc)\r\n1 onion, chopped\r\n1 can tomatoes\r\n1 can beef broth\r\n1 family size can tomato soup\r\n2 C water\r\n1 C brown rice, uncooked\r\n1 tsp garlic\r\nsalt &amp; pepper to taste\r\n\r\n\r\n\r\n \r\n', 'Bring contents to a boil. Let simmer 30-45 minutes. Add more water if soup gets too thick.\r\n', '8 servings at 5 points each', 62),
(26, 'FRENCH TOAST WITH STRAWBERRIES ', '3/4 cup sliced strawberries, sweetened with Splenda\r\n2 tbsp fat free cream cheese\r\n3 tsp Splenda\r\n2 slices of light bread (1pt for both slices)\r\n&amp;frac14; cup of eggbeaters\r\n&amp;frac14; cup skim milk\r\n1 tsp vanilla\r\n2 tbsp fat free cool whip\r\n\r\n\r\n\r\n\r\n \r\n', 'Mix cream cheese and Splenda and 1/2 tsp of vanilla and set aside. Whisk eggbeaters, milk and 1/2 tsp of vanilla. Dip bread slices in egg mixture until mixture is gone. Spray skillet with cooking spray and cook over medium heat until brown. Divide cream cheese mixture in half and spread on each slice of bread. Top with strawberries and cool whip.\r\n\r\n', '3 pts for 1 serving', 63),
(27, 'WW FRUIT SALAD ', '3 medium apple(s)\r\n2 cup Dole Canned Pineapple Tidbits in Juice\r\n2 cup grapes\r\n2 large banana(s)\r\n1/3 cup SPLENDA (R) No Calorie Sweetener\r\n2 Tbsp cornstarch\r\n1 egg\r\n1/2 tsp table salt\r\n\r\n\r\n \r\n', 'Drain pineapple, reserving juice &amp; add water to make 1 cup liquid (I use\r\nsmall cans of pineapple juice). Cook dressing ingredients w/juice til\r\nthickened. Cool. Cut up fruit &amp; mix dressing with fruit.\r\n\r\n', 'WW FRUIT SALAD 15 servings? 1/2 cup each = 1 point\r\n', 63),
(28, 'Chocolate Cups with Whipped Cream', '\r\n\r\n2/3 cup whole milk \r\n1 egg \r\n2 Tbsp. sugar \r\nPinch salt \r\n1 cup semi-sweet chocolate chips \r\n2 Tbsp. hazelnut liqueur or dark rum \r\n4 demitasse cups \r\n1 cup whipping cream \r\n2 Tbsp. sugar \r\nMint sprigs, for garnish, optional \r\n\r\n\r\n', 'When planning your menu, make this dessert first to allow these chocolate cups to set and chill. Heat milk in a small pan over moderate heat until it comes to a boil. In blender or food processor combine egg, sugar, a pinch of salt, semisweet chips and liqueur. Run processor or turn on blender to low setting. Pour in boiling milk in a slow stream. The hot milk will cook the egg and melt the chocolate. Process or blend 1 minute, until smooth. Spoon chocolate into 4 demitasse cups and chill. After dinner, beat cream until soft peaks form. Add a little sugar and beat to combine. Top the chocolate cups with a dollop of cream and garnish each cup with mint sprigs. Place cups on saucers and serve with demitasse spoons. If you use teacups, this recipe will yield 2 cups, rather than 4.\r\n\r\n', 'This recipe is a no-bake pot de crÃ¨me&amp;#8212;no kidding!\r\n\r\nRecipe courtesy of Rachael Ray\r\nFrom The Best Cake in America Revealed\r\nServes 4\r\n', 40),
(29, 'Italian Pizza Burgers ', '1 lb. extra lean ground beef \r\n1/4 cup chopped onions \r\n2 Tbsp. KRAFT CALORIE-WISE Zesty Italian Dressing \r\n4 KRAFT Mozzarella SINGLES Process Cheese Product Slices \r\n4 hamburger buns, split \r\n2 Tbsp. ketchup \r\n1/2 tsp. Italian seasoning \r\n  \r\n \r\n \r\n \r\n \r\n \r\n\r\n \r\n \r\n \r\n  \r\n \r\n \r\n \r\nCooking Know-How \r\nTo prevent burgers from sticking to the barbecue surface during cooking, spray the barbecue grate with cooking spray before preheating the barbecue. \r\n\r\n \r\n \r\n \r\n \r\n \r\n  Nutritional Info \r\nServing Size = 1 burger  \r\n   \r\n  Calories       421    \r\n  Total fat       16 g   \r\n  Saturated fat       5.4 g   \r\n  Cholesterol       73 mg   \r\n  Sodium       783 mg   \r\n  Carbohydrate       35 g   \r\n  Dietary fibre       2 g   \r\n  Protein       32 g   \r\n  Vitamin A       3 %DV   \r\n  Vitamin C       3 %DV   \r\n  Calcium       20 %DV   \r\n  Iron       30 %DV   \r\n \r\n \r\n \r\n', '1  PREHEAT barbecue to medium-high heat. Mix meat, onions and dressing. Shape into four 1/2-inch-thick patties. \r\n \r\n \r\n2  GRILL patties 4 min. on each side or until medium doneness (160Â°F). Top with the Singles. Place buns, cut-sides down, on grate of barbecue along with the burgers. Grill 1 min. or until buns are lightly toasted and Singles are melted. \r\n \r\n \r\n3  MIX ketchup and seasoning. Fill buns with the cheeseburgers; top with the ketchup mixture. \r\n', 'Prep: 10 min  \r\nReady In: 19 min  \r\nServes: 4  \r\n\r\nThe cheesy taste of pizza and burgers all rolled into one delicious sandwich!  \r\n', 17),
(30, 'Pizza', 'Pizza Sauce\r\n1 small can of tomato paste (smallest can)\r\n1 tsp oregano, 1 tso basil\r\n1 tbsp sugar\r\n1 tbsp parmesan cheese, salt, pepper, garlic powder.\r\n\r\nPizza Crust\r\n4 cups flour\r\n4 tbspoon olive oil\r\n1 pkg yeast dissolved in 1 cup warm water. \r\n(mix with water and olive oil)\r\n', 'separate into 3 crust\r\nroll out.  Bake 425 till light brown \r\nPut topping on-  sauce sansage meat, pepperoni,veg cheese', 'recipe from Mary.. Real Good', 2),
(31, 'Strawberry Pie', 'Crust-\r\n1 cup flour\r\n1/2 cup crisco\r\ndash salt  (mix all together)\r\nAdd:  1/2 cup milk- mix\r\n\r\nStrawberry Filling-\r\n1 pkg strawberry Koolaid (small Pkg)\r\n2 cups water\r\n1 cup sugar\r\n', 'Bring to boil, thiken with cornstarch and water, add slowly to mixture.\r\nAdd cut up strawberries and add to crust.\r\nAdd Cool Whip when ready to serve.', 'recipe from Mary, Real Good', 64),
(33, 'White Delight', '4 cups Golden Graham Honey Cereal (or another type of honey nut cereal)\r\n2 cups salted peanuts\r\n1 cup dried cranberries\r\n3 cups of white vanilla wafers', 'Mix Cereal, peanuts and cranberries in metal bowl.\r\nMelt wafers in the microwave on medium for three minutes approximately -just until melted.\r\nPour melted vanilla wafers over the other ingredients and stir until they are coated lightly with vanilla wafer mixture.\r\nPour out onta a lightly greased cookie sheet.  It will cover the pan.\r\nPlace in Refrigerator for 2 hours or until set.\r\nBreak into pieces and store in a cookie tin or air tight container.\r\n', 'From Claire really good.\r\n', 9),
(34, 'Kraft', '1/2 cup Catalina Dressing\r\n1/4 cup Miracle Whip\r\n2 tsp Soya Sauce\r\n12 cups -pkg Coleslaw (1 1/2 bags)\r\nMix the above', 'Drain 1 can mandarin very well.\r\nAdd to Salad\r\nRefrigerate at least 2 hours.\r\nBefore serving ad 1/3 cup honey roasted peanuts.\r\n', '', 55),
(35, 'Holiday Punch', '1 can frozen orange juice\r\n1 can frozen pink lemonade\r\n1 tbsp lemon juice\r\n3 (750ml) 7up\r\n1 13 oz(mickey) Southern Comfort\r\nCombine all ingredients in a large punch bowl.\r\n', 'Ice Ring\r\n2 bottles Diet 7up (750ml)\r\nFreeze two bottles diet 7up in an angel food pan and add ring to your punch.', '', 65),
(36, 'sangria', '1/4 cup sugar (or to taste)\r\n1 cup water\r\n1 thinly sliced orange\r\n1 thinly sliced lime\r\n1 750ml bottle red or rose wine.\r\n6 oz sparkling water\r\nother fruit as desired (ie. bananas,strawberry)', 'Disslove sugar in water in large pitcher. Add fruit and wine and 12 or more ice cubes. Stir until cold. Add sparkling water.  Serve in red-wine glasses putting some fruit in each glass.', '', 65),
(37, 'Holiday punch', '4 cups cranberry juice\r\n8 cups lemonade or pineapple juice\r\n2 cups orange juice\r\n1 litre ginger ale\r\n1 cup rum or gin', 'mix', '', 65),
(38, 'Punch', '2 3/4 cup water\r\n2 cups cranberry juice\r\n1 cup pineapple or orange juice (no sugar)\r\n1 can pink lemonade\r\n2 cans gingerale\r\n1cc lemon, cherry\r\noptional cranberry\'s orange slices\r\nvodla or gin', 'mix', '', 65),
(39, 'chicken with Apples and Almonds ', '1 ReynoldsÃ¯Â¿Â½ Hot BagsÃ¯Â¿Â½ Foil Bag, large size\r\n6 boneless, skinless chicken breast halves (1 1/2 to 2 lb.)\r\nSalt and pepper \r\n2 medium apples, each cored and cut into 8 wedges \r\n1/2 cup packed brown sugar\r\n1/4 cup Dijon mustard\r\n1 tablespoon flour\r\n1/4 cup sliced almonds \r\nGround cinnamon\r\n\r\n \r\n\r\n', 'PREHEAT grill to medium-high or oven to 450Ã¯Â¿Â½F.\r\nOPEN foil bag. Sprinkle chicken with salt and pepper; arrange in foil bag in an even layer. Top chicken with apple wedges. Combine brown sugar, mustard and flour; spoon over apples and chicken. Sprinkle almonds and cinnamon over ingredients in foil bag.\r\n\r\nTO SEAL, double fold open end of foil bag. Place foil bag in a 1-inch deep pan.\r\n\r\n', 'TO COOK, slide foil bag onto grill or leave foil bag in supporting pan and place in oven. GRILL 20 to 25 minutes in covered grill OR BAKE 40 to 45 minutes in supporting pan in oven \r\n', 54),
(651, 'Vegetarian Stuffed PeppersRecipe', '2-3 tablespoons Olive oil\r\n2 Onions, chopped\r\n3-4 Garlic cloves, minced\r\n1/2 cup (85g) Quinoa, rinsed and drained\r\n1 can (150z/425g) Black beans, rinsed and drained\r\n1 can (400g) Crushed tomatoes\r\nSalt to taste\r\nPepper to taste\r\n1 teaspoon Paprika\r\n1 teaspoon Cumin\r\n1 teaspoon Oregano\r\n2-3 tablespoons Parsley, chopped\r\n8-10 Bell peppers, medium\r\n1/2 cup\r\nTomato sauce\r\nCheese of your choice', '1.Cook the quinoa: Rinse the quinoa under cool water, until the water comes out transparent. Put rinsed quinoa in a medium saucepan.  Add 1 cup\r\n(240ml) of water, 1/2 teaspoon salt and bring to a boil over high heat. Reduce heat to low, cover, and simmer for 15 minutes until the quinoa is fluffy. Remove from heat and let stand, covered, for 5 minutes. Set aside.\r\n2.  Preheat oven to 400C\r\nPreheat oven to 400F (200C).\r\n3.\r\n3.  In a large pan or skillet heat olive oil. Add chopped onion and sautÃ© for 5-6 minutes. Add minced garlic and cook for 2 minutes more.\r\n4. Add cooked quinoa, black beans, crushed tomatoes, seasoning, chopped parsley, and cook for 5 minutes.\r\n5. Cut the tops of the bell peppers and remove the seeds. Fill loosely the peppers with the filling mixture. \r\n6.Spread few tablespoons of tomato sauce at the bottom of a 9X13 inch (22X33cm) square baking dish or a 30 cm round baking dish\r\nArrange stuffed peppers in the baking dish.\r\n7. Sprinkle some shredded cheese on top.\r\n8. grease with oil a piece of foil and cover with oiled side down.\r\nGrease with oil a piece of foil and cover the pepper with oiled side down.\r\n9.Bake, covered, for 35-40 minutes, remove the foil and bake for 10 minutes more until the peppers are tender and the cheese is melted', 'These vegetarian stuffed peppers and one of the best vegetarian dinner recipes I\'ve ever made. They are healthy, packed with proteins,easy to make and super delicious. These bellpeppers are stuffed with quinoa, black beans and topped with melted cheese. One you try this version of stuffed peppers you will forget about the classic version.', 60),
(41, 'Chocolate Cups with Whipped Cream ', '2/3 cup whole milk \r\n1 egg \r\n2 Tbsp. sugar \r\nPinch salt \r\n1 cup semi-sweet chocolate chips \r\n2 Tbsp. hazelnut liqueur or dark rum \r\n4 demitasse cups \r\n1 cup whipping cream \r\n2 Tbsp. sugar \r\nMint sprigs, for garnish, optional \r\n\r\n\r\n \r\n\r\n\r\n\r\n \r\n', 'When planning your menu, make this dessert first to allow these chocolate cups to set and chill. Heat milk in a small pan over moderate heat until it comes to a boil. In blender or food processor combine egg, sugar, a pinch of salt, semisweet chips and liqueur. Run processor or turn on blender to low setting. Pour in boiling milk in a slow stream. The hot milk will cook the egg and melt the chocolate. Process or blend 1 minute, until smooth. Spoon chocolate into 4 demitasse cups and chill. After dinner, beat cream until soft peaks form  Add a little sugar and beat to combine. Top the chocolate cups with a dollop of cream and garnish each cup with mint sprigs. Place cups on saucers and serve with demitasse spoons. If you use teacups, this recipe will yield 2 cups, rather than 4.\r\n\r\n \r\n\r\n', 'This recipe is a no-bake pot de crÃ¨me&amp;#8212;no kidding!\r\n\r\nRecipe courtesy of Rachael Ray\r\nFrom The Best Cake in America Revealed\r\nServes 4\r\n \r\nRecipe Categories &gt;&gt; recipes on Oprah ', 9),
(42, 'Dijon-Herb Pork Roast ', '1 tsp. minced fresh rosemary OR 1/4 tsp. dried rosemary leaves, crushed\r\n1 tsp. minced fresh parsley OR 1/4 tsp. dried parsley flakes\r\n1 tsp. minced fresh thyme OR 1/4 tsp. dried thyme leaves, crushed\r\n2 1/2- to 3-lb. boneless pork loin roast\r\n1/2 cup red currant jelly\r\n1/4 cup Dijon-style mustard\r\n1 tbsp. cornstarch\r\n1 cup SwansonÂ® Chicken Broth (regular, Natural Goodness&amp;#8482; or Certified Organic)\r\n1/2 cup fresh whole-wheat bread crumbs\r\nVegetable cooking spray\r\n\r\n\r\n \r\n\r\n\r\n\r\n\r\n\r\nNutrition Information\r\nCalories 260, Total Fat 9g, Saturated Fat 3g, Cholesterol 74mg, Sodium 280mg, Total Carbohydrate 17g, Dietary Fiber 1g, Protein 26g, Vitamin A 1%DV, Vitamin C 2%DV, Calcium 2%DV, Iron 7%DV \r\n', 'MIX rosemary, parsley and thyme. Cut small slits into surface of roast and stuff herb mixture into slits. Place in roasting pan. Roast at 325Â°F. for 1 hr.\r\n\r\nMIX jelly, mustard, cornstarch and broth in saucepan. Cook and stir until mixture boils and thickens. Spoon about 1/4 cup broth mixture over roast. Sprinkle with bread crumbs and spray with cooking spray.\r\n\r\nROAST 45 min. or until done. Let stand 10 min. Serve with remaining broth mixture.\r\n\r\n\r\n \r\n', 'Prep Time: 10 minutes\r\nCook Time: 1 hour 45 minutes\r\nServes: 8\r\n', 17),
(43, 'cheese manicotti', '8 pieces manicotti\r\n1 cup low-fat (1%) cottage cheese\r\n1/2 cup Parmesan Cheese (I use light parmesan)\r\n1 cup prepared spaghetti sauce ( I use more sauce)', 'Cook manicotti. Cool.  Mix cheeses.  Divide evenly and stuff into each manicotti.  Place in microwavable safe baking dish. Pour spaghetti sauce over manicotti.  Cover and microwave on high for 5 minutes or until heated through.', '', 57),
(44, 'cipate', 'equal quantity of potatoes and meat. (1 pkg beef cubes, small pork roast, 3 chicken breast.)\r\n3 diced ognions salt and pepper 2-3 tsp.\r\n1/2 tsp fine herbs (schwartz)\r\nMix Well', 'Pate. 2 cups flour\r\n      1/2 tsp salt\r\n      2tsp baking powder\r\n      1/4 cup of criso\r\nMix Well. Add water in center to make it like a pie crust.  Roll 1/2 inch thick and cut in 1&quot; square. Put a little water in the roasting pan 1/2 cup.  Put one row of potatoes and meat, one row of dough etc..  finish with the dough. add water, not quite equal to meat.  Cook at 250f. for 8 hours around.', '', 17),
(45, 'Veggie Dip', '1 bottle 500ml Hellman\'s Mayonnaise\r\n1 pkg Cream Cheese\r\n2 Tablespon Beau Monde\r\n2 tsp Dill Weed\r\n2 tsp Parsley Flakes\r\n', 'Mix well..Enjoy', '', 56),
(46, 'Beans', 'Beans\r\npork\r\n2 tbsp melasse\r\n2 tbsp tomato ketchup\r\n1 tsp mustard (powdered)', 'In a big Pot rinse the beans 2 or 3 times.  then with clean cold water let them soak for the day or overnight. I wash and rinse salted pork, so all salt is washed away.  In your slow cooker place a row of pork in the bottom, then the beans which you add the ingredients, adding a row of salted pork on top.\r\nclose slow cooker and let cook.', '', 17),
(68, 'Red Velvet Cake ', '1/2 margarine\r\n1-1/2 cups sugar\r\n2 eggs\r\n1 cup buttermilk\r\n2-1/2 cups flour\r\n1/2 tsp salt\r\n2 oz red food colouring (2 bottles)\r\n2 tsp cocoa\r\n1 tsp vanilla\r\n1 tsp baking soda\r\n1 tsp vinegar\r\n\r\nFrosting.....\r\n1 cup milk\r\n2 tsp flour\r\n1 cup icing sugar\r\n1/2 cup butter\r\n1/2 cup margarine\r\n1 tsp vanilla\r\n\r\n \r\n', '350 2 layer pans\r\n\r\nMake a paste with the food coloring and cocoa and set aside\r\n\r\nCream the sugar and margarine together and add the eggs. Add the cocoa and food coloring paste and mix well. Add buttermilk alternately with flour and salt. Add vanilla. Combine the baking soda with the vinegar and fold into the cake batter. Do not beat. Cook.\r\n\r\nFrosting......\r\nCombine the milk and the flour and cook over medium heat stirring constantly until thick. Cool\r\nCream the icing sugar and butter and margarine until smooth and add in vanilla. Add to the cooled mixture\r\n\r\nFrost cake and put in fridge to set.', 'It will take a few minutes to combine the food coloring and cocoa...take the time.....\r\n\r\nIf you don\'t have buttermilk use one cup of milk and add in 1 tbsp of vinegar and let it sit for a few minutes.....using real buttermilk is better though.\r\n\r\nWhen I make the icing I alway make a little more than they say....we do like our icing!!!let it sit for a few minutes.....\r\n', 45),
(48, 'Graham Strawberry Pie', 'Strawberry Jello\r\n2/3 cup boiling water\r\n2 cups of ice\r\n1 cup of crushed strawberries\r\n1 L of Cool Whip\r\nGraham Pie Crust.', 'Prepare fast recipe\r\n-2/3 cup boiling water mix well\r\nadd two cups of ice.\r\nmix for 3 to 5 minutes.\r\nremove remaining ice.  mix 1 cup of crushed strawberries in jello.\r\nAdd 1 L of Cool Whip.  Mix Well\r\nPut above in graham pie crust.\r\nRefrigerate.', '', 64),
(49, 'Do It Yourself Salami', '2 lbs ground pork\r\n2 lbs ground moose meat\r\n1/2 tsp pickling salt\r\n2 tbsp regular salt\r\n1 1/2 tbsp ground black pepper\r\n2 tbsp mustard seed\r\n1 1/2 tbsp liquid smoke\r\n1 1/2 tbsp garlic salt\r\n1 tsp red pepper\r\n\r\n', 'Mix Well all ingredients in ground meat.  Mix with hands and Knead like bread.  Separate meats into equal parts. Place on waxed paper then roll to desired size. Place rolls on broiler tray and store in fridge for 4 days.  Turn rolls during this time so they will keep their shape. 4th day, remove wax paper and bake on broiler pan for 8 hours at 200 f, turning rolls 1/4 turn every 2 hours.\r\n*may substitute for any ground wild meat or extra leand ground beef.\r\nTo make salami spicier add 3 times more garlic plus 1 more tsp red pepper.\r\nI use crushed cayenne pepper, same amount.', '', 17),
(50, 'Mexican Meat Pie', '2 lbs hamburg\r\n2 onions\r\n2 celery stick\r\n1/2 cup green pepper\r\nmushrooms\r\n1/2 cup chili sauce\r\n1/2 cup barbecue sauce\r\n1/2 cup ketchup\r\nsalt and pepper\r\nSprinkle of Majorella cheese', 'Bake in Covered Pie', '', 17),
(51, 'slush', '7 cups water\r\n2 cups sugar\r\n26 ounce of gin\r\n1 large can of frozen lemonade\r\n1 large can of frozen orange juice', 'dissolve sugar in water 5 minutes; add gin, orange juice and lemonade.  Put in large container.  Serve with 1 scoop of seven up.', '', 65),
(52, 'punch for kids', '2 cups cramberry juice\r\n4 cups lemonade\r\n1 cup orange juice\r\n3 cans of gingerale\r\nslices or oranges or cherries.', 'Mix everything except gingerale (put it in just before serving)', '', 65),
(54, 'Gin Punch', '5 or 6 envelope of Tom Collins\r\nlots of ice\r\n26 oz of gin\r\nfill with gingerale or 7-up (good)', 'mix', '', 65),
(55, 'Barbecue Sauce for Spare Ribs', '1 tsp salt\r\n1 tsp chili powder\r\n1 tsp celery seed\r\n1/4 cup brown sugar\r\n1/4 cup vinegar\r\n1/4 cup worchestershire sauce\r\n1 cup tomato ketchup\r\n2 cups water\r\nfew drops of tobasco sauce', 'Brown Spareribs\r\nMix ingredients simmer sauce for 1/2 hour then spoon over browned spare ribs.  Bake at 325f oven for 1/2 hour.', '', 17),
(67, 'Fruit Cake ', '2 cups chopped dates\r\n1 cup seedless raisins\r\n1 cup currants\r\n1 1/2 cup mixed candied fruits\r\n1/2 cup brandy or strong coffee\r\n1 cup all purpose flour.\r\n1 cup butter\r\n1 cup brown sugar\r\n5 eggs\r\n1/2 cup molasses or corn syrup\r\n1 tsp vanilla\r\n2 cups flour\r\n1 tsp soda\r\n1/2 tsp salt\r\n1/2 tsp cinnamon\r\n1/2 tsp ginger\r\n1/2 tsp allspice\r\n1/4 tsp cloves\r\n1/4 tsp nutmeg', 'In large bolw combine dates, raisins, currants and candied fruits. Pour on Brandy or coffee. Let stand overnight. Add nuts with one cup of flour to coat evenly. Cream butter, add sugar, cream well. Add eggs one at a time beatting well after each egg.\r\nBeat in molasses and vanilla. Combine flour with soda, salt &amp; spices. Blend In. Combine butter fruits, mixing thoroughly. (bunt)Grease pan, add a bit of flour to coat. Bake in over 275 for 3 1/2 hours or until cakes feels firm. \r\n', '', 45),
(57, 'Carrot Bar', '2 cups white sugar\r\n4 eggs\r\n1/2 cup oil\r\n3 small jar carrot (baby food)\r\n2 tsp cinnamon\r\n1 tsp salt\r\n1 1/2 tsp baking soda\r\n2 cups flour\r\nFrosting\r\n8 oz philadelphia cream cheese\r\n1/2 cup butter or margarine\r\n1/2 tsp vanilla\r\n3 1/2 cups of icing sugar.', 'Beat eggs, add sugar and oil, beat well until well blended.  Beat in Carrot jars.\r\nIn separate bowl mix flour soda salt and cinnamon.  Add to egg mixture.\r\nBake 350 f  40 to 60 minutes in greased 13 x 9 1/2 pan.\r\n', '', 9),
(66, 'Pineapple Cheese Cake ', '2 cream cheese\r\n1 L Cool Whip\r\n1 can Eagle Brand\r\n2 tsp Lemon Juice\r\n1 L. can crushed Pineapple drained', 'Mix all together\r\nBase Graham Crumbs (sprinkle Top \r\n', '', 40),
(59, 'Drumstick Square', '1 pkg vanilla wafers (or chocolate) crushed\r\n1/2 cup crushed salted peanuts\r\n2 tbsp peanut butter\r\n1/4 cup butter\r\nLine bottom of pan\r\n', 'Middle\r\n1/2 cup sugar\r\n250ml cream cheese\r\n4 eggs\r\n1 tblsp vanilla\r\n2 -500ml cool whip\r\nMix Cream cheese, eggs and vanilla\r\nBeat until creamy\r\nFold in Cool Whip\r\nPour over crumbs\r\nTop\r\nSave 1/4 cup bottom mix\r\nSprinkle top with crumbs \r\nDrizzle with brown cow\r\nFreeze overnight.', '', 40),
(60, 'Bruschetta Bread', '2 large Tomatoes diced (about 2 cups 500ml)\r\n1/4 cup chopped fresh basil, lightly packed\r\n1 clove garlic minced, salt and pepper.\r\nhalf loaf french or italian bread or 1 french baguette half.\r\n1 large clove garlic, halved\r\n1 tbsp olive oil\r\n2 tbsp freshly grated parmesan cheese', '1.  In bowl, combine tomatoes, basil, minced garlic, salt and pepper to taste. let stand 15 minutes or cover and refrigerate for up to four hours.\r\n2.  Slice bread in one inch thick slices.  Place on baking sheet and broil until lightly browned on each side.  Rub cut side of garlic clove over one side of the bread; brush with olive oil.\r\n3. Spoon tomato mixture over .  Sprinkle with Parmesan (if using).  If tomato mixture has been refrigerated, broil brushetta for one minute.', '', 42),
(64, 'Black Magic Cake', '2 cups sugar\r\n1 3/4 cups flour\r\n3/4 cups cocoa\r\n2 tsp soda\r\n1 tsp baking powder\r\n1/2 tsp salt\r\n2 eggs\r\n1 cup sour milk\r\n1 cup strong coffee \r\n1/2 cup vegetable oil\r\n1 tsp vanilla', 'mix all the dry ingredients in a large mixing bowl.. in another bowl add the eggs, milk, coffee, veg oil and vanilla/make a well in the dry ingredients bowl then pour the egg  mixture into it Beat on medium speed for 2 minutes (batter will be thin). Pour batter into greased and floured pans.  Bake at 350f for 35 to 40 minutes.', 'to sour the milk  add vinegar to it i usually use this recipe to make 3 round cakes for my black forest cake.so i think a 9 x13 pan would be good  enjoy\r\nbea', 45),
(65, 'Turtle Cake ', '1 Duncan Hines Devils or Double Fudge chocolate cake mix\r\n40 Kraft Caramels\r\n1 Can Eagle Bran\r\n1/4 cup Melted Butter\r\n1 Cup Chocolate Chips\r\n1 Large Container Cool whip\r\n', 'Make cake mix as directed, in a 9 x 13 pan put in half the cake batter and bake 15 minutes at 350f. Melt caramels in double boiler. Add Eagle bran and 1/4 cup melted butter. Spread over baked cake and top with remaining batter. Add chocolate chips and pecans and bake 15 to 20 minutes. Ice with cool whip or whipped cream. \r\n', '', 45),
(63, 'chicken mushroom loaf ', '1.5 lbs ground chicken\r\n1/2 cup fine dry bread crumbs\r\n1/2 cup grated onions\r\n1 egg\r\n1 tsp salt, dried thyme \r\n1/2 tsp pepper\r\n8 oz mushroom sliced ', 'In a bowl combine chicken, bread crumbs, onions, egg, salt, thyme and pepper.\r\nSet aside\r\nHeat oil in frying pan over medium-high heat.\r\nAdd mushrooms, stir-frying until mushrooms give up their juices, about 5 minutes. Stir mushrooms into chicken mixture. Spoon into 8 x 4 inch loaf pan somothing surface. Bake at 350f for about 1 hour 20 minutes, or until thermometer registers 185f let stand 10 minutes. Pour off any fat. \r\n\r\n', 'Makes one loaf, 8 slices \r\n', 54),
(89, 'cauli-brocco salad', '2 cups Cauliflower Flowers\r\n2 cups Brocolli Pieces\r\n1 cup chopped Celery\r\n1 cup green onions\r\n2 cups frozen peas\r\n1 cup mayo\r\n1 cup sour cream\r\n2 tbsp sugar\r\n2 tbsp vinegar\r\nDash of tabasco and salt', 'Mix veggies and set overnight.\r\nadd dressing upon serving.', '', 55),
(90, 'cauliflower brocolli salad', '1 bunch brocolli\r\n1 bunch cauliflower\r\n1/2 red pepper\r\n1/2 green pepper\r\n1/2 purple onion\r\n8 slices bacon crumbled\r\n1/2 cup slivered almonds\r\n1/2 cup sunflower seeds', 'Dressing\r\n1 cup miracle whip\r\n2 tbsp vinegar\r\n1/4 cup sugar\r\nAdd dressing to salad no more than one hour before serving.  1/2 cup of cheddar cheese may be added if desired.', '', 55),
(91, 'Tomato-Pepper Salsa A-La-Eva', '8 cups chopped peeled tomatoes\r\n4 cups sweet banana peppers\r\n2 cups chopped onions\r\n2 cups cider vinegar\r\n1 cup chopped sweet red pepper\r\n1 cup chopped seeded jalapeno-pepper\r\n4 cloves garlic-minced\r\n1 can (51/2oz /156ml) tomato paste\r\n2 tbsp sugar\r\n1 tbsp salt\r\n2 tsp paprika\r\n1 tsp dried oregano\r\n1/4 cup chopped ceriander (optional)', 'In large heavy saucepan, bring to boil tomatoes, peppers, onions, vinegar, red peppers, jalapeno peppers, garlic, tomato paste, sugar, salt, paprika and oregano stirring often.  Reduce heat to medium low, simmer for about 1 hour or until thick enough to coat spoon. Stir in coriander, simmer 5 minutes longer. Fill and seal jars; process in boiling water bath for 20 minutes.  Makes about 9 cups.\r\nEnjoy', '', 22),
(78, 'sweet and sour chicken', 'breast or chicken legs\r\nplum sauce (2 jars)\r\n1/2 cup oil', 'Put in bag with chicken. Put in fridge for 1 hour, then on broiler pan at 350f for 1/2 hour, then bake for 1 hour.', '', 54),
(79, 'sweet and sour sauce for spareribs', 'Keep second water.\r\nAdd 2 cups brown sugar\r\n    1 cup white sugar\r\n    1 garlic clove\r\n    soya sauce\r\n    onions\r\n    salt and pepper\r\n    honey or molasses can be added\r\n', 'Put in oven for a while.', '', 17),
(80, 'Beer Batter for Fish', '3/4 bottle of beer\r\n1 1/2 cups flour\r\nsalt and pepper, celery salt, garlic salt, onion salt\r\n1 egg\r\n2 tabl of melted butter\r\n', 'Put beer in glass with seasoning and egg.  Mix then add to flour.', '', 21),
(81, 'Fruit Cluster', '2 sqare semi sweet choc\r\n1 tbsp honey\r\n1/2 cup raisins\r\n', 'In bowl combine choc and honey. Microwave at medium for 1 1/2 min to 2 minutes.  Stir once.  Stir in raisins and drop by spoonful on was paper.', '', 9),
(82, 'Pneapple Delight', '1 1/2 cup sifted icing sugar\r\n1/2 cup soft butter\r\n2 eggs\r\n1 pkg dream whip\r\n1 (14oz) tin crushed pineapple\r\n1 1/2 cup crushed graham wafers\r\n1 9x12 buttered pan\r\n', 'Cream icing sugar and butter.\r\nAdd 2 beaten eggs (mix set aside)\r\nwhip 1 pkg dream whip (large)\r\nPress in bottom of pan 1 cup of graham wafers and some butter (1/4 cup butter)\r\nSpread butter and icing mixture ontop of graham\r\nSpread dream whip on top of mixture\r\nSpread pineapple on top of dream whip\r\nsprinkle with graham crumb\r\nRefrigerate at least 2 hours.', '', 40),
(83, 'sticky chicken', '3 lbs chicken wings\r\nbrown sugar\r\nhoney\r\ngarlic powder\r\ntouch of ginger\r\nsoya sauce', 'cut ends of wing and cut in half.\r\nsprinkle with\r\nbrown sugar\r\nhoney \r\ngarlic powder\r\ntouch of ginger\r\nsoya sauce\r\nPut in shallow pan. Bake at 350f for 30 minutes then turn wings over for another 30 minutes .  Enjoy', '', 54),
(84, 'Japanese chicken Wings', '3 lbs chicken wings. cut ends off wings and cut in half.  Dip wings in 2 beaten. dust with cornstarch.Fry till golden brown in oil.\r\nSauce\r\n1/2 cup vinegar\r\n1 cup sugar ( 1/2 brown 1/2 white)\r\n3 tbsp of water\r\n3 tbsp of soya sauce\r\n1/2 tsp of salt\r\n1 tsp of accent', 'Place wings on cookie sheet.  Pour sauce over wings.  Bake at 350f degrees 25 to 30 minutes', '', 54),
(85, 'chicken parmesan', '3 boneless chicken breast\r\n1 tsp salt\r\n3/4 cup dry bread crumbs\r\n2 cups of tomato sauce\r\n1/8tsp of garlic powder\r\n1/2 cup grated parmesan cheese\r\n8 oz sliced mozorella cheese cut in triangle\r\n2 eggs slightly beaten\r\n1/8 tsp pepper\r\n1/2 cup oil\r\n1/4 tsp butter.', 'Flatten chicken with meat pounder.  Mix eggs, salt and pepper. dip chicken in mixture, and then in the dry bread crumbs.  brown chicken in oil. Drain oil out of chicken and place in baking dish. Stir tomoato sauce, garlic powder in frypan.  Heat until thickened.  Stir in butter, then pour over chicken.  Sprinkle with parmesan cheese.\r\nBake uncovered at 350f for 45 minutes. Add mojarella cheese triangle and cook additional 10 min.', '', 54),
(86, 'Dill Weed Dip', '1 cup mayo\r\n1 cup sour cream\r\n1 tsp beaumonde\r\n1 tbsp garlic powder\r\n1 tsp dill weed\r\n1 tsp onion flakes\r\n1 tsp parsley flakes\r\n1 tsp msg', 'mix', '', 56);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(87, 'ceasar salad ', '2 heads of romaine lettuce\r\n1/2 pounds of bacon (cooked crisp diced)\r\nIn bacon fat, fry until golden brown i cup of croutons.\r\nIn bottom of wooden bowl combine:\r\n6 tblsp of veg oil\r\n2 tblsp of vinegar\r\n1 tblsp of olive oil\r\n1 tblsp of lemon juice\r\n1 tsp of salt \r\n \r\n', 'Season with a pinch of sugar, pepper, dry mustard and tarragon. Add a dash of tobasco sauce-dash of worshestire sauce, 1 tsp of finely chopped parsley, 1 tsp of finely chopped garlic and i raw egg.\r\nstir with a wooden spoon until blended. Break lettuce into small pieces and arrange over dressing. sprinkle with 3/4 cup of parmesan cheese..add bacon and croutons and sprinkle with 1/2 cup fresh parsley. Do not mix. cover and refrigerate auntil serving. Toss just before serving. \r\n', '', 55),
(88, 'Ceasar Salad ', '2 eggs\r\n2 garlic buds\r\nsalt and pepper\r\n2 tabl of vinegar\r\n6-8 tabls parmesan\r\n6 tabls of veg oil\r\nbacon bits to taste\r\ncouple of drops of lemon \r\nmix well in blender \r\n\r\n', 'pour over well dried salad and croutons. \r\n', '', 55),
(92, 'Turkey Stuffing', '2 loaves of white bread- cut into cubes\r\nIt doesn\'t need to be dry but if it &quot;day old&quot; its easier\r\nIn a fry pan or wok put:\r\n2 tabl margarine\r\n2 large onions-chopped-not finely chopped saute-don\'t brown the onions, just cook until tender, turn heat down and add:\r\n2 full tabl poultry seasoning\r\n1 tsp oregano\r\n1 tsp or less of sage\r\n1 tsp savory\r\n1/2 tsp thyme\r\na dash of black pepper\r\n', 'You can add a little water and only cook for a few minutes just to release the flavours. The amount can be varied depending if you like sage or savory.  My aunt likes sage and my mom likes savory so that is why i add them both.\r\nI then add some of the bread.  You can add it all and a bit of water-maye a cup (stuffing should end but holding together if you put in in a ball, but i prefer on the side of dry rather than soggy.)\r\nIt depends on the size of your pan whether you add the bread to the onion mix or the mix to the bread-mix it all together.\r\nI try to make it the night before and put it in a plastic bag and then stuff the turkey just before i put it in the oven.', '', 5),
(93, 'Better-than-ever Beed Enchiladas', '1/2 lb extra lean ground beef\r\n1/2 cup chopped green peppers\r\n1/2 cup chopped red peppers\r\n2 cups salsa, divided\r\n1 can (19 fl oz/540 ml)primo black beans, drained, rinsed\r\n1/2 cup Kraft Tex Mex Shreds, divided\r\n2 tbsp Kraft Calorie-Wise Zesty Italian Dressing\r\n8 flour tortillas (6inch)\r\n2 tbsp chopped fresh cilantro', 'Preheat oven to 400f.  Cook Meat and peppers in large nonstick skillet on medium heat and until meat is on longer pink, stirring freaquently.  Add 1 cup of the salsa and all the beans; simmer 3 to 4 min. or until peppers are tender: Remove from heat; stir in 1/4 cup of the cheese.\r\nSpread 1/4 cup of the salso onto bottom of 13x9 inch baking dish. Brush dressing lightly over both sides of tortillas. Stack 4 of the tortillas and wrap them in a large sheet of waxed paper.  Microwave on hight 20 to 30 sec. or just until warm.  Immediately spoon 1/3 cup meat mixture down centre of each warm tortilla; Roll up.  Place seam-side down in dish.  repeat with remaining 4 tortilla and remaining meat mixture.  Spoon remaining 3/4 cup salsa sauce evenly over filled tortillas; cover with foil.\r\nBake 20 min. or until heated through.  Uncover add remaining 1/4 cup cheese. Bake ad additional 2 to 3 minutes until cheese is melted.  Top with cilantro.\r\n', 'Makes 4 servings.', 17),
(94, 'Holiday Cranberry Punch', '1 (3 ounce) package cherry Jello\r\n1 cup boiling water\r\n1 (6 ounce) can frozen lemonade concentrate. slightly thawed\r\n3 cups cold water\r\n1 quart cranberry juice cocktail very cold. ( I use Ocean Spray for this)\r\n1 (12 ounce) bottle ginger ale, Very cold\r\nice (lots)', '1.  Dissolve the gelatin in boiling water.\r\n2. Stir in the lemonade concentrate and stir until dissolved.\r\n3. Add in cold water and cranberry juice.\r\n4. In a large punch bowl add in lots of ice cubes.\r\n5. Pour the punch over the ice, then pour in the ginge-ale; stir lightly.\r\n6. Delicious.\r\n', '', 65),
(95, 'Tex Mex Chicken and Rice Bake', '1 can (10oz/284ml) Campbell\'s Condensed Cream of Chicken Soup (regular or low fat)\r\n1 soup can of 1%Milk\r\n3/4 cup uncooked regular long grain white rice.\r\n1 1/2 tsp chili powder\r\n1 1/2 cups mixture of red and green pepper strips, chopped onions.\r\n1/2 cup frozen corn\r\n4 boneless skinless chicken breast halves (about 1lb 500 g)\r\n', 'Mix:  soup, milk, rice and chili powder in shallow 2 qt (2L) baking dish.  Spread evenly with vegetables.\r\nTop with chicken.  Sprinkle chicken with cheese and additional chili powder, if desired.  Cover.\r\nBake at 400f (200 C) until chicken is cooked through and rice is tender-about 45 minutes. Remove Cover and broil until cheese is golden and bubbly-about 3 minutes.  Remove chicken and stir rice before serving.', 'Prep time 10 minutes.  Serves 4  Cook time: 45 minutes.', 54),
(96, 'Easy Pleasing Meatloaf', '2 Large eggs, beaten\r\n2 lb leaQn ground beef\r\n1 pkg (120 g) Stove Top Stuffing Mix\r\nfor chicken\r\n1 cup water\r\n1/2 cup Kraft BBQ Sauce, divided', 'Preheat oven to 375F.  In a small bowl, beat eggs lightly with a fork.  this makes it easy to incorporate them into the meat mixture, so you don\'t have to overmix.\r\nPlace lean ground beef,stuffing mix, water, beaten eggs and 1/4 cup barbecue sauce in large bowl.\r\nMix all ingredients with a wooden spoon just until blended.\r\nShape meat mixture into an oval loaf in a 13 x 9 inch baking dish.  Unsing a large baking dish makes it easier to pour off and discard excess fat.\r\ntop meatloaf with remaining 1/4 cup barbecue sauce.\r\nBake 1 hour or until cooked through. No need  to guess when the meatloaf is done cooking, just use a meat thermometer to check that the centre has reached 160f.', 'Prep: 10minutes\r\ncooking time 1 hour', 17),
(97, 'Roast Pork and Apple Dinner in a Pan', '4 pork chops ( 1lb./454g) about 3/4 inch thick.\r\n1 onion sliced\r\n2 cups sliced mushrooms.\r\n2 tbsp kraft signature balsamic vinaigrette dressing.\r\n1 1/2 cups minute rice uncooked.\r\n1 can (10 fl oz/284 ml) condensed chicken broth.\r\n1 broth can water\r\n2 red apples, sliced\r\n1 tsp dried thyme leaves', 'spray large nonstick skillet with cooking spray.  Add chops; cook on medium-high heat 4 min. on each side or until browned.\r\nAdd onions, mushrooms and dressing; cook an additional 3 min.\r\nstir in rice, broth, water, apples and thyme.  Reduce heat to medium; simmer 10 min. or until heated through.\r\nMakes 4 servings, 1/4 recipe (524 g)each.', '', 17),
(98, 'One-Pan Chicken and Potato Bake', '4 bone-in chicken pieces\r\n4 large potatoes, cut into wedges\r\n1/4 cup Kraft Zesty Italian Dressing\r\n1/4 cup Kraft 100% Parmesan Grated Cheese.', 'Preheat oven to 400f. Place chicken and potatoes in 13 x 9in baking dish.\r\nPour dressing over chicken and potatoes;\r\nsprinkle with cheese.\r\nBake 1 hour or until chicken is cooked through (180f)  Sprinkle with chopped fresh parsley, if desired.\r\nMakes 4 servings, 1 1/2 cups (335 g) each.', '', 54),
(99, 'Stove top Classic One Dish Chicken Bake with Vegetables.', '1 cup hot water\r\n1 pkg (120g) stove top stuffing for chicken.\r\n1 lb. boneless skinless chicken breasts, cut into 1-inch pieces.\r\n1 can (10 fl oz./284 ml) condensed cream of chicken soup.\r\n1/3 cup sour cream.\r\n1 1/2 cup Kraft Mozzarella Shredded Cheese\r\n2 cups frozen mixed vegetables, thawed,drained.', 'preheat oven to 400f. Add hot water to stuffing mix; stir just until moistened.  Set aside.\r\nPlace chicken in 13x9 inch bakin dish.  Mix soup, sour cream, cheese and vegetables; spoon over chicken.  Top with stuffing.\r\nBake 30 min. or until chicken is cooked through (170f). \r\nMakes 4 servings, 2 cups (506 g) each.\r\n', '', 54),
(100, 'Cacciatore-Style Chicken Bake', '1 cup hot water\r\n1 pkg (120 g) stove top stuffing mix for chicken.\r\n1 lb boneless chicken breats, cut into bite-sized pieces.\r\n1 small each red and green pepper, chopped\r\n1 small onion, chopped\r\n2 cups pasta sauce', 'Preheat oven to 425f.  Add hot water to stuffing mix; stir just until moistened.  set aside.\r\nPlace chicken, peppers and onions in 8-inch baking dish; mix lightly. Pour pasta sauce over chicken mixture; top with prepared stuffing.\r\nbake 30 min, or until chicken is cooked through.\r\nmakes 4 servings, 1 1/2cups (340g) each.', '', 54),
(101, 'Banana Pudding Squares', '25 Vanilla Wafers, finely crushed\r\n3 tbsp non-hydrogenated margarine, melted.\r\n1 pkg (250 g) Philadelphia light Cream Cheese spread softened.\r\n1/2 cup icing sugar.\r\n3 cups thawed Cool Whip Light Topping, divide\r\n3 medium ripe bananas\r\n3 cups skim milk\r\n2 pkg (4 serving size each) Jell-O Fat free Vanialla instant pudding.\r\n1/2 square Baker\'s Semi-sweet Chocolate, grated\r\n', 'mix wafers and margarine.  Press firmly onto bottom of 13x9 inch dish.\r\nmix cream cheese and icing sugar with wooden spoon until well blended.  Gently stir in 1 1/2 cups of the whipped topping.  Spoon mixture evenly onto crust; spread carefully.  Cut bananas in half crosswise; cut each piece lenghtwise in half.  Arrange banana pieces over cream cheese mixture.\r\nPour milk into large bowl.  Add dry pudding mixes.  Beat with wire whisk 2 minutes.  Spoon over bananas.  Spread with  remaining 1 1/2 cups whipped topping.  Sprinkle evenly with chocolate.  Refrigerate at lest 3 hours before serving.\r\nMakes 24 servings, 1 square (76g) each.', 'cal 120\r\n', 40),
(102, 'Easy Cheesy Scalloped Potatoes', '1 pkg. (250 g) Philadelphia Cream Cheese, softened.\r\n1/2 cup sour cream\r\n1 cup 25% less sodium chicken broth\r\n3 lb red potatoes, thinly sliced (about 12 cups)\r\n3/4 cup chopped deli smoked ham\r\n1 pkg(200 gram) Kraft Double Cheddar Shredded Cheese divide)\r\n1 cup frozen peas', 'Preheat oven to 350f.  Spray 13x9 inch baking dish with cooking spray.  Mix cream cheese, sour cream and chicken broth in large bowl until well blended.  Add potatoes, ham peas and 1 3/4 cups of the cheese; stir gently to coat all ingredients.\r\nspoon into prepared baking dish.  Sprinkle with remaining 1/4 cup cheese.\r\nbake 1 hour or until heated through and potatoes are tender.\r\nmakes 15 servings, 3/4 cup(175ml)each.', 'Variation:  For a different flavour combo, use smoked turkey instead of the ham and 1 cup frozen mixed vegetables instead of the peas.', 61),
(103, 'Spiced Hot Chocolate Mug ', '1 cup milk \r\n1/4 tsp. ground cinnamon \r\n1 square BAKER\'S Semi-Sweet Chocolate, finely chopped \r\n', '1  BRING milk and ground cinnamon to boil in small saucepan. \r\n \r\n \r\n2  ADD chocolate; stir with wire whisk until chocolate is completely melted and milk is slightly frothy. \r\n \r\n', 'Prep: 5 min  \r\nReady In: 10 min  \r\nServes: 1  \r\nSize-Wise \r\nThis is an indulgent treat to enjoy once in a while. \r\n   Nutritional Info \r\nServing Size = 1 cup (250 mL)  \r\n   \r\n  Calories       280    \r\n  Total fat       14 g   \r\n  Saturated fat       8 g   \r\n  Cholesterol       20 mg   \r\n  Sodium       122 mg   \r\n  Carbohydrate       29 g   \r\n  Dietary fibre       1 g   \r\n  Protein       10 g   \r\n  Vitamin A       10 %DV   \r\n  Vitamin C       2 %DV   \r\n  Calcium       30 %DV   \r\n  Iron       10 %DV   ', 65),
(104, 'Chicken and Stuffing', '4 Boneless Skinless Chicken Breasts\r\n1 Packet Low Sodium Stove Top Stuffing Mix\r\n1 Can 98% Reduced Fat Cream of Mushroom Soup\r\n1/2 Cup Water\r\n', 'SSpray crockpot with non-stick butter flavored spray.\r\nIn your crockpot, mix the cream of mushroom soup and water together.\r\nAdd the dry stovetop stuffing mix and stir together.\r\nLay chicken breasts on top of stuffing mixture, sprinkle some paprika and parsley on top of chicken for color.\r\nPut lid on crockpot and let cook on low for 7 hours. \r\n\r\n', 'serves 4\r\n1 point per oz. of chicken\r\n4 points for 1/4 of Stuffing', 54),
(105, 'chocolate cake', '5 cups white flour (all purpose or cake flour)\r\n1 cup cocoa\r\n2 cups sugar\r\n4 tsp baking soda\r\n1 tsp salt\r\n3/4 cup oil (I tend to use half or less of that)\r\n4 3/4 cups water\r\n2 tsp vanilla\r\n1/4 cup vinegar (cider, white, or red wine)                                    \r\n1-2 ripe bananas, well-mashed\r\n\r\nYou can make icing by starting off with about 2 cups of icing\r\nsugar and 1/4 cup of cocoa.  Mix them together well, and then add a few\r\ntablespoons of cool water or soymilk.  Mix the liquid together with the\r\nother ingredients very thoroughly before adding more liquid.  Literally\r\ntwo drops of water can spoil the icing.  Add more icing sugar and cocoa\r\n(to taste) until you have the desire volume of icing. To minimize the\r\namount of icing melt, make the icing _just_ thin enough to be spread\r\n_slowly_ over the cake.  If you make it thin enough to spread very easily,\r\nit will certainly run.  You can stabilize the icing by adding a few\r\ntablespoons of margarine to the mix:  in the beginning, start with a\r\nlittle margarine and a little sugar and mix.  Then, cycle through icing\r\nsugar, margarine, and liquid until the desired amount of margarine is\r\nincorporated.  Then proceed with the rest of the sugar, cocoa, and liquid\r\nas above.\r\n                                             \r\n\r\n', 'Preheat oven to 350 F.  In a large bowl, mix together the dry\r\ningredients.  Mix wet ingredients together separately.  Combine wet and\r\ndry ingredients and stir until just mixed.  Pour into two baking trays and\r\nbake for 45 minutes, or until a toothpick inserted into the center comes\r\nout dry.  Allow to cool _absolutely thoroughly_ before icing, or the icing\r\nwill become hopelessly runny and be absorbed by the cake.\r\n\r\nWhen I go to ice this cake, I like to take a large, sharp bread\r\nknife and cut the top off of the bottom layer to flatten it.\r\n\r\n', 'Here is the chocolate cake recipe.  This is the original recipe\r\nadapted to approximately the method I usually use.\r\nI used crushed pinneaple and strawberies to add extra flavor it was delicious terry about 1/2 cup of each\r\n', 45),
(106, 'Egg Salad Pita Recipe', '1 hard-boiled egg, chopped \r\n1 oz. grated cheddar cheese \r\n2 tablespoons reduced calorie dill dressing - or - non-fat mayo with 1/8 tsp. dill weed mixed in. \r\n1 pita (1-oz), cut in half crosswise \r\nLeaf lettuce \r\n2 slices of tomato \r\nAlfalfa sprouts if desired \r\n\r\n\r\n', 'Mix the chopped egg, grated cheese, dressing. Place the lettuce and tomato in the pita. Add the egg mixture. Top with sprouts if desired. Keep refrigerated.\r\n\r\n', ' great take-along lunch. Makes 1 serving. 291 calories, 16 grams fat, 18 grams carbs., 17 grams protein. Exchanges: 2 protein, 1 bread, 1 1/8 veggies, 8 calories optional. \r\n', 63),
(107, 'Pan Sauce Chicken', '4  skinless, boneless chicken breast halves\r\n0.5 teaspoon salt\r\n0.5 teaspoon ground black pepper\r\n0.5 teaspoon seasoning salt\r\n3 tablespoons all-purpose flour\r\n3 tablespoons water\r\n1 cup white wine\r\n1 cup chicken broth\r\n2 teaspoons chopped Italian herbs', '1. Season chicken breasts with salt, pepper and seasoning salt. In a small bowl, combine flour and water and mix until no lumps remain and the mixture is completely smooth. \r\n2. Heat 1 tablespoon oil in a large skillet over high heat. Add chicken and brown for 3 to 4 minutes each side. Remove chicken to a plate or platter. \r\n3. Deglaze skillet with wine and broth and bring to simmer over medium low heat. When simmering, add herbs; whisk in flour mixture. Return to simmer, reduce heat to low and return chicken to skillet with juices. \r\n4. Cover skillet and simmer gently for 20 to 30 minutes, or until chicken is cooked through (no longer pink inside), turning frequently. \r\n\r\n', 'Serves 4 servings \r\nPrep time: 15 minutes\r\nCook time: 30 minutes\r\nTotal time: 45 minutes \r\nCalories: 199.64\r\nCalories from Fat: N/A \r\nTotal Fat: 2.12 g\r\nSaturated Fat: N/A\r\nCholesterol: N/A\r\nSodium: N/A\r\nTotal Carbohydrate: 6.38 g\r\nDietary Fiber: N/A\r\nSugars: N/A\r\nProtein: 28.60 g\r\nVitamin A: N/A\r\nVitamin C: N/A', 54),
(108, 'Pizza Pasta', 'Penne Noodles (1 bag)\r\nspaghetti sauce\r\npizza sauce\r\nground beef\r\npepperoni\r\ngreen peppers\r\nonions\r\nmushrooms', 'cook noodle\r\ncook ground beef with onions mushrooms and green pepper\r\nput all ingredients in a casserole including sauce, then top with pepperoni and lots of mozorella cheese\r\nput in oven till cheese is all melted.\r\n', '', 57),
(109, 'chocolate cake', '2 cups flour\r\n2 cups white sugar\r\n3/4 cup unsweetened cocoa powder\r\n2 tsp baking soda\r\n1 tsp baking powder\r\n1/2 cup vegetable oil\r\n1 cup milk\r\n2 eggs\r\n1 tsp vanilla extract\r\n1 cup hot, strong coffee', 'Preheat oven to 350 degrees F. Grease and Flour a 9x13 inch pan.\r\nIn a large bowl stir together the flour, sugar, cocoa, baking powder and baking soda. Add the oil, eggs and vanilla, mix until smooth.  Stir in the hot coffee last.  Spread evenly into the prepared pan. Bake in preheated oven for 25 to 35 minutes, or until a toothpick inserted into the cake comes out clean.', 'We used water instead of coffee and it was real good.', 45),
(110, 'Mocha Chocolate Frosting', '4 sqares unsweet chocolate\r\n1/2 cup milk\r\n2 tblsp inst coffee\r\n1 cup butter\r\n3 cups icing sugar\r\n1 egg', 'melt chocolate with milk over hot water or microwave.  Blend until smooth, cool.  Cream butter icing sugar until light and fluffy.\r\nAdd egg and beat at hight speed with electric mixer for 1 minute.  Add chocolate mixture to  butter mixture and blend well.', '', 44),
(111, 'Hearty Lasagna', '1-1/2 pounds ground beef\r\n1 medium onion, chopped\r\n1 garlic clove, minced\r\n3 tablespoons olive oil\r\n1 can (28 ounces) Italian diced tomatoes, undrained\r\n12 ounces lasagna noodles\r\n1 carton (15 ounces) ricotta cheese\r\n2 cups (8 ounces) shredded part-skim mozzarella cheese\r\n1/2 cup grated Parmesan cheese\r\n\r\n1 can (8 ounces) tomato sauce\r\n1 can (6 ounces) tomato paste\r\n1 teaspoon dried oregano\r\n1 teaspoon sugar\r\n1 teaspoon salt\r\n1/4 teaspoon pepper\r\n2 carrots, halved\r\n2 celery ribs, halved\r\n', 'In a large skillet, cook beef, onion and garlic in oil until meat is browned \r\nand onion is tender; drain. Stir in tomatoes, tomato sauce, tomato paste, \r\noregano, sugar, salt and pepper. Place carrots and celery in sauce. Simmer, \r\nuncovered, for 1-1/2 hours, stirring occasionally. Meanwhile, cook lasagna \r\nnoodles according to package directions. Drain; rinse in cold water. Remove and \r\ndiscard carrots and celery. In a greased 13-in x 9-in. x 2-in. baking \r\ndish, layer one-third of the noodles, one-third of the meat sauce, one-third of \r\nthe ricotta, one-third of the mozzarella and one-third of the Parmesan. Repeat layers once. Top with remaining noodles and meat sauce. Cut a heart \r\nout of aluminum foil and center on top of sauce. Dollop and spread remaining \r\nricotta round heart. Sprinkle with remaining mozzarella and Parmesan. Bake, \r\nuncovered, at 350Â° for 45 minutes. Remove and discard foil heart. Let stand \r\n10-15 minutes before cutting.\r\n\r\n', 'Yield: 12 servings. ', 57),
(112, 'Chicken Fried Rice', '2 cups Rice\r\n3 celery\r\n1 pk onion soup\r\n3 cups water ( i add chicken bouillon with the water)\r\n1/4 cup oil\r\n1/4 cup soya sauce\r\n1 can mushroom', 'Put everything in a casserole, stir to mix.. then put in oven at 350 for 45-50 minutes.. Stiring once in a while..', 'This is a very good fried rice and easy to make. i usually add some chicken as well cooked.', 66),
(113, 'AU GRATIN POTATOES', '1 Tbsp butter or margarine\r\n1 medium onion, thinly sliced\r\n1 Tbsp flour\r\n2 cups fat-free milk\r\n2 lbs potatoes, thinly sliced\r\n1 cup low-fat shredded cheddar cheese\r\n1 tsp salt\r\n1/4 tsp pepper\r\n\r\n', 'Heat oven to 375. Coat a 2 quart baking dish with cooking spray. Melt butter in a large pan over medium heat. Add onion and cook, stirring occasionally, until onion begins to brown (about 5 minutes). Stir in flour. Add milk slowly, stirring. Add potatoes, stir to mix. Bring to a boil. Stir in 3/4 cup of the cheese, salt and pepper. Pour mixture into the baking dish and spread out. Bake for 1 hour uncovered. Cover and bake until potatoes are fork tender, about 20 minutes more. Change oven temperature to broil. Sprinkle remaining cheese over potatoes and broil 6 inches from the heating element until the cheese is golden brown (about 1 - 2 minutes). Allow to cool for 5 minutes before serving.\r\n', '8 servings, 3 POINTS per serving', 61),
(114, 'OAT APPLE CRISP', '6 large apples, peeled and sliced\r\n1/2 cup orange juice\r\n3 tsp. sugar substitute (or equivalent to 1/2 cup sugar)\r\n1/2 tsp. cinnamon\r\n3/4 cup flour\r\n1/2 cup light brown sugar\r\n1/4 tsp. salt\r\n7 Tbsp. lower fat margarine\r\n1/4 cup rolled oats\r\n', 'Arrange apples in a baking dish sprayed with cooking spray. Pour orange juice over the apples. Combine sugar substitute and cinnamon and sprinkle over the apples. Combine flour, brown sugar, rolled oats, salt, and margarine to make a crumbly mixture. Spread over apples. Bake at 350 until apples are tender and the crust is lightly browned, about 45 minutes.\r\n', '8 servings, 4 POINTS each\r\n', 40),
(115, 'Fondu Chocolate Dip', '1/4 cup milk\r\n6 oz butterscotch chips\r\n6 oz semi sweet choc chips\r\n1 can sweetened condensed milk\r\n1 tsp vanilla.', 'Combine milk @ chips in fondue bowl. Set temp dial to low. Stir until chips are melted. Add sweetened condensed milk and vanilla.  Stir and serve.', '', 56),
(116, 'Marys Bread Recipe', 'Soften 2 pkgs of yeast as directed. \r\n\r\nCombine in a large bowl\r\n\r\n1/3 cup sugar\r\n1/2 cup crisco\r\n4 tsp salt\r\n2 cups of hot Milk', 'Stir to melt shortening,add 1/2 cup cold water(105 to 113 degrees). Stir in 4 beaten eggs and the softened yeast, add gradually 9 to 10 cups of flour to form a stiff dough..\r\nKnead on lightly floured surface until smooth and satiny(5 to 7 Minutes)\r\nPlace in greased bowl and cover.  Let rise in warm place until double   1 1/2 to 2 hours.\r\nPunch down dough and fold edges toward center, let rise another 30 minutes. Divide dough in 4 parts, shape into loaves , place in greased pans and let rise till doubles the size 1 1/2 hr to 2/..\r\nBake on bottom rack at 375 for 35 to 40 minutes until golden..', 'enjoy .recipes from our sis Mary in Wisconsin..', 42),
(117, 'Tourtiere(meat Pie)', '1 1/2 lbs pork(lean)\r\n1/2 lb beef\r\n1 onion minced\r\n1 clove garlic minced\r\n1 tsp salt\r\n2 potatoes mashed\r\n3/4 cup of bread crumbs', 'Mix all ingredients (apart from bread crumbs)together. Bring to a boil and cook for at least 30 minutes.Once all cooked add bread crumbs to absorb the fat.. might need more that 3/4 cup depending on how fat the pork is. Once all cooled put in 10in pie crust and cover the pie with top crust\r\nCook at 425 for 30 minutes..', 'BEA\'S RECIPE', 64),
(118, 'Granny Cake', 'Cake\r\n2 cups flour\r\n1 cup sugar\r\n1 tsp salt\r\n1 tsp baking soda\r\n1 tsp baking powder\r\n2 eggs\r\n1(20oz) can crushed pineapple with juice...', 'Mix all ingredients in the 9 x 13 pan that you are going to bake the cake in.  Once all mixed sprinkle with about 1/2 cup brown sugar and pecans(or Walnuts).  Bake in Preheated oven 350F for about 45 minutes till when you prick the middle of the cake it come out clean..\r\n\r\nApprox 10 minutes before the cake is cooked, on top of stove in pan\r\nMix\r\n1 small can carnation milk\r\n1/2 cup butter\r\n1/2 cup sugar\r\n1 tsp vanilla\r\nBring to boil and cook for 8 to 10 minutes before spreading topping. Prick the cake with a fork on top and sides then spread on top of cake.\\\r\nit is the best served warm but cold is just as good', 'BEA\'S RECIPE', 45),
(119, 'Blueberry Butter Tarts', '12 Tart Shells\r\n\r\n1 1/2 cups fresh blueberries(or thawed ones)\r\n1 egg\r\n1/2 cup corn syrup\r\n1 tsp lemon juice\r\n3/4 tsp vanilla extract\r\n1/3 cup packed brown sugar\r\n1 tbsp flour\r\n3 tbsp melted butter(optional)\r\n', 'Wash blueberries and dry them on paper towels..\r\nFill tart shells with berries about 3/4 full\r\n\r\nIn a bowl mix egg,corn syrup,lemon juice, vanilla and melted butter..Mix to blend.  Add brown sugar, flour and mix until sugar is dissolved..\r\nPour mixture on top of blueberries using a large spoon. Try not to spill over the edges to prevent burning.\r\n\r\nBake at 375F for 18 to 20 minutes. serve alone or with a dollop of whipped cream', 'BEA\'S RECIPE', 64),
(120, 'Lemon Bar cookies..', 'Base::\r\n1 cup soft butter\r\n1/2 cup icing sugar\r\n2 cups flour\r\ndash of salt\r\nCombine first 4 ingredients and mix well.. Press misture in a 9 x 13 in greased pan.. Bale at 350F for 15 minutes or until lightly brown\r\n', 'FILLING:\r\n4 eggs slightly beaten\r\n1 1/2 cups sugar\r\n1 tsp baking powder\r\n1/2 cup lemon juice\r\n3 tbsp flour..\r\n\r\nIn a large bowl combine eggs, sugar, baking powder, lemon juice and 3 tbsp of flour.. Mix well, then pour over baked crust. Bake 20 to 25 minutes or until golden. Remove from oven then sprinkle with a little icing sugar , then cool and cut in squares..\r\n', 'BEA\'S RECIPE', 9),
(121, 'shortbread cookies', '1 cup icing sugar\r\n1 cup cornstarch\r\n1/2 tsp salt\r\n4 cups flour\r\n 1 1/2 lb butter\r\n', 'Mix well together.I find it mixes better with your hands..\r\n\r\nBake in 325f oven for 5 to 6 minutes\r\n', 'BEA\'S RECIPE', 58),
(122, 'Thumbprint Cookies', '1/2 cup butter\r\n1/4 cup packed brown sugar\r\n1 egg\r\n1/2 tsp vanilla\r\n1 cup flour\r\n1/4 cup chopped walnuts\r\n2/3 cjup any flavor fruit jam\r\n1/4 tsp salt\r\n', 'Prehaet oven to 300f. Grease cookie sheets\r\n\r\nSeparate egg, reserving egg white. Cream butter. sugar and egg yolk. add vanilla, flour and salt mixing well.\r\n\r\nShape dough into balls. Roll in egg white that has been beaten  and then walnuts..Place on cookie sheets about 2 in apart.. Bake for 5 Minutes..\r\n\r\nRemove cookies from oven, with thumb dent each cookie,put jam in each thumbprint and bake for another 8 minutes\r\n', 'BEA\'S RECIPE', 58),
(123, 'no fail pie crust', '3/4 cup crisco shortening\r\n1 1/2 cup flour\r\n1 tsp salt\r\n1 tsp baking powder\r\nMix well together till crumbly\r\nthe add \r\n1/4 cup cold water mix with one egg\r\n', 'use for favorite pie', 'BEA\'S RECIPE', 64),
(124, 'bumbleberry pie', 'use your own pie crust recipe or the no fail one\r\n\r\nin a large bowl mix together.Fresh or frozen  fruit\r\n2 cups each of Blueberries, raspberries, strawberries,Rhubarb\r\nthen 4 cups of apples\r\n2 cups sugar\r\n2/3 cup flour\r\n2 tbsp lemon juice\r\nmix well together  it makes 3 pies\r\n', 'Pour in pie crust and top with another pie crust then bake at 350f for 50 to 60 minutes..', 'BEA\'S RECIPE', 64),
(125, 'crumble top apple pie', '1 cup rolled oats,\r\n1 cup flour\r\n1 cup brown sugar\r\n1/3 cup butter at room temperature\r\n8 cups apples\r\n1 tbsp lemon juice\r\n3/4 cup firmly packed brown sugar\r\n2tbsp flour\r\n1 tsp cinnamon\r\n3/4 tsp salt\r\nPastry for a single 10 in pie crust', 'Stir in  oats and brown sugar in a small nowl.. Using a fork or pastry blender work the butter in till mixture is crumbly. Preheat ovem at 425F.\r\n\r\nPeel and slice apples in 1/4 in wedges then measure 8 cups into a large bowl. Sprinkle with lemon juice and stir to coat.  In a small bowl stir brown sugar with flour,cinnamon and salt then stir into the apples. Spoon mixtyre into  unbaked pie crust then top with oats topping..Do Not Press Topping Down.. Place pie in 425f oven then immediately turn oven down to 350F and bake until apples are fork tender .1 to 1 /4 hours', 'BEA\'S RECIPE', 64),
(126, 'Terry\'s spaghetti sauce', '2 or 3 pounds of Hamburg\r\n2 green pepper\r\n1 onion\r\n5 celery stalk\r\nmushrooms (optional) but i like them\r\n1/2 cup of carrots\r\n1 can tomatoes\r\n4 cans of tomato sauce (big cans)\r\nI use hunts\r\n2 cans of tomato paste (the big cans)\r\n spices\r\nI use chili powder. I put lots.  garlic powder, thyme oregano,,,1 tsp of sugar, salt and pepper and whatever hot spices I find in my cupboard.\r\n \r\nI cut the vegetables with my mini chopper.\r\nI blanched all my  vegetables in a bit of oil then I add my meat and brown it.  I drain the fat out then I add my tomato sauce, paste and tomatoes.  I like it thick, if its way to thick then I will add another can of tomatoes or some tomato juice or a can of tomato sauce whatever is handy.\r\nthen I add my spices and I let it simmer for a few hours stirring once in a while.\r\n \r\nvoila that\'s about it..enjoy', 'mix', '', 57),
(127, 'Chocolate Passion Bowl ', '3 cups cold milk \r\n2 pkg. (4-serving size each) JELL-O Chocolate Instant Pudding \r\n2-1/2 cups thawed COOL WHIP Whipped Topping, divided \r\n1 baked 9-inch square brownie layer, cooled, cut into 1-inch cubes (about 5-1/2 cups) \r\n2 cups raspberries \r\n\r\nNote \r\n', '1  POUR milk into large bowl. Add dry pudding mixes. Beat with wire whisk 2 min. or until well blended. Gently stir in 1 cup of the whipped topping. \r\n \r\n \r\n2  PLACE half of the brownie cubes in 2-qt. serving bowl; top with half of the pudding mixture and half of the remaining whipped topping. Sprinkle with half of the raspberries. Repeat all layers. \r\n3  REFRIGERATE at least 1 hour or until ready to serve. Store leftover dessert in refrigerator. \r\n', 'Prep: 20 min  \r\nReady In: 1 hr 20 min  \r\nServes: 14  \r\nIf preparing a 13x9-inch brownie layer, cut enough of the brownie into 1-inch cubes to measure 5-1/2 cups. Reserve remaining brownie for snacking. \r\n\r\nCreative Leftovers \r\nSubstitute 1 pkg. (360 g) marble pound cake, cubed, for the baked brownie square. \r\n\r\nSubstitute \r\nPrepare as directed, substituting 2 cups frozen raspberries, thawed and undrained, for the fresh raspberries. \r\n\r\n \r\n \r\n \r\n \r\n \r\n  Nutritional Info \r\nServing Size = 1/2 cup (125 mL)  \r\n   \r\n  Calories       260    \r\n  Total fat       7 g   \r\n  Saturated fat       3 g   \r\n  Cholesterol       5 mg   \r\n  Sodium       290 mg   \r\n  Carbohydrate       48 g   \r\n  Dietary fibre       1 g   \r\n  Protein       4 g   \r\n  Vitamin A       2 %DV   \r\n  Vitamin C       8 %DV   \r\n  Calcium       6 %DV   \r\n  Iron       2 %DV   \r\n \r\n \r\n', 40),
(128, 'Black Forest Mousse', '1-1/2 cups cold milk \r\n1 pkg. (4-serving size) JELL-O Chocolate Instant Pudding \r\n2 cups COOL WHIP Whipped Topping, thawed, divided \r\n16 OREO Cookies, divided \r\n1-1/2 cups canned cherry pie filling \r\n \r\n \r\n \r\n\r\n \r\n \r\n ', '1  POUR milk into large bowl. Add dry pudding mix. Beat with wire whisk 2 min. or until well blended. Gently stir in 1/2 cup of the whipped topping. \r\n \r\n \r\n2  CRUSH 10 of the cookies coarsely; stir into pudding mixture. Spoon half of the pudding mixture into 1-1/2-L serving bowl. Spread 3/4 cup of the remaining whipped topping over pudding mixture. \r\n \r\n \r\n3  TOP with 1 cup of the pie filling, remaining pudding mixture, remaining whipped topping and 1/2 cup pie filling. \r\n \r\n \r\n4  CRUSH remaining 6 cookies; sprinkle on top of dessert. \r\n \r\nSpecial Extra \r\nGarnish with toasted sliced almonds just before serving. \r\n \r\n  \r\n \r\n', 'An impressive looking layered dessert, easy enough to prepare any night of the week.  \r\nPrep: 15 min  \r\nReady In: 45 min  \r\nServes: 12  \r\n How To Crush Cookies \r\nTo coarsely crush cookies, place them on chopping board and crush using a rolling pin or bottom of sturdy pot. \r\n\r\nSize It Up \r\nThis is a rich dessert. Watch serving size. \r\n\r\n  Nutritional Info \r\nServing Size = 1/12 recipe  \r\n   \r\n  Calories       221    \r\n  Total fat       8 g   \r\n  Sodium       250 mg   \r\n  Carbohydrate       35.8 g   \r\n  Dietary fibre       0.9 g   \r\n  Protein       2.3 g   \r\n  Vitamin A       2 %DV   \r\n  Vitamin C       2 %DV   \r\n  Calcium       4 %DV   \r\n  Iron       1 %DV  \r\n \r\n \r\n\r\n \r\n \r\n\r\n \r\n', 40),
(129, 'Trifle-ing Easy Berry Dessert ', '1.25 l (5 cups) mixed berries (strawberries, raspberries and \r\nblueberries) \r\n30 ml (2 tbsp) granulated sugar \r\n15 ml (1 tbsp) orange liqueur,optional \r\n1 angel food cake \r\n1 750 g container French vanilla yogurt \r\nMint leaves \r\n    \r\n        ', 'Cut strawberries into halves or quarters, depending on size. In bowl, \r\nsprinkle berries with sugar and liqueur if desired, toss gently and set aside. \r\nCut cake into cubes. In 2 l (8-cups) glass serving bowl, layer one-third \r\nof cake cubes, one-third of the berries and one-third of the yogurt. \r\nRepeat layers twice, saving some berries for garnish. Cover and       refrigerate for 2 to 6 hours (not overnight). \r\nGarnish with reserved berries and mint just before serving. \r\n\r\n', '', 40),
(130, 'Chanukah Potato Pancakes ', '1 1/4 pound potato(es), peeled and shredded \r\n2 medium egg white(s) \r\n3 Tbsp all-purpose flour \r\n2 medium scallion(s), minced \r\n3/4 tsp table salt \r\n4 tsp vegetable oil \r\n\r\n', 'Soak the potatoes in cold water 30 minutes; drain and blot dry. Preheat the oven to 375Ã¯Â¿Â½ F.\r\nIn a medium bowl, combine the potatoes, egg whites, flour, scallions and salt. Form into 12 pancakes.\r\n\r\n\r\nIn a large nonstick skillet over medium heat, heat one third of the oil. Cook the pancakes, 4 at a time, until just golden, about 2 minutes on each side; transfer to a baking sheet. Repeat with the remaining oil and pancakes. Bake until crisp and cooked through, 5-7 minutes. \r\n', 'POINTSÃ¯Â¿Â½ Value: 2\r\nServings:  6\r\nPreparation Time:  5 min\r\nCooking Time:  7 min\r\nLevel of Difficulty:  Easy   \r\nTry these tasty potato pancakes for your next holiday meal. \r\nweight watchers recipe\r\n', 61),
(131, 'Cranberry-Orange Glazed Ham', '2 Tbsp frozen orange juice concentrate \r\n1/4 cup canned cranberry sauce \r\n2 Tbsp unpacked brown sugar \r\n1 Tbsp whole cloves \r\n2 pound ham, lean only \r\n1 medium mandarin orange(s), cut into wedges \r\n\r\n', 'Preheat oven to 375Â°F.\r\nFor glaze, in a small saucepan over low heat, stir together orange juice concentrate, cranberry sauce and brown sugar, whisking until smooth.\r\n\r\nStick cloves into top of ham. Place ham in a baking dish and brush with some of the glaze. Bake for 1 hour, brushing with glaze every 15 minutes.\r\n\r\nSlice thinly, garnish with orange wedges and serve. \r\n\r\nRecent WeightWatchers.com Recipes\r\nPotato and Apple Latkes\r\nRed Velvet Cupcakes\r\nMint Hot Chocolate\r\nMushroom and Wild Rice Slow Cooker Stew\r\n\r\n\r\n', 'POINTSÂ® Value: 5\r\nServings:  8\r\nPreparation Time:  5 min\r\nCooking Time:  60 min\r\nLevel of Difficulty:  Easy   \r\nThere is nothing easier to prepare than a ham, but it always makes a meal seem special. \r\n\r\n WeightWatchers.com recipes\r\n', 17),
(132, 'cupcakes', '2 sprays cooking spray \r\n1 1/2 cup all-purpose flour \r\n1 cup whole-grain wheat flour \r\n2/3 cup sugar \r\n2 1/2 tsp baking soda \r\n1 tsp ground ginger \r\n1 tsp ground cinnamon \r\n1 tsp ground allspice \r\n1 1/2 cup unsweetened applesauce \r\n1 cup molasses \r\n3 large egg white(s) \r\n3 cup lite whipped topping \r\n\r\n\r\n \r\n', 'Preheat oven to 325Â°F. Coat two 12-cup muffin tins with cooking spray.\r\n\r\n\r\nCombine flours, sugar, baking soda, ginger, cinnamon and allspice in a large bowl; mix well. Add applesauce, molasses and egg whites; stir until mixture is moist and well-combined. Fill each muffin tin 3/4 full with batter.\r\n\r\n\r\nBake until a toothpick inserted in center comes out clean, about 40 minutes. Cool cupcakes to room temperature and serve each topped with 2 tablespoons of whipped topping. \r\n', 'POINTSÂ® Value: 3\r\nServings:  24\r\nPreparation Time:  20 min\r\nCooking Time:  40 min\r\nLevel of Difficulty:  Easy   \r\nLooking for the perfect holiday dessert? Put these festive cupcakes on the menu. \r\n\r\n', 63),
(133, 'apple streusel', '4 medium apple(s), peeled, cored and thinly sliced (use firm apples) \r\n1/2 cup unpacked brown sugar \r\n1/2 tsp ground cinnamon \r\n2 Tbsp fresh lemon juice \r\n1/4 cup all-purpose flour \r\n1/4 cup uncooked old fashioned oats \r\n3 Tbsp reduced-calorie margarine ', 'Preheat oven to 350Â°F.\r\nStir together apples, 1/4 cup of brown sugar, cinnamon and lemon juice; pour into a 1 1/2 quart baking dish.\r\nCut flour, oatmeal, remaining brown sugar and margarine together with a pastry blender or fork in a medium bowl; sprinkle over apple mixture.\r\n\r\nBake until apples are tender and top is browned, about 45 minutes. Yields about 1/2 cup per serving. \r\n\r\n', 'POINTSÂ® Value: 3\r\n Servings:  8\r\nPreparation Time:  15 min\r\nCooking Time:  45 min\r\nLevel of Difficulty:  Easy   \r\nOur spice-infused apple streusel is the perfect tummy warmer on the coldest of winter days. \r\n\r\n', 63),
(134, 'Fruit Spice Cookies', ' \r\n1/2 cup dark brown sugar \r\n1/4 cup reduced-calorie margarine \r\n2 Tbsp molasses \r\n1/4 cup fat-free egg substitute \r\n1 cup all-purpose flour \r\n2 tsp pumpkin pie spice \r\n1 cup dried mixed fruit, chopped, or dried fruit bits \r\n1 tsp powdered sugar \r\n', 'Preheat oven to 350Â°F. Coat 2 sheet pans with cooking spray or line them with parchment paper. \r\n\r\n\r\nUsing an electric mixer, cream together sugar, margarine and molasses; beat in egg substitute. Blend in flour, 1 teaspoon of pumpkin pie spice and dried fruit.\r\n\r\n\r\nDrop dough by teaspoonfuls onto sheet pans, spacing them 2 inches apart. Bake until they start to become firm, about 8 minutes. Cool for 1 minute before removing from pans and then allow to cool completely.\r\n\r\n\r\nStir together remaining 1 teaspoon of pumpkin pie spice and powdered sugar; sprinkle over cookies. Yields about 2 cookies per serving. \r\n\r\n', 'POINTSÂ® Value: 3\r\nServings:  14\r\nPreparation Time:  10 min\r\nCooking Time:  8 min\r\nLevel of Difficulty:  Easy   \r\nThese quick and easy drop cookies are perfect for all your holiday gatherings. Pair them up with hot cider, spiced tea or other warming, seasonal drinks; no one will know they\'re accompanying you in reaching your goal! \r\n\r\n', 58),
(135, 'Baked Apple Streusel ', '4 medium apple(s), peeled, cored and thinly sliced (use firm apples) \r\n1/2 cup unpacked brown sugar \r\n1/2 tsp ground cinnamon \r\n2 Tbsp fresh lemon juice \r\n1/4 cup all-purpose flour \r\n1/4 cup uncooked old fashioned oats \r\n3 Tbsp reduced-calorie margarine ', 'Preheat oven to 350Â°F.\r\nStir together apples, 1/4 cup of brown sugar, cinnamon and lemon juice; pour into a 1 1/2 quart baking dish.\r\nCut flour, oatmeal, remaining brown sugar and margarine together with a pastry blender or fork in a medium bowl; sprinkle over apple mixture.\r\n\r\nBake until apples are tender and top is browned, about 45 minutes. Yields about 1/2 cup per serving. \r\n\r\n', 'POINTSÂ® Value: 3\r\n Servings:  8\r\nPreparation Time:  15 min\r\nCooking Time:  45 min\r\nLevel of Difficulty:  Easy   \r\nOur spice-infused apple streusel is the perfect tummy warmer on the coldest of winter days. \r\n\r\n', 40),
(136, 'Gingerbread Cupcakes', '2 sprays cooking spray \r\n1 1/2 cup all-purpose flour \r\n1 cup whole-grain wheat flour \r\n2/3 cup sugar \r\n2 1/2 tsp baking soda \r\n1 tsp ground ginger \r\n1 tsp ground cinnamon \r\n1 tsp ground allspice \r\n1 1/2 cup unsweetened applesauce \r\n1 cup molasses \r\n3 large egg white(s) \r\n3 cup lite whipped topping \r\n\r\n\r\n \r\n', 'Preheat oven to 325Â°F. Coat two 12-cup muffin tins with cooking spray.\r\n\r\n\r\nCombine flours, sugar, baking soda, ginger, cinnamon and allspice in a large bowl; mix well. Add applesauce, molasses and egg whites; stir until mixture is moist and well-combined. Fill each muffin tin 3/4 full with batter.\r\n\r\n\r\nBake until a toothpick inserted in center comes out clean, about 40 minutes. Cool cupcakes to room temperature and serve each topped with 2 tablespoons of whipped topping. \r\n', 'POINTSÂ® Value: 3\r\nServings:  24\r\nPreparation Time:  20 min\r\nCooking Time:  40 min\r\nLevel of Difficulty:  Easy   \r\nLooking for the perfect holiday dessert? Put these festive cupcakes on the menu. \r\n\r\n', 40),
(137, 'Slow-Cooker Chicken Cacciatore ', ' 1/4 cup KRAFT Zesty Italian Dressing \r\n 3 lb. (1.5 kg) chicken thighs and drumsticks \r\n 2 cups sliced mushrooms (about 10 medium) \r\n 1-1/2 cups coarsely chopped onions (about 1 medium) \r\n 1/2 cup each: red and green pepper strips \r\n 1 clove garlic, minced \r\n 1 can (19 fl oz/ 540 mL) crushed tomatoes, undrained \r\n 1 tsp. salt \r\n 1 tsp. dried thyme leaves \r\n 3 cups instant white rice, uncooked \r\n', '1  HEAT dressing in large nonstick skillet on medium-high heat. Add chicken, in batches; cook 2 to 3 min. on each side or until browned on both sides. \r\n \r\n \r\n2  PLACE mushrooms, onions, peppers and garlic in slow cooker; top with the chicken. Combine tomatoes, salt and thyme; pour over ingredients in slow cooker. Cover with lid. Cook on LOW for 6 to 8 hours (or on HIGH for 5 hours). \r\n \r\n \r\n3  COOK rice as directed on package. Serve chicken mixture over the rice. \r\n \r\n \r\n \r\n \r\n', 'Prep: 15 min  \r\nReady In: 8 hr 15 min  \r\nServes: 8  \r\nCooking Know-How \r\nTaking the lid off your slow cooker for even just a minute reduces the heat and extends the cooking time. Lift the lid only if instructed to do so in the recipe. \r\n\r\n', 54),
(138, 'Roasted Chickpeas', '1 sprays olive oil cooking spray \r\n2 cup canned chickpeas, drained and rinsed \r\n1/4 tsp garlic powder \r\n1/8 tsp red pepper flakes \r\n\r\n  \r\n', 'Preheat oven to 350ÂºF. Lightly coat a rimmed baking sheet with cooking spray.\r\n\r\n\r\nSpread chickpeas on baking sheet and sprinkle with garlic powder and red pepper; toss to coat.\r\n\r\n\r\nRoast on bottom rack of oven, shaking pan about every 15 minutes, until browned and slightly crunchy, about 45 to 50 minutes. (The chickpeas will still be somewhat soft. Cook longer for desired texture.) Cool before serving. Yields about 1/2 cup per serving. \r\n\r\n\r\n\r\n\r\n \r\n', '', 60),
(139, 'Holiday Sugar Cookies ', '1 cup sugar \r\n1/2 cup reduced-calorie margarine, at room temperature \r\n1 large egg(s), lightly beaten \r\n1/4 cup light corn syrup \r\n2 Tbsp fresh lemon juice \r\n1 Tbsp vanilla extract \r\n2 3/4 cup all-purpose flour \r\n3/4 tsp baking powder \r\n1/2 tsp baking soda \r\n1/2 tsp table salt \r\n1/2 tsp ground cardamom, if desired \r\n2 large egg white(s) \r\n2 cup powdered sugar, lightly packed \r\nInstructions\r\n\r\n \r\n\r\n\r\n\r\n \r\n  \r\n', 'In mixer on medium, beat sugar and margarine together until crumbly. Add 1 egg, corn syrup, lemon juice and vanilla; beat until smooth and pale in color.\r\n\r\n\r\nIn a medium bowl, stir together flour, baking powder, baking soda, salt and cardamom. Slowly beat flour mixture into margarine mixture until blended. Divide dough into four equal parts and flatten each quarter to form a round. Wrap each in plastic; refrigerate 30 minutes or overnight.\r\n\r\n\r\nPreheat oven to 350Â°F.\r\n\r\n\r\nLightly spray baking sheet(s) with cooking spray. On a lightly floured board roll out one round to 1/4-1/8 inch thickness. With a lightly floured Christmas tree cookie cutter (about 2 inches tall), cut out cookies and transfer them, about 2 inches apart, to baking sheet(s); repeat with remaining dough.\r\n\r\n\r\nBake until golden brown on bottom, 5 to 9 minutes. Remove from the oven; cool completely.\r\n\r\nFor Royal Icing, in a large bowl whip egg whites and powdered sugar at low speed until sugar is moistened. Beat at high speed until glossy and stiff peaks form when beaters are lifted, about 6 minutes. Divide icing depending on how many colors you want to use. Add food coloring to achieve desired tint. To decorate cookies place icing in a small plastic bag; snip a tiny hole off one corner of the bag. Pipe icing onto the cooled cookies to create tree-trimming designs and ornaments. Yields 24 trees. \r\n\r\n', 'POINTSÂ® Value: 3\r\nServings:  24\r\nPreparation Time:  20 min\r\nCooking Time:  9 min\r\nLevel of Difficulty:  Moderate   Decorate these classic holiday treats with the icing recipe given below, or experiment with colored sugar crystals and other colorful sprinkles found in your store`s baking section. \r\n', 58),
(140, 'Holiday Punch ', '4 cup Schweppes Diet Ginger Ale, or equivalent product \r\n4 cup grapefruit-mango juice \r\n2 2/3 Tbsp frozen orange juice concentrate, thawed \r\n4 fl oz rum, preferably white, 80 proof \r\n2 lime(s) \r\n1 small grapefruit, red, sliced \r\n1 orange(s), sliced \r\n\r\n\r\n\r\n  \r\n', 'Combine ginger ale, juice, concentrate, rum and juice of 1 lime.\r\nSlice remaining lime. Garnish punch with sliced lime, grapefruit and orange. Yields eight 1-cup servings. \r\n\r\n \r\n\r\n\r\n', 'POINTSÂ® Value: 2\r\nServings:  8\r\nPreparation Time:  10 min\r\nCooking Time:  0 min\r\nLevel of Difficulty:  Easy   \r\nMake this healthy punch for your New Year\'s celebrations. Omit the rum for a flavorful, alcohol-free refresher. \r\n\r\n', 65),
(141, 'Holiday Eggnog ', '1 large egg(s) \r\n1/4 cup fat-free egg substitute \r\n1/4 cup sugar \r\n2 cup fat-free evaporated milk \r\n1 tsp vanilla extract \r\n2 fl oz brandy, or rum, 80 proof (1/4 cup) \r\n1 tsp ground nutmeg \r\n', 'Beat together egg, egg substitute and sugar in a medium bowl; set aside. Warm milk in a small saucepan until it steams (do not boil); very gradually beat milk into egg mixture.\r\nReturn egg-milk mixture to stove and cook over low heat, stirring constantly, until thickened slightly and very steamy. Do not let eggnog boil. Stir in vanilla and chill thoroughly.\r\nStir brandy into chilled eggnog. Pour into four glasses and sprinkle a touch of nutmeg on top of each serving. Yields about 3/4 cup per serving. \r\n\r\n\r\n\r\n', ' POINTSÂ® Value: 5\r\nServings:  4\r\nPreparation Time:  10 min\r\nCooking Time:  10 min\r\nLevel of Difficulty:  Easy   \r\nThis rich-tasting creamy beverage is a delicious way to celebrate with family and friends. \r\n', 65),
(142, 'gingerbread cake', '1 1/2 cup all-purpose flour \r\n1 1/2 tsp baking powder \r\n1 1/4 tsp ground ginger \r\n1/2 tsp baking soda \r\n1/2 tsp table salt \r\n4 Tbsp unsalted butter, melted \r\n1/3 cup unpacked brown sugar \r\n1/2 cup buttermilk \r\n1/3 cup molasses \r\n1 large egg(s), lightly beaten \r\n', 'Heat oven to 350Ã¯Â¿Â½F. Coat a 9-inch square cake pan with cooking spray. Whisk together flour, baking powder, ginger, baking soda and salt.\r\n\r\n\r\nStir butter, brown sugar, buttermilk, molasses, 1/4 cup water and egg together until smooth.\r\n\r\n\r\nStir dry ingredients into butter mixture. Pour into pan. Bake until cake springs back when lightly touched, about 45 to 50 minutes. Serve warm or at room temperature. \r\n\r\n \r\n\r\n\r\n\r\n', 'POINTSÃ¯Â¿Â½ Value: 2\r\nServings:  16\r\nPreparation Time:  10 min\r\nCooking Time:  35 min\r\nLevel of Difficulty:  Easy   \r\nFor spicier gingerbread add 1/2 teaspoon white pepper, 1/4 teaspoon cloves and 1/2 teaspoon cinnamon with the ginger. \r\n\r\n', 45),
(143, 'Spicy BBQ Meatballs', '1 1/2 pound lean ground turkey \r\n1 cup uncooked quick oats \r\n2 medium egg white(s) \r\n1 large onion(s), finely chopped \r\n1 medium garlic clove(s), chopped \r\n1/4 cup parsley, chopped \r\n1 tsp dried oregano \r\n1 1/2 tsp beef bouillon granules \r\n1/2 tsp black pepper \r\n1 1/4 cup barbecue sauce \r\n', 'Preheat oven to 350ÂºF. Combine all ingredients, except barbecue sauce, in a medium-size bowl; mix well.\r\n\r\nCoat a baking sheet with cooking spray. Shape meatball mixture into sixty 1-inch balls; place on baking sheet.\r\n\r\n\r\nBake at 350ÂºF until cooked through, about 25 minutes. Transfer meatballs to a chafing dish or crockpot to keep warm.\r\n\r\n\r\nMeanwhile, heat barbecue sauce over medium-high heat until hot. Pour sauce over cooked meatballs, toss gently and serve. Yields 2 meatballs per serving. \r\n\r\n \r\n\r\n\r\n\r\n', 'POINTSÂ® Value: 1\r\nServings:  30\r\nPreparation Time:  20 min\r\nCooking Time:  25 min\r\nLevel of Difficulty:  Easy   \r\nKeep the calories low in this popular hors d\'oeuvre by making the meatballs with ground turkey instead of ground beef and by using fat-free barbecue sauce. \r\n\r\n', 17);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(145, 'Five-Minute Fudge Wreaths', '12 ounce package semisweet chocolate chips \r\n1 cup butterscotch chips \r\n14 ounce can sweetened condensed milk (save the can) \r\n1 teaspoon pure vanilla extract \r\n8 ounce can walnuts, plus more for topping \r\n1/2 cup raisins or dried currants (a couple of handfuls) \r\ncandied red and green cherries to decorate top (like holly) \r\nsoftened butter to grease an 8 inch round cake pan \r\n\r\n\r\n* For more information about Rachael Ray, visit www.rachaelrayshow.com. \r\n\r\n \r\n  \r\n  \r\n  \r\n \r\n', 'Grease an 8-inch round cake pan with softened butter. Pour the chocolate and butterscotch chips, condensed milk and vanilla into a medium saucepan. Put the pan on the stove and turn the heat to low. \r\nCover the empty condensed milk can with plastic wrap and put it in the center of the round cake pan. \r\nStir the chips and milk until they melt together, about 3 minutes. Stir in nuts and raisins. Scoop the fudge into the cake pan all around the plastic-covered can in the center to form a wreath or ring shape. Let it be all bumpy on top. Keep pushing the can back to the center if the fudge moves it away from there. Cut the red cherries in half with scissors and the green cherries into quarters. Use the green pieces to make leaves and the red to make holly berries. Decorate the fudge with several groups of holly berry sprigs made from the cherries and garnish with walnuts between the sprigs. \r\nPut the fudge in the fridge and chill until firm. Remove the can from the center, then loosen the sides and bottom of the fudge with a spatula. Cut the fudge into thin slices to serve. \r\nTo give the wreath as a gift-wrap in cellophane and secure with a bow or ornament.\r\n\r\nVariations:\r\nWhite Chocolate Wreath with Pistachio\r\nand Cranberry\r\n\r\nSubstitute the chocolate chips with white chocolate chips, 1 1/2 ounce bag plus 1 cup. \r\nSubstitute 1 to 1 1/2 cups of shelled natural pistachio nuts for walnuts. \r\nSubstitute 1/2 cup dried sweetened cranberries for currants. \r\nGoober and Raisinette Wreath\r\n\r\nSwap butterscotch for peanut butter chips \r\nSwap large whole peanuts for walnuts used in original recipe (such as peeled Virginia Peanuts) \r\nSwap 1/2 cup large raisins for currants in original recipe \r\n\r\n', 'This super-simple recipe will be a hit at your holiday party! Try all three varieties: the Chunky Chocolate Fudge Wreath with Walnuts and Currants, the White Chocolate Wreath with Pistachio and Cranberry or the Goober and Raisinette Wreath! \r\nChunky Chocolate Fudge Wreath with Walnuts and Currants \r\nRecipe courtesy of Rachael Ray\r\nFrom the show Oprah and Rachael Ray\r\nThrow a Holiday Party\r\nMakes 2 pounds\r\n', 9),
(146, 'Oprah\'s Pomegranate Martini', '1 1/2 cups pomegranate juice \r\n2 oz. Absolute Citron vodka OR white tequila \r\n1 oz. Cointreau liquor \r\nCup of ice \r\nOptional: Splash of sparkling water \r\nOptional: Squeeze of lemon \r\n\r\n', 'Shake ingredients in a shaker and put in chilled martini glasses. Put pomegranate fruit into glass as garnish. \r\n', 'Recipe courtesy of Oprah Winfrey\r\nFrom the show Oprah and Rachael Ray\r\nThrow a Holiday Party\r\nServes 2\r\n', 65),
(147, 'Chicken and Biscuits', '2 quarts chicken stock \r\n2 1/2 pounds boneless, skinless chicken breast \r\n5 tablespoons butter, divided \r\n2 tablespoons Extra Virgin Olive Oil (EVOO), 2 turns of the pan \r\n2 large carrots, peeled and sliced into half inch thick discs \r\n1 large onion peeled and chopped \r\n4 ribs of celery from the heart chopped \r\n2 large russet potatoes, peeled and chopped \r\nCoarse salt and black pepper \r\n1 bay leaf, fresh or dried \r\n1 cup frozen green peas \r\n1/4 cup fresh flat leaf parsley chopped, a generous handful \r\n3 tablespoons, a generous handful, chopped fresh dill \r\n2 tubes, any brand or variety, store bought, bake off biscuits \r\nA few pinches cayenne pepper \r\n\r\n', 'Heat chicken stock to a boil in a deep skillet or pot. Add chicken breasts and poach at a gentle simmer until cooked through about 10 to 12 minutes. Remove chicken, cut into bite size pieces and reserve.\r\n\r\nHeat a large deep pot over medium heat. Add 2 tablespoons butter plus 2 tablespoons EVOO, 2 turns of the pan. When butter melts into oil add all chopped vegetables. Season with salt and pepper, add bay leaf, cook vegetables 10 minutes until they begin to become tender. Do not brown vegetables; you just want to sweat them out a bit. While vegetables are working, over small skillet over medium heat, melt 3 tablespoons butter, whisk in flour, and cook a few minutes to form a roux. Remove and reserve.\r\n\r\nTo the vegetables add the chicken and stock that you cooked the chicken in, pouring stock through a strainer to remove any by-products from poaching the chicken. Whisk roux into your completed chicken and vegetable mixture. Simmer until vegetables are tender and sauce thickens, about 20 minutes.\r\n\r\nWhile chicken works, bake off biscuits to package directions, sprinkle the tops of each biscuit with a little bit of cayenne pepper just before they go in the oven.\r\n\r\nWhen ready to serve, stir peas, dill and parsley into chicken. Split biscuits and place in bottom of shallow bowls and ladle chicken on top. \r\n\r\n', 'Recipe courtesy of Rachael Ray\r\nFrom the show Oprah and Rachael Ray\r\nThrow a Holiday Party\r\nServes 8\r\nThis dish, along with Beef and Burgundy, makes for easy entertaining&amp;#8212;get everyone in line for a stove-top buffet! \r\n', 54),
(479, 'White chocolate, walnut, cranberry cookie', '1 cup (250 mL) unsalted butter, at room temperature\r\n\r\n3/4 cup (185 mL) granulated sugar\r\n\r\n3/4 cup (185 mL) dark brown sugar, packed\r\n\r\n2 large eggs\r\n\r\n1 tsp (5 mL) vanilla\r\n\r\n2-1/4 cup (685 mL) all-purpose flour\r\n\r\n1 tsp (5 mL) baking soda\r\n\r\n1 cup (250 mL) each chopped: walnuts, dried cranberries, white chocolate\r\n\r\n', ' a large bowl using an electric mixer, beat butter, sugars, eggs and vanilla until fluffy, about 2 minutes.\r\n\r\nIn another bowl, combine flour and baking soda. Beat into sugar mixture, in several batches. Using wooden spoon, stir in walnuts, cranberries and chocolate.\r\n\r\nScoop dough by tablespoon onto parchment-lined baking sheet, about 2 inches (5 cm) apart. Flatten with fork or palms into disks. Bake in preheated 350F (180C) oven for 8 to 10 minutes.\r\n\r\nCool 5 minutes on baking sheets. Transfer to wire racks to cool completely. Store in airtight container at room temperature up to 1 week or freeze up to 1 month.\r\n\r\nMakes about 60 cookies ', 'There is some âje ne sais quoiâ quality to this cookie that makes it sweet, tart, chewy, crunchy and downright delectable. Miranda Turnbull, a constant and consummate baker, knew she had a winner the moment she took her first bite. Adapted from a magazine recipe for plain chocolate chip cookies, it has been wowing palates ever since. âThis is my husbandâs favourite cookie,â she says. âI only make them at Christmas although Iâm not sure why.â ', 58),
(480, 'Apricot Brandy Slussh', '1 can OJ (concentrated)\r\n1 can lemonade (concentrated)\r\n1 can pineapple juice\r\n7 1/2 cups boiling water\r\n1 1/2 cups sugar\r\n1/2 (26oz) vodka\r\n1/2 (26 oz) Apricot brandy\r\n\r\n', 'freeze and mix w gingerale', 'from cindy', 65),
(481, 'Parmesan Chicken', '4 boneless, skinless chicken breasts\r\n2 tsp. crushed garlic (garlic puree from a jar is perfect here)\r\n1/4 cup extra virgin olive oil\r\n1/2 tsp poultry seasoning (I used Penzeys)\r\n1/4 cup whole wheat Panko bread crumbs\r\n1/4 cup finely grated Parmesan cheese\r\n\r\n', 'Combine crushed garlic, olive oil, and poultry seasoning in small pan and heat 1 minute, until just warm.\r\n\r\nTrim all visible fat and membranes from chicken breasts, then make small crosswise slits about 1/2 inch apart down the length of each chicken breast, being careful not to cut too far into the chicken. (This helps the garlic and herb flavor penetrate the chicken more.) Put chicken into zip loc bag, pour heated oil over, and marinate all day in refrigerator.\r\n\r\nTo cook, take chicken out of refrigerator and let it come to room temperature for a few minutes while you preheat oven to 425.\r\n\r\nMix bread crumbs and parmesan (pulse a few times in food processor if the mixture isn\'t fine enough.) Place cheese/breadcrumb mixture in flat dish and dip each chicken breast into it, pressing on as much of the coating as you can.\r\n\r\nPlace each chicken piece in casserole dish which has been sprayed with nonstick spray. or olive oil. Bake until chicken is firm and cooked through, about 25 minutes, then put under the broiler to brown more if desired. (Original directions said to bake 30-40 minutes, but I wouldn\'t cook it that long. Actual cooking time will depend on the thickness of your chicken breasts, but chicken should feel firm but not hard when it\'s cooked.)\r\n\r\n\r\n\r\n ', 'want to try', 54),
(149, 'Tortilla Pizza for One', '2 soft taco size flour tortillas\r\n4 tablespoons spaghetti sauce\r\n1/2 cup shredded Monterey Jack or Mozzarella cheese\r\n6 thin slices pepperoni\r\n1 tablespoon grated parmesan cheese\r\nToppings: chopped fresh basil, chopped green pepper, sliced black olives \r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n', 'Place both tortillas flat on top of each other. Spread sauce on top of tortilla to within 1 inch of edge. Spread with cheese. Top with pepperoni slices, green pepper, black olives. Sprinkle with basil and parmesan cheese. Microwave on High for 45 to 60 seconds, until cheese melts or heat in conventional oven at 350 degrees for 5 to 7 minutes. Serves 1.\r\n\r\n', '', 2),
(151, 'RAGOUT DE PATES DE COCHON - PORK HOCKS', '4 pigs feet or hocks \r\n1 1/2 lb. hamburg\r\n1/2 lb. ground pork\r\n1 large onion, chopped\r\nsalt and pepper to taste\r\n1/4 teaspoon ground allspice\r\nYou may substitute cinnamon and/or cloves if you prefer.\r\n2 Tbsp. flour\r\n\r\n', 'Boil the hocks in 2 quarts of water. When boiling, add onion, reduce heat and cook for 3 to 4 hours, until meat is done. Add additional water as needed. In a large bowl, mix hamburg and ground pork with salt, pepper and spices. Make small meatballs. Remove hocks from pot. Add meatballs to broth and cook for 1 hour. Brown flour in a heavy skillet. Add to broth to thicken to the consistency of gravy. Return hocks to pot. Enjoy!\r\n\r\n', '', 17),
(152, 'Pommes de terre au gratin', '1 petit oignon tranche\r\n4 tasses de pommes de terre tranchees\r\n3 c a table de margarine\r\n4 a 5 c a table de farine\r\n1 c a the de sel\r\n1/4 c a the de poivre\r\n3 tasses de lait\r\n1 tasse de fromage cheddar rape', 'Graisser une cocotte de 2 l (2 pintes).  Trancher les pommes de terre et l\'oignon transversalement dans le robot culinaire.  Raper le fromage.  Dans une casserole, faire fondre la margarine, puis y ajouter la farine, le sel et le poivre.  Ajouter le lait.  Faire cuire a feu moyen en remuant jusqu\'a ce que la sauce epaississe.  Disposer en couches l\'oignon, les pommes de terre, le fromage et la sauce dans la cocotte.  faire cuire a 350f de 50 a 60 minutes ou jusqu\'a ce que les pommes de terre soient tendres.  6 portions', '', 61),
(153, 'Brise de Noel', '3 oz Cocktail aux canneberges\r\n3 oz Cocktail au pamplemousse\r\n1 1/2 oz vodka\r\nrondelle de citron ou de lime (garniture)', 'Verser dans un verre rempli de glace.  Garnir avec la rondelle de citron ou de lime.  Rendement 1 portion.', '', 65),
(154, 'pork hocks and meatballs', '1 lb. lean ground pork\r\n1 lb. lean ground beef\r\n1 minced onion\r\n1 clove garlic, minced\r\n1/2 cup warm water\r\n1 cup bread crumbs\r\n1/4 cup ketchup\r\n\r\n5-6 pork hocks or pattes de cochon\r\n3-4 cups of chicken broth\r\n\r\n', 'Incorporate all ingredients together and form into meatballs.  Cook at 400 degrees C until cooked through.\r\n\r\nOnce this has been completed we move on to step number 2.\r\n\r\nBoil pork hocks in chicken broth in a large pot until cooked through.  Drain, reserving broth and let pork hocks cool.  When cool enough to handle, cut away and discard fat.  Remove meat from bones and set aside.\r\n\r\nStep number three.  DON\'T BURN THE FLOUR.\r\n\r\nBrown two cups of flour in frying pan carefully, watching constantly.  When completely brown set aside.\r\n\r\nBring the reserved broth to a boil.  Gradually add the heated broth to the browned flour whisking constantly until it turns to thick gravy.  Add shredded meat and meat balls.  Serve with cooked boiled potatoes.\r\n\r\n\r\n', '', 17),
(155, 'cherry balls', '3/4 cup mashed pototoes\r\n1 # { 4 cups} coconut\r\n1 # powder sugar sifted  { 4 3/4 cups}\r\n1 teaspoon almond extract\r\n\r\n\r\n', 'cooked and mashed pototoes cool\r\nmix altogether refrigate 1/2 hr to 1 hr\r\nroll the mixture around cherrys and form a ball\r\nrefigrate for 1/2 hr then dip in choc\r\n\r\nmelt 6 0z of choc chips\r\n1/2 square parafin wax\r\n\r\nput on wax paper and refrigate for 1/2 hr\r\n\r\n', 'it sound like a lot of work but not really, they a puttsy\r\nhave fun as these are my dads favorite\r\n\r\nMary\r\n', 9),
(156, 'Very Berry Pie', '8 cups (2 pounds) mixed frozen berries  \r\n1/2 cup sugar  \r\n1/4 cup cornstarch  \r\n1 tablespoon fresh lemon juice  \r\nOne 9-inch refrigerated piecrust, such as Pillsbury Just Unroll  \r\n2 tablespoons unsalted butter, cut into small pieces  \r\n1 large egg yolk  \r\n1 tablespoon heavy cream  \r\n  \r\n \r\n \r\n\r\n\r\n \r\n\r\n\r\n \r\n \r\n\r\n   \r\n\r\n\r\n', '1. Preheat the oven to 350Â°. In a large bowl, toss together the frozen berries, sugar, cornstarch and lemon juice.\r\n2. Unroll a piecrust into a 10-inch pie plate. Using your thumbs, gently press the pastry up the sides of the dish so it is even with the top rim.\r\n3. Pour the fruit mixture into the crust and dot with the butter. Moisten the rim of the pastry with water. Unroll the second piecrust, set it on top of the berry mixture and pinch the crusts together with your fingers to seal. Cut 3 small slits in the center of the crust.\r\n4. Mix together the egg yolk and cream and brush onto the pie. Set the pie on a baking sheet and bake for 30 minutes; increase the heat to 375Â° and bake until the crust is nicely browned, about 20 minutes longer.\r\n\r\n', 'Rachael Ray\r\nFebruary 2007\r\nMAKES ONE TEN-INCH PIE\r\nPrep Time: 20 min\r\nCook Time: 50 min \r\n', 64),
(157, 'Roasted Chicken Shepherd Pie', '4 pounds Idaho potatoes, peeled and quartered\r\n1 stick butter\r\n1/2 cup milk\r\nSalt and freshly ground black pepper\r\n1/4 of the cooked roasted chicken, shredded (about 2 cups)\r\n1/3 of the cooked roasted vegetables, chopped into bite-size pieces (about 2 cups)\r\n2 cups reserved gravy\r\n1 package frozen peas\r\n10-15 chives, chopped (optional)\r\n', 'For the potatoes: Place the peeled and quartered Idaho potatoes in a large pot and cover them with an inch of water. Place over high heat, bring up to a bubble and boil for about 12 minutes, or until the potatoes are tender. Drain and return them to the pot to dry out a little. Add the butter and milk to the pot, and smash potatoes with a fork or potato masher. \r\nSeason with salt and pepper, and reserve until you are ready to assemble the Roasted Chicken Shepherd&amp;#8217;s Pie.When the chicken have finished roasting, remove  to a platter and loosely cover  with foil. Allow  to rest for 10-15 minutes. When  cool enough to handle, remove all the skin and then the meat from the bird. Shred the chicken meat. Remove all but 1/4 of the veggies from the pan and chop them into bite-size pieces. \r\nWhile the chickens rest, prepare the gravy: To a skillet over medium heat, melt 2 tablespoons of butter and 2 tablespoons of EVOO. Once the butter melts, add the 1/4 cup of flour and cook for a minute or so. Whisk in the remaining quart of chicken stock, bring up to a bubble and simmer for a couple of minutes to thicken. Assemble the Roasted Chicken Shepherd\'s Pie: Combine chicken and roasted veggie portions, 2 cups of gravy and the defrosted peas together in a large oven-safe casserole dish.\r\nTop with the smashed potatoes, spreading them out evenly across the surface of the dish. \r\n\r\n\r\n\r\n\r\n\r\n', '', 54),
(158, 'Lasagna Casserole -- Curly Pasta with Meat and Ricotta', '1 pound campanelle (curly-shaped pasta), such as Barilla brand \r\nSalt\r\n3 tablespoons extra-virgin olive oil (EVOO)\r\n1 pound ground beef, pork and veal mix \r\n1 carrot, grated \r\n1 onion, finely chopped \r\n4 cloves garlic, grated \r\nBlack pepper \r\n1 28-ounce can Italian plum tomatoes\r\n1 cup chicken stock\r\n1/2 cup basil leaves, shredded or torn\r\nA handful of flat-leaf parsley, coarsely chopped  \r\n2 cups ricotta cheese \r\n1/2 cup (a couple of handfuls) Parmigiano Reggiano cheese\r\n\r\n', 'it\'s all about you .... really!\r\n\r\n\r\n\r\n\r\nWhat\'s cooking\r\n\r\n\r\n\r\nback\r\nLasagna Casserole -- Curly Pasta with Meat and RicottaDinner\r\nPreheat oven to 400Â°F\r\nHeat a pot of water to boil for the pasta. \r\n\r\nOnce at a boil, salt liberally and add pasta. Cook just shy of al dente leaving a good bite to it, about 6-7 minutes.\r\n\r\nWhile water comes to a boil, heat EVOO, 3 turns of the pan, over medium-high heat.  Add the meat and lightly brown it for 3-4 minutes, breaking it up into small bits with the back of a wooden spoon.  \r\n\r\nAdd carrot, onions and garlic, season with salt and pepper, and cook until veggies soften, 5-6 minutes.  Break up the tomatoes with a wooden spoon in a colander over a bowl to crush them up. \r\n\r\nAdd them to beef and vegetables. Add stock, bring up to a bubble and simmer for 15 minutes. Fold in basil and parsley.  \r\n\r\nCook and drain pasta, and return it to the pot. Add the ricotta cheese and the sauce, and toss to coat. Transfer pasta to a casserole dish and top with Parmigiano Reggiano cheese. \r\n \r\nBake 15 minutes or so, until top crusts up a bit. Toss together a green salad while the casserole\'s in the oven to serve alongside.\r\n\r\nYields 6 servings\r\naired on: February 27, 2007\r\n \r\n \r\n \r\n', '', 57),
(159, 'Peanut Butter, Apple and Honey Wafflewich', '1 box store-bought waffles\r\n1 jar peanut butter, crunchy or smooth\r\nHoney\r\n1 Granny Smith apple, sliced\r\nYou can also make these sandwiches with bananas, sliced on a bias\r\n', 'it\'s all about you .... really!\r\n\r\n\r\n\r\nToast waffles. Spread peanut butter on top of warm waffle. Top with a drizzle of honey and either a few slices of or apple or banana. Top with another warm waffle. Delish!!\r\nYields 4 servings\r\n', '', 67),
(160, 'Stuffed Apples', '4 large Macintosh or Empire apples\r\n1 tablespoon lemon juice \r\n3/4 cup brown sugar \r\n1/4 cup instant oatmeal mix or rolled oats \r\n1/4 teaspoon nutmeg, a healthy grating \r\n1 teaspoon ground cinnamon \r\n4 tablespoons butter, cut into pieces \r\n2 ounces, 1/8 cup, golden raisins, chopped \r\n1/4 cup chopped walnuts, walnut pieces or pecans\r\n', 'Preheat oven to 425Â°F. \r\nCut the top off of each apple, about 1/4 - 1/2 inch from the stem end and reserve the tops. Core and hollow out each apple to make room for the filling. Sprinkle apples with lemon juice to prevent them from turning brown.\r\n\r\n\r\nMix the rest of the ingredients together in a bowl. Overstuff the apples and replace the tops. Bake 20 minutes in a small oven-safe dish or a muffin tin to keep the apples from tumbling over.\r\n\r\nYields 4 servings\r\naired on: november 30, 2006\r\npass it on | print\r\n video block\r\n \r\n ', '', 9),
(161, 'French Toast Sticks ', '4 slices white bread\r\n1/2 cup peanut butter, creamy or chunky\r\n1/2 cup jelly, any flavor you like\r\n3 eggs\r\n3 tablespoons milk\r\n1 teaspoon vanilla\r\n1-2 tablespoons butter\r\n1/2 cup maple syrup\r\n', 'Spread peanut butter on 2 slices of bread and the jelly on the other 2 slices of bread to make 2 sammies. \r\n \r\nScramble the eggs, milk and vanilla in a bowl to make french toast batter. \r\n\r\nPlace a large non stick skillet over medium heat, add butter. When the butter is almost melted, dunk two of the sammies into the batter and let the excess drip off. Place in the pan and cook until golden brown on each side, about 3-4 minutes per side. \r\n\r\nCut into sticks and serve with warm maple syrup.\r\n\r\n\r\nYields 2-3 kid-size servings\r\naired on: January 29, 2007 [0]\r\n\r\n', '', 67),
(162, 'Ladybug Pizzas ', '4 English muffins, split and toasted lightly\r\n1-2 tablespoons store-bought pesto\r\n1 cup mozzarella cheese, shredded\r\n1-2 vine-ripe tomatoes, sliced about 1/4-inch thick\r\n', 'Preheat oven to 350Â°F.\r\n\r\nSpread the pesto evenly on all 8 halves of the lightly toasted English muffins. Top with equal amounts of shredded mozzarella cheese, a slice of tomato. Place on a cookie sheet and bake until the cheese is gooey and melted, about 5 minutes. Look, little ladybugs!\r\nYields 4 servings', '', 2),
(163, 'Chili-Cheese Dogs In Beach Blankets ', ' tablespoon vegetable oil or extra-virgin olive oil (EVOO)\r\n3/4 pound ground beef, turkey or tempeh\r\n1 tablespoon (a palmful) chili powder\r\n1 teaspoon garlic powder\r\n2 teaspoons dehydrated onion\r\nSalt and pepper \r\n2 tablespoons tomato paste \r\n1/4 cup water \r\n1 tube refrigerated pizza dough, found on the dairy aisle\r\n8 beef, turkey, pork or tofu dogs\r\n1 1/2 cups shredded cheddar cheese\r\n', 'Preheat oven to 400Â°F.\r\nIn a small pot, heat the oil over medium-high heat. Add the meat to the pot and brown it up, 6-7 minutes. \r\nAdd the chili powder, granulated garlic, dehydrated onion and a little salt and pepper. Add the tomato paste, stir it around a minute, then add the water and stir. Turn the heat down to low, simmer 5 minutes and turn off the heat.\r\n\r\nRoll the pizza dough out into a big rectangle. Cut the dough in half lengthwise with a small knife. Cut the dough into four equal pieces across -- you should end up with 8 small, rectangular pieces of dough. Across the center of each rectangle place a couple spoonfuls of chili sauce and a small handful of cheese. \r\n\r\nSet the dog on the dough, and wrap and roll the pizza dough around the dog like a blanket, sealing in the chili and cheese. The nubs of each end of the dog should be peeking out. Bake in the oven 18 minutes until golden. YUM-O!\r\nYields 8 dogs\r\n', '', 17),
(164, 'Veggie Mac and Cheese Casserole ', 'n/a', 'Bring a large pot of water to boil for the pasta. Once boiling, add some salt and undercook the pasta, about 7 minutes until just under al dente.\r\n\r\nPreheat broiler and set rack 12 inches from heat.\r\n\r\nWhile the pasta cooks, heat a large, deep, nonstick skillet over medium-high heat. \r\nAdd the chopped bacon and cook till golden and crispy. Remove with a slotted spoon to a paper towel-lined plate and reserve. Add another tablespoon EVOO to the skillet, 1 turn of the pan,. Add onions and cook till soft, 4-5 minutes. Add flour and cook another minute or two before adding the chicken broth -- it should look real pasty and thick. Whisk in milk and bring to a bubble, season with salt and pepper, and stir in the mustard. Lower heat and add 1 1/2 cups of each cheese. Stir to melt, 1 minute. Adjust seasoning with mustard, salt and pepper, to your taste.\r\n\r\nDrain pasta well. Combine pasta and veggies with the cheese sauce, stir in chopped parsley, then pour into large casserole and top with remaining cheese. \r\n\r\nTransfer to broiler to melt and brown cheese, about 2 minutes, and serve.\r\n\r\nYields 4-6 servings\r\n', '', 57),
(165, 'Poutine', '1 bag frozen crinkle-cut fries\r\n1 tablespoon extra-virgin olive oil (EVOO)\r\n8 slices Canadian bacon, sliced thin and chopped\r\n3 tablespoons water\r\n4 tablespoons cornstarch\r\n2 cloves of garlic, finely chopped\r\n1/4 small onion, finely chopped\r\n1 bottle Molson Canadian beer, or 1 1/2 cups chicken stock\r\nSalt and freshly ground black pepper\r\n2 cups shredded mozzarella cheese\r\n', 'Preheat oven to 400Â°F.\r\n\r\nPlace fries onto a baking sheet and bake according to package directions.\r\n\r\nPlace a medium sauce pot over medium-high heat, add EVOO. Cook bacon until it is slightly browned and crispy. Remove half of the bacon from the pot, and set aside. \r\n\r\nIn a small bowl, mix the cornstarch and water together with your fingers until it reaches a heavy cream-like consistency.  \r\n\r\nAdd the garlic and onion to the pot with the remaining bacon and cook for 3-4 minutes. Slowly add the beer or stock. Bring up to a boil and cook for 2-3 minutes. When the fries are almost ready, pour in the cornstarch mixture, a little at a time, and whisk until thickened, about 1-2 minutes. The mixture may be thin at first, but it will thicken as it cooks. Continue to cook for about 5 minutes.\r\n\r\nWhen the fries are done, pour them into a deep serving dish and sprinkle the cheese and the reserved bacon all over them. Top with the gravy.\r\n\r\nYields 4 servings\r\n', '', 22),
(166, 'Lasagna Casserole -- Curly Pasta with Meat and Ricotta ', '1 pound campanelle (curly-shaped pasta), such as Barilla brand \r\nSalt\r\n3 tablespoons extra-virgin olive oil (EVOO)\r\n1 pound ground beef, pork and veal mix \r\n1 carrot, grated \r\n1 onion, finely chopped \r\n4 cloves garlic, grated \r\nBlack pepper \r\n1 28-ounce can Italian plum tomatoes\r\n1 cup chicken stock\r\n1/2 cup basil leaves, shredded or torn\r\nA handful of flat-leaf parsley, coarsely chopped  \r\n2 cups ricotta cheese \r\n1/2 cup (a couple of handfuls) Parmigiano Reggiano cheese\r\n\r\n\r\n', 'n/a', 'Source URL:\r\nhttp://www.rachaelrayshow.com/?q=recipes/lasagna-casserole ', 57),
(167, 'cheeseball', '1 can flake ham\r\n1 cream cheese\r\n1 green onion (tail)\r\ngrated cheddar cheese\r\n1 drop tobasco sauce\r\n1 tsp milk\r\ngarlic powder (bit)\r\n', 'mix with mixer\r\nput in bowl\r\nform a ball with knife', 'given to me by Denise Dubosq', 34),
(168, 'Kellogg\'s Corn Flakes Banana Muffins', '1 1/4 cup flour\r\n1 tbsp baking powder\r\n1/2 tsp salt\r\n1/2 tsp cinnamon\r\n1/4 tsp ground nutmeg\r\n1/2 cup brown sugar firmly packed\r\n2 cups kellogg\'s corn flakes crushed to 1 cup crumbs.\r\n1 egg\r\n1/3 cup skim milk\r\n1/4 cup vegetable oil\r\n1 cup mashed fully ripe bananas (about 3 medium)', '1.  combine flour, baking powder, salt, spices, sugar and kellogg\'s corn flakes cereal. Set aside\r\n2.  In large mixer bowl, combine egg, milk and oil.  Stir in bananas.  Add flour mixture, stirring only until combined.  Portion evenly into twelve 21/2 inch muffin-pan cups coated with cooking spray.\r\n3.  Bake at 400 (200 c) for 20 minutes or until lightly browned.\r\nServe warm\r\nYield 12 muffins', 'per serving  165 calories', 59),
(169, 'Mexican rice', '1 cup minced onions\r\n1/3  Cup Olive Oil\r\n1 cup Rice\r\n1 tsp salt\r\n1 tbsp chili powder\r\n3 to 4 cups tomato juice', 'Cook onions in oil for 2 to 3 minutes.\r\n Add remaining ingredients. Bring to a boil;cover and simmer for 18 to 25 minutes,or until rice is tender.\r\n\r\nMakes 4 to 6 servings..', 'Enjoy\r\n\r\nBEA\'S RECIPE', 22),
(170, 'Banana Chocolate Chip Mini-Muffins', '1 cup low fat vanilla yogurt\r\n1/2 cup skim milk\r\n1/2 cup uncooked quick oats\r\n1/2 tsp vanilla\r\n1 egg, beaten\r\n1 large banana mashed\r\n1/2 cup brown sugar\r\n1 1/4 cup flour\r\n1/2 tsp. baking soda\r\n2 tsp. baking powder\r\n1/2 tsp. salt\r\n1/2 cup mini chocolate chips', 'Preheat oven to 375.  Combine yogurt, milk, oats, vanilla, egg and banana.\r\n\r\nSet aside for 5 minutes to soften.  In separate bowl, stir together brown sugar, flour, baking soda, baking powder, and salt.  \r\n\r\nStir flour mixture into yogurt mixture to moisten.  Add chips.  Do not beat, will be thick.  \r\n\r\nSpoon by heaping teaspoons into mini-muffin tins.  Bake until golder brown, about 15-18 minutes.\r\n makes 36 mini muffins at 1 point each.', 'try substituting chocolate chips for pineapple or strawberries and add about 1/4 cup of coconut.  I tried it and it was delicious.\r\nnext time i will try splenda brown sugar as well.', 59),
(171, 'Broccoli Casserole', '2 pounds fresh broccoli cut into florets\r\n1 can (10-3/4 ounces) condensed cream of mushroom soup undiluted\r\n1/2 cup mayonnaise\r\n1/2 cup shredded cheddar cheese\r\n1 tbsp lemon juice\r\n1 cup crushed cheese-flavored snack crackers\r\n\r\n\r\n\r\n\r\n', 'Place 1 in. of water and broccoli in sausepan.  bring to a boil.  Reduce \r\nheat.  cover and simmer for 5 - 8 minutes or just until crisp tender.  Drain \r\nand place in greased 2 qt baking dish.  In a bowl combine the soup, \r\nmayonnaise, cheese and lemon juice. Pour over broccoli.  Sprinkle with \r\ncrushed crackers.  Bake uncovered at 350 for 25 or 30 minutes or until \r\nheated through.  Yield 6 - 8 servings.\r\n\r\n', 'From Mary Lovequist\r\n', 22),
(172, 'sucre a la creme', '2 tasses de sucre blanc\r\n2 tasses de sucre brun\r\n1 can de lait carnation\r\n1 tasse de beurre\r\n2 c a table de caramel\r\n1 c a the de vanille', 'mix all together cook 9 minutes or until soft ball.  Beat with mixer for 10 minutes.  put in greased pan.', '', 9),
(173, 'sucre a la creme 2', '1 1/2 tasse de sucre brun\r\n1 1/2 tasse de sucre blanc\r\n1 tasse lait carnation\r\n3 c a table de beurre\r\n2 c a table de sirop de ble dinde\r\n1 c a the de vanille.', 'cuire a feu tres bas.  battre jusq\'a ca commence a epaisir, avant de mettre dans un plas graisser.', '', 9),
(174, 'barbecue ribs', '2 full racks baby backs ribs(remove membrane)\r\nrub with seasoning\r\nplace in roasting pan with 1 bottle of beer &amp; cook at 300 for 4 hours top side up.\r\nbrush ribs with bbq sauce and let marinade for 2 hours.\r\ngrill on bbq on high to side down for 5 min, turn over and grill for another 3 minutes\r\n\r\nbbq sauce\r\nin sauce pan combine dianas rib and chicken bbq sauce 1/4 cup with 1 tablespoon dijon mustard and 1 tablespoon brown sugar.\r\nin \r\n', '', '', 17),
(175, 'greek salad', '1 green pepper\r\n1 red pepper\r\n1/3 english cucumber\r\n2 tomatoes 3/4 cup of feta\r\n1/4 cup of red onions\r\ngreek dressing', 'n/a', '', 55),
(176, 'fish chowder', '1 lb fish\r\n1/4 cup onions\r\n1/4 cup celery\r\n1/2 tsp pepper\r\n2 cups of chicken soup base\r\n3 cups of milk\r\n2 tsp butter\r\n1 cup carrot\r\n1/4 cup flour\r\npaprika', 'melt butter, saute vegetables.Blend in flour, salt, paprika and pepper. Add bouillon, milk.  When veggies are cook, add fish and cook for 10 minutes.\r\n', '', 21),
(177, 'Pudding Chaumere', 'cake\r\n2 Tabl. butter\r\n1/2 cup sugar\r\n1 egg\r\n1 cup flour\r\n1/2 cup milk\r\n2 tsp baking powder\r\n1/2 tsp salt\r\nSauce\r\n1 cup brown sugar\r\n1 cup boiling water\r\n1 tsp of butter\r\n1 tsp of vanilla\r\n', 'Mix butter sugar and egg well.  Add milk and then add rest of the ingredients for cake.\r\nMix all sauce ingredients together and pour over cake.  cook at 350f for about 25 minutes.', '', 40),
(178, 'Barbeque Gravy', '3 tablespoons butter \r\n3 tablespoons flour \r\n2 cups chicken stock \r\n1/4 cup barbeque sauce \r\nSalt and freshly ground black pepper ', 'Heat a saucepan over medium-high heat. Melt the butter then stir in the flour and cook until light brown, about 1 minute. \r\nWhisk in the chicken stock and barbeque sauce, and season with salt and freshly ground pepper. Continue whisking and cook until thickened, about 3 minutes. \r\n', '', 17),
(271, 'MERINGUE COOKIES', '2 EGG WHITES\r\n150ML 2/3 CUP SUGAR\r\n1 ML 1/4 TSP OF TARTAR\r\n2 ML 1/2 TSP OF VANILLA OR ANY FLAVOUR', 'BEAT EGG WHITE AND CREAM OF TARTAR UNTILFOAMY.\r\nGRADUALLY BEAT IN SUGAR, BEAT WELL AFTER EACH ADDITION\r\nBEAT IN FLAVOURING\r\nCONTINUE BEATING UNTIL MIXTURE STAND IN STIFF PEAK\r\nDROP BY TSP ON A GREASED COOKIE SHEET\r\nBAKE AT 250 FOR 40 MINUTES OR UNTIL SET BUN NOT BROWN.', 'VARIATIONS 1-COCONUT.  FOLD 1/2 CUP OF COCONUT AFTER THE EGG WHITE. BEAT UNTIL STIFF PEAK\r\n            2- 1/2 CHOCOLATE CHIPS OR NUTS\r\nFOOD COLOURING', 58),
(180, 'Apple Cider Gravy', '3 tablespoons butter \r\n3 tablespoons flour \r\n2 cups chicken stock \r\n1/2 cup apple cider \r\nSalt and freshly ground black pepper \r\n', 'Heat a saucepan over medium-high heat. Melt the butter then stir in the flour and cook until light brown, about 1 minute. \r\nWhisk in the chicken stock and apple cider, and season with salt and freshly ground pepper. Continue whisking and cook until thickened, about 3 minutes. \r\n', '', 17),
(182, 'Oven-Roasted Spicy Potatoes &amp; Glazed Carrots', 'For the potatoes: \r\n5 pounds red potatoes \r\nA palmful garlic powder \r\nA palmful of onion powder \r\nA palmful of dried parsley \r\nA palmful of dried rosemary \r\nA palmful of dried thyme \r\nExtra-virgin olive oil (EVOO), to coat the potatoes \r\nSalt and lots of freshly ground black pepper \r\nFor the carrots: \r\n3 to 4 tablespoons butter \r\n1/2 cup water \r\n2 28-ounce bags (the large ones) of frozen carrots \r\n1/2 cup honey \r\nDash of curry powder \r\n', 'Preheat oven to 400Ã¯Â¿Â½F. \r\n \r\nRemove carrots from freezer and let them come to room temperature. Cut potatoes in half and place them on a large baking sheet or roasting pan. Add all of the spices to a small bowl and mix to create a seasoning mixture (keep the leftovers in a well-sealed container for a later use). \r\n \r\nCoat the potatoes with EVOO then sprinkle with the spice mixture. Toss the potatoes so the EVOO and spices are distributed evenly. Roast for about 20-25 minutes, until golden brown. \r\nWhile potatoes are roasting, place a large skillet over medium-high heat. Add butter to the skillet and let melt. Add the water, thawed carrots, honey and curry powder to the butter and stir to coat the carrots in the butter. When they\'re heated tWhile potatoes are roasting, place a large skillet over medium-high heat. Add butter to the skillet and let melt. Add the water, thawed carrots, honey and curry powder to the butter and stir to coat the carrots in the butter. When theyâre heated through, they are ready to serve.\r\n\r\nServe the roasted potatoes and glazed carrots alongside Rachaelâs âBuying In Bulkâ Pot Roast.\r\n\r\nCoat the potatoes with EVOO then sprinkle with the spice mixture. Toss the potatoes so the EVOO and spices are distributed evenly. Roast for about 20-25 minutes, until golden brown.\r\n\r\nWhile potatoes are roasting, place a large skillet over medium-high heat. Add butter to the skillet and let melt. Add the water, thawed carrots, honey and curry powder to the butter and stir to coat the carrots in the butter. When theyâre heated through, they are ready to serve.\r\n\r\nServe the roasted potatoes and glazed carrots alongside Rachaelâs âBuying In Bulkâ Pot Roast.\r\n', '', 61),
(183, 'Chicken Teriyaki Sliders', '1 pound ground, all-white meat chicken \r\n4 scallions (one large handful), chopped \r\n2 cloves garlic, finely chopped or grated \r\n1 tablespoon grill seasoning \r\n1/4 cup teriyaki sauce \r\n1 tablespoon canola oil \r\n1/4 cup pickled ginger \r\n1 cucumber, seeded and sliced \r\n1 head Bibb or Boston lettuce \r\nSmall buns (about 3 inches in diameter) or dinner rolls \r\n', 'Combine meat, scallions, garlic, grill seasoning and teriyaki sauce. Score and divide meat into 8 portions and form small patties, about 1/2 inch thick. \r\nHeat a large skillet over medium-high heat and add canola oil, about once around the pan. Cook mini chicken burgers in the pan, about 3 minutes on each side, until cooked through. \r\nPlace burgers on buns, top each burger with some pickled ginger, a slice of cucumber and some lettuce then place the top half of bun on top. \r\n', '', 54),
(184, '&quot;Buying In Bulk&quot; Pot Roast', '3 to 4 tablespoons canola oil \r\n1 4 to 5-pound rump roast \r\nSalt and freshly ground black pepper \r\n3 tablespoons flour, plus enough to dredge the roast in \r\n3 carrots, roughly chopped \r\n4 stalks of celery, roughly chopped \r\n2 large onions, roughly chopped \r\n6 cloves of garlic, chopped \r\n2 fresh bay leaves \r\n3 cups water \r\n3 tablespoons butter \r\n3 to 4 cups beef stock \r\n2 tablespoons brown sugar \r\n2 tablespoons Worcestershire sauce \r\nA handful of parsley, chopped, for garnish \r\n', 'Preheat oven to 350Â°F. \r\n \r\nHeat a large Dutch oven over medium-high heat with the canola oil. Season all sides of the roast well with salt and freshly ground black pepper then dredge it in flour. Brown the roast well, about 3-4 minutes per side. \r\n \r\nOnce all sides are brown, add the carrots, celery, onion, garlic, fresh bay leaves to the pot, and fill it with water so the liquid comes 1/3 the way up the roast. Cover with a tight-fitting lid and place in the oven for about 3 1/2-4 hours. If you don\'t have a tight-fitting lid for the pot, use tin foil instead and baste the roast every 30-40 minutes. \r\n \r\nOnce the roast is about a half hour away from being done, start your gravy: Place a medium skillet over medium-high heat. Melt the butter and stir in 3 tablespoons of flour. Cook the butter-flour mixture about 2-3 minutes, until it is light brown. Then, whisk in the beef stock, brown sugar and Worcestershire sauce, season to taste with salt and freshly ground black pepper. Let the gravy cook down, whisking occasionally, until desired consistency. \r\nOnce the roast is done, remove it from the oven and place the meat on a cutting board, loosely covered with foil. Let the roast rest for about 15-20 minutes. While the meat is resting, strain the pan juices through a fine strainer, remove any extra fat, then stir the pan juices into the gravy. \r\n \r\nOnce the meat has rested, slice it across the grain and pour gravy over each portion. Garnish with parsley and serve with Oven-Roasted Spicy Potatoes &amp; Glazed Carrots alongside. \r\n', '', 17),
(185, 'Sicilian Meatballs', '4 to 5 slices of bread, torn up \r\n3/4 cup milk \r\nExtra-virgin olive oil (EVOO), for drizzling \r\n2 28-ounce cans San Marzano plum tomatoes, crushed by hand \r\nSalt and freshly ground black pepper \r\n2 pounds ground sirloin \r\n4 cloves garlic, chopped \r\n1/2 cup (about a handful) flat-leaf parsley, chopped \r\n1 cup grated Parmigiano-Reggiano \r\n1 teaspoon allspice \r\n1 pinch crushed red pepper flakes \r\n1/3 cup pine nuts, toasted and chopped \r\n1/4 cup currants \r\n1 egg \r\nFor the salad: \r\n3 hearts of romaine \r\n1/2 medium red onion, sliced \r\n1 orange, zested and sliced \r\n1 lemon, juiced \r\n1 pint ricotta cheese \r\n1/2 cup basil leaves, torn \r\n', 'Preheat oven to 425ÂºF. \r\nIn a small bowl, place torn up bread and pour milk over it, set aside to soak. \r\n \r\nDrizzle a good amount of EVOO into a roasting pan, then pour in the 2 cans of tomatoes and crush them up with your hands or a potato masher. Season with salt and freshly ground black pepper and set aside while you prepare the meatballs. \r\n \r\nIn a large bowl, combine ground sirloin, garlic, parsley, grated Parmigiano, allspice, red pepper flakes, pine nuts, currants, egg and season with salt and freshly ground black pepper. Squeeze out excess milk from the soaking bread (it should be loose and in small pieces) then add it to the meat mixture and mix everything with your hands to combine. \r\nForm 12 baseball-sized balls, each about 2 1/2 inches in diameter, and place them on top of the mashed tomatoes in the roasting pan. Transfer to the oven and roast until the meatballs are brown and cooked through, about 30 minutes. \r\nWhile the meatballs are cooking, chop the hearts of romaine, red onion and orange and toss together in a large bowl with lemon juice, orange zest, about a tablespoon of EVOO, salt and freshly ground black pepper. \r\nRemove meatballs from the oven and arrange torn pieces of crusty bread in and around the meatballs and sauce. Serve with some ricotta cheese mixed with lots of black pepper and the torn basil alongside. \r\n\r\n--------------------------------------------------------------------------------\r\n\r\n', '', 17),
(186, 'Horseradish Mashed Potato-Topped Shepherd Pie', '5 pounds Russet potatoes, peeled and cut into chunks \r\n1/2 to 3/4 cup milk (use more or less depending how thick you like your mashed potatoes) \r\n1 egg, beaten \r\n1/4 cup prepared horseradish \r\nSalt and freshly ground black pepper \r\n2 tablespoons extra-virgin olive oil (EVOO) \r\n2 pounds lean ground sirloin \r\n3 parsnips, peeled and chopped or sliced 1/4-inch thick \r\n2 carrots, peeled and chopped or sliced 1/4-inch thick \r\n1 large onion, chopped \r\n1 fresh bay leaf \r\n3 tablespoons flour \r\n2 cups beef stock \r\n1 tablespoon Worcestershire sauce \r\n2 to 3 tablespoons chives, chopped \r\n', 'Place the potatoes in a medium-size pot, cover them with cold water and bring to a boil. Salt the water and cook potatoes until fork tender, about 12-15 minutes. Drain the potatoes and allow them to cool slightly. Mash them with the milk then stir in the egg and horseradish. Season with salt and freshly ground black pepper and set aside. \r\nWhile the potatoes are cooking, make the filling: Heat the EVOO in a large, deep skillet over medium-high heat until it shimmers. Add the meat and brown it well, about 5 minutes. Add the vegetables and bay leaf to meat, season with salt and pepper and cook until the vegetables are softened, 8-10 minutes. Sprinkle the flour around the pan, stir and cook for about 1 minute. Add the stock and bring up to a simmer to thicken the gravy, 3-4 minutes. Discard the bay leaf and season the gravy with Worcestershire sauce, salt and pepper. \r\nTurn broiler on and place rack in the middle of the oven. \r\n \r\nTransfer the filling to a medium-size casserole or baking dish and top it with heaping spoonfuls of the horseradish mashed potatoes so they completely cover it. Brown the potatoes under the broiler, about 2 minutes, garnish with chives and serve. \r\n', '', 22),
(187, 'Pizza Pasta Casserole ', '2 pounds ground beef\r\n\r\n1 large onion, chopped\r\n\r\n2 jars (28 ounces each) spaghetti sauce\r\n\r\n1 package (16 ounces) spiral pasta, cooked and drained\r\n\r\n4 cups (16 ounces each) shredded part-skim mozzarella cheese\r\n\r\n8 ounces sliced pepperoni', 'Preheat oven to 350Â°. In a large skillet, cook beef and onion over medium heat until meat is no longer pink; drain. Stir in spaghetti sauce and pasta.\r\nTransfer to 2 greased 13x9-in. baking dishes. Sprinkle with cheese. Arrange pepperoni over the top.\r\nBake, uncovered, 25-30 minutes or until heated through. \r\nFreeze option: Cool unbaked casseroles; cover and freeze up to 3 months. To use, partially thaw in refrigerator overnight. Remove from refrigerator 30 minutes before baking. Preheat oven to 350Â°. Bake as directed, increasing time to 35-40 minutes or until heated through and a thermometer inserted in center reads 165Â°.', '', 57),
(188, 'Turkey-Stuffin Meatloaf With Scallion Mashed Potatoes &amp; Gravy', '7 tablespoons butter, divided \r\n1 large onion, cut into small dice \r\n5 to 6 pieces celery heart, cut into small dice \r\n1 bay leaf \r\n2 tablespoons poultry seasoning \r\nSalt and freshly ground black pepper \r\n1 bag Pepperidge Farm traditional flavor stuffing cubes \r\n2 quarts chicken stock, divided \r\n3 to 3 1/2 pounds ground turkey \r\n2 eggs \r\n2 1/2 pounds (about 4 to 5 medium-size) peeled Idaho potatoes \r\n1/2 cup reduced fat sour cream \r\n1/2 cup milk \r\n1 small bunch scallions, chopped \r\n1/4 cup flour \r\n1 pound green beans \r\n', 'Preheat oven to 375ÂºF. \r\n\r\nHeat a large skillet over medium-high heat and add 3 tablespoons of butter. When the butter is melted, add the onions, celery and bay leaf to the skillet, season with poultry seasoning, salt and freshly ground black pepper and cook until the veggies are tender. \r\n\r\nAdd the stuffing cubes to the skillet and mix in about 2 to 3 cups of chicken stock to moisten. Take the bay leaf out of the skillet, remove the skillet from the heat and let the mixture cool, about 5 minutes. \r\n\r\nIn a large bowl, mix the ground turkey, eggs and cooled stuffing mixture. Form the meat mix into 2 long loaves on a baking sheet. Drizzle them with EVOO and cook in the oven for about an hour, until brown and cooked through (165ÂºF internal temperature), about 45 minutes. \r\n\r\nOnce the turkey loaves are about half way done, start the sour cream and scallion potatoes: Add the potatoes to a medium-size pot of cold water and boil until tender. \r\n\r\nWhile the potatoes are boiling start the gravy: Add the remaining four tablespoons butter to a large skillet over medium-high heat. Once the butter is melted, add the flour and cook for about a minute. Whisk the remaining 6 cups of chicken stock into the skillet with the butter and flour mixture, and cook until thickened and bubbling, about 3 minutes. Season with salt and freshly ground black pepper. Set aside half the gravy for tonight&amp;#8217;s meat loaf and mashed potatoes and reserve the other half for the Enchil-Lasagna. \r\n\r\nHeat a pot over high heat with enough water to come one inch up the side of the pot. Once boiling, add the green beans and cook until tender, 3-4 minutes. Once the potatoes are cooked, drain the water from the pot and mash up the potatoes with the sour cream, milk, salt and freshly ground black pepper. Once the potatoes are mashed, stir in the scallions. \r\n\r\nServe one of the loaves of meatloaf and the potatoes with the green beans alongside. Save the second meatloaf for Enchil-Lasagna. \r\n\r\n', '', 5),
(190, 'Art Smith\'s Hummingbird Cake', 'Cake\r\n3 cups all-purpose flour \r\n2 cups granulated sugar \r\n1 tsp. baking soda \r\n1 tsp. ground cinnamon \r\n1/2 tsp. salt \r\n2 cups chopped ripe bananas \r\n1 cup drained crushed pineapple \r\n1 cup vegetable oil \r\n2 large eggs, beaten \r\n1 1/2 tsp. vanilla extract \r\n1 cup (4 ounces) finely chopped pecans \r\n\r\nIcing:\r\n\r\n8 ounces cream cheese, at room temperature \r\n1/2 cup (1 stick) butter, at room temperature \r\n1 pound confectioners\' sugar (about 4 1/2 cups sifted) \r\n1 tsp. vanilla extract \r\n\r\n', 'To make the cake, position racks in the center and bottom third of the oven and preheat to 350Ã¯Â¿Â½. Lightly butter two 9&quot; round cake pans, sprinkle evenly with flour and tap out the excess. (If you wish, butter the pans, line the bottoms with rounds of parchment paper, then flour the pans and tap out the excess.)\r\n\r\nSift the flour, sugar, baking soda, cinnamon and salt into a bowl. In another bowl, stir or whisk the bananas, pineapple, oil, eggs and vanilla until combined. Do not use an electric mixer. Pour into the dry mixture and fold together with a large spatula just until smooth. Do not beat. Fold in the pecans. Spread evenly into the pans.\r\n\r\nBake until the cake springs back when pressed in the center, 30 to 35 minutes. Transfer the cakes to wire racks and cool for 10 minutes. Invert the cakes onto the racks (remove the parchment paper now if using). Turn right side up and cool completely.\r\n\r\nTo make the icing: Using an electric mixer on high speed, beat the cream cheese and butter in a large bowl until combined. On low speed, gradually beat in the sugar, then the vanilla, to make a smooth icing.\r\n\r\nPlace 1 cake layer, upside down on a serving platter. Spread with about 2/3 cup of the icing. Top with the second layer, right side up. Spread the reaming icing over the top and sides of the cake. The cake can be prepared up to 1 day ahead and stored, uncovered in the refrigerator. Let stand at room temperature 1 hour before serving.\r\n\r\n', 'use to be Oprah\'s Chef now owns his own restaurant.\r\n', 45),
(192, 'Broiled French Toast with Honey Glazed Strawberries', '1 tablespoon honey, slightly warmed \r\n1 pint strawberries, hulled and quartered \r\n1/2 teaspoon vanilla extract \r\n\r\n\r\n2 whole eggs \r\n2 egg whites \r\n1/4 cup soy milk \r\n2 tablespoons maple syrup \r\n1 teaspoon vanilla extract \r\n1 teaspoon ground cinnamon \r\n8 slices whole grain wheat bread \r\n', 'To prepare the strawberries, in a medium bowl, mix honey with 2 teaspoons water; stir until dissolved. Add strawberries and vanilla; mix and set aside. \r\n\r\nTo make French toast, preheat broiler. Spray a baking sheet with vegetable spray and set aside. \r\n\r\nIn a large bowl, combine all ingredients except bread; mix well. Dip bread into egg mixture, let excess drip off, and place bread on prepared baking sheet. Repeat with remaining bread (don\'t overlap) Broil on each side until golden brown, about 1 1/2 to 2 minutes. Remove and serve with strawberries on top. \r\n\r\n', 'From the August, 2004 issue of O, The Oprah Magazine  \r\nMakes 4 servings \r\n', 67),
(193, 'Pumpkin Applesauce Muffins', '1 1/2 Tablespoons melted butter or cooking spray \r\n3 1/3 cups all-purpose flour \r\n2 teaspoons baking soda \r\n1/2 teaspoon baking powder \r\n2 teaspoons ground cinnamon \r\n1/2 teaspoon ground cloves \r\n1/2 teaspoon freshly grated nutmeg \r\n1 teaspoon salt \r\n8 Tablespoons unsalted butter, softened \r\n2 cups sugar \r\n4 large eggs \r\n1 cup applesauce \r\n1 cup canned mashed pumpkin \r\n1 teaspoons vanilla extract \r\n2/3 cup apple juice, cider, or orange juice \r\n1 1/2 cups raisins \r\n', 'n/a', 'Created by Nina Simonds \r\nFrom the February, 2005 issue of O, The Oprah Magazine  \r\nMakes 21 muffins \r\n', 59);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(195, 'Chocolate-Glazed Brownies ', '1/3 cup butter, softened\r\n1 cup sugar\r\n3 egg whites\r\n1 teaspoon vanilla extract\r\n2/3 cup all-purpose flour\r\n1/2 cup baking cocoa\r\n1/2 teaspoon baking powder\r\n1/4 teaspoon salt\r\n\r\nCHOCOLATE GLAZE:\r\n2/3 cup confectioners\' sugar\r\n2 tablespoons baking cocoa\r\n1/4 teaspoon vanilla extract\r\n3 to 4 teaspoons hot water\r\nHalloween candy sprinkles, optional\r\n', 'In a large mixing bowl, cream butter and sugar until light and fluffy. Beat in egg whites. Beat in vanilla. Combine the flour, cocoa, baking powder and salt; gradually add to creamed mixture. \r\n    Spread into an 8-in. square baking pan coated with nonstick cooking spray. Bake at 350Ã¯Â¿Â½ for 20-25 minutes or until a toothpick inserted near the center comes out clean. Cool on a wire rack. \r\n    For glaze, in a small bowl, combine the confectioners\' sugar, cocoa, vanilla and enough water to achieve desired consistency. Spread over brownies. Decorate with candy sprinkles if desired. Cut into bars. Yield: 1 dozen. \r\n\r\n', 'NUTRITIONAL INFO\r\nNutritional Analysis: One serving (1 each) equals 173 calories, 6 g fat (3 g saturated fat), 14 mg cholesterol, 124 mg sodium, 30 g carbohydrate, 2 g fiber, 2 g protein. Diabetic Exchanges: 2 starch. \r\n', 40),
(196, 'New York Deli-Style Mac & Cheese', '1 pound cavatappi pasta, or any shape you like \r\nSalt and freshly ground black pepper \r\n3 tablespoons butter, plus additional for buttering toast \r\n3 tablespoons flour \r\n2 cups chicken stock \r\n1 cup milk \r\n1/4 cup spicy deli mustard \r\n3 cups (12 ounces) NY aged sharp cheddar, grated \r\n1/2 pound deli pastrami, roughly chopped \r\n6 slices rye toast, crumbled or coarsely chopped in a food processor \r\n', 'n/a', '', 57),
(197, 'Peanut Butter, Apple and Honey Wafflewich', '1 box store-bought waffles, such as Kellogg\'s brand Eggo Nutri-Grain \r\n1 jar peanut butter, crunchy or smooth \r\nHoney \r\n1 Granny Smith (green) apple, sliced \r\nYou can also make these sandwiches with bananas, sliced on a bias \r\n', 'Toast waffles. \r\nSpread peanut butter on top of warm waffle. \r\nTop with a drizzle of honey and either a few slices of banana or apple. \r\nTop with another warm waffle. Delish!! \r\n', '', 67),
(198, 'Apple and Onion Stuffin\'', '2 tablespoons extra virgin olive oil (EVOO), plus extra for oiling the pan \r\n1/2 stick of butter, softened \r\n1 fresh bay leaf \r\n4 ribs celery and greens from the heart, chopped \r\n1 medium to large yellow onion, chopped \r\n3 McIntosh apples, quartered and chopped \r\nSalt and freshly ground black pepper \r\n2 tablespoons poultry seasoning \r\n1/4 cup parsley leaves, chopped \r\n8 cups cubed stuffing mix, such as Pepperidge Farm brand, or homemade croutons of any bread you choose &amp;#8211; pumpernickel and rye work well \r\n4-5 cups chicken stock \r\nIf preparing as &quot;Stuffin\' Muffins:&quot;\r\n\r\nAdditional 1/2 stick butter, softened \r\n1 egg, beaten \r\n', 'Pre-heat the oven to 400Â°F.\r\n\r\nPre-heat a large skillet over medium-high heat. Add the EVOO to the skillet and the butter. When the butter melts, add the bay leaf, celery, onions and apples. Season with salt, pepper and poultry seasoning and cook 5-6 minutes or until vegetables and apples begin to soften.\r\n\r\nAdd the parsley and stuffing cubes to the pan and combine. Moisten the stuffing with chicken broth until all of the bread is soft, but not wet. Remove bay leaf and let cool either in the pan or in a bowl.\r\n\r\nBrush a cookie sheet or a metal oven safe oval tray with EVOO. Form a loaf shape out of your stuffing and bake until set and crisp on top, about 15-20 minutes. \r\n\r\nFor individual muffins: brush a 12-muffin tin with the remaining butter. Add the beaten egg to the cooled stuffing mixture.\r\n\r\nUsing an ice cream scoop, fill and mound up the stuffing in muffin tin. \r\n\r\nBake until set and crisp on top, about 10-15 minutes. Remove Stuffin\' Muffins to a platter and serve hot or room temperature.\r\n', '', 5),
(199, 'Mashed Potatoes with Cream Cheese and Chives', '2 1/2 pounds small red potatoes or baby Yukon Gold potatoes, large ones halved and small ones left whole \r\n1/2 cup cream or half-and-half \r\n8 ounces cream cheese \r\n10 chives, finely chopped \r\n', 'Place the potatoes in a large pot with cold water. Once the water comes to a boil, add a generous amount of salt. Boil until the potatoes are tender when pierced with a fork, about 10-12 minutes.\r\n\r\nDrain the potatoes and return them to the hot pot to let them dry out a bit. Mash the potatoes with cream or half-and-half, cream cheese, chives, salt and freshly ground black pepper.\r\n', '', 61),
(200, 'Mini Twice-Baked Potatoes', '4 slices center-cut bacon (turkey bacon can be substituted) \r\n24 Red Bliss potatoes, washed and dried \r\n1/2 cup extra virgin olive oil (EVOO) \r\n1/4 cup milk \r\n1/2 stick butter \r\n1/4 cup sour cream \r\n1/2 cup extra-sharp cheddar cheese, shredded \r\nSalt and freshly ground black pepper \r\n1/4 cup chives, snipped ', 'Pre-heat the oven to 350Ã¯Â¿Â½ F.\r\n\r\nIn a small sautÃ¯Â¿Â½ pan over medium-high heat, cook the bacon until crispy. Cool and then chop.\r\n\r\nPlace the potatoes in a bowl and drizzle with EVOO, salt and freshly ground black pepper. Bake in the oven on a cookie sheet for 45-60 minutes until they are cooked through; you may have to rotate the pan so they brown evenly.\r\n\r\nRemove from the oven. When cool enough to handle, cut a thin lid from the top of each potato. Using a small teaspoon or melon baller, scoop out the inside of the potato, leaving a half-inch border from the edge. Remove all the potato &quot;guts&quot; and lids to a medium size mixing bowl. To the bowl, add the milk, butter, sour cream, cheese, reserved bacon, salt and freshly ground black pepper. Mix to combine.\r\n\r\nDivide the filling among all the hollowed-out potatoes. Using the same cookie sheet you roasted them on, bake the potatoes in the oven until the tops are golden brown. Remove and garnish with chives.\r\n', '', 61),
(201, 'Quick Turkey Croquettes', '2 tablespoons vegetable or any light colored oil, plus some for frying \r\n1 stalk celery, finely chopped \r\n1 small onion, finely chopped \r\n1 carrot, peeled and finely chopped \r\n1/4 cup chopped parsley \r\n1 pound leftover sliced turkey \r\n1 1/2 cup leftover mashed potatoes \r\n1 1/2 cup plain breadcrumbs, divided \r\n1 teaspoon poultry seasoning \r\nA few pinches whole nutmeg \r\nSalt and freshly ground black pepper \r\n1 egg, beaten \r\nCranberry sauce \r\nGravy \r\n', 'Heat 2 tablespoons of oil in a skillet over medium-high heat. Add the celery, onion, carrot and parsley, and cook until softened, about 5 minutes. Let cool slightly.\r\n\r\nHeat a 1/4 of an inch of oil in a large skillet with high sides over medium-high heat.\r\n\r\nIn a mixing bowl, shred the leftover turkey using two forks.\r\n\r\nAdd the mashed potatoes, 1/2 cup of the breadcrumbs, poultry seasoning, nutmeg, salt, pepper, egg and cooled veggies. Mix to combine and form 10 patties about an inch thick.\r\n\r\nDredge the patties in the remaining breadcrumbs and brown in two batches in a single layer in the hot oil for 2 minutes on each side or until deep golden brown. Drain on paper towels and transfer to a serving plate. Serve with cranberry sauce and gravy alongside.\r\n', '', 5),
(202, 'Pork Chops and Applesauce', '1 1/2 pounds baby red-skinned potatoes, cut in half \r\n1 pound green beans, trimmed and cut into 1-inch pieces \r\n6 tablespoons extra virgin olive oil (EVOO), divided \r\nSalt and freshly ground black pepper \r\n1/4 cup parsley leaves (about a handful), chopped \r\n4 McIntosh apples, peeled, cored and diced \r\n1 cup all-natural apple juice or cider (it should look cloudy) \r\n3 tablespoons light or dark brown sugar \r\nZest of 1 orange, reserving the juice \r\n1/4 cup soy sauce or Tamari (dark soy sauce) \r\n4 1-inch thick center-cut boneless pork loin chops (6-8 ounces each) \r\n', 'Pre-heat the oven to 400Â°F.\r\n\r\nPlace the potatoes on a baking sheet. Drizzle with two tablespoons of EVOO and season with salt and freshly ground black pepper. Roast in the oven for 20-25 minutes. During the last 15 minutes of cooking time, add the green beans to the baking sheet with the potatoes. Remove from the oven and garnish with parsley.\r\n\r\nCombine the apples, brown sugar and apple juice in a medium pot over medium-high heat and cook until a chunky sauce forms, about 10-12 minutes, stirring occasionally. If the sauce begins to spatter as it bubbles, reduce the heat. Once the apples are soft and a sauce forms, remove from the heat.\r\n\r\nPre-heat a large skillet over medium-high heat with two turns of the pan of EVOO.\r\n\r\nIn a shallow dish, combine the orange zest and juice of the zested orange and the soy sauce. Add some salt and freshly ground black pepper. Dip the chops into the mixture and place in the hot pan. Brown and caramelize the chops for four minutes on each side or until the juices run clear. Remove the chops from the heat and let them rest a couple minutes for the juice to redistribute. Serve with applesauce, roasted potatoes and green beans.\r\n', '', 17),
(203, 'Stuffed Roasted Strawberries', '12 extra-large strawberries (the bigger the better!) \r\n1-2 ounces bittersweet chocolate, chopped \r\n1 teaspoon sugar (optional) \r\nSpray whipping cream (the real kind in the canister in the dairy section) \r\nCocoa powder, for garnish \r\n', 'Pre-heat the oven to 400Â°F.\r\n \r\nSlice the tops of the berries off just below the stem. Cut the tips off (about 1/4-inch), so that the berries will sit upright. Next, use a small spoon or a melon baller to hollow out the strawberries, working from their tops, in order to create a cavity in each one. Stuff some chocolate into the cavity of each strawberry and place them upright in a baking dish. Lightly sprinkle the berries with sugar, if desired.\r\n\r\nRoast the berries until soft and the chocolate is melted, about 10-12 minutes.\r\n \r\nTo serve, place three strawberries on a dessert plate in a triangle. If the berries have given off liquid in the baking dish, spoon it over them. Spray a small mound of cream in the center of the berries, and top each berry with a rosette of cream. Sift a little cocoa powder over the plate and enjoy!\r\n\r\n', '', 9),
(204, 'Terri\'s Triple Chocolate Chip Cookies', '1 cup butter \r\n3/4 cup packed brown sugar \r\n1/2 cup white sugar \r\n1 egg \r\n1 teaspoon rum extract \r\n1 teaspoon vanilla extract \r\n1 2/3 cup flour \r\n1/2 cup cocoa \r\n1/2 teaspoon salt \r\n1 teaspoon baking powder \r\n1 1/2 cup white chocolate chips \r\n1 1/2 cup semi sweet chocolate chips \r\n', 'Preheat oven to 350 degrees.\r\n\r\nCream together butter, brown sugar and white sugar.  Beat until smooth  Add egg, vanilla and rum extracts and blend together.\r\n\r\nIn a separate bowl, mix together flour, cocoa, salt and baking powder. \r\n\r\nAdd wet ingredients to dry, a little at a time and stir but don\'t over mix.\r\n\r\nAdd chips.\r\n\r\nRoll dough into small balls and place a few inches apart on an ungreased cookie sheet or a cookie sheet lined with parchment paper. \r\n\r\nBake for 10 minutes.  Cookies will not look done but they will be.  Allow to cool one minutes on the tray and then slide onto cooking racks and let cookies cool completely before serving.\r\nEmail a Friend Print this Page Submit Your Own Recipe \r\n Advertisement\r\n Advertisement\r\n ', '', 58),
(206, 'Garlic Bread', '4 cloves garlic, crushed \r\n2 tablespoons butter \r\n2 tablespoons extra virgin olive oil (EVOO)\r\n\r\n1 loaf crusty bread, split \r\n3 tablespoons grated cheese, Parmigiano Reggiano or Romano (optional) \r\nChopped fresh parsley \r\n', 'Combine garlic, butter, and EVOO in a microwave safe dish or in a small saucepan. Heat in microwave for one minute or in saucepan over moderate-low heat for three minutes.\r\n\r\nToast split bread under broiler. Remove bread when it is toasted golden brown in color. Brush bread liberally with garlic oil. Sprinkle with cheese, if desired, and parsley. If you add cheese, return to broiler and brown 30 seconds. Cut into chunks and serve.\r\n', '', 42),
(207, 'Cassata Cake', '16 ounces ricotta cheese \r\n2 pints heavy cream, whipped \r\n3 tablespoons sugar \r\n2 sponge cakes (store-bought or homemade) \r\n1 tablespoon vanilla extract \r\n2 chocolate bars \r\nMaraschino cherries ', 'Mix ricotta, one pint of the whipped heavy cream, sugar and vanilla in a bowl until smooth. Add one roughly chopped chocolate bar. Fold in.\r\n\r\nSpray a large bowl with nonstick cooking spray. Slice sponge cake into 1/2-inch pieces. Line the bowl with one layer of cake. Follow with a layer of filling. Continue alternating layers of cake and filling until you have reached the top of the bowl. Finish with a layer of cake. Seal with plastic wrap and refrigerate overnight.\r\n\r\nRemove plastic wrap. Place a pretty cake plate on top of the bowl. Invert the cake and remove the bowl.\r\n\r\nFrost with remaining pint of whipped cream. Decorate with chocolate curls from second chocolate and well-drained maraschino cherries.\r\n', '', 45),
(208, 'Cinnamon Buns', 'ROLLS:\r\n\r\n1 cup luke warm milk (scalded and cooled) \r\n4 cups flour \r\n1 tsp. salt \r\n1/4 cup sugar \r\n1 cup (2 sticks) margarine \r\n3 egg yolks \r\n1 pkg. dry active yeast \r\n1/4 cup warm water \r\n\r\nFILLING:\r\n\r\nmelted butter \r\n1/2 cup sugar \r\n1 1/2 tsp. cinnamon \r\n\r\nICING:\r\n\r\n1 1/2 cup powdered sugar \r\n1 1/2 tsp. vanilla extract \r\n2 TBSP. margarine \r\n1-3 TBSP. hot water \r\n', 'Mix together flour, salt, 1/4 c. sugar. Cut in  2\r\nsticks margarine. \r\n\r\nDissolve yeast in 1/4. c. warm water, then add 3\r\nbeaten egg yolks to yeast mixture. Add scalded and\r\ncooled milk. Mix well. Split dough into 2 equal\r\nhalves. Refrigerate over night wrapped in plastic\r\nwrap. \r\n\r\nRoll out halves and brush with melted butter.\r\nSprinkle with 1/2 c. sugar and 1 1/2 tsp.\r\ncinnamon. Roll up. Cut. Place rolls in greased\r\ndish. Cover with kitchen towel and let rise for 1\r\nhour. Bake 20-25 minutes @ 375 degrees.\r\n', '', 42),
(209, 'Chicken or Turkey Quesadilla Suiza', '1 cup chopped roast chicken or turkey \r\n1/4 cup mild salsa verde \r\n2 teaspoons extra virgin olive oil (EVOO) \r\nTwo 8-inch whole wheat or spinach flour tortillas \r\n1 cup shredded Monterey Jack or queso fresco cheese \r\n1 scallion, chopped \r\nGreen olives with pimiento, chopped (a small handful) \r\n1 teaspoon chopped cilantro \r\n', 'Have a grown-up helper (GH) pre-heat the broiler. In a small bowl, combine the chicken and salsa and heat in the microwave for a minute (or have your GH heat it in a small pot over medium-low heat).\r\n\r\nAsk your GH to heat 1 teaspoon EVOO in a medium nonstick skillet over medium-high heat. Add a tortilla and cook for 30 seconds, then flip and cook for 30 seconds more; slide the tortilla onto a cutting board. Heat the remaining 1 teaspoon EVOO in the skillet, then add the remaining tortilla and cook for 30 seconds. Flip the tortilla and sprinkle with half of the cheese. Top with the first tortilla. Slide onto a baking sheet and top with the chicken mixture, remaining cheese, scallion, olives and cilantro. Have your GH place the quesadilla under the broiler, 6 inches away from the heat, and cook until the tortillas are crisp around the edges, about 2 minutes.\r\n\r\nSlide the quesadilla onto a cutting board, cut into 4 pieces and serve.\r\n\r\n', 'This is a great recipe for kids and the whole family from Yum-o! It\'s good AND good for you. For more information about Yum-o! go to the Yum-o! website.\r\n\r\n', 5),
(210, 'Chive Buttermilk Biscuits', 'BISCUITS:\r\n2 1/2 cups all purpose flour\r\n1/2 cup chopped fresh chives\r\n1/2 cup crumbled or shredded cheese,such as cheddar or monterey\r\n2 tbsp dried minced onions\r\n1 tbs baking powder\r\n3/4 tsp salt\r\n1/2 tsp baking  soda\r\n1/2 cup cold butter,cut in 1/2&quot; cubes\r\n1 1/4 cups buttermilk\r\n1 egg beaten.\r\n\r\nCHIVE PEPPER BUTTER\r\n1/4 cup butter at room temperature\r\n1 tsp chopped fresh chives\r\n1/2 tsp ground peppercorn medley\r\n1/8 tsp garlic powder\r\n', 'BISCUITS\r\nPreheat oven to 425 f.Grease baking sheet,.In large bowl,combine flour,chives,cheese,onions,baking powder,salt and baking soda.  Cut in butter until mixture resembles coarse crumbs. Stir in buttermilk until just moistened: gently knead in bowl until dough forms.\r\nOn floured surface ,pat dough into 8&quot; round.Using 3&quot; round cutter cut out 8 biscuits.I made smaller cuts and had more biscuits.Place biscuits on baking sheet 2&quot; apart .Brush tops with egg. Bake 15 minutes or until golden\r\n\r\nBUTTER:\r\nIn small bowl,combine butter,chives,pepercorn medley and garlic powder.Refrigerate until serving. Serve with biscuits', 'They are awesome\r\n\r\nBEA\'S RECIPE', 42),
(211, 'Pumpkin Raisin bars', '2 cups flour\r\n2 cups sugar\r\n1 tbsp cinnamon\r\n2 tsp baking powder\r\n1 tsp baking soda\r\n1 tsp salt\r\n1/2 tsp ground nutmeg\r\n1/2 tsp ground cloves\r\n1 -15 oz can pumpkin\r\n4 large eggs\r\n3/4 cup vegetable oil\r\n1 cup raisins\r\n\r\n6oz cream cheese,room temperature\r\n1 cup powdered sugar\r\n1/3 cup butter,room temperature\r\n\r\n', 'PREPARATION:\r\nPreheat the oven to 350f.  Grease 15 1/2 x 10 1/2 x 1 inch baking sheet.  Stir first 8 ingredients in large bowl to bkend. Add Pumpkin, eggs,and oil and beat until blended.  ix in raisins. Spread butter in prepared pan.  Bake until tester inserted into centre comes out clean,about 25 minutes.  Cool in pan on rack.\r\nBeat cream cheese,powdered sugar and butter in medium bowl to blend. Spread frosting over the  cake in thin layer.( can be prepared 1 day ahed.Refrigerate until cold, then cover and keep refrigerated) cut cake into bars and serve', 'taste like Carrot cake. At least the girsl at work thought so.\r\n\r\nBEA\'S RECIPE', 9),
(212, 'sweet and sour meatballs', '2 lbs lean ground beef\r\n2 eggs\r\n1 cup dry bread crumbs\r\n1/2 cup finely chopped onions\r\n1/2 tsp ground ginger\r\n1 tsp seasoning salt\r\n1/2 tsp ground black pepper\r\n2 tsp Worcestershire sauce\r\n2 tsp white sugar.\r\n\r\n1 (20oz)can pineapple chunks,darined with juice reserved\r\n1/3 cup water\r\n3 tbsp distilled white vinegar\r\n1 tbsp soy sauce\r\n1/2 cup  packed brown sugar\r\n3 tbsp cornstarch\r\n1/2 tsp ground ginger\r\n1/2 tsp seasoning salt\r\n1 large carrot diced\r\n1 large green pepper cut into 1/2 in pieces\r\n', 'DIRECTIONS&quot;:\r\nPreheat oven to 400f.Lightly grease a large shallow baking sheet. In a large bowl,thoroughly mix the ground beef,eggs,bread crumbs and onion. Sprinkle with ginger,seasoning salt, pepper, Worcestershire sauce and sugar. SHape in to one inch balls.\\Place meatballs in a single layer on prepared baking sheet. Bake in preheated oven for 10 to 15 minutes.\r\nTo make the sauce,mix enough water with the reserved pineapple juice to make one cup.  In a large pot over medium heat, combine the juice mixture,1/3 cup water,vinegar,soy sauce and brown sugar.  Stir in cornstarch, ginger and seasoning slat, until smooth. Cover and cook until thickened.\r\nStir pineapple chunks,carrot,green pepper and meatballs into the sauce. Gently stir to coat the meatballs with sauce. Simmer, uncovered, for about 20 minutes or until meatballs are thoroughly cooked', 'BEA\'S RECIPE', 17),
(214, 'Gateau Modele (Model Cake)', '1 cup flour\r\n3 1/2 tsp. baking powder\r\n1/2 tsp salt\r\n1/2 cup margarine\r\n1 cup sugar\r\n2 eggs\r\n1 tsp vanilla\r\n1 cup milk \r\nfruits (your choice)', 'Place fruits in bottom of cake pan, preheat a few  minutes, place cake dough over and cook in over at 375 for 25 minutes.', 'This is a very simple and easy recipe to prepare.', 45),
(215, 'Cool Whip Slices', '1st layer\r\n\r\n1 cup flour\r\n2 tbsp sugar\r\n1/2 cup butter or margarine\r\n1/2 cop chopped nuts\r\nMix, pat evenly in 9 x 12 pan and bake 12 minutes in 350 oven.\r\n\r\n2nd layer\r\n1/2 large carton cool whip-soften\r\n2/3 cup icing sugar - sifted\r\n1 large pkg. Philidelphia Cream Cheese (8oz) soften\r\nMix, spread on top of cooled crust.\r\n\r\n3rd layer\r\n2 pkg Pistachio Instant Pudding - Follow instructions on package but use:\r\n2 1/2 cups milk total, only\r\nMix, spread on top of 2nd layer.\r\n\r\n4th layer\r\nSpread other 1/2 Cool Whip on third layer-sprinkle with chopped roasted almonds.\r\n', 'Refrigerate until served', '*other flavours may be use if preferred.', 40),
(216, 'Cheese Sauce', '2 tbsp 30ml butter\r\n2 tbsp 30ml flour\r\n1/2 tsp 2ml dry mustard\r\n1 c  250ml milk\r\n1 1/2 cup 375ml cheese', 'Melt butter, blend in flour and dry mustard.  Gradually stir in milk.  cook and stir over medium heat until mixture comes to a boil and thickens.  Remove from heat, add cheese and stir until melted.  Makes about 1 3/4 cup.', '', 22),
(217, 'chicken Pot Pie', '2 cans cream of celery or 1 can 10oz condensed.\r\n2 cans cream mushrooms\r\n1 large onion chopped\r\n4 chicken breast diced\r\n1 1/2 cup chicken drippings\r\n7 medium potatoes diced\r\n1 kg frozen peas\r\n500 g frozen carrots\r\nsalt and pepper, season all chives', 'put all execpt chicken in pot.  Simmer until carrots are tender 1 to 1 1/2 hours.  Stir always.  Then add chicken  makes 7 pies', '', 64),
(218, 'How to Cook a Turkey ', '1. If turkey is frozen, thaw in the refrigerator or cold water. When ready to cook, remove the wrapper. Preheat the oven to 325 degrees Fahrenheit. \r\n\r\n2. Remove the neck from the body cavity and the giblets from the neck cavity. Drain the juices and blot the cavities with paper towels. \r\n\r\n3. Just before roasting, stuff the neck and body cavities lightly, if desired. Turn the wings back to hold the neck skin in place. Return legs to tucked position, if untucked. No trussing is necessary. \r\n\r\n4. Place the turkey, breast side up, on a flat rack in an open roasting pan about 2 inches deep. A handy, &quot;turkey lifter&quot; comes with each Butterball turkey. Place this special string cradle on a rack, then place the turkey on top and bring the loops up around the turkey. Do this before putting the turkey in the oven and when lifting the cooked turkey from the pan, use the loops as handles. \r\n\r\n5. Insert an oven-safe meat thermometer deep into the lower part of the thigh next to the body, not touching the bone. \r\n\r\n6. Brush the skin with vegetable oil to prevent the skin from drying. Further basting is unnecessary. (Moulton uses butter.) \r\n\r\n7. Wash preparation utensils, work surfaces and hands in hot, soapy water after contact with uncooked turkey and juices. \r\n\r\n8. Roast at 325 degrees Fahrenheit. To calculate roasting time click here. When the skin is light golden, about 2/3 done, shield the breast loosely with lightweight foil to prevent overcooking. \r\n9. Check for doneness 1/2 hour before turkey is expected to be done. Turkey is fully cooked when the thigh\'s internal temperature is 180 degrees Fahrenheit. The thickest part of the breast should read 170 degrees Fahrenheit and the center of the stuffing should be 165 degrees Fahrenheit. \r\n\r\n10. When done let the turkey stand for 15 to 20 minutes before carving. \r\n\r\n\r\n', '1. Cut band of skin holding drumsticks. Grasp end of drumstick. Place knife between drumstick/thigh and body of the turkey and cut through skin to joint. Remove entire leg by pulling out and back, using the point of the knife to disjoin it. Separate the thigh and drumstick at the joint. \r\n\r\n2. Insert fork in upper wing to steady turkey. Make a long horizontal cut above wing joint through to body frame. Wing may be disjointed from body, if desired. \r\n\r\n3. Slice straight down with an even stroke, beginning halfway up the breast. When knife reaches the cut above the wing joint, slice will fall free. \r\n\r\n4. Continue to slice breast meat, starting the cut at a higher point each time. \r\n\r\n', '', 5),
(219, 'Butter Tarts', '6 cups brown sugar\r\n6 eggs\r\n2 tsp vanilla\r\n1 cup melted margarine\r\n1 cup whipping cream\r\n1 tabl of vinegar\r\npinch salt.', 'SUGAR AND EGGS MUST BE WELL MIXED BEFORE ADDING CREAM &amp; BUTTER.', 'ENJOY MAKES ABOUT 6 DOZEN.', 64),
(220, 'SUGAR PIE', 'combine 1 1/2 cup firmly packed brown sugar and 2 tabl. flour in saucepan.  Add 1 cup carnation milk.  Cook over low heat stirring until dissolved.', 'Remove from heat, slowly add one beaten egg stirring constantly.  Add if desired 1/3 cup copped pecan.  Poor into 8&quot; unbaked pie shell.  Bake for about 40 minutes  10 minutes at 375 and 30 minutes at 350.\r\n', '', 64),
(221, 'Pie Dough', '1 pound tenderflake\r\n5 cups flour\r\npinch of salt.  Mix all in together.\r\n\r\nAdd: 1 egg beating with fork in measuring cup fill to one cup with milk.\r\n\r\nmix all together, dough will be sticky but as you roll on a floured surface dough will be fine.', 'n/a', 'never fail.  great pie dough recipe', 64),
(222, 'Chicken Risotto', '3 tbsp olive oil\r\n1/4 cup butter\r\n4 chicken breast,cut into strips\r\n1 zucchini diced\r\n1 8oz pkg mushrooms, sliced\r\n12 cherry tomatoes,halved\r\n1 onion chopped\r\n1 garlic clove, chopped\r\n1 1/2 cup Arborio rice\r\n1 cup white wine\r\n1 bay leaf\r\n1 sprig of fresh thyme or a pinch of dried thyme\r\nSalt and ground black pepper to taste\r\n2 cups chicken broth\r\n1/2 cup grated parmesan\r\nsalt and pepper to taste', 'preparation...\r\n1. In a large saucepan,heat 1 tbsp of oil and butter to brown the chicken strips.Cook the chicken completely   approx 5 minutes  Add the zucchini,mushrooms and tomatoes. Cook 3-4 minutes until vegetables are al dente. Transfer into an ovenproof dish and keep warm..\r\n2. In  the same saucepan,heat the rest of the oil and melt the butter/Sweat the onions and gsrlic over medium heat.\r\n3. Add the rice,stir well and continue cooking until  it becomes translucent\r\n4.Add the wine,bay leaf,thyme,salt and pepper.Add the broth gradually,stirring frequeently, Cook 16-18 Minutes.Remove the bay leaf and thyme sprig.\r\n5 Remove the saucepan from heat and the chicken and veggies and the parmesan.Mix in well to melt the parmesan and season to taste and serve', '**Sweat** cook without changing colour\r\n\r\nBEA\'S RECIPE', 54),
(223, 'Jumbo Chocolate Chip Cookies', ' \r\n   1 stick (4 ounces) unsalted butter, chilled  \r\n  3/4 cup granulated sugar  \r\n  1/2 cup brown sugar  \r\n  1 large egg  \r\n   1 1/4 cups flour  \r\n  1/2 teaspoon baking soda  \r\n  1/4 teaspoon salt  \r\n  1 cup chocolate chips  \r\n \r\n \r\n', 'n/a', 'MAKES ONE DOZEN COOKIES \r\nPrep Time: 15 min\r\nBake Time: 20 min \r\n', 58),
(224, 'dip constance', '1 pkg Cream cheese\r\n2 cups hellman\'s mayonnaise\r\n2 tbsp beau monde spice(or bon appetit)\r\n1 tsp dill weed\r\n1 tsp parsley', 'Soften Cream cheese in microwave(works better to mix together).Mix all ingredients together then\r\n\r\nserve with vegetables', 'BEA\'S RECIPE', 56),
(225, 'sweetheart (jam thumbprint)', '3 cups flour\r\n1 cup butter\r\n2 tsp baking powder\r\n1/4 tsp. salt\r\nmix together\r\n\r\nadd:  1 cup brown sugar and mix.\r\n2 eggs\r\n1 tabl Milk\r\n1 tsp. vanilla', 'n/a', '', 58),
(226, ' Oprah loves martinis and this is one of her favorites! ', '1 1/2 cups pomegranate juice \r\n2 oz. Absolute Citron vodka OR white tequila \r\n1 oz. Cointreau liquor \r\nCup of ice \r\nOptional: Splash of sparkling water \r\nOptional: Squeeze of lemon \r\n\r\n', 'Shake ingredients in a shaker and put in chilled martini glasses. Put pomegranate fruit into glass as garnish. \r\n', '', 65),
(227, 'Five-Minute Fudge Wreaths: Chunky Chocolate Fudge Wreath with Walnuts and Currants ', '12 ounce package semisweet chocolate chips \r\n1 cup butterscotch chips \r\n14 ounce can sweetened condensed milk (save the can) \r\n1 teaspoon pure vanilla extract \r\n8 ounce can walnuts, plus more for topping \r\n1/2 cup raisins or dried currants (a couple of handfuls) \r\ncandied red and green cherries to decorate top (like holly) \r\nsoftened butter to grease an 8 inch round cake pan \r\n\r\n\r\n', 'Grease an 8-inch round cake pan with softened butter. Pour the chocolate and butterscotch chips, condensed milk and vanilla into a medium saucepan. Put the pan on the stove and turn the heat to low. \r\nCover the empty condensed milk can with plastic wrap and put it in the center of the round cake pan. \r\nStir the chips and milk until they melt together, about 3 minutes. Stir in nuts and raisins. Scoop the fudge into the cake pan all around the plastic-covered can in the center to form a wreath or ring shape. Let it be all bumpy on top. Keep pushing the can back to the center if the fudge moves it away from there. Cut the red cherries in half with scissors and the green cherries into quarters. Use the green pieces to make leaves and the red to make holly berries. Decorate the fudge with several groups of holly berry sprigs made from the cherries and garnish with walnuts between the sprigs. \r\nPut the fudge in the fridge and chill until firm. Remove the can from the center, then loosen the sides and bottom of the fudge with a spatula. Cut the fudge into thin slices to serve. \r\nTo give the wreath as a gift-wrap in cellophane and secure with a bow or ornament.\r\n\r\nVariations:\r\nWhite Chocolate Wreath with Pistachio\r\nand Cranberry\r\n\r\nSubstitute the chocolate chips with white chocolate chips, 1 1/2 ounce bag plus 1 cup. \r\nSubstitute 1 to 1 1/2 cups of shelled natural pistachio nuts for walnuts. \r\nSubstitute 1/2 cup dried sweetened cranberries for currants. \r\nGoober and Raisinette Wreath\r\n\r\nSwap butterscotch for peanut butter chips \r\nSwap large whole peanuts for walnuts used in original recipe (such as peeled Virginia Peanuts) \r\nSwap 1/2 cup large raisins for currants in original recipe \r\n\r\n \r\n \r\n', 'Recipe courtesy of Rachael Ray\r\nFrom the show Oprah and Rachael Ray\r\nThrow a Holiday Party\r\nMaThis super-simple recipe will be a hit at your holiday party! Try all three varieties: the Chunky Chocolate Fudge Wreath with Walnuts and Currants, the White Chocolate Wreath with Pistachio and Cranberry or the Goober and Raisinette Wreath! \r\n\r\nkes 2 pounds', 9),
(228, 'Chicken and Biscuits', '2 quarts chicken stock \r\n2 1/2 pounds boneless, skinless chicken breast \r\n5 tablespoons butter, divided \r\n2 tablespoons Extra Virgin Olive Oil (EVOO), 2 turns of the pan \r\n2 large carrots, peeled and sliced into half inch thick discs \r\n1 large onion peeled and chopped \r\n4 ribs of celery from the heart chopped \r\n2 large russet potatoes, peeled and chopped \r\nCoarse salt and black pepper \r\n1 bay leaf, fresh or dried \r\n1 cup frozen green peas \r\n1/4 cup fresh flat leaf parsley chopped, a generous handful \r\n3 tablespoons, a generous handful, chopped fresh dill \r\n2 tubes, any brand or variety, store bought, bake off biscuits \r\nA few pinches cayenne pepper \r\n\r\nHeat chicken stock to a boil in a deep skillet or pot. Add chicken breasts and poach at a gentle simmer until cooked through about 10 to 12 minutes. Remove chicken, cut into bite size pieces and reserve.\r\n\r\n\r\n  \r\n ', 'Heat a large deep pot over medium heat. Add 2 tablespoons butter plus 2 tablespoons EVOO, 2 turns of the pan. When butter melts into oil add all chopped vegetables. Season with salt and pepper, add bay leaf, cook vegetables 10 minutes until they begin to become tender. Do not brown vegetables; you just want to sweat them out a bit. While vegetables are working, over small skillet over medium heat, melt 3 tablespoons butter, whisk in flour, and cook a few minutes to form a roux. Remove and reserve.\r\n\r\nTo the vegetables add the chicken and stock that you cooked the chicken in, pouring stock through a strainer to remove any by-products from poaching the chicken. Whisk roux into your completed chicken and vegetable mixture. Simmer until vegetables are tender and sauce thickens, about 20 minutes.\r\n\r\nWhile chicken works, bake off biscuits to package directions, sprinkle the tops of each biscuit with a little bit of cayenne pepper just before they go in the oven.\r\n\r\nWhen ready to serve, stir peas, dill and parsley into chicken. Split biscuits and place in bottom of shallow bowls and ladle chicken on top. \r\n\r\n', 'Recipe courtesy of Rachael Ray\r\nFrom the show Oprah and Rachael Ray\r\nThrow a Holiday Party\r\nServes 8\r\nThis dish, along with Beef and Burgundy, makes for easy entertaining&amp;#8212;get everyone in line for a stove-top buffet! \r\n', 54),
(230, 'Robin McGraw\'s Almond Cookies', '1 pound (4 sticks) margarine, softened \r\n1 cup granulated sugar \r\n3 to 4 teaspoons vanilla extract \r\n1 cup blanched sliced almonds, finely chopped \r\n3 1/2 to 4 cups all-purpose flour \r\n1 cup powdered sugar \r\n', 'In a mixing bowl, thoroughly combine margarine, sugar, vanilla extract and chopped almonds using a rubber spatula. \r\nFold in the flour you want the dough to be dense enough to handle with your hands. Sometimes it will take more flour to make this happen, so start with 3 1/2 cups and add flour as necessary. \r\n \r\nRoll spoonfuls of the dough into balls about the size of a small walnut and arrange them on a cookie sheet. Transfer to the oven and bake for 45 minutes to an hour, until the cookies are no longer doughy and are cooked through. \r\n \r\nRemove the cookies from the oven and, while still hot, roll and toss around in a bowl with the powdered sugar. Once coated, allow to cool. And then they\'re ready to eat! \r\n', '', 58),
(231, 'coconut balls', '2 1/2 cup of graham cracker crumbs\r\n1 can eagle bran\r\n2/3 cup of chocolate chips\r\n1/2 cup of walnuts\r\ncoconut', 'mix all together except coconut\r\nthen roll in coconut.\r\nno cooking', 'from Louisiane', 9),
(232, 'peanut butter balls', '1/2 cup of peanut butter\r\n1/2 cup of graham crumbs\r\n1/2 cup of icing sugar\r\nmix all then roll in whatever you want, chocolate, candies, coconut.....\r\n', '', '', 9),
(233, 'CHOP SUEY', ' \r\n 2 T  Cooking oil\r\n 3/4 c  Finely chopped celery\r\n 1/2 c  Finely chopped onion\r\n 1 lb Ground beef\r\n 19 oz Bean sprouts &amp; juice\r\n 10 oz Mushroom pieces with juice\r\n 1 T  Soy sauce\r\n 1 t  Sugar\r\n 1/2 t  Salt\r\n 1 T  Cornstarch\r\n 1 T  Water\r\n \r\n ', '  Put oil, celery, onion and meat in frying pan.  Saute slowly until\r\n   meat is browned and vegetables are limp.\r\n \r\n   Empty bean sprouts and mushrooms into large saucepan.  Stir in soy\r\n   sauce, sugar and salt.  Bring to boil.\r\n \r\n   Stir cornstarch and water together in small cup.  Pour into boiling\r\n   mixture stirring until boiling again.  Add meat mixture.  Ready to\r\n   serve or hold in casserole.\r\n \r\n ', 'Yield: 4 servings', 66),
(234, 'Whole-Wheat Pizza Dough', '1/2 cup warm (105Â°F-110Â°F) water\r\n1 tablespoon olive oil\r\n1/2 teaspoon salt\r\n1 package active dry yeast\r\n1 cup whole-wheat flour\r\n3/4 cup all-purpose flour\r\n\r\n  \r\n', ' 1. Put the warm water, oil and salt in a small bowl and sprinkle in the yeast. Let stand 5 minutes until foamy.\r\n\r\n   2. Combine both flours in a food processor. With the machine running, pour the yeast mixture through the feed tube. After the dough forms a ball, move it to a lightly floured counter. Knead briefly until smooth and elastic.\r\n\r\n   3. Spray a large bowl with nonstick spray; put the dough in the bowl. Cover tightly with plastic wrap and let rise in a warm spot until it doubles in size, about 1 hour.\r\n\r\n   4. Preheat the oven to 400Â°F. Punch down dough and roll into a 12-inch circle. Spray a nonstick cookie sheet with nonstick spray. Place the dough on the tray and top as desired. Bake until light brown and crunchy, 12 to 15 minutes.\r\n\r\nA few words about tomato sauce and cheese:\r\n\r\n    * Jarred pizza sauce is often full of fat and sugar. Try fat-free/sugar-free pasta sauce&amp;#8212;just whisk in a little tomato paste to thicken it.\r\n\r\n    * Excessive cheese does not a pizza make, and it adds lots of calories. A pizza without cheese can be delicious, especially when topped with fresh vegetables. If you do opt for cheese, buy a good-quality one and use it sparingly.\r\n', 'Makes one 12-inch pizza crust.\r\nen New Ideas for Pizza Toppings\r\n\r\n   1. Pimiento, Goat Cheese and Spinach Pizza. Checkerboard the dough with baby spinach leaves. Place jarred pimiento strips on top of the leaves, and dot with soft, low-fat goat cheese.\r\n\r\n   2. Zucchini and Ham Pizza. Cover crust thinly with prepared pizza sauce (as indicated above). Shred one large green zucchini; squeeze out all moisture. Toss with finely diced, low-fat ham; sprinkle on dough. Top with grated Parmigiano-Reggiano, then bake.\r\n\r\n   3. Shrimp Nacho Pizza. Spread a thin layer of salsa over the crust. Cover with cooked, peeled shrimp. Sprinkle shredded low-fat cheddar cheese on top. Dot with fat-free sour cream after baking.\r\n\r\n   4. Salad Pizza. Spray crust with nonstick spray and sprinkle evenly with your favorite salt-free herb blend. Bake without any toppings until browned and crisp, then top with your favorite salad, dressed with fat-free vinaigrette.\r\n\r\n   5. Garden Pizza. Cover crust with chopped, frozen mixed vegetables (thawed) before baking. Bake. Sprinkle with balsamic vinegar and, if desired, extra-virgin olive oil before serving.\r\n\r\n   6. BBQ Chicken Pizza. Cover crust with a thin layer of BBQ sauce. Sprinkle chopped, cooked chicken breast, chopped red onion, minced cilantro and shredded smoked mozzarella (optional) over top before baking.\r\n\r\n   7. Fajita Pizza. Top crust with thinly sliced onion and red bell peppers. Sprinkle canned, chopped green chiles and sliced, cooked chicken breast over pizza before baking.\r\n\r\n   8. Hawaiian Pizza. Drain 1 large can pineapple rings. Place rings on crust. Sprinkle with chopped Canadian bacon, thinly sliced scallions, and reduced-fat Swiss cheese (optional) before baking.\r\n\r\n   9. Turkey Club Pizza. Cover crust with thinly sliced tomatoes. Crumble cooked turkey bacon and chopped turkey breast over top. Bake. Toss shredded iceberg with fat-free vinaigrette then spread onto pizza.\r\n\r\n  10. Dessert Pizza. Spread fat-free hot fudge or caramel sauce thinly on dough; cover with sliced bananas and bake. Let cool 5 minutes before set', 2),
(235, 'Mini Meatloaves With Tomato-Balsamic Gravy', '    * 1/2 pound ground beef\r\n    * 1/2 pound ground pork\r\n    * 1/2 pound ground veal\r\n    * 2 cups (about 2 large handfuls) breadcrumbs\r\n    * 3 sprigs sage, leaves removed from stems and chopped\r\n    * 1 cup (about 1 large handful) parsley, chopped\r\n    * 1/2 bunch scallions, finely chopped on an angle\r\n    * 1 tablespoon Worcestershire sauce\r\n    * 1 egg\r\n    * Salt and freshly ground black pepper\r\n    * 2 pints grape tomatoes\r\n    * Extra-virgin olive oil (EVOO), for drizzling\r\n    * 1/2 medium red onion, sliced\r\n    * 2 tablespoons butter\r\n    * 2 tablespoons flour\r\n    * 1 tablespoon balsamic vinegar\r\n    * 1 to 1 1/2 cups beef stoc\r\n\r\n', 'Preheat oven to 375ÂºF.\r\nIn a large bowl, mix ground beef, pork, veal, breadcrumbs, sage, parsley, scallions, Worcestershire sauce, egg, salt and a palmful of freshly ground black pepper.Using a 6-cup muffin pan, divide the meat mixture into 4 equal parts and scoop the portions into four of the muffin cups. Bake the mini meatloaves until cooked through and golden on top, about 30 minutes.\r\nWhile the mini meatloaves are cooking, toss the grape tomatoes and onion slices onto a baking sheet along with a drizzle of EVOO, salt and freshly ground black pepper. Once the meatloaves have been in the oven for about 15 minutes, put the tray of veggies in and roast until the onions are caramelized and the tomatoes have burst open, about 15 minutes.\r\nWhile the tomatoes and onion are roasting away, get the roux started: Melt the butter in a medium-size skillet over medium-high heat. Sprinkle the flour over the melted butter, cook for 1-2 minutes, then add the balsamic and stock to the pan, whisking to incorporate. Cook until thickened, then remove it from the heat and reserve.\r\nRemove the mini meatloaves and the tomatoes from the oven and set the meat aside to rest for about 5 minutes.\r\nAdd the roasted tomatoes and onion to the sauce and break up the veggies with a potato masher. Serve one mini meatloaf per person with a hearty ladle of the tomato balsamic and some Mac &amp; Seafood Au Gratin alongside.', 'Yields: 4 servings', 17),
(236, 'Maple-Glazed Pork Chops With Scallion Smashed Potatoes &amp; Escarole', '    * 2 1/2 pounds small potatoes, such as baby Yukon Gold or small red skin potatoes, halved\r\n    * 4 boneless pork loin chops (each about 1 1/2-inches thick)\r\n    * Salt and pepper\r\n    * 6 tablespoons extra-virgin olive oil (EVOO), divided\r\n    * 1 heaping tablespoon grainy mustard (eyeball it)\r\n    * 2 tablespoons white wine vinegar (eyeball it)\r\n    * 1 cup chicken stock\r\n    * 6 thyme sprigs, leaves stripped and chopped\r\n    * 1/4 cup maple syrup (eyeball it)\r\n    * Juice and zest of 1 lemon\r\n    * 1/2 cup milk or half-and-half (eyeball it)\r\n    * 3 tablespoons butter\r\n    * 4 scallions, white and green parts thinly sliced\r\n    * 1 large head escarole, cored and the leaves torn into bite-size pieces\r\n\r\n', 'Place the potatoes in a medium saucepot with water to cover by about 1 inch. Bring up to a boil over high heat and, add some salt, and cook for about 12-15 minutes, until tender.\r\nStep\r\n\r\nSeason the pork chops with salt and pepper. Preheat a large skillet over medium high-high heat with 2 tablespoons of EVOO, 2 times around the pan. When the oil begins to ripple, add the pork chops and sear for 2 minutes on each side, then turn the heat down to medium and cook another 5-6 minutes.\r\n\r\nWhile the chops cook, stir together the grainy mustard, a little salt and pepper and the vinegar in the bottom of a salad bowl. Whisk in the remaining 1/4 cup of EVOO, pouring it in a slow steady stream.\r\nStep\r\n\r\nTransfer the pork chops to a plate and cover loosely with foil to keep warm. Add the chicken stock, thyme, maple syrup, 2 teaspoons of lemon zest and the lemon juice to the skillet. Bring up to a bubble and simmer until lightly thickened, a couple of minutes.\r\n\r\nDrain the potatoes and return them to the hot pot. Add the milk, butter, scallions, some salt and pepper, and mash the potatoes to your preferred consistency.\r\n\r\nReturn the pork chops to the pan with the glaze and flip them around to coat. Place the chops on dinner plates; drizzle with any remaining glaze from the skillet. Add the escarole to the salad bowl with the dressing and toss to coat. Serve the pork chops with a pile of smashed potatoes and some escarole alongside.\r\n', '', 17),
(237, 'French Dip Panini', '4 tablespoons butter, softened\r\n1 shallot, finely chopped\r\n1 tablespoon cornstarch\r\n2 cups beef broth\r\n1 pound sliced roast beef\r\n1 baguette, split lengthwise and sliced crosswise into 4 sections\r\n4 ounces sliced pepper Jack cheese\r\n	\r\n\r\n\r\n\r\n\r\n\r\n	', '1. In a medium saucepan, melt 2 tablespoons butter over medium heat. Add the shallot and cook, stirring, until translucent, 1 to 2 minutes. Add the cornstarch and cook for 1 minute. Whisk in the beef broth.\r\n2. Add the roast beef to the sauce and warm over low heat.\r\n3. Preheat a nonstick grill pan over medium heat. Spread the remaining 2 tablespoons butter on the split sides of the baguette sections. Using tongs, top half the sections with the warm roast beef, reserving the sauce. Top with the cheese and the remaining baguette sections. Place the 4 panini on the hot pan. Weigh down with a heavy skillet and cook for 2 minutes, then flip the panini and cook for 2 minutes longer.\r\n4. Remove the panini from the heat and divide the sauce among 4 small bowls for dipping.\r\n\r\n', 'FOUR SERVINGS\r\nPrep Time: 15 min\r\nCook Time: 10 min\r\n', 56),
(239, 'Broccoli and Cheddar Potato Skins', '    * 4 Idaho potatoes\r\n    * Extra-virgin olive oil (EVOO), for drizzling\r\n    * Salt and freshly ground black pepper\r\n    * 1 head broccoli, trimmed of tough end and cut into small chunks\r\n    * 1/2 to 1 cup chicken stock\r\n    * 1 1/2 cups shredded cheddar cheese, divided\r\n\r\n\r\n\r\n\r\n', 'Preheat an oven to 425Ã¯Â¿Â½F.\r\n\r\nScrub the potatoes of any excess dirt and prick them each several times with a fork. Place them on a baking sheet, drizzle with EVOO and season with salt and freshly ground black pepper, tossing lightly to coat.\r\n\r\nBake in the oven until tender, about 45-60 minutes depending on the size of the potato. Remove the baked potatoes from the oven and let cool enough to handle.\r\n\r\nOnce the potatoes are cool, prepare the broccoli by placing high-sided pan with a lid over high heat with about an inch of water (if your pan doesn&amp;#8217;t have a lid, just cover it with foil). Cook the broccoli in the pan until tender, 3-5 minutes. Remove the broccoli from the pan with a slotted spoon to a medium-size mixing bowl.\r\nStep\r\n\r\nCut each potato in half lengthwise and scoop the insides out into the bowl with the broccoli, leaving a thin layer of flesh still intact. Be sure not to pierce the skin of the potato.\r\nStep\r\n\r\nAdd your chicken stock and a large handful of shredded cheese (about 1/2 cup) to the broccoli-potato mixture and mash everything together (use more stock if you like your potatoes wet and less to keep them drier). Season the filling with salt and freshly ground black pepper and scoop the filling back into the hollowed out potato shells, dividing it evenly between all eight.\r\n\r\nPlace the potato skins back onto a baking sheet and sprinkle the remaining cheese over each one. Place back into the oven to melt the cheese, 1-2 minutes, and serve them up with your favorite salad alongside.\r\n', 'Yields: 4 servings', 61),
(240, 'Summer Strawberry Salad', '2 bags of tender mixed greens\r\n1/2 medium red onion thinly sliced\r\n2 cups(500ml)fresh strawberries,Quartered\r\n1/4 cup (60ml) goat cheese crumbled\r\n3/4 cup (180ml) chopped pecans toasted\r\n\r\nDRESSING\r\n1/4 cup (60ml) red wine vinegar\r\n1/2 cup (125ml)safflower oil\r\n1 tbsp (15ml)dijon Mustard\r\n1 tsp honey\r\nsalt and pepper to taste\r\n', 'Place first 5 ingredients in a salad bowl...\r\n\r\nCombine dressing ingredients in a small bowl, whisk until combined.\r\nPour over salad\\\r\nToss and serve', 'very very good and healthy\r\n\r\nenjoy\r\nBEA\'S RECIPE', 55),
(241, 'An AMAzing Spinach Salad', 'Ingredients\r\nSpinach,washed and torn\r\nRed onion Sliced\r\nMandarin orange segiments(alternative Strawberries)\r\nAlmonds Sliced &amp; Toasted (or Candied)\r\n\r\nDressing\r\nExtra virgin oil\r\nBalsamic Vinegar\\\r\nSalt and pepper \r\nmustard', 'dressing theory\r\nclassic proportions  1 part vinegar to 3 parts oil\r\nif lemon juice is the acid  1 part acid to 4 to 5 parts oil\r\nProblems \\\r\n\r\nif too oily   add more vinegar and seasoning\r\nif too sharp  add more oil\r\nOil and vinegar will always separate unless EMULSION is made.  An Enulsion is created when a third ingredient and friction is introduced. The result would be a creamy salad dressing..', 'Candying\r\nPut butter in a pan, add nuts to brown, any spice (cinnamon then add brown sugar\r\nabout 2 to 1\r\nshould see a bit of steam(then smoke will smell nuttier)\r\nput on parchment paper and spread out\r\nBEA\'S RECIPE', 55),
(242, 'Classic Potato Gratin', ' 3 cups 35% Cream\r\n1lb new potatoes, peeled\r\n1 clove garlic,peeled &amp; cut in half\r\n1/2 tsp Unsalted butter\r\nsalt &amp; pepper  3tsp salt\r\nKick Start 425 then reduce heat', 'pre heat oven to 325-350f\r\nbring cream to a simmer, season with salt, pepper&amp;nutmeg\r\ncut potatoes into very thin &amp; even slices(using a mandoline is ideal)\r\nrub gratin dish with garlic and butter\r\nplace potatoe slices in dish circular layers(ovalDish) or straight rows(square)\r\noptional:: layer chopped onions in between potaoes layers(one layer is enough)\r\npour heated cream over top to cover by 1/4 in(if necessary warm more cream)\r\nbake until top has a golden crust and potaoes are tender when pierced by a knife)\r\nThe gratin should lightly bubble NEVer boil around edges\r\nlet rest slightly before cutting &amp; serving (5Min)', 'BEA\'S RECIPE', 61);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(243, 'best damm ribs', 'Maple/Garlic Sauce\r\n1/4 cup maple syrup\r\ngarlic minced\r\n1tsp worchestire sauce\r\n1/2tsp mustard\r\n1 1/2 tbsp brown sugar\r\n1 oz cider vinegar\r\n1/4 tsp onion powder\r\n4 tbsp tomato paste\r\n4 tbsp plum sauce\r\n\r\nCHIPOTLE BBQ SAUCE\r\n1/4 Cup hoisin sauce\r\n1/3 cup ketchup\r\n1 tsp mustard\r\n1 tsp worchestire sauce\r\n1 tbsp red pepper thai sauce\r\n1 oz bourbon\r\n1/4 cup brown sugar\r\n1 pepper chipolte pepper(jar or canned)\r\n1/2tsp paprika or cayenne\r\n1 oz cider vinegar\r\ngarlic minced.\r\n\r\nPORK RIBS\r\npork back ribs\r\npeppercorns 10\r\nbay leaves 2\r\n\r\nEQUIPMENT\r\nbig soup pot\r\ncookie sheet', 'pre-pep\r\n\r\nplace ribs,handful of peppercorns and a bay leaf in a pot of cold water(must have a wet environment)(don\'t put warm hot water),bring up to a boil,then reduce heat to a slow simmer.(don\'t put meat in boiling level)..simmer(poaching ribs) the ribs for approximately 30-45or 45 to 60  minutes(this will allow meat to relax because of tough mneat)-until tender..PULL out ribs from the pot on to a aluminum line cookie sheet..(put on parchment paper for easy clean up)\r\nBAKING:\r\nBrush on favorite sauce liberally to ribs on both sides\r\nplace on 300F.-325F oven for approximately 30 minutes(use parchment paper for easy clean up)\r\nbaste at least once depending on dryness of ribs\r\n\r\nServing\r\n\r\nserver on a platter,if dry looking baste one more time\r\n', 'the pre-pep steps are not optional~!This is crucial for  tenderizing this third grade quality meat. The oven process is the flavour infusing step.\r\n\r\nOnly BABY BACK RIBS do not need the pre-prep step because it is younger piece of already tender meat. It does need  longer oven time to achieve the same tenderness &amp; flavour infusion..\r\n\r\nBEA\'S RECIPE', 17),
(244, 'Cranberry Iced Tea   ', 'PREPARE 1 disc Tassimo Twinings Earl Grey Tea in large heatproof glass or mug as directed on package.\r\nSTIR in 1/2 cup cranberry juice and 2 tsp. sugar. Pour into 2 tall glasses filled with ice.\r\nMakes 2 servings, 3/4 cup (175 mL) each.\r\n\r\n', 'Special Extra:\r\nWhen making ice cubes, place a fresh or frozen cranberry in each section of ice cube tray before filling with water. Freeze and serve with the prepared drink. ', 'Prep:	5 min.\r\nTotal: 	5 min.\r\n', 36),
(245, 'Zesty Hot Chocolate', 'Prepare one TASSIMO SUCHARD Hot Chocolate in a mug. Stir in finely grated peel of half an orange. Top with a dollop of thawed COOL WHIP Whipped Topping and garnish with chopped chocolate pieces and orange peel if desired. Makes 1 serving.\r\n\r\n', 'Jazz It Up: Stir in 1 oz. shot of orange-flavoured liqueur or brandy. ', 'Chocolate and orange makes an tempting combination.\r\n', 36),
(246, 'Peppermint Hot Chocolate', 'Place 1 Tbsp. finely crushed peppermint stick or candy cane in mug. Prepare one TASSIMO SUCHARD Hot Chocolate in same mug; stir until candy is completely dissolved. Top with a dollop of thawed COOL WHIP Whipped Topping and a sprinkling of additional crushed peppermint. Makes 1 serving.', '', '', 36),
(247, 'Latte Macchiato  ', 'PREPARE milk from 1 disc Tassimo Nabob LattÃ© in large heatproof glass or mug as directed on package.\r\nPrepare Tassimo Nabob Espresso directly over milk.\r\n', 'Makes 1 serving, 1 cup (250 mL).\r\n\r\nCaramel Macchiato:\r\nOmit sugar. Prepare drink as directed, spooning 2 Tbsp. caramel ice cream topping into glass before adding milk and espresso. ', 'Prep:	5 min.\r\nTotal: 	5 min.', 36),
(248, 'Irish Cream Coffee', 'PREPARE 1 disc Tassimo Maxwell House House Blend Decaffeinated Coffee in large heatproof glass or mug as directed on package.\r\nSTIR in 2 Tbsp. Irish cream liqueur.\r\nMakes 1 serving, 1 cup (250 mL).\r\n\r\n', 'Variation:\r\nTo serve chilled, prepare drink as directed; pour into tall glass filled with ice cubes. ', 'Temps de prÃ©paration:	5 min.\r\nPrÃªt en: 	5 min.', 36),
(249, 'Dreamy Cappuccino', 'Prepare one TASSIMO NABOB Cappuccino in cappuccino cup or large mug. Add your favourite flavoured syrup, such as caramel, hazelnut or vanilla, to taste; stir. Sprinkle lightly with cocoa powder or ground cinnamon, if desired. Makes 1 serving.', '', '', 36),
(250, 'White Chocolate Cappuccino', 'Chop 1/2 square BAKER\'S White Chocolate into small pieces; place in cappuccino cup or large mug. Prepare one TASSIMO NABOB Cappuccino in same cup; stir until chocolate is completely melted. Garnish with chocolate curl, if desired. Makes 1 serving.	\r\nWhite Chocolate Cappuccino', '', '', 36),
(251, 'Velvety Chocolate Mocha', 'Prepare one TASSIMO SUCHARD Hot Chocolate in mug or heatproof glass. Then, prepare one TASSIMO NABOB Espresso in same mug. Top with a dollop of thawed COOL WHIP Whipped Topping and a light drizzle of chocolate syrup. Makes 1 serving.', '', '', 36),
(252, 'Candy Bar Hot Chocolate', 'Prepare one TASSIMO SUCHARD Hot Chocolate in mug or heatproof glass. Top with JET-PUFFED Miniature Marshmallows and 1 Tbsp. of your favorite finely chopped candy bar. Makes 1 serving.', '', '', 36),
(253, 'Petite Mocha Paradise', 'Place 1 cup whipping cream in medium saucepan. Cook on medium-low heat 5 min. or just until cream begins to bubble around edge. Remove from heat. Add 6 chopped squares BAKER\'S Semi-Sweet Chocolate; stir until completely melted. Prepare one TASSIMO NABOB Espresso. Add to chocolate mixture; mix well. Cool slightly. Add 2 Tbsp. butter; stir until melted. Pour into six small bowls or espresso cups; cover. Refrigerate 3 hours or until firm. Garnish with chocolate curls just before serving, if desired. Makes 6 servings.', '', '', 36),
(254, 'Espresso Float', 'Prepare 2 discs Tassimo Nabob Espresso in large heatproof glass or mug as directed on package.\r\nTOP with 1/4-cup scoop of vanilla ice cream; sprinkle with 1/4 tsp. unsweetened cocoa powder.\r\nMakes 1 serving, 3/4 cup (175 mL).\r\n\r\n', 'Substitute Substitute 2 Tbsp. Cool Whip Whipped Topping for the ice cream. No need to thaw first. ', 'Prep: 	5 min.\r\nTotal: 	5 min.', 36),
(255, 'Indulgent Granita', 'Prepare four TASSIMO NABOB Espressos. Pour into shallow freezerproof container. Add 3 Tbsp. sugar; stir until completely dissolved. Cool slightly. Cover. Freeze 2 hours or until firm. Remove from freezer. Pull fork through espresso mixture several times to break up ice crystals; spoon evenly into two bowls. Serve with spoons. Makes 2 servings.', '', '', 36),
(256, 'Iced Tea', 'Prepare two TASSIMO TWININGS Earl Grey Teas; pour into medium heatproof bowl. Add lemon juice and sugar to taste; cool completely. Or, refrigerate until ready to serve. Pour over ice cubes in two tall glasses. Makes 2 servings.', '', '', 36),
(257, 'Iced Coffee', 'Prepare one TASSIMO MAXWELL HOUSE Decaffeinated or House Blend Coffee in mug. Add sugar to taste; cool completely. Or, refrigerate until ready to serve. Pour over ice cubes in tall glass. Add cream to taste. Makes 1 serving.', '', '', 36),
(258, 'Green Tea and Mint Summer Punch', 'Prepare 1 disc TASSIMO Twinings Green Tea in large heatproof glass or mug as directed on package. Stir in 1 tsp. sugar. Add ice cubes, sprig of fresh mint and 1 halved fresh strawberry; stir. Makes 1 serving, 1 cup (250 mL). 	\r\nGreen Tea and Mint Summer Punch', '', '', 36),
(260, 'Pesto with Farfalle Pasta with Roasted Chicken', 'Pesto:\r\n\r\n    * 4 cups fresh basil leaves\r\n    * 4 cups Italian parsley springs\r\n    * 4 large cloves garlic\r\n    * 1 1/2 cups olive oil\r\n    * 1/4 tsp. salt\r\n\r\nRoasted Chicken Salad:\r\n\r\n    * 1 cup diced Roasted Chicken\r\n    * 1 cucumber , peeled, seeded and diced\r\n    * 2 cups mixed greens\r\n    * 1/4 cup roasted pine nuts\r\n    * 1/2 lemon , juiced\r\n    * Parmesan cheese\r\n    * 1/4 cup sliced black olives\r\n    * 1/2 pound farfalle pasta\r\n    * Handful pomegranate seeds\r\n\r\n', 'To prepare the pesto: Chop basil, parsley and garlic in a food processor. Slowly add olive oil and keep chopping. Add salt.\r\n\r\nTo prepare the chicken mixture and final dish: Place Roasted Chicken, cucumber, pine nuts, 1 Tbsp. of pesto and olives in a bowl and mix together. Cook pasta until al dente. Add 2 tablespoons of pesto to the pasta and mix well. Top off with 2 cups of mixed greens and the juice of 1/2 a lemon. Add the chicken mixture to pasta and toss. Garnish with Parmesan cheese and pomegranate seeds\r\nRelated Resources\r\n\r\n    ', 'FROM OPRAH SHOW', 57),
(261, 'Roasted Chicken', '    * 2 chickens , 4 1/2 to 5 pounds each\r\n    * 6 lemons\r\n    * A poultry mix of fresh herbs: Rosemary, sage, thyme, parsley and oregano work well\r\n\r\nMarinade for one chicken:\r\n\r\n    * 1 cup Dijon mustard\r\n    * 1/2 cup soy sauce\r\n    * 1/2 cup juice from fresh lemon (don\'t discard lemon rinds)\r\n\r\n\r\n', 'To make marinade: Place all ingredients in a nonreactive bowl. Whisk with a wire whisk until ingredients are incorporated wellÃ¯Â¿Â½the marinade should have a smooth and creamy consistency.\r\n\r\nTo make roasted chicken: Preheat oven to 425Ã¯Â¿Â½.\r\nClean chickens well and pat dry. Place each chicken in its own baking dish.\r\n\r\nStuff cavities with lemon rinds and fresh herbs. A poultry mix is fine, usually consisting of rosemary, sage, thyme, parsley and oregano.\r\n\r\nPour marinade over chicken. Add cracked pepper and remaining herbs to the top of each chicken.\r\n\r\nPlace an oven thermometer in each chicken and cover with aluminum foil. Place on the lower rack of the oven. Bake for 1 1/2 hours, then remove the aluminum foil. Baste with a basting bulb. Keep basting often, ever 15 minutes until the thermometer reads 180Ã¯Â¿Â½.', 'Recipe created by Cristina Ferrare\r\nThis classic roasted chicken is great on its own and in countless other recipes. This recipe calls for two chickens so that you have leftovers!\r\n\r\n', 54),
(262, 'MEAT PIE', '1 1/2 GROUND PORK\r\n1 ONION CHOPPED\r\n2 TABL FLOUR\r\n1/2 CUP CHICKEN BROTH\r\n1 TBL MUSTARD (DIJON)\r\n1/2 TSP THYME\r\n1/2 TSP SALT\r\n2 APPLES PEELED AND SLICED', 'FRY MEAT WITH ONIONS.\r\nDRAIN FAT\r\nSTIR IN FLOUR\r\nAND CHICK BROTH, MUSTARD THYME AND SALT\r\nCOOK AND STIR UNTIL THICKENS \r\n\r\nAPPLES IN BOTTOM', 'COOK AT 400 FOR 35 MINUTES', 64),
(263, 'BUTTERSCOTCH SQUARE', 'MELT TOGETHER\r\n1 PKG BUTTERSCOTCH CHIPS\r\n3 TABL BUTTER\r\n1 CUP OF PEANUT BUTTER\r\n\r\nTAKE OFF STOVE\r\nADD: 1 BAG OF MINI MARSHMALLOWS\r\n     1 CUP OF COCONUT', 'ADD TO BUTTERED PAN AND PUT IN FRIDGE\r\n\r\nCUT INTO SQUARES\r\nENJOY', '', 9),
(264, 'MAGIC COOKIE BARS', '1/2 CUP MARG OR BUTTER\r\n1 1/2 CUP GRAHAM CRACKER CRUMBS\r\n1 CAN EAGLE BRAN SWEET CONDENSED MILK\r\n1 CUP OF CHIPITS SEMI SWEET CHOCOLATE BAKING CHIPS\r\n1 1/4 CUP COCONUT\r\n1 CUP NUTS\r\n', 'PREHEAT OVEN TO 350F OR 325F FOR GLASS DISH.  IN (13X9) BAKING PAN, MELT MARGARINE IN OVEN, SPRINKLE CRUMBS OVER MARGARINE, MIX TOGETHER AND PRESS INTO PAN.  POUR EAGLE BRAND OVER CRUMBS.  TOP EVENLY WITH REMAINING INGREDIENTS AND PRESS DOWN FIRMLY.  BAKE 25 TO 30 MINUTES OR UNTIL LIGHTLY BROWNED.  COOL THOROUGHLY BEFORE CUTTING.  STORE LOOSELY COVERED AT ROOM TEMPERATURE.\r\n', '', 9),
(265, 'DRIZZLED CHOCOLATE MINT BARS', '1 CUP CHOCOLATE MINT CHIPS (CHIPITS)\r\n1/4 CUP MARGARINE\r\n1/4 CUP ICING SUGAR\r\n1 EGG\r\n1 1/2 CUP GRAHAM WAFER CRUMBS (HONEY MAID)\r\n1/2 CUP CHOPPED WALNUTS\r\n1/4 CUP MARGARINE\r\n2 CUPS OF ICING SUGAR\r\n2 TBLS MILK\r\nGREEN FOOD COLORING (OPTIONAL)', 'MELT CHIPITS AND 1/4 CUP MARGARINE OVER HOT WATER. RESERVE 1/4 CUP FOR TOP DRIZZLES.  ADD 1/4 CUP ICING SUGAR AND EGG TO REMAINING MELTED CHIPITS AND BEAT WELL.  STIR IN WAFER CRUMBS AND NUTS.  PRESS EVENLY ON BOTTOM OF 8 IN SQUARE PAN.  CHILL.  CREAM 1/4 CUP MARGARINE 2 CUPS ICING SUGAR AND MILK UNTIL FLUFFY.  ADD GREEN FOOD COLOURING IF DESIRED.\r\nSPREAD EVENLY OVER BASE IN PAN.  DRIZZLE RESERVED CHIPITS OVER TOP.  CHILL UNTIL FIRM. CUT INTO BARS ', 'MAKES ABOUT 3 DOZEN', 9),
(266, 'CHERRY BARS', 'BASE\r\n1 1/2 CUPS FLOUR\r\n1/4 CUP ICING SUGAR\r\n1/2 CUP BUTTER OR MARG\r\nTOPPING\r\n2 EGGS\r\n1 CUP BROWN SUGAR\r\n1 CUP COCONUT\r\n1 CUP RED CANDIED CHERRIES\r\n1/2 TSP ALMOND EXTRACT', 'COMBINE FLOUR AND ICING SUGAR IN BOWL-STIR WELL TO BLEND.  CUT IN BUTTER UNTIL MIXTURE IS CRUMBLY.  PRESS IN UNGREASED 9&quot; SQUARE PAN.  BAKE AT 350F FOR 10 MINUTES.  BEAT EGGS WELL THEN ADD BROWN SUGAR AND BEAT UNTIL WELL  MIXED. STIR IN COCONUT CHERRIES AND EXTRACT.\r\nSPREAD MIXTURE EVENLY OVER PARTIALLY BAKED BASE.  BAKE AT 350F FOR ABOUT 30 MINUTES OR UNTIL SET AND GOLDEN .  WHEN COOLED CUT INTO BARS.  MAKES ABOUT 30 BARS.', '', 9),
(267, 'OAT DELIGHTS', 'IN A SAUCEPAN BRING TO BOIL THE FOLLOWING INGREDIENTS.\r\n2 CUPS OF SUGAR\r\n6 TBSP COCOA\r\n1/2 CUP BUTTER\r\n1/2 CUP MILK', 'REMOVE FROM HEAT AND ADD 1/2 TSP VANILLA\r\nSTIR IN -1 CUP COCONUT\r\n         3 CUPS OF INSTANT OATS\r\nDROP BY SPOONFUL ON WAXED PAPER UNTIL FIRM. STORE IN TIGHTLY SEALED CONTAINER.', '', 58),
(268, 'CHOCOLATE DROP COOKIES', '1/2 CUP BUTTER\r\n1/2 CUP MILK\r\n2 CUPS OF WHITE SUGAR\r\n1 TABLESPOON COCOA\r\nBRING TO A ROLLING BOIL FOR 1 MINUTE.\r\nADD 2 CUPS ROLLED OATS\r\n    1 CUP COCONUT\r\n     1/2 CUP NUTS', 'DROP BY TEASPOON ON BUTTERED PAN\r\nENJOY.', '', 58),
(269, 'PUDDING AU SUCRE BRUN', '1/4 CUP BUTTER\r\n1/2 CUP SUGAR WHITE\r\n1 EGG\r\nSALT\r\n1 CUP MILK\r\n2 CUPS FLOUR\r\n2 TSP BAKING POWDER', 'MIX ALL TOGETHER PUT IN PAN THEN MIX 2 1/2 CUP BROWN SUGAR AND 1 CUP WATER (HEAT FIRST TO MELT) THEN POUR OVER CAKE.  BAKE AT 375F FOR ABOUT 1/2 HOUR.', '', 40),
(270, 'BLUEBERRY MUFFINS', '1 EGG\r\n1/2 CUP MILK\r\n1/4 CUP SHORTENING MELTED\r\n1 1/2 CUP FLOUR\r\n2 TBSP BAKING POWDER\r\n1/2 TSP SALT\r\n1/2 CUP SUGAR\r\n1 CUP BLUEBERRIES\r\n', 'IN BOWL BEAT EGG LIGHTLY, STIR IN MILK, MELTED SHORTENING.  MIX TOGETHER FLOUR BAKING POWDER SALT AND SUGAR: ADD TO EGG MIXTURE.  STIR JUST ENOUGH TO MOISTEN. FLOUR BATTER WILL BE LUMPY. DO NOT OVER MIX.  FOLD IN BLUEBERRY.  FILL GREASED MUFFIN TINS 2/3 FULL.', 'BAKE AT 400F 20-25 MINUTES', 59),
(272, 'GATEAU MICHELLE', '1 OEUF\r\n1 1/2 T SUCRE BLANC\r\n1 TASSE FARINE\r\n2 C A THE POUDRE A PATE\r\n1 C A THE VANILLE\r\n1 CAN FRUIT SALAD 19 OZ', 'MELER LES INGREDIENTS SEC.  AJOUTER LE RESTANT ET MELER A LA CUILLERE\r\nGRAISSER ET FARINER LE MOULE.\r\n\r\nPARDESSUS 1/2 T DE SUCRE BLANC BIEN TASSE ETENDRE SUR PREMIERE PARTIE ET 1/2 TASSE COCONUT RAPE.\r\nAU FOUR 300F 1 A 1/2 HEURE', 'GLACE:  1/4 T MARG\r\n        1 TASSE SUCRE BLANC\r\n        1/2 TASSE LAIT BOUILLIR 5 A 8 MINUTES RETIRER DU FEU ET AJOUTER 3 CUILLERE A SOUPE DE COGNAC', 45),
(274, 'cheese ball', 'cream together&quot;\r\n1/2 pound velveta cheese yellow or blue\r\n3 tabl of mayonaise\r\n\r\nadd: 2 tabl finely chop green peppers\r\n     2 tabl finely chop green onions\r\n     2 tabl olive (optional)\r\n     1/3 cup finely crushed crackers\r\n', 'form into ball\r\nrefrigerate', '', 34),
(275, 'HOT FUDGE SUNDAE CAKE', '1 CUP FLOUR\r\n3/4 CUP SUGAR\r\n2 TABL COCOA\r\n2 TSP BAKING POWDER\r\n1/4 TSP SALT\r\n1/2 CUP MILK\r\n2 TABL OIL\r\n1 TSP VANILLA\r\n1 CUP CHOPPED NUTS (OPTIONAL)\r\n1 CUP BROWN SUGAR (PACKED)\r\n1/4 CUP COCOA\r\n1 3/4 CUP HOTTEST TAP WATER\r\nFAVOURITE ICE CREAM', 'HEAT OVEN TO 350.  IN UNGREASED SQUARE PAN 9X9X2 INCHES, STIR TOGETHER FLOUR, SUGAR, 2 TABL COCOA, THE BAKING POWDER AND SALT.  MIX IN MILK, OIL AND VANILLA WITH FORK UNTIL SMOOTH.  STIR IN NUTS.  SPREAD EVENLY IN PAN.  SPRINKLE WITH BROWN SUGAR AND 1/4 CUP COCOA.  POUR HOT WATER OVER BATTER.  BAKE 40 MINUTES.  WHILE WARM, SPOON INTO DESERT DISHES AND TOP WITH ICE CREAM.  SPOON SAUCE FROM PAN OVER EACH SERVING.', '', 45),
(276, 'DUMPLINGS', '1 CUP OF FLOUR\r\nSALT AND PEPPER\r\n1/4 CUP MILK\r\n1/2 TSP BAKING POWDER', 'MIX ALL TOGETHER DROP BY TSP IN STEW AND LET COOK FOR 15 MINUTES.', '', 17),
(277, 'DATE SQUARE', '1 1/2 CUP FLOUR\r\n1/2 TSP BAKING SODA\r\n1 1/2 CUP ROLLED OATS\r\n1 1/2 CUP BROWN SUGAR\r\n1 CUP BUTTER OR MARG\r\nFILLING\r\n1 LB DATED\r\n1 CUP HOT WATER\r\n1/4 CUP SUGAR\r\nPINCH OF SALT \r\n1 TSP VANILLA', 'PREPARE FILLING FIRST. COMBINE DATES, HOT WATER SUGAR AND SALT TOGETHER IN A POT.  COOK UNTER SOFT AND WATER ABSORBED, OVER MEDIUM HEAT.  ADD VANILLA.  LET COOL.  STIR FLOUR AND BAKING SODA TOGETHER; ADD TO OATS AND BROWN SUGAR AND MIX WELL.  WORK IN BUTTER WITH FORK UNTIL MIXTURE IS CRUMBLY.  SPREAD 1/2 THE MIXTURE IN BOTTOM OF A GREASED 9&quot; SQUARE PAN PAT ON TOP. COVER WITH COOLED DATE FILLING. PAT 1/2 REMAINING MIXTURE ON TOP.  THEN SPRINKLE WITH REMAINDER ON TOP.  BAKE AT 350 FOR 20 TO 25 MINUTES.', '', 40),
(278, 'ZUCHINNI LOAF', '3 EGGS\r\n1 1/2 CUP SUGAR\r\n1 CUP OIL\r\n2 TSP VANILLA\r\n2 CUPS OF GRATED ZUCHINNI\r\n3 CUPS FLOUR 1 TSP BAKING POWDER \r\n1 TSP BAKING SODA\r\n1 TSP SALT\r\n1 1/2 TSP CINNAMON\r\n1/2 TSP NUTMEG\r\nADD NUTS OR RAISINS (OPTIONAL)', 'PREHEAT OVEN TO 350F COOK FOR 55 MINUTES', '2 RECIPES MAKES 3 LOAF.', 42),
(280, 'BEANS', '1 LB DRIED BEANS\r\n1/2 LB SALT PORK, CUT IN STRIPS\r\n1/2 CUP OF MOLASSES\r\n1/4 CUP BROWN SUGAR\r\n1 CAN TOMATO SOUP\r\n1 TSP SALK\r\n1 TSP DRY MUSTARD\r\n1/4 TSP PEPPER\r\n1 MEDIUM ONION', 'COVER BEANS IN COLD WATER AND LEAVE OVERNIGHT TO SOAK.  DRAIN. RINSE AND COVER BEANS WITH COLD WATER.  COOK UNTIL TENDER.  MIX DRY INGREDIENTS AND THE MOLASSES. POUR OVER THE DRAINED BEANS (JUST ENOUGH TO COVER) INTO A BEAN POT OR OVEN DISH.  ADD ONIONS AND SALT PORK.  COVER AND BAKE AT 275 FOR 6 HOURS. ADD MORE WATER IF REQUIRED.  REMOVE COVER FOR LAST HOUR.', '', 17),
(281, 'CHUNKY SPLIT PEA SOUP', '1 POUND(2 CUPS) DRIED SPLIT PEAS RINSED AND DRAINED.\r\n2 LARGE CARROTS CHOPPED COARSE (1 1/2 CUP)\r\n1 MEDIUM SIZE ONION CHOPPED COARSE (1 CUP)\r\n1/2 TSP DRIED OREGANO\r\n1/2 TSP DRIED THYME\r\n1 BAY LEAF\r\n8 CUPS WATER\r\n2 CUPS CHICKEN BROTH\r\n12 OUNCES FULLY COOKED HAM, CUT IN 3/4 INCH CHUNKS (ABOUT 2 1/2 CUPS)\r\nPEPPER TO TASTE.', 'PUT SPLIT PEAS, CARROTS,ONION OREGANO, THYME AND BAY LEAF IN A LARGE POT.  ADD WATER AND CHICKEN BROTH.  BRING TO A BOIL, SKIMMING OFF ANY FOAM THAT RISES TO THE SURFACE WITH A SLOTTED SPOON.  REDUCE HEAT, AND SIMMER UNCOVERED FOR  1 HOUR. ADD HAM AND PEPPER; CONTINUE COOKING 30 MINUTES OR UNTIL PEAS ARE VERY TENDER. REMOVE FROM HEAT; DISCARD BAY LEAF AND STIR SOUP UNTIL SMOOTH.  MAKES 9 CUPS', 'LEFTOVERS FREEZES WELL.', 62),
(282, 'CARROT SOUP (MICROWAVE)', 'MELT 2 TO 3 TABL OF BUTTER IN CASSEROLE.\r\nADD 2 TABL OF ONIONS CHOPPED \r\nMICROWAVE 1:30 MINUTES. STIR.  ADD 3 CUPS OF CARROTS (GRATED).  COVER IN MICROWAVE 1 MINUTE. STIR. BACK IN MICROWAVE FOR FIVE MINUTES, STIR BACK IN FOR ANOTHER 5 MINUTES. TAKE OUT STIR. BACK IN FOR 2 MINUTES. REMOVE ADD 3 CUPS MILK.  MICR 5 MINUTES.', 'STIR AGAIN FOR 2 MINUTES STIR COOK AGAIN 1:40 MINUTES. ADD CORNSTARCH WATER. BACK FOR 2 MINUTES STIR IN AGAIN FOR 1:30 MINUTES STIR ADD PARSLEY COOK FOR 1:30 MINUTES\r\nLET REST FOR A WHILE', '', 62),
(283, 'SWEET AND SOUR MEATBALLS', 'MEAT\r\n1 1/2 LBS GROUND BEEF\r\n2 LBS GROUND PORK\r\n1 1/2 CUPS BREAD CRUMBS\r\n2 EGGS\r\n1 CUP MILK\r\nMIX WELL  MAKE MEATBALLS 1 TO 1 1/2 INCH\r\n', 'SAUCE\r\n4 CUPS BROWN SUGAR\r\n2 CUPS VINEGAR \r\n2 CUPS WATER\r\n2 CUPS KETCHUP\r\n2 TABLESPOON DRY MUSTARD\r\n\r\nBRING TO A BOIL 1 HOUR\r\nPOUR SAUCE OVER MEAT BALLS\r\nBAKE 400F FOR 1 HOUR', 'THESE ARE THE MEATBALLS THAT JAYGEES USE TO MAKE. VERY GOOD\r\n', 17),
(284, 'Brown Rice Casserole', '    3 3/4 cups water\r\n    1 cup brown rice\r\n    1 cup chopped celery\r\n    1/2 cup oignon (onion), chopped\r\n    1 can (19 0z.) chopped tomatoes\r\n    2 tablespoon flour\r\n    2 teaspoon chili powder\r\n    1 teaspoon salt\r\n    1/4 teaspoon garlic powder\r\n    1 cup frozen green peas\r\n    1 cup chopped mushrooms\r\n\r\n\r\n\r\n', 'Bring 3 cups water to a boil, add rice and cook 45 minutes.  Meanwhile, saute oignons (onions) and celery in a small amount of water until tender.  Add tomatoes and mushrooms and bring to a boil, then simmer.  Mix flour, seasonings and remaining water in separate bowl and then add to vegetables.  Cook 3 minutes, or until thick. Add peas. Pour into an 8 cup casserole dish. Cover with rice and cook for 20 minutes, at 350F.\r\n', 'I ADDED GARLIC  WHEN SAUTE. I ALSO ADDED A TOMATO WITH THE CAN OF DICED TOMATOES WITH HERB. I MIXED THE RICE IN THE SAUCE \r\nPreparation time: 25 minutes\r\n', 17),
(285, 'Praline Sweet Potato Casserole ', '    4 cups cooked, mashed sweet potatoes (or yams)\r\n    3 tablespoon melted soy butter\r\n    1/3 cup orange juice\r\n    1/4 cup brown sugar\r\n    2 tablespoon brandy\r\n    1/2 ts ground ginger (1 tablespoon fresh grated)\r\n    1 ts salt\r\n    1/8 ts pepper\r\n    1/4 ts allspice\r\n    1 ts grated orange peel (I\'m sure I use more)\r\n    1/2 ts cinnamon\r\n\r\n\r\n', 'Combine all ingredients. Mix well with an electric beater.  Pour into a well-buttered 2 qt. shallow casserole.  Spread with praline topping.\r\n\r\nTOPPING: 1/3 cup brown vegan sugar, 1/2 cup chopped pecans, and 1/2 ts cinnamon.\r\n\r\nCombine ingredients and mix until well blended.\r\n\r\nBake at 350 for 30 minutes\r\n', 'HAVEN\'T TRIED IT YET BUT WANT TO TRY IT Actually the praline topping is the pecan mixture in the directions part.  Praline is a mixture of pecan and sugar and (usually) fresh cream. \r\n', 61),
(286, 'chestnut & bacon', '1 pound of bacon\r\n2 cans of water chestnuts\r\n1/4 cup ketchup\r\n1/4 cup brown sugar', 'slice the bacon in two.  if large chestnuts slice those in two. wrap them. put them in oven for 1.2 hour at 350 to 400.\r\ndrain the fat into the ketchup and brown sugar. mix well and pour over chestnuts.\r\ncook for 30 minutes at 350\r\n', '', 34),
(287, 'BRIE /CAMEMBERT CHEESE', 'Brie or camembert cheese any size\r\n1/2 cup pecans,chopped\r\n1/2 cup dried cranberries\r\n1/4 cup butter melted\r\n2 or 3 or more tbsp of brown sugar\r\n\r\n', 'make a pastey consistency of butter and brown sugar, add about 1 tbsp brandy,then add pecans and cranberries.Score top of cheese and put into oven for about 2 minutes. Take out and pour sauce over and put back into oven for about 5 minutes...', 'PREHEAT OVEN TO 400 C', 22),
(289, 'AMISH\'S week BREAD', 'DAY 1..this is the day you get your batter.Be sure the bag is sealed (when sealing the bag,besure to remove the excess air.(DO NOTHING)\r\nDAY 2.3,4.and 5 \\just mush the bag.\r\nDAY 5 Add to the bag 1 cup of flour and 1 cup milk mush the bag.\r\nDAY7,8,9 MUSH THE BAG\r\nDAY 10... Pour the entire contents of the bag into a NON METAL BOWL, AND ADD 1 1/2 cup flour,1 1/2 cup sugar,1 1/2cup of milk.MIX WELL...Measure out 1 cup each into 4 separate large ZIPLOCK BAGS and seal well.KEEP 1 for yourself and give the other 3 to friends along with a copy of recipe.This is the starter base .Be sure to put today\'s date on the bag so you can keep track of days.\r\n', 'Preheat oven to 325f .To the remaining  batter in the bowl add:::\r\n3 eggs\r\n1 cup of oil(or 1/2cup applesauce and 1/2 cup oil)\r\n1/2 cup milk\r\n1 cup sugar\r\n2 tsp vanilla  \r\n\r\nin a separate bowl mix\r\n1 1/2 tsp baking soda\r\n1/2 tsp baking powder\r\n1/2 tsp salt\r\n2 cups flour\r\n1 large pkg instant pudding mis(any flavour)\r\nOPTIONS:::\r\nnuts,raisins,chocolate chips\r\n\\mix well\r\n', 'Grease 2 large pans.Mix 1/2 cup brown sugar and 1/2 tsp cinnamon.SPRINKLE some of the mixture in each of the loaf pans.Pour the batter evenly into the 2 pans.Sprinkle remaining mixture over the top of the batter\r\nBAKE  1 hoiur un til bread starts to separate from the sides of the pan.\\cool and turn out on a rack. \\serve hot or cold...\r\n\\if you keep a bag for yourself  you will be baking every 10 days..\r\n\r\nDO NOT REFRIGERATE THE BATTER BAG...KEEP ON THE COUNTER...LET EXCESS AIR OUT \r\n\r\nONLY THE AMISH KNOW HOW TO CREATE THE STARTER BAG SO IF YOU GIVE THEM ALL AWAY YOU WILL HAVE TO WAIT TILL SOMEONE GIVES YOU A STARTER BAG..\r\n\r\nENJOY...', 42),
(290, 'Crockpot Honey Ribs', '2 lbs. country style spareribs\r\n1 can (10 3/4 oz.) beef broth\r\n1/2 cup water\r\n4 Tbsps. honey\r\n2 Tbsps. soy sauce\r\n4 Tbsps. BBQ sauce\r\n1 tsp. dry mustard\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n', 'Combine all ingredients except for ribs in CrockPot. Mix well, then add ribs. Cover and cook on Low for 6 to 8 hours or on High for 3 to 4 hours.', '', 17),
(291, 'Banana loaf', ' \r\nMix well: 3 cups flour\r\n               2 cups sugar\r\n              1 tsp. baking powder\r\n              1 tsp. baking soda\r\n              1 tsp. salt\r\n---------------------\r\n', 'Mix well: 1 cup undrained crushed pineapple\r\n               3 eggs\r\n               1 cup oil\r\n               2 teasp vanilla\r\n               2 cups mashed bananas\r\n----------\r\nMix  flour ingred. into wet mixture  mix well  \r\nAdd cranberries if desired\r\n \r\nCook approx 45 min. @ 350  till toothpick comes out clean\r\n ', '', 42),
(292, 'White Sauce ', '\r\n\r\n    * 4 tablespoons (60 g) butter\r\n    * 4 tablespoons (35 g) flour\r\n    * 2 cups (500 mL) milk\r\n    * Salt and pepper, to taste \r\n\r\n', 'White Sauce Preparation:\r\n\r\n    * Melt butter mix in flour, stirring for a few minutes.\r\n    * Pour in milk, stirring.\r\n    * Cook over medium heat, stirring until thick salt and pepper.\r\n', '', 17),
(293, 'Thin White sauce', '\r\n\r\n1 tablespoon butter\r\n1 tablespoon flour\r\n1/2 teaspoon salt\r\n1 cup milk or 1/2 cup evaporated milk and 1/2 cup water\r\n\r\n\r\n\r\nMelt butter in a sauce pan and whisk in flour and salt until smooth. Gradually stir in cold milk, cooking over direct heat and stirring constantly until sauce boils; reduce heat slightly and continue to stir until sauce becomes smooth and thick. When sauce thickens, simmer for an additional 10 minutes over very low heat, stirring occasionally.\r\nStir carefully to avoid lumps. If sauce becomes lumpy, use a stick blender or rotary beater to blend out lumps or else press through a sieve. Wondra flour may be used to great advantage since this flour does not have a tendency to lump.\r\n', 'MEDIUM WHITE SAUCE:\r\n\r\n2 tablespoons butter\r\n2 tablespoons flour\r\n1/2 teaspoon salt\r\n1 cup milk or 1/2 cup evaporated milk and 1/2 cup water\r\n', 'THICK WHITE SAUCE:\r\n\r\n3 or 4 tablespoons butter\r\n3 tablespoons flour\r\n1/2 teaspoon salt\r\n1 cup milk or one half cup evaporated milk and 1/2 cup water\r\n', 17),
(294, 'THAI REDCHICKEN CURRY', '  	\r\n\r\n\r\n\r\n2 tablespoons canola or peanut oil\r\n1 onionÃ¯Â¿Â½finely chopped\r\n2 teaspoons Thai red curry paste (or 3 teaspoons for a hotter curry)\r\n2 cloves garlicÃ¯Â¿Â½finely chopped\r\n1 cup coconut milk\r\n1 cup chicken stock\r\n2 tablespoons fish sauce\r\n1 tablespoon brown sugar\r\nÃ¯Â¿Â½ teaspoon salt\r\n1 zucchini (courgette)Ã¯Â¿Â½sliced into thin rounds\r\n1 red pepper (capsicum)Ã¯Â¿Â½julienned\r\n1 cup Jasmine rice\r\n12 oz (360g) uncooked skinless chicken breast filletsÃ¯Â¿Â½cut into bite-sized pieces\r\n2 tablespoons cornstarch (cornflour) mixed to a paste with 2 tablespoons water\r\n2 tablespoons lemon juice\r\n4 large fresh basil leavesÃ¯Â¿Â½finely sliced', 'HEAT the oil in a large saucepan over a medium heat and cook the onion for 5 minutes, stirring occasionally. ADD the curry paste and garlic and cook, stirring, for a minute. ADD the coconut milk, stock, fish sauce, sugar and salt, then bring to the boil. ADD the red pepper and zucchini, cover with a lid, then reduce the heat to medium and simmer for 12 minutes. WHILE the curry simmers, cook the rice. ADD the chicken to the curry and simmer, covered, for a further 8 minutes. ADD the cornstarch paste and stir continuously until the curry thickens, then stir in the lemon juice and basil. SERVE on a bed of rice.\r\n\r\nVariations: This curry tastes equally delicious using any selection of seafood (such as shrimp, scallops or pieces of firm fish), or cubed firm tofu. You can also use a variety of different vegetables with this curry including shredded cabbage, thinly sliced carrot or green beans. Be flexible and adapt the recipe to make the most of seasonal produce.\r\n\r\nÃ¯Â¿Â½ 2004 - 2009 MEDITERRASIAN.COM', 'A traditional Thai curry made with a subtle blend of hot, salty, sweet and sour flavors to get the taste buds tingling. You can make your own curry paste from scratch, however to save time we recommend you buy a good-quality pre-made Thai curry paste.\r\n', 54),
(295, 'Stilton Scalloped Potaoes', '2 Tbsp vegetable oil\r\n1/4 cup all purpose flour\r\n3 cups skim milk (warmed)\r\n1/2 cup crumbled stilton cheese\r\n1 tsp Dijon Mustard\r\n1/2 tsp salt\r\n1/4 tsp pepper\r\n3 Yukon Gold potatoes,peeled and thinly sliced\r\n2  small sweet potatoes peeled and thinly sliced\r\n1 small onion thinly sliced\r\n', '1. Heat oil over medium heat in saucepan. Add flour and cook,stirring for 1 minute. Whisk in milk slowly and continue whisking gently for about 5 minutes or until mixture is thick enough to coat the back of a spoon.  Remove from heat and add Stilton cheese,mustard,salt and pepper; whisk until smooth. Set aside.\r\n\r\n2. Preheat to 375 F\r\n\r\n3. Alternately layer Yukon Gold and sweet potatoes with onion in lightly greased or sprayed 13 x 9 inch casserole dish. Pour milk mixture evenly over potatoes.\r\n4. Bake in oven,uncovered for about 1 hour  or until potatoes are golden brown and tender when pierced with a knife.', 'serve 6 to 8\r\n\r\nenjoy', 61),
(296, 'Chocolate Turtle Cheesecake', '1 1/4 cups finely chopped toasted pecans\r\n2 tbsp non-hydrogenated margarine, melted\r\n3/4 cup plus 2 tbsp sugar,divided\r\n32 Kraft caramels,chopped\r\n3 tbsp milk\r\n3 pkg (250g) each brick cream cheese,softened\r\n3 eggs\r\n1 pkg (8 squares) semisweet chocolate, melted ,cooled slightly\r\n1/2 cup pecan halves toasted\r\n\r\n', 'HEAT oven at 350f. Cover bottom of 9 inch springform pan with parchment paper.  Combine chopped pecans ,margarine and 2 tbsp sugar;press onto bottom of pan. Microwave caramels and milk in microwaveable bowl on medium 4 to 5 minutes or until caramels are completely melted and mixture is well blended,stirring every 2 minutes. Spread over crust to within 1 inch of edge ;cool.\r\n\r\nBEAT cream cheese and remaining sugar in large bowl with mixer until blended.  add eggs, 1 at a time ,mixing on low speed after each just until blended. Stir in chocolate;pour over caramel layer.\r\n\r\nBAKE 45 to 50 minutes or until centre is almost set. Run knife or metal spatula around rim of pan to loosen cake;cool before removing rim.  Refrigerate 4 hours, Top with pecan halves just before serving..\r\n\r\n', 'enjoy', 45),
(297, 'Cinnamon French Toast Recipe', ' * 4 eggs\r\n    * 6 slices thick bread (Texas Toast is great for this)\r\n    * Cinnamon to taste\r\n    * 2 tsp vanilla\r\n    * 1 cup milk\r\n    * Cooking spray ', '\r\n\r\n   1. Beat eggs in a large bowl. Add milk, vanilla, and cinnamon, and beat well.\r\n   2. Lightly coat a large skillet with cooking spray, and heat over a medium fire.\r\n   3. While the skillet heats, soak bread in the milk mixture, turning to coat both sides evenly.\r\n   4. Cook bread over medium heat until nicely browned, approximately 4 minutes per side. ', '', 67),
(298, 'Supreme Nacho Platter', '1 (12 oz.) bag tortilla chips\r\n# 3 plum tomatoes\r\n# 1/2 medium yellow onion\r\n# 2 jalapeno peppers\r\n# 8 oz. cheddar cheese\r\n\r\n\r\n\r\n\r\n\r\n\r\nPrep Time: 6 seconds\r\nNotes: Make these nachos right before your guest arrive so they are hot and fresh.\r\nTips: Put some refried beans on the chips before adding the toppings. Black olives, green onions, and cooked chicken are all great additions.\r\n\r\nClose Window ', 'Before you begin... Preheat oven to 350ÃÂ°F. Arrange tortilla chips on a large oven-proof serving dish.add tomatoes, onion, jalapeno peppers and cheese  Finally... Place dish in oven and cook until cheese has melted, about 5 minutes.', '', 34),
(299, 'Baked Slow Cooker Chicken', '1 (2 to 3 pound) whole chicken\r\nsalt and pepper to taste\r\n	\r\n1 teaspoon paprika\r\n\r\n', '1. 	Wad three pieces of aluminum foil into 3 to 4 inch balls, and place them in the bottom of the slow cooker.\r\n2. 	Rinse the chicken, inside and out, under cold running water. Pat dry with paper towels. Season the chicken with the salt, pepper and paprika, and place in the slow cooker on top of the crumbled aluminum foil.\r\n3. 	Set the slow cooker to High for 1 hour, then turn down to Low for about 8 to 10 hours, or until the chicken is no longer pink and the juices run clear.', 'Prep Time: 20 Minutes\r\nCook Time: 10 Hours', 54),
(300, 'Apple Chunk Bread', '1 cup milk\r\n1/4 cup oil\r\n2 tablespoons sugar\r\n1/2 teaspoon cinnamon\r\n1 1/2 teaspoons salt\r\n3 cups bread flour\r\n2 1/2 teaspoons yeast\r\n1 1/3 cups apples, peeled and finely chopped\r\n\r\n', 'Add ingredients in order, adding apple pieces with liquid ingredients', '', 42),
(301, '100% Whole Wheat Pizza Dough', '-- (1-pound loaf)\r\n2 1/4 cups Whole wheat flour\r\n1/4 cup Gluten flour\r\n1 teaspoon Sugar\r\n1 teaspoon Salt\r\n1 cup Water\r\n2 tablespoons Olive oil\r\n1 package Active dry yeast\r\n1 teaspoon Cornmeal\r\n\r\n-- (1 1/2 pound loaf)\r\n2 2/3 cups Whole wheat flour\r\n1/3 cup Gluten flour\r\n1 1/2 teaspoons Sugar\r\n1 1/2 teaspoons Salt\r\n1 1/4 cups Water\r\n3 tablespoons Olive oil\r\n4 teaspoons Active dry yeast\r\n1 1/2 teaspoons Cornmeal\r\n\r\n', 'Fit the kneading blade firmly on the shaft in the bread pan. Carefully measure the flours, salt, and the sugar, and transfer to the pan. Add the water, oil, and yeast. Place the bread pan inside the machine and close the lid. Program the bread maker for the whole wheat dough mode.\r\n\r\nAt the end of the rising cycle, turn the dough out onto a lightly floured surface. Cover and let rest for 10 minutes. Lightly oil a 12-inch (or 15-inch) pizza pan and sprinkle with the\r\ncornmeal.\r\n\r\nWith floured hands, gently stretch the dough into a 12-inch (or 15-inch) circle and place in the prepared pan. Continue stretching until the dough covers the entire surface if the pan. Push the dough against the rim of the pan to make an edge, then top the dough with your choice of pizza fillings. Bake the pizza on the bottom rack of a preheated 400?F oven for 20 to 25 minutes, until the crust is golden and the filling is melted and bubbly.\r\n\r\nServe hot.', '', 42),
(302, '100% Whole Wheat Bread', 'For 1 1/2 lb. bread machine\r\n1 1/4 cups water\r\n2 tablespoons olive or vegetable oil\r\n1/4 cup honey or maple syrup\r\n3 cups King Arthur 100% White Whole Wheat or (3 to 3 1/2 ) Stone-Ground Whole Wheat Flour\r\n1/4 cup sunflower sesame or flax seeds, or a combination (optional)\r\n1 tablespoon vital wheat gluten\r\n1 1/2 teaspoons salt\r\n1 1/2 teaspoons instant yeast\r\n\r\n', 'Put all of the ingredients into the bread pan in the order listed.\r\nProgram for basic white bread, and press Start. ', '', 42),
(303, 'Hawaiian Bread (ABM)', '3/4 cups pineapple juice\r\n1 tablespoon butter, softened\r\n2 1/3 cups bread flour\r\n1/2 teaspoon salt\r\n1 1/2 tablespoons brown sugar\r\n2 tablespoons shredded carrots\r\n1/4 cup flaked, shredded coconut\r\n1/2 cup crushed pineapple\r\n1/3 cup chopped macadamia nuts\r\n2 teaspoons yeast\r\n1/2 teaspoon cinnamon\r\n\r\n\r\n', 'Drain the pineapple well. Juice may be substituted for up to 2/3 of the water. May use regular milk or water/dry milk for pineapple juice.\r\n', 'Put all ingredients into pan in order recommended for your machine. Select light crust, sweet bread.', 42),
(304, 'Blueberry Muffin Bread', '3/4 cup milk\r\n1 egg\r\n3 tablespoons water\r\n2 tablespoons margarine or butter, cut up\r\n3 cups bread flour\r\n3 tablespoons sugar\r\n3/4 teaspoon salt\r\n1/4 teaspoon ground nutmeg\r\n1 teaspoon active dry yeast or bread machine yeast\r\n1/3 cup dried blueberries\r\n1/2 cup sifted powdered sugar (optional)\r\nMilk (optional)\r\n\r\n', 'Add the first 10 ingredients to a 1-1/2- or 2-pound bread machine according to manufacturer\'s directions. Select the basic white bread cycle.\r\n\r\nIf desired, in a small mixing bowl, stir together powdered sugar and enough milk (1 to 2 teaspoons) to make a glaze of drizzling consistency. Drizzle over cooled loaf.\r\n\r\nMakes 16 servings.\r\n\r\n  ', '', 42),
(305, 'Orange Spice Bread', '2 teaspoons yeast\r\n3 cups bread flour\r\n3 tablespoons sugar\r\n1 teaspoon salt\r\npeel from 1 large or 2 med oranges, grated\r\n1/2 teaspoon cinnamon\r\n1/8 teaspoon cloves\r\n1/8 teaspoon nutmeg\r\n5 tablespoons butter\r\n2 eggs\r\n2/3 cup milk\r\n1/2 cup raisins (optional)\r\n\r\n', 'Bake on light setting if available. Let cool. If desired, top bread with a glaze of 1/4c powdered sugar and enough orange juice to make a glaze. ', '', 42),
(306, 'Raisin Bran Bread', '1 pkg yeast (2 to 2 1/4 t)\r\n2 C bread flour\r\n1 1/2 C raisin-bran cereal, right from the box\r\n1/2 t salt\r\n1/4 t baking soda\r\n1 t cinnamon\r\n4 T brown sugar, packed\r\n2 T butter\r\n1 C + 1 T warm water (or cool if recommended by your machine)\r\n\r\n\r\n\r\n', 'Add all ingredients in the order of your machine. Select white bread and push &quot;start&quot;.\r\n', 'Note: This is a DAK bread machine recipe. You may want to use 1 to 2 T less water.\r\n', 42),
(307, 'Cinnamon Oatmeal Bread', '7/8 cup + 1 tbsp warm water (90-100 deg)\r\n2 cups bread flour\r\n1/2 cup oats\r\n1 tablespoon brown sugar, packed\r\n1 teaspoon salt\r\n1 teaspoon ground cinnamon\r\n1 tablespoon butter or margarine\r\n1 1/2 teaspoons yeast\r\n\r\n', 'Add ingredients to pan in order specified by your machine\'s manufacturer.\r\n\r\nMakes a 1 lb loaf.', '', 42),
(308, 'Italian Bread Using a Bread Machine', '4 cups unbleached all-purpose flour\r\n1 tablespoon light brown sugar\r\n1 1/3 cups warm water (110 degrees F/45\r\ndegrees C)\r\n1 1/2 teaspoons salt\r\n1 1/2 teaspoons olive oil\r\n1 (.25 ounce) package active dry yeast\r\n1 egg\r\n1 tablespoon water\r\n2 tablespoons cornmeal\r\n', '1. 	Place flour, brown sugar, warm water, salt, olive oil and yeast in the pan of the bread machine in the order recommended by the manufacturer. Select dough cycle; press Start.\r\n2. 	Deflate the dough and turn it out onto a lightly floured surface. Form dough into two loaves. Place the loaves seam side down on a cutting board generously sprinkled with cornmeal. Cover the loaves with a damp cloth and let rise, until doubled in volume about 40 minutes. Meanwhile, preheat oven to 375 degrees F (190 degrees C).\r\n3. 	In a small bowl, beat together egg and 1 tablespoon water. Brush the risen loaves with egg mixture. Make a single long, quick cut down the center of the loaves with a sharp knife. Gently shake the cutting board to make sure that the loaves are not sticking. If they stick, use a spatula or pastry knife to loosen. Slide the loaves onto a baking sheet with one quick but careful motion.\r\n4. 	Bake in preheated oven for 30 to 35 minutes, or until loaves sound hollow when tapped on the bottom.\r\n', 'Prep Time: 20 Minutes\r\nCook Time: 35 Minutes\r\n&quot;Wonderful Italian bread made in a bread machine then baked in the oven.Ready In: 3 Hours 20 Minutes\r\nServings: 20', 42),
(309, 'Bread Machine Recipe for White Bread', 'Add to the bread maker in this order:\r\n\r\n5/8 cup warm water (132.75 mL)\r\n5/8 cup milk (132.75 Ml)\r\n1 1/2 Tbsp butter (22.5 mL)\r\nOptional but recommended: Bread Dough Enhancer. Use per manufacturer\'s instructions.\r\n1 1/2 tsp salt (7.5 mL)\r\n3 cups bread flour (708 mL)\r\n3 Tbsp sugar (45 mL)\r\n1 tsp active dry yeast (5 mL)', 'Tried this recipe and this is the first bread that turned out good.....not lopsided in my bread maker...', 'Note: This makes a 1 1/2 pound loaf. Use the math to adjust for one pound or two pound loaves.', 42),
(310, 'White Bread #2', 'Add to the bread maker in this order:\r\n\r\n3/4 cup milk (177 mL)\r\n4 Tbsp. Butter (60 mL)\r\n1 egg (1 egg)\r\n3/4 tsp salt (3.75 mL)\r\n3 cups bread flour (708 mL)\r\nOptional but recommended: Optional but recommended: : Bread Dough Enhancer. Use per manufacturer\'s instructions.\r\n\r\n1 1/2 tsp active dry yeast (7.5 tsp)', '', 'Note: This bread maker recipe makes a 1 1/2 pound loaf. Use the math to adjust for one pound or two pound loaves.', 42),
(311, 'BANANA BREAD', '1 1/2 cup Bread flour\r\n1 1/2 cup Wheat flour\r\n1/2 teaspoon Salt\r\n2 med Ripe bananas\r\n1/4 cup Honey\r\n1/4 cup warm water\r\n1 Egg\r\n1/4 cup Oil\r\n1/2 teaspoon Vanilla\r\n1 teaspoon Poppy seeds -- (optional)\r\n1 package Yeast\r\n\r\n', '', 'Follow the instructions for your machine as to which order you put in your\r\ningredients. Make sure that if you set your machine on delayed timer that\r\nyou don\'t get your yeast wet or your bread will flop!', 42),
(312, 'ALMOST WONDER BREAD', '3/4 Cup Milk\r\n1 Egg\r\n1 T Butter\r\n3 T Sugar\r\n1/2 t Salt\r\n2 Cups Bread Flour\r\n1 1/2 t Yeast\r\n\r\n\r\n', 'Just like Wonder Bread! Add ingredients according to manufacturer\'s\r\ndirections. Use the light crust setting.', '', 42),
(313, 'ALOHA BREAD', '8 oz. crushed pineapple in juice, drained and juice reserved\r\n1/3 cup Water\r\n1/4 cup Reserved pineapple juice\r\n1 Tb. butter softened\r\n3 cups Bread flour\r\n1/2 cup Shredded coconut, toasted\r\n1/3 cup Pecan or walnut halves\r\n1 Tb. Dry milk\r\n1 Tb. Packed brown sugar\r\n1 Tsp. Salt\r\n1 1/2 Tsp. Yeast\r\n\r\n ', 'Measure carefully, placing all ingredients in bread machine pan in the order\r\nrecommended by the manufacturer. Select Sweet or Basic/White cycle. Use\r\nmedium or light crust color. Do not use delay cycle. Remove baked bread from\r\npan and cool on a wire rack', '', 42),
(314, 'AMISH BREAD', '1 1/2 LB LOAF:\r\n1 cup water + 1 T\r\n4 tablespoons Olive oil\r\n3 tablespoons Sugar\r\n1 teaspoon Salt\r\n3 1/4 cups flour\r\n2 teaspoons Yeast\r\n3 teaspoons Vital wheat gluten\r\n\r\n1 LB LOAF:\r\n6 ounces water\r\n2 1/2 tablespoons Olive oil\r\n2 tablespoons Sugar\r\n1/2 teaspoon Salt\r\n2 cups flour + 2 T\r\n1 teaspoon Yeast\r\n2 teaspoons Vital wheat gluten\r\n\r\n', 'Place ingredients into bread maker pan according to your machine\'s\r\ndirections. Bake on regular cycle, light setting.', '', 42),
(315, 'ANADAMA BREAD', '2 1/4 ts Active dry yeast - (1 1/2 tsp)\r\n1 2/3 c Bread flour - (1 c + 2 t)\r\n1 1/2 c Whole wheat flour - (1 c)\r\n1/3 c Yellow cornmeal - (1/4 c)\r\n1/3 c Molasses, unsulfured - (1/4 c)\r\n1 1/2 ts Salt - (1 t)\r\n1 1/2 c Water - (1c)\r\n\r\n\r\n\r\n', 'Add all ingredients in the order suggested by your bread machine manual and\r\nprocess on the basic bread cycle according to the manufacturer\'s directions.\r\nLet the loaf cool before slicing.\r\n', '1 1/2 lb loaf - (1 lb loaf) Note: The original recipe called for 1 1/2 T vegetable oil for the lg loaf\r\nand (1T) for the smaller loaf. I omitted it. Could use Wonderslim or\r\npossibly applesauce instead.', 42),
(316, 'APPLE CRANBERRY NUT BREAD', '8 oz Bread Flour\r\n8 oz Whole Wheat Flour\r\n1 1/2 t Salt\r\n2 T Sugar, white or brown\r\n1 t Cinnamon\r\n1 t Nutmeg\r\n2/3 c Applesauce\r\n1/2 c Applejuice (or Orange Juice)\r\n1/3 c Dried cranberries\r\n1 oz Chopped walnuts\r\n1 1/2 t Yeast\r\n\r\n', 'Add ingredients to baking pan in order given.. Bake on basic/light mode (4\r\nhour). Drop in cranberries which have been coated with the cinnamon and\r\nnutmeg after first knead. Add yeast to dispenser. Created for Panasonic 65P.\r\nAdjust as needed for other machines. Makes a nice loaf for holiday giving or\r\nserving.', '', 42),
(317, 'APPLE PIE BREAD', '1 1/2 ts Active dry yeast\r\n1 1/2 ts Cinnamon\r\n5 tb Sugar\r\n3 1/4 c &amp; 2 tb Bread flour\r\n1 1/2 ts Salt\r\n3 tb Buttermilk powder, or dry milk\r\n3/4 c Apple-pie filling\r\n1 1/2 tb Butter\r\n4 1/2 oz Apple juice\r\n\r\nFor a 1 pound loaf, use:\r\n\r\n1 ts Active dry yeast\r\n1 ts Cinnamon\r\n3 1/2 tb Sugar\r\n2 1/4 ts Bread flour\r\n1 ts Salt\r\n4 ts Buttermilk powder, or dry milk\r\n1/2 c Apple-pie filling\r\n1 tb Butter\r\n3 oz Apple juice\r\n', 'Combine ingredients and bake according to manufacturer\'s directions. This\r\nmakes a 1 1/2 pound loaf.\r\n\r\n\r\nNote: For Panasonic/National machines, use 3 1/2 ts of yeast for the 1 1/2\r\npound loaf.', '', 42),
(318, 'APPLE RAISIN BREAD', '3/4 c Water\r\n1/3 c Apple juice\r\n1 tb Butter\r\n3/4 ts Salt\r\n2 ts Sugar\r\n1 tb Cinnamon\r\n3 c Bread flour\r\n1 1/2 ts Yeast\r\n1/3 c Raisins\r\n\r\n', '12-serving recipe = 1 1/2 lb. loaf; adjust for your machine if necessary.\r\nUse sweet bread cycle; adjust cinnamon to taste if necessary.', '', 42),
(319, 'APPLE WHEAT BREAD', '1 pk yeast\r\n3 c whole wheat flour\r\n1/2 c kellogg\'s bran flakes (or eqivalent)\r\n3 tb gluten (optional)\r\n1 ts cinnamon\r\n1 c plus 1 tbs apple juice, warmed\r\n1/2 c applesauce, warmed\r\n1 golden delicious apple, grated with skin (measures about 1 1/4 cups)\r\n\r\n', 'Put all the ingredients into pan in the order listed, select \'whole wheat\'\r\nand push \'start\'.\r\n', '', 42),
(320, 'Recipe Strawberry Bread for the Bread Maker', '1/2 c milk\r\n1/2 cups mashed strawberries\r\n1/2 cups mashed bananas\r\n2 tbsp butter\r\n2 tsp sugar\r\n2 tsp salt\r\n3 cups bread flour\r\n2 1/2 tsp yeast\r\n\r\n\r\n', 'Add ingredients to the maker in the order recommended by the manufacturer. Add a little extra flour to the dough if it appears to be too moist. Bake using the medium bake cycle. ', 'Optional but recommended: Bread Dough Enhancer. Use per manufacturer\'s instructions.', 42),
(321, 'Tupperware Chelsie Buns', '    1/4 c  reduced-calorie margarine\r\n    1/3 c  brown sugar\r\n      2 tb corn syrup\r\n    1/4 ts cinnamon\r\n    1/3 c  pecan halves\r\n     12    maraschino cherries; cut in\r\n           -half\r\n      1 pk biscuit dough, lowfat;\r\n           -pillsbury,buttermilk\r\n\r\n\r\n\r\n', 'Use a 8&quot; or 9&quot; glass pie plate. Combine first 4 items, Add nuts and\r\ncherries. Arrange Pillsbury biscuits on top. Cook in oven 425 F for 20\r\nmin.\r\n\r\nMakes 8 servings.\r\n\r\n', 'NOTE: I call it Tupperware because I was given it at a Tupperware party.\r\n\r\nLOWER FAT NOTE: Use reduced calorie margarine instead of butter, cut down\r\nthe brown sugar to 1/3 cup instead of 1/2 cup, use 1/3 cup pecan halves\r\ninstead of 1/2 cup.\r\n\r\nMC Formatted by Jennifer Hall\r\n\r\n- - - - - - - - - - - - - - - - - -\r\n\r\nNOTES : Per serving: 460.6 cal, 7.3g fat, 3.0g fibre, 256mg sodium\r\n\r\nPer serving (using lower fat note): 425.1 cal, 4.3g fat, 2.9g fibre, 264mg\r\nsodium\r\n\r\nPer serving: 9.22', 42),
(322, 'Cinnamon Rolls ', '1 cup milk\r\n1 cup water\r\n1/4 cup butter\r\n1 1/2 teaspoons salt\r\n6 cups all-purpose flour\r\n1 1/2 tablespoons active dry yeast\r\n1/2 cup white sugar\r\n2 eggs\r\n	\r\n1/3 cup butter, softened\r\n1 1/2 teaspoons ground cinnamon\r\n3/4 cup white sugar\r\n3/4 cup raisins (optional)\r\n3/4 cup chopped walnuts (optional)\r\n2 cups confectioners\' sugar\r\n3 tablespoons butter, melted\r\n1/2 teaspoon vanilla extract\r\n3 tablespoons milk\r\n', '1. 	In saucepan, heat 1 cup milk, water, and 1/4 cup butter until very warm (butter doesn\'t need to be completely melted). Place milk mixture, salt, flour, yeast, sugar, and eggs in the pan of the bread machine in the order suggested by the manufacturer. Select the Dough cycle. Press Start.\r\n2. 	Once Dough cycle is complete, remove the dough from the bread machine. Punch down, and divide into 2 parts. On a floured surface, roll each part into a large rectangle. Smear each rectangle with the softened butter. Combine the cinnamon and 3/4 cup sugar. Sprinkle over the rectangles. Generously sprinkle the raisins and/or chopped nuts over the top.\r\n3. 	Roll the dough up into two logs starting at the long side. Cut each log into 12 slices. Place the rolls cut side down into two 9x13 inch greased baking pans. Cover, and let rise in a warm place until almost doubled (about 30 minutes).\r\n4. 	Bake in a preheated 375 degrees F (190 degrees C) oven for 20 to 25 minutes, or until golden. Combine the confectioners\' sugar, 3 tablespoons melted butter, vanilla, and 3 tablespoons milk. Frosting should be thick. Spread over baked rolls and enjoy.', 'Prep Time: 20 Minutes\r\nCook Time: 25 Minutes\r\n	Ready In: 3 Hours 20 Minutes\r\nServings: 24&quot;Your bread machine does the mixing -- all you have to do is roll out the dough, coat it with butter, cinnamon sugar and raisins or walnuts, roll it up and pop them in the oven. A powdered sugar icing seals the deal for these prize-winning rolls.&quot;', 42),
(323, 'Strawberry Banana Tofu Smoothie', '4 ounces soft tofu\r\n1/2 cup fruit juice\r\n1 cup strawberry\r\n1/2 cup banana\r\n\r\nPut all ingredients in blender and blend until smooth. ', 'n/a', '', 65),
(324, 'Tofu Fruit Sauce', '1/2 pound soft tofu\r\n1/4 cup oil (something light and not strong tasting-- like Mazola or canola)\r\n2 tablespoons honey\r\n1/2 tablespoon lemon juice\r\n1/2 teaspoon vanilla\r\n1/4 teaspoon salt\r\n\r\n', 'Blend in a food processor or blender until smooth and creamy; chill and serve as you would use whipped cream.\r\n\r\nIt\'s thick and smooth like sour cream. 4 oz serving is 6 oz of fat or 86 calories; my recipe suggests 2 tablespoon serving is 78 calories, 2 g fat 4 g carbohydrates.\r\n\r\nIt is absolutely wonderful and much more easily disguised than the hard chunks of tofu which would be in miso soup.\r\n\r\nNote that it is non-dairy, so keep it in your collection for those who are lactose intolerant. ', '', 60);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(325, 'Chicken and Artichoke casserole', '4 Large chicken breasts Deboned\r\nflour,salt and pepper- Butter\r\n1 lb fresh mushrooms 1 Tbsp butter\r\n2 Jars Artichokes hearts(drained)\r\n1/2 cup sherry\r\n1/3 cup flour\r\n1/3 cup butter\r\n1 1/2 cup Cream or milk\r\n1 tbsp worcestire sauce -tobasco sauce to your taste\r\n1/2 cup freshly grated Parmesan cheese\r\npaprika and parsley\r\n', 'Cut each deboned breast in 2.Dredge in flour,salt and pepper  and saute in butter on both sides till golden. Remove  from pan and cut in serving pieces.Wash and dry the mushrooms and cut into slices and  saute in 2 tbsp butter,Partially cook the Artichokes.In a casserole dish place layers of chicken , mushrooms and artichokes.\r\nPour sherry over layers.\r\nMake a cream sauce of flour,melted butter and cream with a wisk works better to mix up\r\nSeason with worchestire sauce, tobasco sauce salt and pepper/\r\nPour Sauce over casserole,sprinkle cheese,paprika sand parsley over the casserole. BAKE at 375 degrees for 4r0 minutes', 'very taty enjoy\r\n\r\nbea', 54),
(326, 'Roasted Butternut Squash Soup', '	4 cup(s) vegetable broth\r\n	12 oz Butternut squash, peeled and cut into 1- to 1 1/2-inch cubes*\r\n	1/2 large vidalia onion(s), cut into 2-inch cubes\r\n	1/2 small apple(s), peeled and cut into to 2-inch\r\n	1/4 tsp table salt, or to taste\r\n	1/8 tsp black pepper, or to taste\r\n	1/8 tsp ground nutmeg, or to taste\r\n\r\n\r\n \r\n\r\n', '   * In a large stock pot, combine broth, squash, onion and apple; cover pot and bring to a boil over high heat. Uncover pot and reduce heat to low; gently simmer until squash is very tender, about 10 minutes.\r\n\r\n    * Puree soup in pot using an immersion blender (or puree in a regular blender in batches, careful not to splatter hot liquid). Season with salt, pepper and nutmeg; serve. Yields about 1/2 cup per serving. \r\n\r\nNotes\r\n\r\n    * *You can purchase already peeled and cubed squash in the produce section of some supermarkets. You can also swap frozen, cubed squash for the fresh.\r\n\r\n      Garnish with chopped mint.', 'POINTSÃÂ® Value: 0\r\nServings:  12\r\nPreparation Time:  10 min\r\nCooking Time:  10 min\r\nLevel of Difficulty:  Easy\r\nNice and simple: a puree of squash and apples with just a hint of fall spice. Serve hot, chilled or at room temperature.', 62),
(327, 'Summer Vegetable Salad', '1 English Cucumber, chopped\r\n1 Large Tomato, chopped\r\n2 Red, Green or Yellow Peppers, chopped\r\n4 tbsp Fat free Greek Dressing\r\n\r\n', 'Mix all ingredients.\r\n\r\nSpecial Notes\r\n\r\nCan also add chopped red onion or Feta cheese.\r\nThe serving size is pretty large at 6 servings. ', '		Estimated POINTSÃÂ® Values Per Serving | 2\r\nServings | 6\r\n\r\nSide Dishes | Community built RECIPE\r\n', 55),
(328, 'STRIPED DELIGHT', '1 1/2 c. graham crackers, crushed\r\n1/4 c. sugar\r\n1/3 c. melted butter\r\n1 oz. 8 oz. cream cheese, softened\r\n1/4 c. sugar\r\n2 tbsp. milk\r\n1 oz. (8 oz.) container Cool Whip\r\n2 (4 oz.) pkg. Jello instant pudding\r\n3 1/2 c. cold milk\r\n\r\nOr use one (6 servings) instant pudding and pie filling and 2 1/2 cups milk.\r\n\r\nTry Striped Delight in chocolate, pistachio, lemon and butterscotch, too.\r\n \r\n', 'Combine graham cracker crumbs, 1/4 cup sugar and melted butter. Press firmly into bottom of 9 x 13 pan.\r\n\r\nBeat cream cheese with sugar and 2 tablespoons milk until smooth. Fold in half of Cool Whip. Spread over crust.\r\n\r\nUsing the 3 1/2 cups cold milk, prepare the pudding as directed on the package. Pour over the cream cheese mixture layer. Chill several hours or overnight.\r\n\r\nSpread the remaining Cool Whip over the pudding. Garnish with grated chocolate or chopped nuts, if desired. ', 'Makes 12 to 15 servings.\r\n', 40),
(329, 'Cranberry Sauce', '1 cup (200 g) sugar \r\n1 cup (250 mL) water \r\n4 cups (1 12-oz package) fresh or frozen cranberries \r\nOptional Pecans, orange peel, raisins, currants, blueberries, cinnamon, nutmeg, allspice.\r\n\r\n', '1 Wash and pick over cranberries. In a saucepan bring to a boil water and sugar, stirring to dissolve sugar. Add cranberries, return to a boil. Reduce heat, simmer for 10 minutes or until cranberries burst. \r\n\r\n2 At this point you can add all number of optional ingredients. We typically mix in a half a cup of roughly chopped pecans with or without a few strips of orange peel. You can add a cup of raisins or currants. You can add up to a pint of fresh or frozen blueberries for added sweetness. Spices such as cinnamon, nutmeg or allspice can be added too.\r\n\r\n3 Remove from heat. Cool completely at room temperature and then chill in refrigerator. Cranberry sauce will thicken as it cools.\r\n\r\n', 'Cranberry sauce base makes 2 1/4 cups.\r\n', 5),
(330, 'turkey stuffing Chantal', '8-10 cups stale bread\r\n1 cup chopped onions\r\n1/2 cup chopped celery\r\n1 cup onions\r\n1/2 cup butter\r\n1/2 tsp salt\r\n1/4 tsp pepper\r\n2 tsp poultry seasoning or 1 tsp of each\r\nsage savory  thyme marjory\r\nor hot broth and water 2/3 cup', 'melt butter add onions and celery till clear through\r\nadd seasonings and salt and pepper\r\nadd butter to broth\r\nadd 1/2 broth to frying pan, swish around\r\nadd broth to bread.  taste. add poultry seasoning if needed.\r\ncontinue to add broth until consistency.', '', 5),
(331, 'choc cake', '1 3/4 cups flour\r\n1 cup cocoa powder\r\n1 tsp baking powder\r\n1 tsp baking soda\r\n1/4 tsp salt\r\n1 cup hot brewed coffee\r\n1/2 cup butter or marg\r\n1 cup white sugar\r\n2 eggs\r\n1 tsp vanilla extract', '1.Preheat oven to 350.  Grease and flour a 9x13 or two 9 inch round pans.  sift together the flour, baking powder, baking soda and salt.  set aside. in a small bowl, combine hot coffee with 1 cup cocoa and let cook to lukewarm.\r\n2. In a large bowl, cream together the 1/2cup butter and 1 cup sugar until light and fluffy.  Add the eggs one at a time, beating well with each addition, then stir in the 1 tsp vanilla.  Add the flour mixture alternately with the coffee and cocoa mixture; beat well.\r\n3.  Pour batter into a 9x13 cake or two 9 inch round pans.  Bake in the preheated oven for 45 minutes or until toothpick inserted into the cake comes out clean.  Allow to cool.', 'from cindy\'s house.', 45),
(332, 'Egg Rolls', '4 cups shredded cabbage\r\n1/2 cup onions\r\n1/2 cup celery\r\n2 tsp sifto salt\r\n1 cup cooked chicken\r\n1 tbsp soya sauce\r\n1 tbs peanut oil\r\n1/2 tsp pepper', 'combine vegetables in a deep dish with salt. Let stand 15 minutes .  drain add other ingredients.  mix well', '', 66),
(333, 'chicken chow mein', '3 tbsp oil\r\n1 lb chicken in thin fillets\r\n1 minced garlic clove\r\n3 tsp soya sauce\r\n1 cup onions\r\n1 cup celery cut on the bias\r\n1 1/2 cup beef or chicken broth\r\n2 cups bean sprouts\r\n2 tsp corn starch\r\n3 tsp water\r\n2 cups fried noodles', 'Stir fried chicken in oil 4 minutes.  Add garlic salt and soya sauce.  stir constantly 1 minute. add onions, celery stir 2 minutes.  add broth and bean sprouts.\r\nheat to a boiling point, mix together corn starch and cold water then add to preparation and cook stirring constantly till mixture thickens.  cook 3 minutes.  add fried noodles.  serve\r\n', '', 66),
(334, 'crepes', '7 eggs\r\n2 tsp vanilla\r\n1 tabl white sugar\r\npinch of salt\r\n1/4 cup of butter\r\nlemon juice\r\n1/2 tsp orange peel grinded\r\n2 cups flour \r\n2 1/2 cup milk', 'n/a\r\n', '', 67),
(335, 'Quiche Lorraine', '8 sliced crumbled bacon\r\n9-inch unbaked pie shell\r\n2 cups shredded swiss cheese (8oz)\r\n4 beaten eggs\r\n1 large can undiluted carnation evaporated milk.\r\n3 tabl minced onions.\r\n1 tsp worcestershire sauce\r\n1/2 tsp salt\r\n1 tabl grated parmesan cheese', 'sprinkle bacon over bottom of unbaked bie shell.  cover with swiss cheese. Combine eggs, evaporated milk, onion, worcestershire sauce and salt. Mix well. Pour into pie shell. sprinkle with parmesan cheese. bake in moderate oven 375 for 30-35 minutes or until knife inserted halfway between centre and edge comes out clean.  Let stand 5 minutes before serving.', '', 67),
(336, 'Brownie Icing', '3 tbsp butter or marg\r\n3 tbsp cocoa\r\n1 tbsp corn syrup or honey\r\n1/2 tsp vanilla\r\n1 cup icing sugar\r\n1 to 2 tbsp milk', 'cream butter or marg add cocoa, corn syrup or honey and vanilla in small bowl.  add icing sugar and milk.. beat ', '', 44),
(337, 'chicken balls', '    * 4 boneless chicken breasts cut-up in 1 inch cubes\r\n    * 1 1/4 cup all purpose white flour plus 1/4 cup for coating the chicken\r\n    * 2 tsp baking powder\r\n    * 1 tsp salt\r\n    * 1/4 tsp pepper\r\n    * 2 eggs\r\n    * 3/4 cup milk\r\n    * 1 to 2 tbsps cooking oil\r\n\r\n', '1. Cut up chicken breasts in 1 inch cubes and set aside.\r\n   2. Mix together 1 1/4 cup of white flour with the baking powder, salt, pepper (reserve 1/4 cup for coating chicken pieces before dipping into this mixture). Add the 2 eggs and the milk. Mix all together well.\r\n   3. Take the chicken pieces and dip them in the 1/4 cup of flour, then dip into this batter to coat the chicken. Fry the chicken pieces in hot cooking oil until browned on all sides and serve with my chicken balls red sauce.\r\n\r\n', '', 66),
(338, 'red sauce for chicken balls', '    * 2 cups water\r\n    * 3/4 cup Heinz ketchup\r\n    * 3/4 cup white sugar\r\n    * 3 tbsps (red) grenadine\r\n    * 3 tbsps cornstarch\r\n    * 1/4 cup water\r\n\r\n\r\n\r\n\r\n  ', ' 1. Combine the first 4 ingredients in a saucepan on top of the stove and cook on medium heat for 1 to 2 minutes. In the meantime, mix 3 tbsps of cornstarch with 1/4 cup of water and add to the other ingredients to thicken the sauce. Cook until thickened.\r\n   2. Serve with Chinese chicken balls.\r\n\r\n', '', 66),
(339, 'Potato Pancakes 2', 'ngredients\r\n\r\n    * 1 medium potato, raw\r\n    * 1/2 cup onion\r\n    * 2 eggs\r\n    * 3 tbsp flour\r\n    * 1 tsp salt\r\n    * 1/2 tsp pepper\r\n\r\n\r\n', '1. Grate the potato and onion. I used a food processor to get it over with. Noisy but fast.\r\n   2. Mix the the potato, egg, flour salt and pepper well.\r\n   3. Spray a large griddle liberally with PAM cooking spray and heat to medium high. I use an electric griddle for this and put the setting at about 350.\r\n   4. 3 table spoons of mixture makes 1 pancake.\r\n   5. Cook each side about 3 - 4 minutes until browned.\r\n   6. Servings 6', '', 61),
(340, 'Blueberry Orange Smoothie', '2-1/2 cups frozen blueberries\r\n\r\n8 ounces vanilla low fat yogurt\r\n\r\n1/2 cup orange juice\r\n\r\n1/2 cup milk\r\n\r\n1 teaspoon vanilla extract\r\n\r\n\r\n\r\n\r\n', 'Whirl all ingredients together in a blender until smooth. Serve immediately.\r\n\r\nused cranberry juice with the blueberries no sugar\r\nWonderful recipe! It works well with Rice Milk and V8 Fusion tropical orange blend as well!\r\nVery Good 	I tried it, subbing blueberry yogurt for the vanilla because that\'s what I had. It was delicious. I\'ll make it again.', 'Makes 3 servings. \r\nNutritional Info\r\n\r\n    * Fat: 2.6g\r\n    * Carbohydrates: 27.8g\r\n    * Calories: 156.6\r\n    * Protein: 6.5g ', 65),
(341, 'Tropical Smoothie', '1 cup frozen pineapple pieces\r\n\r\n1 frozen banana (peel banana before freezing)\r\n\r\n3/4 cup milk\r\n\r\n1/2 cup low fat vanilla yogurt\r\n\r\n1/2 cup orange juice\r\n\r\n3 tablespoons coconut\r\n\r\n', 'Directions\r\nWhirl all ingredients together in a blender until smooth. Serve immediately.\r\n\r\n\r\n', 'Nutritional Info\r\n\r\n    * Fat: 2.0g\r\n    * Carbohydrates: 26.7g\r\n    * Calories: 140.4\r\n    * Protein: 6.0g \r\n\r\nMakes 3 servings. ', 65),
(342, 'Strawberry Soy Smoothie', '1 cup vanilla soymilk\r\n\r\n1 cup soft silken tofu\r\n\r\n10 oz strawberries, frozen\r\n\r\n1/2 cup orange juice\r\n\r\n1 tablespoon honey\r\n\r\n\r\n\r\nMakes 4 servings.', 'Whirl all ingredients together in a blender until smooth. Serve immediately.\r\n', 'nutritional Info\r\n\r\n    * Fat: 3.6g\r\n    * Carbohydrates: 18.7g\r\n    * Calories: 126.8\r\n    * Protein: 6.6g ', 65),
(343, 'French (Women Don\'t Get Fat) Toast', '- 1/4 cup egg beaters\r\n- 1/8 cup skim milk\r\n- 1/2 teaspoon ground cinnamon\r\n- 1/2 teaspoon vanilla extract\r\n- non-stick cooking spray\r\n- 2 pieces whole wheat brea\r\n\r\nNumber of Servings: 1\r\n\r\n', 'Heat a skillet sprayed with cooking spray over medium-high heat.\r\n\r\nIn a shallow bowl/dish, combine the first four ingredients. Mix together well.\r\n\r\nQuickly dip the first piece of bread flat in the bowl, letting it soak up the liquid, but not so much that it falls apart. Do this on both sides. Put the bread on the skillet, cooking it on both sides until browned. Repeat this process with the next piece of bread.\r\n\r\nPut on a plate and eat! It tastes extra great topped with one of the following: fresh fruit, pure maple syrup, powdered sugar, or whipped cream.\r\n\r\nMakes 2 pieces of french toast, or 1 serving.\r\n', 'Nutritional Info\r\n\r\n    * Fat: 1.6g\r\n    * Carbohydrates: 21.7g\r\n    * Calories: 150.2\r\n    * Protein: 12.1g ', 67),
(344, 'cheese cake with magic bullet', '1 (8 oz.) package cream cheese\r\n2 eggs\r\n1/2 cup sugar\r\n1 tsp. vanilla\r\n1 graham cracker crust\r\nPreparation\r\n', 'First ... Add all the ingredients (except crust) to the Tall Cup and mix until smooth.\r\n\r\nThen .... Pour the ingredients into the graham cracker crust.\r\n\r\nAnd ... Bake at 350 degrees for 20-25 minutes (until set).\r\nServing Suggestion\r\nFruit toppings are always a scrumptious way to top a cheesecake. To make Strawberry Cheesecake, or Blueberry Cheesecake, fill the Short Cup up 3/4 of the way with your fresh strawberries or blueberries, add 1-2 tablespoons of sugar, and blend until you achieve a chunky syrup consistency. Pour that over the top of the cooled cheesecake (at least an hour in the refrigerator), then add a layer of sliced strawberries, or whole blueberries, to the top. Chill for a few hours, then serve.\r\nTip!\r\nTotally easy cherry topping: Just let your cheesecake cool for at least an hour in the refrigerator, then add a can of cherry topping to the top of it. Totally delicious and virtually effortless Cherry Cheesecake!\r\n	\r\nfooter', 'Delicious cheesecake has never been easier. In seconds, you can prepare the fluffiest, creamiest cheesecake to ever touch a fork!\r\nBefore you get started ... Preheat the oven to 350 degrees.\r\nThen...Blend everything together until smooth.', 45),
(345, '100% Whole Wheat Bread', '\r\n LARGE LOAF (1 1/2 lb/3 cup or 2 lb/4 cup machine)\r\n1 cup 	water 	250 mL\r\n1 	egg , beaten 	1\r\n2 tbsp 	butter or margarine 	30 mL\r\n2 tbsp 	honey 	30 mL\r\n3 cups 	ROBIN HOOD Best For Bread \r\nWhole Wheat Flour 	750 mL\r\n1 1/2 tsp 	salt 	7 mL\r\n1 1/4 tsp 	bread machine yeast 	6 mL', '\r\nSELECT loaf size.\r\n\r\nADD ingredients to machine according to manufacturerÃ¢â¬â¢s directions.\r\n\r\nSELECT Whole Wheat or White, Rapid or Regular Cycle.\r\n\r\n', 'The flavour of this bread is distinctive and hearty. Distinctive because of the sweet, nutty taste, and hearty because of its wholesome goodness. ItÃ¢â¬â¢s the perfect alternative for those of us who donÃ¢â¬â¢t really enjoy fruits and other added ingredients in bread.\r\n \r\n', 42),
(346, 'Artichoke dip', '1 pkg (250g) Cream cheese softened\r\n1 can or jar 10z artichoke hearts drained and chopped\r\n2 tbsp butter\r\n1 clove garlic minced\r\n1/4 cup 100% Parmesan Grated cheeswe\r\n\r\n\r\n', 'PREPARATION\r\n\r\n1) Spread cream cheese onto bottom of microwaveable 9 in pie plate\r\n2) |COMBINE artichokes,butter and garlic; Spoon evenly over cream cheese.Sprinkle with Parmesan cheese\r\n3) Microwave on High 1 min or until heated through.Serve with crackers', 'enjoy it is awesome\r\n\r\nbea', 56),
(347, 'Tomato Bruschetta with Fresh Basil', '2 large tomatoes ,diced (about 2 cups)\r\n1/4 c chopped fresh basil  ,lightly packed\r\n1 clove garlic minced\r\nsalt and pepper\r\n\r\n1/2 loaf French or italian bread or french baguette\r\n1 large clove garlic ,halved\r\n1 tbsp olive oil\r\n2  tbsp freshly grated parmesan cheese', '1. In bowl ,combine tomatoes,basil,minced garlic and salt and pepper to taste:let stand for 15 minutes or cover and refrigerate for up to 4 hours.\r\n2. Slice bread in one in thick slices.PlACE on baking sheet and broil until slightly browned on each side.Rub cut side of garlic clove over one side of bread :brush with olive oil\r\n3 Spoon tomato mixture over top.Sprinkle with parmesan .If mixture has been refrigerated broil bruschetta for 1 minute\r\n', 'enjoy\r\n\r\nbea', 42),
(348, 'Roasted chicken risotto with caramelized onions', '4 tbsp olive oil divided\r\n1 onion chopped\r\n1/2 cup balsamic vinegar\r\n1 1/2 cups uncooked Arborio RICE\r\n1/4 cup dry white wine\r\n7 cups hot chicken broth\r\n2 tbsp butter\r\n2 cups chopped cooked chicken breast\r\nsalt and pepper to taste\r\n2 tbsp chopped fresh thyme', '1. Heat 2 tbsp of the oil in a medium saucepan over medium heat. Stir in the onion and saute for 15 to 20 minutes or until onions are dark golden brown. Remove from heat,stir in the balsamic vinegar and set aside\r\n2. Heat the remaining oil in a separate large skillet over medium heat.Stir in the rice and mix well. Let heat for about 2 minutes,thne pour in the wine. Reduce heat to medium low and start pouring in the broth about 1 cup at a time. Add more broth as each cup is absorbed Continue in this manner until all the broth is absorbed  and the rice is dente,about 20 minutes\r\n3. Stir in the reserved onion mixture and allow to heat through. Remove from heat and stir in the butter and chicken. Season with salt and pepper to  taste and garnish each serving with fresh thyme', 'enjoy\r\n\r\nBEA', 54),
(349, 'Sweet and Sour spare ribs', '2 cups brown sugar\r\n1 cup white sugar\r\n1 garlic clove\r\nsoya sauce\r\nonions\r\nsalt &amp; pepper\r\nhoney or molasse can be added', 'boil spareribs for around 20 minutes, change water cook for another 20 minutes .Keep second water add ingredients put in oven for a while', '', 17),
(350, 'meat pie from jay gees restaurant', '5 lb ground pork\r\n5lbs ground beef\r\n1 3/4 cup onions\r\n3 1/2 cup water\r\n2 tabl salt\r\n1 tsp pepper\r\n1 tsp cinnamon (optional)\r\n1/3 tsp cloves\r\nmashed potatoes', 'n/a', '', 64),
(351, 'meatballs stew from jay gees restaurant', '5 lbs pork\r\n5 lbs beef\r\n1 3/4 cups onions\r\n1 scoop beef base\r\n1 scoop chicken base\r\n3 cups chopped turkey\r\n7 cups water', '', '', 17),
(352, 'Sweet and sour chicken (slow cooker', 'ketchup 2tbsp 30ml\r\nbrown sugar 1 cup 250ml\r\nwater 1 cup 250ml\r\nwhite vinegar 1/2 cup 125ml\r\nsoy sauce 1 tbsp 15ml\r\n\r\nwater 2tbsp 30ml\r\ncornstarch 2 tbsp 30ml\r\n\r\nchicken breasts 1 1/2 lbs 680g\r\n\r\n', 'combine first 5 ingredients in slow cooker. stir.\r\n\r\nAdd chicken. Stir. cover. Cook on Low for 6 to 8... hours or on High for 3 to 4 hours.\r\n\r\nCombine cornstarch and second amount of water in small bowl. Stir into slow cooker. cook on High, stirring often for 15 to 20 mins until thickened. For faster cooking, pour into saucepan. heat on stove, stirring often serves 6.\r\n\r\nI usually have to put it in the sauce pan so it thickens and add more cornstarch.\r\n\r\n', 'You can use pork if you want too. or double the recipe if you want leftovers. It freezes awesome. I usually put 3 chicken breasts in', 41),
(353, 'chicken with tomatoes', '2 chicken breasts, cubed\r\n1 can of tomatoes, diced with italian seasoning\r\n1 pkg of Stove Top stuffing, for chicken\r\n1 Cup Mozarella Cheese, shredded\r\n\r\n', 'preheat oven to 350\r\nMix tomatoes and stove top together, set aside\r\nplace chicken in baking dish, cover with cheese\r\nspread mix over top\r\nbake covered for 20 minutes, uncover and bake for an additional ten minutes\r\nor until brown and bubbling.', '', 54),
(354, 'Chocolats Mess', 'spray crockpot with pam , sprinkle in 1 chocolate cake mix,then add 3/4 cup vegtable oil,1 pint sour cream,4 eggs 1 pkg chocolate instant pudding , and fold in 6 ounces chocolate chips . cook 6-8 hours in slowcooker and whatever you do NO PEEKING , then serve with vanilla ice cream ! this is soo good', '', '', 40),
(355, 'white bread from facebook', '1 cup warm water\r\n2 tablespoons white surgar\r\n1 package bread machine yeast... Read More\r\n1/4 cup vegetable oil\r\n3 cups bread flour\r\n1 teaspoon salt\r\n\r\nPlace the water, sugar and yeast in the pan of the bread machine. Let the yeast dissolve and foam for 10 minutes. Add the oil, flour and salt to the yeast mixture. Select Basic or White Bread setting, and press Start. ', '', '', 42),
(356, 'Cherry Dump Cake (facebook)', 'Empty out a can of Cherry Pie Filling into a 9x12 baking dish. Spread it around. Layer on a can of crushed pineapple, then sprinkle dry yellow cake mix on top. Melt a stick of butter or margarine and drizzle it over the top. Some people us...e 2. Options: Over top of the butter, you can add pecans, coconut or both. Bake at 350 for 45-50 minutes. So good!!', '', '', 45),
(357, 'slow cooker bbq pulled pork', '1 boneless pork shoulder ( approx 3 lbs.)\r\n1/2 tsp salt and pepper\r\n3 medium onions, separated into rings\r\n3/4 cup Bull\'s eye bbq sauce\r\n\r\n', 'Place meat in slow cooker, sprinkle with salt and pepper. Top with onions and bbq sauce. Cover. Cook on high fo...r 4 to 6 hours or on low for 8 to 10 hours. Remove the meat by pulling apart and return to sauce in the cooker.', '', 17),
(358, 'Slow Cooker Pepper Steak ', '2 pounds beef sirloin, cut into 2 inch strips\r\ngarlic powder to taste\r\n3 tablespoons vegetable oil\r\n1 cube beef bouillon\r\n1/4 cup hot water\r\n1 tablespoon cornstarch\r\n1/2 cup chopped onion\r\n2 large green bell peppers, roughly chopped\r\n1 (14.5 ounce) can stewed tomatoes, with liquid\r\n3 tablespoons soy sauce\r\n1 teaspoon white sugar\r\n1 teaspoon salt', '', 'Serve over your favourite noodle or rice!', 17),
(359, 'Hamburger Soup', 'Ingredients :\r\n2 packs hamburger\r\n10 nice size potatoes\r\n5 nice size carrots\r\n1 onion\r\n1 small can corn\r\n3 stalks of celery\r\n(1/2 can of peas if you like em)\r\n1/2 pack of onion soup mix\r\na pinch of Garlic Salt\r\nsalt n pepper to taste ...\r\n\r\n\r\n', 'Fry hamburger with some of the onion\r\npeel , cut n wash all veggies that need it ...\r\n\r\nPut all your vegies in a big pot of water, bring to a boil ....let it boil for about 5 minutes\r\nNow put your hamburger n garlic salt n soup mix in ......\r\nReduce the heat .. and let simmer for about 30 mins ... ENJOY !', 'this really good if you add V8 juice for your base!', 62),
(360, 'potato casserole', '8 medium potatoes (about 2 1/2 to 3 lb. total), peeled and cut into equal chunks\r\n1 cup Carnation evaporated milk\r\n1/2 cup sour cream\r\n1 teaspoon salt\r\n1/2 teaspoon ground black pepper\r\n2 cups (8-oz. pkg.) shredded cheddar cheese, divided\r\n6 slices bacon, cooked and crumbled, divided\r\nsliced green onions (optional)', 'Boil your potatoes with salt.  mash with sour cream and carnation milk and pepper. add cheese, bacon, green onions. keep some of the cheese bacon and green onions to put on top. bake for 25 minutes. add rest of cheese,onions and bacon.  bake again for 5 minutes to melt the cheese', '', 61),
(361, 'Chicken Nugget casserole', '1 package (13-1/2 ounces) chicken nuggets\r\n1/3 cup grated parmesan cheese\r\n1 can (26-1/2 ounces) spaghetti sauce\r\n1 cup shredded mozzarella cheese\r\n1 teaspoon italian seasoning\r\n\r\n', 'Place chicken nuggets in a greased 11-in x 7-in x2-in. baking dish\r\nSprinkle with parmes...an cheese. Top with spaghetti sauce, mozzarella cheese and Italian seasoning.Cover and bake at 350 degrees for 30-35 minutes or until chicken is heated through and cheese is melted\r\n', '', 54),
(362, 'baked spaghetti', '...but sorry, I cook by the seat of my pants, so no measurements, add as you like. Cook as much spaghetti as your family normally eats, rinse with cold water. Grate approx. 1 lb. old cheddar, mix with the cold spaghetti. Butter a large casserole dish (the flatter, the bet...ter), add the spaghetti mixture (spread it out to cover the pan). Chop onions (I like lots), ok, about 6 if you\'re shy about it, fry in a small amount of oil until tender. Add one or two cans of tomatoes (break them up with your hands so they\'re not whole), cook with the onions until some of the water has evaporated (maybe 5-10 min). Pour this mixture over the spaghetti mixture, spread evenly. Cut 1 lb. bacon into small pieces (cut each slice in 4) and layer over the top (it should be completely covered). Bake at 325-350 for about an hour or until bacon is done. sinful and yummy.', 'n/a', '', 57),
(363, 'meatloaf recipe', '2 lbs. ground beef, l pkg. stove top stuffing mix for chicken, 1 cup of warm water, 2 eggs, and 1/2 cup of BBQ sauce(1/2 for the recipe and 1/2 for the top)--', '', '-this recipe makes 2 loaves, or you can cut back the meat(say 1 1/2 lbs) and make a large one . Bake at 375 for about an hour or until done. EnjoyMakes good meatballs too, just eliminate the bbq sauce  yu can use tomato soup instead of barbecue sauce', 17),
(364, 'great meatloaf', 'Combine 1/2 cup milk, 3/4 cup bread crumbs and 1 egg. To this add 2 tbsp ketchup, 1 tbsp mustard, 1/4 cup dried minced onion, 1 tsp salt, 1/2 tbsp Worcestershire sauce and mix well. Add 1 lb ground beef. Mix well. Press into a greased loaf pan. Top with crushed crackers (Ritz or Veggie Thins). ', 'Cover with foil. Bake at 375 for 1 1/4 hours. (p.s. if you line the pan with foil it makes for real easy clean up -still grease it though)\r\n2 hours ago ÃÂ· Report', '', 17),
(365, 'Skor Toffee Squares', '1 - Package of SKOR bar chips (made by ChipIts)\r\n1 - Box of Ritz Crackers, crushed\r\n1 - Can of Sweetened Condensed Milk\r\n', 'Crush Ritz crackers with rolling pin (if you leave them in the bag it is less messy). Add the can of milk. Mix all ingredients and press into an 8x8 well greased pan. Bake at 350 for 20 minutes, let it cool and enjoy', '', 40),
(366, 'Cabbage Rolls', '2 cups cooked rice I use preboiled just cause I preferit\r\n1/2 tsp each of salt,pepper,paprika\r\n1/2 cup chopped celery... Read More\r\n1 medium onion chopped fine\r\n1/2 pound each of groud beef and ground pork but can use all just pork if u prefer I use whatever our store has in at the time.\r\n2 med heads of cabbage\r\n5 cans campbells tomato soup\r\n1 can tomato sauce\r\nhandful of brown sugar.\r\n\r\n', 'Boil cabbage in rapid boiling water. Slice it first around the top so the pieces fall off in the water.\r\nMix all ingredients with 1 can of tomato soup. ( keep other 4 cans and tomato sauce to go on rolled cabbage rolls.\r\nOnce rolled up place in large greased casserole pan and top with the 4 cans of tomato soup 1 can of tomato sauce and handful of brown sugar.. You need to add a few cans of water to this. Judge how much.. You dont want it too thick but not too thin..\r\n\r\nthen cook at about 350 for about 1.5 hours.. Test to see if done\r\nI usually double this recipe.. We love it ..Very tasty.. ', 'one tip; use the wrinkly cabbage(savoy i think it\'s called) much easier to roll and work with:)\r\nFreeze the cabbage. Thaw out thoroughly and leaves are easily removed. Works well for me..\r\n.We actually used purple cabbage leaves the last time we made cabbage rolls. Tasted better in my opinion! the purple cabbage was a bit sweeeter. AND you can use the water you boil the leaves in to cook pasta later on and have a blue couloired pasta salad to go with the cabbage rolls!', 17),
(367, 'Caramel Apple Dip- Amazing Appetizer!!', 'Mix one package of Phillidelphia Cream Cheese with 4 tbsp brown sugar.\r\nSmooth evenly over large serving plate.\r\nLayer caramel spread (not caramel ice cream topper--too runny!) over cream cheese.\r\nGenerously top with Skor bar bits.\r\n\r\nUse sliced, unpeeled apples, to dip!!!\r\n\r\nDelicious!!!', 'n/a', '', 34),
(368, 'CHICKEN STUFFING BAKE', '1 can cream mushroom soup, undiluted\r\n1 can milk\r\n1 box stovetop\r\n2 cups cooked chicken breasts\r\n2 cups cooked broccol: florets, fresh\r\n1 and one half cup shredded cheese\r\nmix soup and milk. add all other ingredients in large bowl\r\npour into 9/13 casserole dish. add more cheese and cover. bake\r\n@375 for 20 minutes. or untill cheese is melted. DELICIOUS.\r\nto make more just double the recipe.', 'n/a', '', 54),
(369, 'One Dish Chicken and Stuffing', '4 or more chicken breasts, boneless and skinless\r\n1/4 cup margarine\r\n1 pkg. Stove Top stuffing mix\r\n1 can mushroom soup\r\n1/3 cup milk\r\n1 1/2 cups hot water\r\n', 'Mix stuffing crumbs, margarine and hot water together. Set aside. Place chicken in 9 X 13 inch bakin...g dish. Mix soup and milk and pour over chicken. Top with stuffing. Back at 375 for 35-45 minutes or until chicken is cooked through.', '', 54),
(370, 'Mac \' N Cheeseburger Casserole', '1 lb (500 g)extra lean ground beef\r\n2 cups (500 mL) sliced mushrooms\r\n1 cup (250 mL) chopped red and yellow peppers\r\n1/2 cup (125 mL) each, chopped onions and chopped celery\r\n1 can (14 oz) Hunts stewed tomatoes, undrained\r\n1 can (284 mL) CAMPBELL\'SÃÂ® Condensed Low Fat ...Cream of Mushroom Soup\r\n2 cups (500 mL) uncooked Primo whole wheat elbow pasta\r\n2 tbsp (30 mL) Worcestershire sauce\r\n1 tbsp (15 mL) chili powder\r\n1/4 cup (60 mL) shredded sharp Kraft Cheddar cheese', '', ' - Quick and yummy anytime meal!\r\nI make something like this...only I dice chicken breast and omit the cream of mushroom soup...Super yummy and my girls (4 &amp; 2) gobble it up...Makes a Mommy happy! Oh, and I add way more cheese...lol', 17),
(654, 'Easy Bruschetta Recipe', '\r\nBruschetta\r\n2 lb beefsteak tomatoes* de-seeded and diced\r\n3 tbs fresh basil chopped fine\r\n3 tbs parmesan cheese freshly shredded\r\n1 tbs olive oil\r\n1 tbs garlic minced\r\nsalt and pepper to taste\r\nFrench Bread\r\n1 baguette cut into Â½ inch slices\r\n1-2 tbs extra virgin olive oil\r\n1-2 whole garlic cloves\r\n', 'Instructions\r\nIn a large bowl, combine all bruschetta ingredients and stir together. All ingredients can be adjusted to personal taste. Allow to rest for 10 minutes.\r\nMeanwhile, preheat oven to 325 degrees. Place french bread slices on a baking sheet. Drizzle with olive oil and bake for 5-7 minutes or until lightly browned. \r\nImmediately out of the oven, rub the tops of the bread slices with garlic cloves a few times. Allow to cool and serve with bruschetta.', 'Made with ripe tomatoes, fresh basil, garlic and olive oil served on top of garlic-rubbed toasted crusty bread.\r\nPrep Time\r\n\r\n10minutes mins\r\nCook Time\r\n7minutes minS\r\nTotal Time\r\n17minutes \r\nNotes\r\n*I have also used Roma or vine ripened tomatoes with great success.\r\nTo make ahead: Prepare up to 1 day in advance and store in the refrigerator in an airtight container until ready to serve. Toast baguette slices just before serving for optimal freshness.\r\nStorage instructions: Store leftover bruschetta in an airtight container in the refrigerator for up to 3 days.\r\n', 34),
(372, 'chicken with smashed potatoes, potpie', '    * 1 1/2 pound(s) baby red potatoes, each cut in half\r\n    * 1 tablespoon(s) vegetable oil\r\n    * 4 medium (about 1 1/4 pounds) skinless, boneless chicken-breast halves\r\n    * 1/2 teaspoon(s) salt\r\n    * 1/4 teaspoon(s) ground black pepper\r\n    * 1 1/2 cup(s) (about half 10-ounce bag) matchstick-thin carrots\r\n    * 1 cup(s) chicken broth\r\n    * 1/4 cup(s) heavy or whipping cream\r\n    * 1/2 teaspoon(s) dried tarragon, crumbled\r\n    * 1 cup(s) tiny frozen peas, thawed\r\n    * 1 tablespoon(s) margarine or butter\r\n    * Tarragon sprigs for garnish\r\n\r\n\r\n\r\n ', '  1. In 5-quart Dutch oven, place potatoes with water to cover; heat to boiling over high heat. Reduce heat to low; cover and simmer 12 minutes or until potatoes are fork-tender.\r\n   2. While potatoes are cooking, in nonstick 12-inch skillet, heat oil over medium-high heat until hot. Add chicken and sprinkle with 1/4 teaspoon salt and 1/8 teaspoon pepper; cook 6 minutes. Turn chicken over. Reduce heat to medium; cover and cook 8 minutes longer or until juices run clear when thickest part of chicken is pierced with knife. Transfer chicken to plate; keep warm.\r\n   3. To same skillet, add carrots, broth, cream, and dried tarragon; cover and cook over medium-high heat 5 minutes or until carrots are tender. Remove skillet from heat and stir in peas.\r\n   4. Coarsely mash potatoes with margarine and remaining salt and pepper.\r\n   5. Spoon potatoes onto platter; top with chicken and vegetable mixture. Garnish with tarragon.\r\n\r\nTips &amp; Techniques\r\n\r\nFor a leaner version that cuts the fat by 6 grams, increase broth by 1/4 cup and omit cream.\r\n', '', 61),
(373, 'caramel apple pie', '-4-6 large red apples, sliced\r\n1/2 cup sugar\r\n1/2 cup brown sugar\r\n6 tbsp unsalted butter\r\npinch of salt\r\n1/4 tsp cinnamon\r\n1/4 cup water\r\n1 package Pillsbury Pie Crust, or pie dough for a double-crust 9&quot; pie\r\n ', 'cook ingredients let it boil.\r\nput pie crust in bottom.  add apples slice I leave the red peel on the apples in this pie, which not only adds nutritional value, but also gives the filling a beautiful color. I used Gala apples, and after the pie was cooked, the skin was perfectly tender, and almost disappeared into the filling. Be sure to let this pie cool completely! Since there is no starch to bind the apples, the caramel/apple syrup in the filling will not set while warm.\r\n\r\nTo me, this is the purest and most intensely flavored apple pie recipe there is. The interesting thing about this recipe is the way the caramel sauce is poured over the apples and the lattice crust. You know how with a traditional apple pie some of the apple juices will caramelize as it bakes and bubble out of the pie and bake into and onto the flaky crust? You know how awesomely chewy-flaky-sticky-crumbly that part is? That\'s how this whole pie is. Enjoy!', 'you put the syrup on top of the pie after the top is on.', 64),
(374, 'Strawberry Brownies', '\r\nBottom/Crust: 2 oz dark chocolate, 1/4 cup butter, 1 egg, 1/2 c...up sugar, 1 tsp vanilla, 1/3 cup flour\r\n\r\nTopping: 2 cups of fresh or frozen sliced strawberries, 1 oz dark chocolate\r\n', 'Grease an 8x8 casserole dish and preheat oven to 375. Melt the 2 oz of chocolate and 1/4 butter in the microwave. Stir until smooth. In another bowl beat the egg, sugar and vanilla for 2 minutes until almost frothy. Slowly pour in the chocolate/butter mixture, stirring as you go. Fold in the flour (careful not to overmix). Pour into the greased pan and bake for 15-17 minutes (until a toothpick comes out with a few crumbs on it)\r\n\r\nLet cool for 5 minutes, then scatter the strawberries over top. (If strawberries are frozen, be sure to thaw and drain before adding on top of the brownie base). Melt the last 1 oz of chocolate and drizzle on top', '', 40),
(375, 'Spinach Dips ', '10oz pkg frozen chopped spinach thawed and drained as dry as you can get it, Iuse paper towels to dry it well\r\n2 cups Sour Cream\r\n1 Cup Miracle Whip\r\n1 pkg Knorr dry Veg soup mix\r\n3-4 strips of crisp bacon broken in small pieces\r\n2-3 chopped green onion\r\n', 'Mix,Chill for 2 hours. I usually use hollowed out pumperknicle or any round bread will do. Put mixture in this just before serving and put the scraps of bread with it ', '', 56),
(377, ' Easy Peasy Pastery', '5 cups all purpose flour\r\n1lbs lard\r\n1 can ice cold Gingerale.\r\nGingerale provides the sugar and the carbonation makes it light and fluffy. ', 'n/a', '7 up works too', 64),
(378, 'Slow Cooker Hot Fudge Sundae Cake', '1 cup all-purpose flour\r\n1/2 cup granulated sugar\r\n2 tablespoons baking cocoa\r\n2 teaspoons baking powder\r\n1/2 teaspoon salt\r\n1/2 cup milk\r\n2 tablespoons vegetable oil\r\n1 teaspoon vanilla\r\n1/2 cup chopped nuts\r\n3/4 cup packed brown sugar\r\n1/4 cup baking cocoa\r\n1 1/2 cups hot water', '1.Spray inside of 2- to 3 1.../2-quart slow cooker with cooking spray. Mix flour, granulated sugar, 2 tablespoons cocoa, the baking powder and salt in medium bowl. Stir in milk, oil and vanilla until smooth. Stir in nuts. Spread batter evenly in slow cooker.\r\n2.Mix brown sugar and 1/4 cup cocoa in small bowl. Stir in hot water until smooth. Pour evenly over batter in slow cooker.\r\n3.Cover and cook on high heat setting 2 hours to 2 hours 30 minutes or until toothpick inserted in center comes out clean.\r\n4.Turn off slow cooker. Let cake stand uncovered 30 to 40 minutes to cool slightly before serving. Spoon warm cake into dessert dishes. Spoon sauce over top.', '', 41),
(379, 'The Extreme Cherry Cake', '1 cup butter\r\n2 cups white sugar\r\n6 eggs\r\n1 tablespoon vanilla extract\r\n1/2 teaspoon red food color\r\n3 cups all-purpose flour\r\n1 tablespoon baking powder\r\n1/4 cup maraschino cherry juice\r\n14 maraschino cherries, chopped\r\n', '1. 	Preheat oven to 350 degrees F (175 degrees C). Grease and flour 2 - 9 inch round pans. Sift together the flour and baking powder. Set aside.\r\n2. 	In a large bowl, cream together the butter and sugar until light and fluffy. Beat in the eggs one at a time, then stir in the vanilla and red food color. Beat in the flour mixture alternately with the cherry juice. Stir in the cherries. Pour batter into prepared pans.\r\n3. 	Bake in the preheated oven for 45 minutes, or until a toothpick inserted into the center of the cake comes out clean. Allow to cool.', 'Prep Time: 20 Minutes\r\nCook Time: 45 Minutes\r\n	\r\nReady In: 1 Hour 45 Minutes\r\nServings: 12\r\n&quot;A very cherry cake with maraschino cherries and red food color for that extra burst of color.&quot;', 45),
(380, 'Fluffy Boiled Icing', '1 cup white sugar\r\n1/3 cup water\r\n1 tablespoon light corn syrup\r\n1/8 teaspoon salt\r\n	\r\n2 egg whites\r\n1 teaspoon vanilla extract\r\n3 tablespoons confectioners\' sugar\r\nDirections:\r\n', '1. 	Combine sugar, water, corn syrup, and salt in a saucepan; stir until well blended. Boil slowly without stirring until mixture will spin a long thread when a little is dropped from a spoon (hold the spoon high above saucepan), or reaches 238 - 242 degrees F (114 - 117 degrees C).\r\n2. 	In a large bowl, beat egg whites with a mixer until they are stiff, but still moist. Pour hot syrup slowly over egg whites while beating. Continue until mixture is very fluffy, and will hold its shape. Add vanilla, and beat until blended. If icing does not seem stiff enough, beat in 2 or 3 tablespoons confectioners sugar 1 tablespoon at a time until stiff enough to hold its shape. Spread on cake.', '', 44),
(381, 'Brownie Icing', '    * 6 tablespoons milk\r\n    * 6 tablespoons butter, softened\r\n    * 1 1/2 cups white sugar\r\n    * 1 cup chocolate chips\r\n    * 1 dash vanilla extract\r\n\r\n', '   1. Combine the milk, butter, and sugar together in a saucepan and bring to a boil; allow to cook at a rolling boil for 30 seconds and immediately remove from heat. Add the chocolate chips and vanilla to the milk mixture and stir until the chips are completely melted. Pour immediately over warm brownies.\r\n\r\n', 'Original Recipe Yield 1 9x13-inch pan of brownies\r\n Nutritional Information open nutritional information\r\n\r\nAmount Per Serving  Calories: 219 | Total Fat: 10.1g | Cholesterol: 16mg', 44),
(382, 'can frosting with nutella', '    * 1 (16 ounce) can prepared chocolate frosting\r\n    * 3/4 cup chocolate-hazelnut spread (such as NutellaÃÂ®)\r\n    * 3/4 cup confectioners\' sugar\r\n    * 1 teaspoon vanilla ext\r\n\r\n', '   1. Combine the chocolate frosting, chocolate-hazelnut spread, confectioners\' sugar, and vanilla extract in a large bowl. Use an electric mixer to beat until well blended and fluffy, about 2 minutes.\r\n\r\n\r\n', 'Amount Per Serving  Calories: 143 | Total Fat: 6.1g | Cholesterol: 0mg', 44),
(383, 'caramel icing', '    * 1/4 cup butter\r\n    * 3/4 cup brown sugar\r\n    * 1/4 cup heavy cream\r\n    * 2 cups confectioners\' sugar\r\n\r\n\r\n\r\n  ', ' 1. Place the butter and brown sugar in a heavy saucepan over low-medium heat; cook and stir until the sugar dissolves and the mixture boils. Stir in the cream, return to a boil, and boil for 1 minute. Remove from the heat and cool.\r\n   2. Beat in the powdered sugar until smooth.\r\n\r\n', 'Nutritional Information open nutritional information\r\n\r\nAmount Per Serving  Calories: 163 | Total Fat: 5.7g | Cholesterol: 17mg\r\nThis icing has been used every time I have made the Banana Cake X and freezes so well. ', 44),
(384, 'Banana Cake X', '    * 2 tablespoons lemon juice\r\n    * 2/3 cup milk\r\n    * 2 large very ripe bananas, mashed\r\n    * 1 (18.25 ounce) package butter cake mix\r\n    * 1 teaspoon baking soda\r\n    * 1/2 cup butter, softened\r\n    * 3 eggs\r\n    * 1 teaspoon vanilla extract\r\n\r\n\r\n  ', ' 1. Preheat oven to 350 degrees F (175 degrees C). Grease and flour a 9x13 inch pan. Put 1 tablespoon lemon juice in a measuring cup with 2/3 cup milk. Set aside. Mash bananas with a fork, adding the remaining 1 tablespoon lemon juice to them as you mash. Set aside.\r\n   2. In a large bowl, combine cake mix and baking soda. Stir to combine. Add bananas, softened butter, milk mixture, eggs and vanilla. Beat at low speed until moistened (about 30 seconds). Beat at medium speed for 4 minutes. Pour into prepared pan.\r\n   3. Bake in the preheated oven for 30 to 35 minutes, or until center of cake springs back when lightly tapped. A toothpick stuck in the center may leave a slight crumb. Allow to cool on a wire rack.\r\n\r\n', 'Original Recipe Yield 1 - 9x13 inch pan\r\nNutritional Information open nutritional information\r\n&quot;This is an incredibly moist banana cake from a mix... I always serve it with caramel icing and get raves every time!&quot;\r\n\r\nAmount Per Serving  Calories: 284 | Total Fat: 12.3g | Cholesterol: 75mg', 45),
(385, 'banana loaf 2 (more like a cake)', '    *   1 (18.25 ounce) package yellow cake mix\r\n    * 1 (3.5 ounce) package instant banana pudding mix\r\n    * 1/2 cup mashed banana\r\n    * 4 eggs\r\n    * 1 cup water\r\n    * 1/4 cup vegetable oil\r\n    * 1/2 cup chopped walnuts\r\n\r\n\r\n\r\n   ', '1. Preheat oven to 350 degrees F (175 degrees C). Grease and flour two 8x4 inch loaf pans.\r\n   2. In a medium bowl, stir together the cake mix and instant pudding. Add the eggs, oil, water and mashed banana, mix with an electric mixer until smooth. Fold in the chopped nuts. Pour evenly into the prepared pans.\r\n   3. Bake for 50 to 55 minutes in the preheated oven, until a toothpick inserted comes out clean. Cool in pans for 15 minutes before removing to cool completely on wire racks.\r\n\r\n', 'Nutritional Information open nutritional information\r\n\r\nAmount Per Serving  Calories: 161 | Total Fat: 7.3g | Cholesterol: 36mg', 45),
(386, 'Zesty Apple Mashed Potatoes', '4 medium yellow-fleshed or oblong baking-style potatoes (about 2 lbs/1 kg)\r\n1 large tart apple\r\nSalt\r\n3/4 cup (175 mL) milk, heated\r\n1 tbsp (15 mL) Dijon mustard\r\n1 cup (250 mL) shredded Canadian Swiss or old Canadian Cheddar cheese, divided\r\n1/4 tsp (1 mL) pepper\r\n', 'Peel potatoes and cut into quarters. In a pot, cover potatoes with cold water and bring to boil over high heat.\r\nMeanwhile, peel apple and cut into quarters. Cut out stem and core.\r\nSeason boiling water with salt and stir in apple. Reduce heat and simmer for about 20 min or until potatoes are fork tender. Drain; return pot to low heat for 1 min to dry, shaking pan.\r\nRemove pot from heat. Mash potatoes and apple while gradually adding warmed milk and mustard. Mash in 3/4 cup (175 mL) of the cheese, 1/4 tsp (1 mL) salt or to taste and pepper until blended. Transfer to a serving bowl and sprinkle with remaining cheese.', '', 61),
(387, 'Cheese Ball', ' 2 8 oz. pkg. of cream cheese\r\n\r\n1 8 oz. pkg. Cheddar cheese\r\n\r\n1 tsp. Worcestershire\r\n\r\ndash salt\r\n\r\n1 tsp. onion powder\r\n\r\n1 pkg. walnuts, chopped fine\r\n\r\n\r\n\r\n', 'Let cream cheese soften.\r\n\r\nGrate Cheddar cheese. Mix with everything but nuts.Form into a ball, then roll into nuts.', '', 34),
(388, 'Oreo balls', ' Take a package of oreo cookies and crush them up. Cream a package of cream cheese and mix in the oreo crumbs. Form into balls and dip in chocolate. She used a package of chocolate chips with a bit o...f shortening to make it harden a bit. Refrigerate. She also made some using mint chocolate chips.', 'n/a', '', 58),
(389, 'Perogy and Ham Casserole', '16 - 20 Perogies\r\n1 Onion, chopped\r\n1/4 cup Milk\r\n1 tbsp. Butter or Margarine\r\n1/2 cup Cooked Ham, diced\r\n1 Green Pepper, diced\r\n1/4 cup Cheddar Cheese, shredded\r\n10 oz. can Condensed Mushroom Soup\r\n\r\n', '... In a small skillet m...elt butter or margarine and sautÃÂ© onion and green pepper for 5 minutes. In a medium size casserole dish, combine frozen perogies, onion, green pepper, and ham. Combine milk and mushroom soup and pour over casserole. Top with cheddar cheese.\r\n\r\nBake 35 minutes at 175ÃÂºC (350ÃÂºF), or microwave until heated through.', '', 22),
(390, 'meatballs', 'Cook up a batch of meatballs, then put into oven safe dish preferably without stacking them up. Take equal amounts Heinz Chili sauce and Grape jelly ( I use one cup of each for a batch of meatballs large enough to serve 4 hungry adults). Heat slowly till sauce comes to a boil; pour sauce o...ver meatballs, cover and cook in 325 oven for 30 minutes.\r\n\r\nI know it sounds like a crazy combo, but it is amazing...enjoy!', '', 'I slopped my favorite cranberry jelly from the can, (my favorite) and on the label it suggested to use the cranberry jelly in place of grape jelly. It sounded like a good match. I think I\'ll try it. But I totally agree with this yummy recipe.', 17),
(391, 'homemade butterscotch pudding', '1/2 cup brown sugar\r\n1/4 cup butter\r\n2 cups milk\r\n1/2 cup boiling water\r\ncornstarch (I just add in slowly until it\'s thick enough)\r\n\r\n', 'on meduim heat melt butter\r\nadd brown sugar and caramelize\r\nslowly add boiling water (caution it\'ll be very hot and steamy so pour slowly)\r\nstir unti...l sugar is melted with the water\r\nadd milk continue stirring\r\nmake a paste with approx 2 tbl cornstarch and about 1/4 cup water\r\nslowly add cornstarch mixture to pudding until desired thickness\r\npour into dishes cool\r\n\r\n', 'very tasty! I like to put sliced bananas on top with a bit of whip cream', 40),
(392, ' Lazy Perogy Casserole', '15 lasagne noodles\r\n2 c cottage cheese\r\n1 egg\r\n1/4 ts onion salt\r\n1 c shredded cheddar cheese\r\n2 c mashed potato\r\n1/4 ts salt\r\n1/4 ts onion salt\r\n1/8 ts pepper\r\n1 c butter or margarine\r\n1 c chopped onions\r\n', 'Cook noodles as directed on package. Drain. Line bottom of 9x13 inch\r\npan.In medi...um-sized bowl, mix cottage cheese, egg and onion salt together.\r\nSpoon over noodles and spread. Cover with layer of noodles.In same bowl, mix Cheddar cheese with potato, salt, onion salt and\r\npepper. Spread over noodles. Cover with layer of noodles.Melt butter in frying pan. Saute onions slowly until clear and soft.\r\nPour over noodles. Cover. Bake 30 minutes in 350ÃÂ°F oven. Let stand\r\n10 minutes before cutting. Serve with sour cream.', 'Yield: 8 large Servings\r\nadded a little more seasonings, garlic and herb salt. I also added cooked crumbled bacon to the mashed potatoe mixture and extra cheese on top. Served with extra sour cream on top too.', 22),
(393, 'chicken parmesan', '.first boil chicken. Then place breasts in a 9x13 pan or any pan that all breasts will fit it. sprinkle with salt, pepper, roasted red pepper and garlic spices. Dollop a spoon of mushroom soup on top of each breast and spread out just a little then sprinkle on each breast some bacon bits and shredded cheddar cheese. bake in 350 degree oven til heated thru and cheese meilts. before serving you may add a little chopped green onion. ENJOY', 'n/a', '', 54),
(394, 'Snappy Chicken', '1 cup sliced onion\r\n12 skinless chicken thights\r\n1 cup whole cranberry sauce\r\n1 pack beef bouillon\r\n1 tsp cider vinegar\r\n1tsp prepared mustard\r\nsalt and pepper\r\n', 'Put onions in then put chicken over them .Mix all the other ingr .Spoon over the chicken being sure to get every piece.... Cover and cook on low for 6 to 8 hours or high for 3 to 4 hours .So good over rice .', '', 54),
(395, 'Scottish Whipped Shortbread', '1 lbs.butter... See More\r\n1 cup icing sugar\r\nÃÂ½ cup cornstarch\r\n3 cups flour\r\n1 tsp. Vanilla extract\r\n\r\n', '1. Preheat oven to 350F\r\n2. Line cookie sheets with parchment paper if possible\r\n3. Cream butter (which means soften and mix well with spoon)\r\n4. Sift together icing sugar, cornstarch, and flour\r\n5. Put butter, dry ingredients and vanilla in electric mixer and beat until consistency of whipped cream\r\n6. Drop by teaspoon onto cookie sheet\r\n7. Can decorate with sprinkles, green or red cherries (canned) or marked with floured fork\r\n8. Bake at 350F for 15-20 minutes\r\n9. Can be stored in covered tin\r\n10. Eat until guilty feeling sets in\r\n9 hours', '', 40),
(396, 'Chunky toblerone Shortbread cookies!', ' 2 cups butter, softened\r\n1 cup fine sugar\r\n3 1/2 cups flour\r\n1/2 cornstarch\r\n2 100 g bars Toblerone chocolate, chopped\r\n3 Tbsp sifted icing sugar\r\n', 'Directions Preheat oven to 350\r\nBeat butter and sugar in large bowl with electric mixer on high speed until light and fluffy.\r\nCombine flou...r and cornstarch. Gradually add to butter mixture, beating until well blended. Stir in chocolate.Drop by heaping tablespoonfuls onto ungreased baking sheets, about 1&quot; apart.Bake 20 to 25 minutes or until lightly browned. Cool 5 minutes on baking sheet. Sprinkle with icing sugar. Remove to wire racks and cool completely. These are awesome!\r\n', '', 58);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(397, 'Oatmeal Cake with Coconut Pecan Frosting', '    * 1/2 cup quick cooking oatmeal\r\n    * 3/4 cups boiling water\r\n    * 1/2 cup sugar\r\n    * 1/2 cup brown sugar\r\n    * 2/3 cups flour\r\n    * 1/2 tsp salt\r\n    * 1/2 tsp baking soda\r\n    * 1 egg\r\n    * 1/4 cup of shortening', 'Mix the oatmeal with the boiling water, stir and cover. Mix the remaining ingredients then stir in the oatmeal mixture. Grease and flour a 9x9 pan. Pour batter into pan and bake at 350 for 23-25 minutes.', 'Coconut Pecan Frosting:\r\n\r\n    * 3 tbsp melted butter\r\n    * 1/3 cup brown sugar\r\n    * 1/2 cup sweetened shredded coconut\r\n    * 1/2 cup chopped nuts\r\n    * 2 tbsp milk\r\n    * 1/2 tsp vanilla\r\nCombine all ingredients and mix thoroughly. Carefully spread frosting over the top of the cake. Broil until coconut is just brown. Watch very closely Ã¢â¬â it doesnÃ¢â¬â¢t take long. Cool, slice and serve. Enjoy.', 45),
(398, 'cinnamon rolls', '1 cup warm milk (110 degrees F/45 degrees C)\r\n2 eggs, room temperature\r\n1/3 cup margarine, melted\r\n4 1/2 cups bread flour... See More\r\n1 teaspoon salt\r\n1/2 cup white sugar\r\n2 1/2 teaspoons bread machine yeast\r\n\r\n1 cup brown sugar, packed\r\n2 1/2 tablespoons ground cinnamon\r\n1/3 cup butter, softened\r\n\r\n1 (3 ounce) package cream cheese, softened\r\n1/4 cup butter, softened\r\n1 1/2 cups confectioners\' sugar\r\n1/2 teaspoon vanilla extract\r\n1/8 teaspoon salt\r\n', '1.Place ingredients in the pan of the bread machine in the order recommended by the manufacturer. Select dough cycle; press Start.\r\n\r\n2.After the dough has doubled in size turn it out onto a lightly floured surface, cover and let rest for 10 minutes. In a small bowl, combine brown sugar and cinnamon.\r\n\r\n3.Roll dough into a 16x21 inch rectangle. Spread dough with 1/3 cup butter and sprinkle evenly with sugar/cinnamon mixture. Roll up dough and cut into 12 rolls. Place rolls in a lightly greased 9x13 inch baking pan. Cover and let rise until nearly doubled, about 30 minutes. Meanwhile, preheat oven to 400 degrees F (200 degrees C).\r\n\r\n4.Bake rolls in preheated oven until golden brown, about 15 minutes. While rolls are baking, beat together cream cheese, 1/4 cup butter, confectioners\' sugar, vanilla extract and salt. Spread frosting on warm rolls before serving.', '', 42),
(399, ' 5 MINUTE CHOCOLATE MUG CAKE ', '4 tablespoons flour\r\n4 tablespoons sugar\r\n2 tablespoons cocoa\r\n1 egg\r\n3 tablespoons milk\r\n3 tablespoons oil\r\n3 tablespoons chocolate chips (optional)\r\na small splash of vanilla extract\r\n1 large coffee mug ', 'Add dry ingredients to mug, and mix well. Add the egg and mix thoroughly. Pour\r\nin the milk a...nd oil and mix well. Add the chocolate chips (if using) and vanilla extract,\r\nand mix again.\r\nPut your mug in the microwave and cook for 3 minutes at 1000 watts. The cake\r\nwill rise over the top of the mug, but don\'t be alarmed! Allow to cool a little, and\r\ntip out onto a plate if desired.\r\nEAT! (this can serve 2 if you want to feel slightly more virtuous). ', 'And why is this\r\nthe most dangerous cake recipe in the world?\r\nBecause now we are all only 5 minutes away from chocolate cake at any time of\r\nthe day or night!', 45),
(400, 'Skor Cookies', ' 1 cup of margerine\r\n1 cup of white sugar\r\n1 cup of brown sugar\r\n2 eggs\r\n1 tsp of vanilla\r\n2 cups of all purpose flour\r\n2 cups of oatmeal\r\n1 tsp of baking powder\r\n1 tsp of baking soda\r\n12 oz of milk chocolate chips\r\n3 crushed Skor Bars\r\n', 'Directions Combine and mix well the first 5 ingredients\r\nMix together a...ll purpose flour,oatmeal, baking powder and baking soda and mix well with wet ingredients. Add the chocolate chips and skor bars mix well\r\nPlace spoon size balls on an ungreased cookie sheet flaten slightly and bake @ 375 for about 10 to 12 mins Bake just until they are golden brown DO NOT OVER BAKE Otherwise they will not be chewy. Remove from cookie sheet immediately after baking. Enjoy!!\r\n( We tried it with white chocolate chips and they were also good', '- really very very good', 58),
(401, 'Chunky toblerone Shortbread cookies!', '2 cups butter, softened\r\n1 cup fine sugar\r\n3 1/2 cups flour\r\n1/2 cup cornstarch\r\n2 100 g bars Toblerone chocolate, chopped\r\n3 Tbsp sifted icing sugar\r\n', 'Preheat oven to 350\r\nBeat butter and sugar in large bowl with electric mixer on high speed until light and fluffy.\r\nCombine flou...r and cornstarch. Gradually add to butter mixture, beating until well blended. Stir in chocolate.\r\nDrop by heaping tablespoonfuls onto ungreased baking sheets, about 1&quot; apart.\r\nBake 20 to 25 minutes or until lightly browned. Cool 5 minutes on baking sheet. Sprinkle with icing sugar. Remove to wire racks and cool completely. These are awesome!', '', 58),
(402, 'BREAKFAST CASSEROLE', '4 slices bread\r\n1 lb. bacon or sausage\r\n1 c. grated sharp cheese\r\n6 eggs\r\n2 c. milk\r\n1 tsp. dry mustard\r\n1/2 tsp. salt\r\nPepper\r\n\r\n', 'Grease 13 x 9 inch casserole. Tear bread and put in casserole. Brown and drain bacon or sausage. Crumble over bread. Sprinkle with cheese. Beat eggs with milk, mustard and seasonings. Pour over mixture in casserole. Bake for 35 minutes at 350 degrees.\r\n\r\n', 'Best if prepared the night before, cover and refrigerate. Breakfast cooks with no effort or mess.\r\n\r\nServes 4-6.', 67),
(403, 'Chocolate-Peanut Butter Mallow Bars', '1 pkg. (2-layer size) devil\'s food cake mix\r\n1/2 cup (1 stick) butter, melted\r\n2/3 cup milk, divided\r\n3/4 cup creamy peanut butte\r\n1 jar (7 oz.) JET-PUFFED Marshmallow Creme\r\n1/2 cup PLANTERS Salted Peanuts\r\n6 squares BAKER\'S Semi-Sweet Chocolate, coarsely chopped\r\n\r\n', 'HEAT oven to 350ÃÂ°F. Mix dry c...ake mix, butter and 1/3 cup milk until blended; press 2/3 onto bottom of 13x9-inch pan. Bake 12 to 14 min. or until center is almost set; cool 3 min. Meanwhile, mix peanut butter and remaining milk.\r\nSPREAD peanut butter mixture onto crust; top with small spoonfuls of the marshmallow creme and remaining cake mixture. Sprinkle with nuts and chocolate; press gently into cake mixture.\r\nBAKE 18 min. or just until center is set. Cool completely before cutting into bars.', '', 9),
(404, ' Reeses Peanut Butter Cups Recipe', 'Peanut Butter Cups Base ingredients:\r\n1 3/4 cups icing sugar\r\n1 1/2 cups graham wafer crumbs\r\n1 cup peanut butter\r\n1/2 cup melted margarine\r\nTopping ingredients\r\n1 cup chocolate chips\r\n3/4 cup peanut butter', 'Directions:Mix all the ingredients for the base and press into a 9Ãâ13 pan.\r\nMelt the topping ingredients together, mixing well, and pour over the base smoothly and evenly.\r\nRefrigerate for a minimum two hours then slice into squares.', 'Caution: You may lose your mind and eat the whole pan in one sitting. IÃ¢â¬â¢ve done it and itÃ¢â¬â¢s not pretty!', 9),
(405, 'chocolate peanut butter snowballs', '8 squares semi-sweet chocolate.\r\n1/2 cup smooth peanut butter\r\n2 cups thawed cool whip topping\r\n1/4 cup icing sugar..', 'Microwave chocolate in large bowl on med. for 2 mins. Stir until chocolate is completly melted.\r\nstir in peanut butter until well blended. cool to room temp. gently stir in whipped topping. refrigerate 1 hour.\r\nscoop mixture with melon baller or tsp, then shape into 1 inch balls. Roll balls in icing sugar.\r\nstore in fridge.\r\n\r\n', 'substitute: roll in chopped pecans, coconut, grated bakers choc, white choc, or finely crushed vanilla wafers', 9),
(406, ' French Toast Overnight Breakfast Casserole', 'Ã¢â¬Â¢1 loaf (10 oz) French bread, cut into 1-inch cubes (10 cups)\r\nÃ¢â¬Â¢8 eggs\r\nÃ¢â¬Â¢3 cups milk\r\nÃ¢â¬Â¢4 tsp sugar\r\nÃ¢â¬Â¢1 tsp vanilla\r\nÃ¢â¬Â¢3/4 tsp salt, optional\r\nÃ¢â¬Â¢Topping:\r\nÃ¢â¬Â¢2 Tbsp butter, cubed\r\nÃ¢â¬Â¢3 Tbsp sugar\r\nÃ¢â¬Â¢2 tsp ground cinnamon\r\nÃ¢â¬Â¢Maple syrup,', '1.Place bread cubes in a greased 13x9x2-in. baking... dish. In a mixing bowl, beat eggs, milk, sugar, vanilla and salt if desired. Pour over bread. Cover and refrigerate for 8 hours or overnight. Remove from the refrigerator 30 minutes before baking. Dot with butter. Combine sugar and cinnamon; sprinkle over the top. Cover and bake at 350 for 45-50 minutes. Let stand for 5 minutes. Serve with syrup if desired.', '', 67),
(407, ' Overnight Breakfast Casserole:', 'Ã¢â¬Â¢14 - 15 slices stale bread.\r\nÃ¢â¬Â¢3 cups cooked and crumbled sausage, ham, or bacon, or a combo.\r\nÃ¢â¬Â¢3/4 lb shredded cheddar\r\nÃ¢â¬Â¢10 eggs, beaten\r\nÃ¢â¬Â¢1 cup onion, diced\r\nÃ¢â¬Â¢1 cup bell pepper, diced\r\nÃ¢â¬Â¢3 cups milk\r\nÃ¢â¬Â¢1tsp salt\r\nÃ¢â¬Â¢1/2 tsp pepper\r\nÃ¢â¬Â¢4 dashes worchester sauce\r\nÃ¢â¬Â¢1/2 stick butter', 'Melt butter into 9 x 13 casserol...e set aside.Cook bacon, or sausage, set aise, reserve small amt of grease.Saute onion and bell pepper in small amount of grease, set aside.Mix eggs, milk, salt, peppers, sauce and beat until well blended.Add meat of your choice, stir in.Add 1 or 2 lb shredded cheese, fold in.cut or tear bread into small cubes and place in bottom of buttered casserole.Pour egg, meat, veggie mixture over and top with remaining shredded cheese. Cover and refrigerate overnight. In the Morning, Bake uncovered approximately 1 hour at 350, or until eggs are firmly set. Cut into squares and serve. For a more colorful dish, use pimentos or red bell peppers', '', 67),
(408, 'Chicken Supreme', '1 medium onion, chopped and browned in butter, \r\n1/2 cup celery (chopped), \r\n1 cup water, \r\n1 tsp dry mustard, \r\n3 tbsp green pepper, chopped, \r\n1 cup ketchup,\r\n2 tbsp brown sugar, \r\n2 tbsp vinegar, \r\n3 tbsp Worchestershire sauce, \r\n2 lb chicken pieces. ', 'Combine all ingredients (except chicken), simmer f...or 15 minutes. Pour over chicken pieces in roast pan. Bake at 350F for 2 hours. The last 1/2 hour, remove cover and bank at 325F.', '', 54),
(409, 'Butterscotch Brownies', '3/4 Cup Flour,\r\n1 tsp baking powder, \r\n1/4 cup butter or margarine, \r\n1 cut brown sugar, \r\n2 eggs, slightly beaten; \r\n1/4 tsp salt, \r\n1 tsp vanilla, \r\n1/2 cup chopped nuts (either walnuts or pecans) ', 'Stir flour, baking powder and salt together then set aside. Melt the butter and brown sugar over low heat (I j...ust use microwave). Stir in slightly beaten eggs to the brown sugar butter mixture. Then blend in the dry ingredients, mixing well. Add the vanilla and the nuts. Bake in greased &amp; floured 8 inch square pan in slow oven at 300F for 25 to 35 minutes. Cut while still warm, but remove from the pan when cooled.', '', 9),
(411, 'BBQ sauce', '2 C ketchup\r\n1 C Molasses\r\n1/4 C Worchestershire sauce\r\n1 spoonful of mustard (diff flavors give the sauce a diff kick, I usually use reg mustard)\r\n2 heaping tsp Horseradish\r\n3-4 Tblspn A-1 sauce\r\n2tsp garlic powder or minced garlic\r\n1 Tblspn onion powder or dehydrated onions\r\noptional:\r\n1 tsp white vinegar to make it ta...ngy or honey to make it sweeter\r\n\r\n', 'mix all ingredients into pot on stove and let simmer for 10-15 minutes\r\n\r\nI have a family of 5 and I usually double this recipe so I have plenty of sauce :)', '', 17),
(412, 'Coconut Snowball Cookies vegan,', 'makes 12 large snowballs or 20 small\r\n\r\ndry:\r\n1 cup + 2 Tbsp whole wheat flour\r\n1/3 cup medium grain unsweetened coconut shreds\r\n1/2 tsp salt\r\n3 dashes of cinnamon\r\n1/2 tsp nutmeg\r\n2 tsp baking powder\r\nwet:\r\n1/4 tsp vanilla extract\r\n1 extra-ripe banana, mashed\r\n1/2 cup brown sugar\r\n1/2 tsp apple cider vinegar\r\n1/2 cup soy milk, vanilla\r\n2 Tbsp extra virgin coconut oil\r\n3 Tbsp warm water\r\n\r\nSnow Topping\r\n1/2 cup raw Brazil nuts\r\n1 Tbsp brown sugar\r\n1/4 cup coconut shreds\r\n1/2 tsp cinnamon\r\n1/4 tsp nutmeg\r\ndash salt\r\n\r\nOptional &quot;Mud&quot; Bits\r\n1/4 cup mini vegan chocolate chips\r\n\r\nOptional &quot;Extra Snow&quot;\r\n1/4 cup extra coconut flakes, last step\r\n\r\n', 'Directions:\r\n\r\n1. Preheat oven to 375 degrees, set aside a baking sheet.\r\n\r\n2. Combine all dry ingredients for cookie dough. Stir in the liquid ingredients. Note: combine the warm water and coconut oil in a small bowl in order to \'melt\' the coconut oil to almost liquid form. This will allow it to easily blend into your batter. If you are adding in \'mud\' chocolate chips, fold them in now.\r\n\r\n3. In a small food processor (I use a mini-grinder) add your Brazil nuts, coconut, salt, sugar and spices. Chop on high until the bits are finely ground. Pour into a flat bottom small bowl. If you are using \'extra snow\' for a whiter snowball, place your extra coconut flakes in another small flat bowl.\r\n\r\n4. Using your hands, grab about 2 tbsp of dough. If the dough seems a bit too sticky, add a few pinches of dry coconut bits. However, you want the dough to be nice and moist so it will absorb the snow coating.\r\n\r\n5. Roll your cookie ball into the Brazil nut/coconut mix, fully coating all sides. If you are adding an additional layer of \'extra snow\' roll the ball in just coconut, then place on baking sheet.\r\n\r\n6. Repeat until all your balls are made. You will probably have leftover coconut mix-I like to simply store it in a baggie in the fridge for the next time I make snowy cookies.\r\n\r\n7. Bake at 375 degrees for 15 minutes. Cooking times will vary based on cookie size. If you are making small snowballs, you may want to pull them out around 12 minutes. For larger golf-ball sized snowballs 16-20 minutes may be needed. You will know the cookies are ready when the outer coconut coating tinges a light caramel color.\r\n\r\n8. Allow to cool for ten minutes before serving. Store in the fridge. These cookies taste delicious cold-straight from the fridge. They are snowballs!...\r\n\r\n', 'Oh, and these cookies are for eating kids, not for throwing! However, a little coconut dashed at a fellow baker is always a little fun', 60),
(413, 'CHAI TEA RECIPES', 'TRADITIONAL CHAI\r\nYIELD: 8 OUNCES\r\n\r\n4 ounces Chai Tea Concentrate\r\n\r\n4 ounces of milk\r\n\r\nCombine concentrate and milk and steam with steaming wand, heat on stove or in microwave.\r\n\r\nCHAI SPICED CIDER\r\nYIELD: 8 OUNCES\r\n\r\n4 ounces Chai Tea Concentrate\r\n\r\n4 ounces apple or pear cider\r\n\r\nCombine concentrate and cider; steam with steaming wand, heat on stove or in microwave.\r\n\r\nRASPBERRIES AND CREAM CHAI\r\nYIELD: 8 OUNCES\r\n\r\n3 ounces Chai Tea Concentrate\r\n\r\n1 ounce raspberry syrup\r\n\r\n4 ounces milk\r\n\r\nCombine all ingredients in steaming pitcher and steam.', 'n/a', '', 65),
(414, 'North Pole Peppermint Chai vegan, ', 'makes one big mug or two little mugs\r\n\r\n1 cup vanilla soy milk\r\n*I like Soy Dream brand best for this recipe\r\n1 cup vegan chai liquid concentrate\r\n*Oregon Chai brand\r\n1 Tbsp soy creamer\r\n1 candy cane, smashed to bits\r\n*Pure Fun brand organic candy canes are a great vegan choice\r\n1 dash cayenne\r\n3 dashes cinnamon\r\n1 black tea bag\r\n1 chai tea bag\r\n*I like Peet\'s Masala chai tea bags best\r\nOptional: Areolatte milk frother. Steam milk frother can also be used.\r\n\r\n\r\n', '1. Pour your chai concentrate and 1/2 cup of soy milk into your serving mug. Microwave on high for 1-2 minutes, or until steamy HOT!\r\n\r\n2. After microwaving, add the 2 tea bags to the liquid, let steep for 2-5 minutes. When bags have steeped, removes, squeeze excess liquid from bags back into mug.\r\n\r\n3. Stir into your liquid 1 tsp of peppermint candy cane bits. Stir in your cinnamon and cayenne dashes too.\r\n\r\n4. If you have a milk frother, froth the remaining soy milk and soy creamer into a foamy white pillow of liquid. Perfect frothing is done at about 60 degrees. If you don\'t have a frother you can heat this liquid to HOT and add to you beverage. You can add in a bi more soy creamer or replace a bit of the soy milk with soy creamer - for a creamier latte.\r\n\r\n5. On top of your beverage (hopefully you have a nice mound of foam), sprinkle about a teaspoon of candy cane bits. Add another dash of cinnamon if you\'d like.\r\n\r\nDrink and enjoy this sweet minty refreshing tea latte!\r\n\r\nOptional: add a swirl of rice cream or a few vegan marshmallows for an extra-decadent treat.', 'serves one', 60),
(415, 'Two Cups of Cocoa', 'vegan, recipe for one mug each\r\n\r\nIn Each Mug Add:\r\n2/3 cup soy milk\r\n*I like Soy Dream brand for beverage recipes.\r\n1/3 cup water\r\nvery small pinch of salt\r\n1 Tbsp + 1 tsp of organic cocoa powder (unsweetened)\r\nsweetener to taste (options below)\r\n1/2 tsp cinnamon spice blend powder\r\n*my blend has cinnamon, nutmeg, Madagascar cloves\r\noptional: 1 dash spicy cayenne for heat\r\n\r\nFrothy Foam:\r\n1 cup soy milk\r\n2 Tbsp soy creamer\r\noptional: vanilla sugar powder\r\n*note: higher cream ratio, creamier froth.\r\n\r\nSweetener Options:\r\n2-4 tsp vegan fine sugar\r\n3-4 tsp agave syrup\r\n2 tsp sugar/2 tsp agave\r\n(you can also use a stevia-based sweetener if that is your preference)\r\n\r\nOptional: 1 shot of espresso or 1/4 cup of black coffee for a &quot;mocha-cocoa&quot;\r\n\r\nDirections:\r\n\r\n1. Add the water and soy milk to each mug. Will be 1 cup of liquid total. Pinch the very very small amount of salt in each glass. Microwave on high for about 75 seconds (or until liquid starts to bubble with heat.)\r\n\r\n2. When the liquid is steaming hot, add in the cocoa powder-a little at a time while stirring briskly, to avoid clumps.\r\n\r\n3. Stir in the sweetener and spices. Add in a shot of espresso if you are making a mocha.\r\n\r\n4. In a separate glass mug add the frothy foam ingredients. Heat to about 60 degrees in the microwave. About 40 seconds for my micro. Using an aerolatte wand milk frother, froth the milk until it is nice and foamy. You can also use a steam-foamer or other kitchen gadget you may own. If you do not have a foamer, simply heat the milk and stir it very briskly for about 30 seconds.\r\n\r\n5. Add the foam to the top of the cocoa mugs. Fill to the brim with white foam. Add in vegan marshmallows or rice whip on top, as you desire.\r\n\r\nServing Instructions: See above list of required locations, destinations, modifications, allocations, instructions and venue\'s for proper cocoa drinking for two.', 'n/a', '', 60),
(416, 'Holiday Tangerine French Toast', 'vegan, makes 8 triangles\r\n\r\n4 pieces of sliced bread, soft (multigrain or whole wheat)\r\n*I used Vermont Bread Co. Soft Multigrain and it was perfect!\r\n1 cup + 2 Tbsp Silk Soy Nog\r\n1 large tangerine, zest and juiced\r\n(About 1/4 cup tangerine juice and about 2 tsp zest.)\r\n1/2 tsp cinnamon + a few more dashes\r\na few dashes nutmeg\r\n1 Tbsp whole wheat flour\r\n1 Tbsp vegan buttery spread for cooking\r\n*Earth Balance brand is my fave.\r\ngarnish: extra tangerine for garnish slices and zest, powdered sugar, maple syrup (but it doesn\'t need it)\r\n\r\n', '1. Slice your bread diagonally, into 8 triangles.\r\n\r\n2. Add the ingredients (soy nog, spices, flour, tangerine juice and tangerine zest) to a flat-bottom dish, a square piece of Tupperware works perfectly. Whisk them together.\r\n\r\n3. Turn your stove on med-high and plop your 1 Tbsp of buttery spread into a flat saute pan. Allow it to coat the surface of the pan.\r\n\r\n4. You don\'t want to over-soak your bread, however soaking it through is important. Using bread that isn\'t perfectly fresh may be the best way to combat french toast sog. But then again, I used a fresh loaf and it turned out splendidly. Dipping process: Dip and soak for 2 seconds on each side and immediately transfer to hot oiled pan. Repeat until your pan is filled to the brim with toasts. My pan held 5 triangles at a time.\r\n\r\nquick soak for bread:\r\n\r\n\r\n\r\n5. Allow your french toast to sit in the pan! Don\'t go flipping-early or mushing it around on the pan or it will likely turn to bits and pieces and/or burn the crust off. Sprinkle a nice hefty dash of cinnamon on each of the toasts while they are cooking in the pan. After 3 minutes, flip the toasts. They should be a nice marbled dark golden brown color. If the first \'flipper\' is still soggy and mushed after flipping, leave the remaining triangles unflipped for another 1-2 minutes. Then flip and again, test for doneness. Practice makes perfect!\r\n\r\n6. Once all the toasts are flipped, allow them to cook for another 3 minutes on the other side. By the end of cooking time, the edges should be nice crisp, buttery and smell of warm cinnamon and candied tangerine zest. If your toasts didn\'t turn out perfectly the first time, try with the second batch of bread. Possible troubleshooting errors: your pan wasn\'t hot enough, you needed a bit more flour or you over or under soaked your bread. Also note: you may want to refresh the buttery spread or even simply spray a bit of canola oil in the pan after a few cooking rounds. A \'greased\' pan is a must for this french toast.\r\n\r\n7. Serve with a sprinkle of fresh tangerine zest, a dash of cinnamon and a few tangerine slices. Other toppings are nice, but really not needed. (That\'s right, I ate my french toast without maple syrup! Shocking I know!)\r\n\r\n\r\n\r\n', '', 67),
(417, 'Coconut Jam Tarts', '2 single pie crusts\r\n1/2 cup soft butter\r\n1/2 cup sugar\r\n2 eggs\r\n1 cup coconut\r\n1 teaspoon vanilla\r\n1/4 cup raspberry jam\r\n', 'Prepare pie crust according to your directions and cut and fit into small tart tins. Press evenly against bottom and sides. (or you c...an use pre-made small tarts\r\nCream butter and sugar.\r\nAdd eggs, one at a time, beating until smoothly blended.\r\nStir in coconut and vanilla.\r\nSpoon 1/2 teaspoon jam into each tart shell.\r\nCover each tart 2/3 full with coconut mixture.\r\nBake on bottom shelf at 300ÃÂ°F for 15-20 minutes or until golden brown.\r\nCool slightly then remove from pans. Makes 2 dozen tarts.', '', 40),
(418, 'shortbread cookie recipe', '1/2 cup corn starch\r\n1/2 cup icing sugar\r\n1 cup flour\r\n1 cup butter\r\n', 'beat with mixer on medium, refrigerate dough until firm but not hard (15 or 20 mins). Roll into balls onto a greased cookie sheet, lightly press down with fork( I always dip fork into icing sugar so it doesnt stick) bake in a preheated 350 degree oven for approx. 10 to 12 mins. (until very slightly browned edges) let sit on cookie sheet for 1 or 2 mins. then remove to cooling rack until cool. These are so darn easy and tasty too!.', '', 58),
(419, 'Pecan Parsley Pepper Cheese Log vegan', '1 cup vegan cheese chunks\r\n*I used half Mozzarella/half Monterey Jack, Follow Your Heart brand\r\n1/4 cup chopped raw pecans\r\n1 tbsp chopped parsley\r\n1 tsp red pepper flakes\r\n1 Tbsp extra virgin olive oil\r\n1 tsp orange juice\r\n1 tsp maple syrup\r\na few dashes of black pepper\r\npinch of sea salt\r\n\r\n\r\n', '1. Grab your \'mold\' dish. Just make sure that it has a large flat surface area on the top and bottoms so that you can properly season the dish before pouring in the cheese. I used a more angular rather than round dish, but it worked out well.\r\n\r\n2. Crush you pecans, chop your parsley and tear your cheese into rough chunks.\r\n\r\n3. Prepare your cheese mold dish. Wipe the inside surface with olive oil and drizzle a bit of olive oil in the bottom of the dish. Add a hefty layer of pecans and half your parsley. Sprinkle a bit of salt and pepper int he bottom as well. Sprinkle half your red pepper flakes. Set aside.\r\n\r\n4. Using a separate small container you will be melting the cheese. Spray this dish with oil spray so the the melted cheese easily slides out. Microwave on high for about 1 minute - or until the cheese bubbles and is fully liquid.\r\n\r\n5. Immediately pour the melted cheese into your mold dish - right on top of the pecans/parsley/pepper.\r\n\r\n6. Next, cover the top of the melted cheese with your remaining topping ingredients. The pecans, parsley, red pepper, black pepper and salt. Lastly, drizzle your maple syrup, orange juice and remaining olive oil right on top and around the inside brim of the dish.\r\n\r\n7. Fully harden in fridge. Cover your dish with foil and place in the fridge for at least 2 hours or overnight if needed. Note: a shallow dish with a thinner \'log\' will harden faster than a dense thick log.\r\n\r\n8. Serve with crackers, sliced apples, flax seed chips, seaweed chips and veggie sticks. You can even add another drizzle of oil or maple syrup to the cheese before serving. Plate with a cheese or butter knife so that guests (or you) can easily get a nice thin portion of the cheese.\r\n\r\nEnjoy!', '', 60),
(420, 'Sunshine Bruschetta vegan', '4 fresh garlic cloves, sliced thin\r\n1 vine-red tomato, diced\r\n1 small ciabatta roll, sliced into 1/2&quot; rounds\r\n6 large fresh basil leaves, chopped into thin shreds\r\n2 Tbsp Olive Oil\r\n1 Tangelo, tangerine or orange, 1/2 juiced and 1/2 chopped\r\nsea salt\r\nfresh ground black pepper\r\n\r\n', 'Add to bowl: tomato, garlic, basil, oil, juice, citrus bits, salt and pepper.\r\n\r\nMix well with spoon. Folding motion.\r\n\r\nBread: You may apply mixture to fresh bread toasted or untoasted. Spoon about 1 large tablespoon of bruschetta mixture to each round. A crispier bread can handle a heartier spoonful. If you use raw bread, spoon liquid more sparingly, to avoid a soggy bread.\r\n\r\nGarnish with basil leaves. Add fresh black pepper to taste.', 'serves 2-3', 60),
(421, 'CHOCOLATE OATMEAL COOKIES', '&gt;&gt;using a large mason Jar,put in jar in this order... \r\n1 1/3 c oatmeal,\r\n1/2 c sugar,\r\n1/2 c br sugar,&gt; \r\n1 1/3c flour mixed with 1 tsp baking soda, \r\n1 tsp baking powder, \r\n1/4 tsp salt,&gt;\r\ntop with 1 1/3 c choc chips\r\nSeal jar and add a decorative ribbon and attach this recipe:\r\n', 'Empty contents of this container into a bowl and ... See Moremix in\r\n1/2 c melted butter 1 slightly beaten egg, 1 tsp vanilla, mix until blend, Shape dough into balls and place 2&quot; apart on a greased cookie sheet. Bake @350 10-12 mins until lightly brown. Makes 3 dozen cookies.\r\nIts a great hit for young people and older folks...all they have to add is the wet ingreds...and cook.', '', 58),
(422, 'Christmas mice', 'open up an oreo cookie, dip a stem cherry into chocolate, place the cherry on the cookie, stick a Kiss chocolate to the cherry for the head, insert two sliced almonds in between the kiss and cherry for the ears and use green (or red) icing for the eyes ......et voila!\r\n7 hours ago', 'n/a', '', 58),
(423, 'Get Cozy Sangria', '    * 1/4 cup Apple Jack brandy\r\n    * 2 tablespoons sugar\r\n    * 1 seedless orange, thinly sliced\r\n    * 2 McIntosh apples, cored and thinly sliced\r\n    * 1 Granny Smith apple, cored and thinly sliced\r\n    * 1 bottle rosÃÂ© or white wine\r\n    * 1 cup cranberry juice\r\n    * Ice\r\n    * 1 liter soda water\r\n\r\n\r\n', 'In a large pitcher, combine the brandy with the sugar and orange slices, mashing everything together with a wooden spoon or muddler for about one minute.\r\n\r\nAdd the remaining fruit, wine and cranberry juice, and stir to combine.\r\n\r\nTo serve, fill a tall glass with ice, add a large splash of soda water and then fill the glass with the fruit-wine mixture.\r\n', 'Yields: 6 to 8 servings', 65),
(424, 'Salsa, Sour Cream and Cream Cheese Chip & Dip', '1 package of cream cheese (softened)\r\n1 tub of sour cream\r\n1 bottle Salsa thick &amp; chunky sauce\r\n11/2 cup shredded cheddar and/or mozzarella cheese\r\n2 tomatoes, seeded, finely chopped\r\n1 small Iceberg lettuce, broken into bit-sized pieces\r\n1/4 cup green onion, chopped (optional)\r\n2 big bags triangle-shaped Nacho chips\r\n\r\n', 'Mix together softened cream cheese and sour cream. Spread evenly in small casserole dish. Pour Salsa over top, spreading evenly. Sprinkle with grated cheese(s). Sprinkle chopped tomato, lettuce and green onion (if using) on top. Chill. Serve with Nacho chips on the side.\r\n\r\n', '', 34),
(425, 'Boston Baked Beans', 'Ã¢â¬Â¢Beans, small white, navy or Great Northern -- 1 pound\r\nÃ¢â¬Â¢Baking soda -- pinch\r\nÃ¢â¬Â¢Onion, chopped -- 1\r\nÃ¢â¬Â¢Molasses ( or Maple Syrup) -- 1/2 cup... See More\r\n*Ketchup -- 1/3 cup\r\nÃ¢â¬Â¢Brown sugar -- 2 tablespoons\r\n* mustard -- 2 teaspoons\r\nÃ¢â¬Â¢Salt -- 2 teaspoons\r\nÃ¢â¬Â¢Pepper -- 1 teaspoon\r\nÃ¢â¬Â¢Salt pork Or Bacon or ham, sliced 1/4-inch thick -- 1/4 pound\r\n', '1.Add the beans to a large saucepan and add water to cover them by at least 1 inch. Soak the beans overnight, drain and rinse.\r\n2.Preheat oven to 275ÃÂ°F. Cover the beans with fresh water and add a pinch of baking soda. Bring to a boil over medium-high heat. Reduce heat to low, cover and simmer for 20 minutes, or until the skins of the beans flake when you blow on them. Drain again but do not rinse.\r\n3.Stir the onion, onion, molasses, brown sugar, Ketchup, mustard, salt and pepper into the beans. Place half the salt pork slices on the bottom of a deep, 2-quart casserole dish or bean pot. Add the beans and enough water to just barely cover them. Place the remaining salt pork slices on the top of the beans. Cover the casserole or bean pot with a lid or aluminum foil.\r\n4.Bake the beans for 6-8 hours, adding water as needed to keep the beans just barely covered--about every hour or so. Do not stir the beans.\r\n5.Uncover for the last 30 minutes of baking to brown the salt pork and caramelize the top of the beans. Serve hot\r\n', ' - 6 to 8 servings  Variations\r\nÃ¢â¬Â¢Vermont or Canadian Maple Baked Beans: \r\nUse real maple syrup instead of molasses. A chopped apple is sometimes added.\r\nÃ¢â¬Â¢The baking soda supposedly helps the beans soften up. It is a traditional addition but probably not necessary.\r\n10 hours ago ÃÂ· Report', 17),
(653, 'Potato Fritters with Zucchini', '3 cups shredded zucchini about 13 ounces or 2 medium\r\n2 cups shredded Yukon gold potatoes about 12 ounces or 2 small/medium, scrubbed and peeled\r\n1/2 medium yellow onion shredded\r\n3 large eggs lightly beaten\r\n1/2 cup seasoned whole wheat breadcrumbs\r\n1/3 cup white whole wheat flour or substitute all-purpose flour\r\n1 teaspoon garlic powder\r\n1 teaspoon kosher salt plus additional to season\r\n1/2 teaspoon ground black pepper\r\n1 teaspoon baking soda\r\n1/2 cup freshly grated sharp cheddar cheese\r\n1-2 tablespoons olive oil for frying\r\nPlain nonfat Greek Yogurt for serving\r\nChopped fresh chives for serving\r\n', 'If you\'d like to keep the fritters warm between batches, preheat your oven to 200 degrees F.\r\nSpread the shredded zucchini, potatoes, and onion onto a clean kitchen towel and press out as\r\nmuch moisture as possible, changing the towel once or twice as needed.\r\n2 Place the shredded vegetables in a large bowl, then add the eggs, breadcrumbs, flour, garlic\r\npowder, salt, pepper, and baking soda. Mix until completely combined, using your fingers if\r\nneeded to make sure all of the ingredients are evenly distributed. Fold in the shredded cheese.\r\n3 In a large nonstick skillet, heat 1 tablespoon of the olive oil over medium heat. Scoop a scant\r\n1/4-cup portion of the fritter batter onto the frying pan and flatten into an even layer, using\r\neither the back of the measuring spoon or the bottom of a drinking glass.\r\n4 Cook for 3 to 4 minutes until golden on the first side, then flip and continue cooking until the\r\nsecond side is golden as well. Depending upon your skillet, you may need to adjust the heat as\r\nyou go to ensure the pancakes cook all the way through but still get crisp on the outside.\r\n5 Repeat with the remaining pancakes, keeping batches warm in the oven as desired. If excess\r\nliquid collects in the bottom of the bowl, discard it. Serve warm, topped with Greek yogurt and fresh chives.', 'TIP: Be sure to measure the shredded zucchini and potatoes. If you use a different amount than\r\ncalled for in the recipe, the fritters may not hold together.\r\nGLUTEN-FREE: I have not tried this recipe gluten free, but I believe you could swap oat flour\r\nfor the whole wheat flour and gluten free bread crumbs, plus a pinch of extra salt and pepper\r\nfor the seasoned breadcrumbs.\r\nTO STORE: Keep leftovers in the refrigerator for up to three days.\r\nTO REHEAT: Reheat gently on the stovetop with a bit of olive oil to crisp them back up and to\r\nprevent sticking.\r\nTO FREEZE: Store cooked fritters flat and separated with sheets of parchment paper in the\r\nfreezer for up to 3 months. Defrost overnight in the refrigerator and reheat as directed above.\r\n', 61),
(427, ' Cheesecake Brownies', '1 pkg. (440 g) brownie mix\r\n1/2 cup  applesauce\r\n3 egg whites, divided\r\n1/4 cup  water\r\n1 pkg. (250 g) PHILADELPHIA Light Brick Cream Cheese Spread, softened\r\n1/2 cup  sugar\r\n1/4 cup flour\r\n\r\n', 'HEAT oven to 350ÃÂ°F.\r\n\r\nMIX brownie mix, applesauce, 2 egg whites and water until well blended. Pour into 13x9-inch pan sprayed with cooking spray.\r\n\r\nBEAT cream cheese spread, sugar, flour and remaining egg white with mixer until well blended; spoon over brownie batter. Swirl gently with knife.\r\n\r\nBAKE 28 to 30 min. or until toothpick inserted in centre comes out with fudgy crumbs. (Do not overbake.) Cool completely.\r\nKraft Kitchens Tips\r\nMocha Cheesecake Brownies\r\nPrepare as directed, mixing 2 Tbsp. Maxwell House Instant Coffee Granules with the water before using to prepare brownie batter.\r\n', 'Prep Time:\r\n10 min\r\nTotal Time:\r\n38 min\r\nMakes:\r\n18 servings, 1 brownie (63 g) each', 40),
(428, 'Make-Ahead Spinach Phyllo Roll-Ups', '1/2 cup finely chopped green onions\r\n1   egg, beaten\r\n1 tub (250 g) PHILADELPHIA Cream Cheese Spread\r\n1 cup  KRAFT Feta with Oregano, Sun Dried Tomatoes and Cracked Peppercorns\r\n1 pkg. (300 g) frozen chopped spinach, thawed, well drained\r\n15 sheets  frozen phyllo dough, thawed, divided\r\n1/3 cup butter, melted, divided\r\n\r\n', 'COMBINE all ingredients except phyllo and butter. Place 1 phyllo sheet on clean work surface; brush lightly with butter. Top with 2 more phyllo sheets, brushing some of the remaining butter between each layer. Place remaining phyllo between sheets of plastic wrap; set aside.\r\n\r\nSPREAD 1/5 of the the spinach mixture along one short side of phyllo stack to within 1 inch of ends. Fold in long sides of phyllo; roll up from one short side to make log. Brush with some of the remaining butter. Repeat with remaining phyllo sheets, spinach mixture and butter. To prevent phyllo from cracking, score logs at 1-inch intervals.\r\n\r\nPLACE in large freezer-weight resealable plastic bags. (Or wrap tightly in plastic wrap until ready to bake.) Remove from freezer 30 min. before baking. Let stand at room temperature while heating oven to 375ÃÂºF. Place on baking sheet.\r\n\r\nBAKE 25 min. or until golden brown. Cool 5 min. Transfer to cutting board. Use serrated knife to cut each log into 6 slices to serve.\r\nKraft Kitchens Tips\r\nNote\r\nUnbaked logs can be stored in freezer up to 3 months.\r\nSubstitute\r\nSubstitute cooking spray for the melted butter.\r\nStorage Know-How\r\nAny leftover phyllo sheets can be wrapped tightly and refrozen.\r\nK:43077v0ec:89117\r\nAverage Rating  (128)\r\nRated  by lyndajane on 12/7/2009\r\n&quot; Excellent - will make again. But some reviewers are confused - this recipe does NOT call for salad dressing, it calls for the Kraft feta cheese product available in a resealable bag, this can be found with the other shredded cheeses in similar packaging.&quot; ', 'prep Time:\r\n25 min\r\nTotal Time:\r\n55 min\r\nMakes:\r\n5 logs or 30 servings, 1 slice (28 g) each', 34),
(429, 'crumpets', '- 2 cups all purpose flour\r\n- 2 cup bread flour\r\n- 2 tsp salt\r\n- 1 cup water\r\n- 1 1/2 cup plain soy milk\r\n- 2 tbsp canola oil\r\n- 1 tbsp sugar\r\n- 2 1/4 tsp active dry yeast\r\n- 1/2 tsp baking soda\r\n- 1/2 cup warm water\r\n\r\n', '1. Sift flours and salt together in a large bowl. Make a well in the center.\r\n2. Heat water, soy milk, oil, and sugar to lukewarm. Dissolve yeast into mixture, then mix into the flour. Beat for 5 mins, until smooth (I did this in a stand mixer with the batter attachment). Cover and let rise for 1.5 hours in a warm place.\r\n3. Dissolve baking soda in the warm water and mix into the batter. Add more water, if needed--the batter should thick, but able to be poured. Cover again and let rise for 30 mins. Meanwhile, heat a griddle or cast iron pan on low heat. Oil some crumpet rings (how ever many fit on your griddle).\r\n4. Fill each ring with 1/2 inch of batter and cook for 5-6 minutes, or until tops are dry. The trick here is to have the heat high enough to cook the crumpet, but low enough that the bottoms do not burn before the middles are cooked. If the crumpet does not bubble, as all good crumpets should, add more water to the batter.\r\n5. Remove crumpet from ring and flip over, cooking the top for 1 minute. Slather with margarine and jam and enjoy!\r\n', '', 42),
(430, 'vegan butter', '    * 1/2 C. Soymilk\r\n    * 2 tsp. freshly squeezed lemon juice\r\n    * 1 C. canola oil \r\n\r\nPlace soymilk into food processor. With motor running, pour oil into soymilk. When mixture starts to stiffen, add lemon juice. Makes about 1 1/2 Cups.\r\n	', 'n/a', '', 60),
(431, 'vegan coleslaw', '    * 1 head of green cabbage\r\n    * 4 large or 6 medium carrots, peeled\r\n    * ÃÂ½ medium onion\r\n    * ÃÂ½ cup canola or extra light virgin olive oil\r\n    * ÃÂ½ cup apple cider vinegar\r\n    * 2 cloves minced garlic\r\n    * 1 tsp. salt\r\n    * 1 tsp. pepper\r\n    * 1 tsp. dill\r\n\r\n', '\r\ncut cabbage, carrots and onion into large chunks. Shred in food processor or with hand-held shredder.\r\n#\r\nStep 2\r\n\r\nIn large mixing bowl, combine cabbage, carrots and onion, stirring until evenly distributed.\r\n#\r\nStep 3\r\n\r\nIn small mixing bowl, combine oil, apple cider vinegar, garlic, salt, pepper and dill. Stir vigorously with whisk or fork.\r\n#\r\nStep 4\r\n\r\nPour oil mixture over cabbage mixture and stir until evenly distributed.\r\n#\r\nStep 5\r\n\r\nChill your vegan coleslaw for at least one hour and serve.\r\n', '', 60),
(432, 'Chocolate Cake', 'Cake :\r\n\r\n    * 4 ounces unsweetened chocolate, chopped\r\n    * 1/2 cup unsalted butter\r\n    * 1 cup boiling water\r\n    * 2 eggs\r\n    * 1 3/4 cups granulated sugar\r\n    * 1 1/2 teaspoons vanilla\r\n    * 2 1/2 cups all-purpose flour\r\n    * 2 teaspoons baking powder\r\n    * 2 teaspoons baking soda\r\n    * 1/2 teaspoon salt\r\n    * 1 cup hot coffee\r\n\r\nFrosting:\r\n\r\n    * 1/2 cup unsalted butter, at room temperature\r\n    * 2 tablespoons milk\r\n    * 1 1/3 cups powdered sugar\r\n    * 2 ounces unsweetened chocolate, melte\r\n    * 1 teaspoon vanilla\r\n', '\r\n    * 1. Preheat oven to 350&amp;deg;F. Melt the chocolate and butter in boiling water over medium heat, until smooth. Remove from the heat.\r\n    * 2. In a bowl, beat eggs, sugar, and vanilla until creamy. Add to chocolate mixture.\r\n    * 3. Sift together flour, baking powder, baking soda, and salt. Add dry mixture to chocolate mixture, then add coffee and stir. Pour into two 8-inch greased cake pans and bake 25 to 30 minutes.\r\n    * 4. Mix together frosting ingredients until smooth. When cake is cool, frost sides and top of cake.\r\n\r\n', 'Serves 10\r\nNutrients per serving:\r\nCalories: 553\r\nFat: 28g\r\nCholesterol: 91mg\r\nCarbohydrate: 77g\r\nSodium: 490mg\r\nProtein: 7g\r\n\r\n \r\n	\r\n\r\n', 45),
(435, ' Chicken and Taco Bake!', '4- 5 boneless skinless chicken breasts.\r\nplace each one in baking dishe greased.\r\nmake 3 or 4 cuts on each one.\r\nspread sour cream on each with low fat or fat free.\r\nspread salsa on each one also.\r\nSprinkle crushed Tostitos chips on each.\r\nBake for 20 mins or (longer if chicken is larger than 4 ounces.)\r\n@400 d...egrees.\r\ntake out and sprinkle tex mex shredded cheese on each chicken breasts. Bake for 10 mins longer or until melted!', 'n/a\r\n', '', 54),
(434, 'The Perfect Muffin', '2cups flour\r\n4 tbsp splenda\r\n4 tsp baking powder\r\n1/2 tsp salt\r\n1/2 tsp cinnamon\r\n1 egg\r\n1 cup milk\r\n4 tbsp applesauce\r\n1 cup grated apple\r\n', 'Sift together dry ingredients. In a separate bowl beat egg  slightly add milk and applesauce and beat again.Stir in apple.Add wet ingredients to dry ingredients and do not overmix...Batter should remain pebbly in texture. With 1/4 measuring cup scoop batter into greased muffin  tin filling 2/3 full. Bake at 425f for 25 minutes or until golden brown', 'i replaced sugar with splenda and the oil with applesauce. \\much healthier\r\nenjoy', 59),
(436, ' Christmas Morning Wife Saver', '  16      Slices        Bread -- crusts removed\r\n  16      Slices        Back bacon or ham -- cooked\r\n  16      Slices        Cheddar cheese -- sharp\r\n   6                    Eggs\r\n     1/2  Tsp           -Salt\r\n     1/2  Tsp           Pepper\r\n     1Tsp           Dry Mustard\r\n     1/4  C             Onion -- minced\r\n     1/4  C             Green Pepper -- finely chopped\r\n   2      tsp           Worcestershire sauce\r\n   3      C             Milk -- whole or 2%\r\n   1      Ds            TabascoÃÂ® Sauce\r\n     1/4  lb            Butter\r\n                        Cornflakes &lt;&lt;Or&gt;&gt;\r\n                        Special K -- crushed\r\n\r\n', 'Oven 350ÃÂ° F.\r\n\r\nIn 9 X 13&quot; buttered baking dish (use a BIG dish), put 8 pieces of bread, Add\r\npieces to cover dish entirely. Cover bread with cooked back bacon slices or\r\nham slices. Lay slices of cheddar cheese on top, then cover with slices of\r\nbread (to make it like a sandwich).\r\nIn a bowl, beat, eggs, salt and pepper.To egg mixture, add dry mustard,\r\nonion, green pepper, Worcestershire sauce, milk and Tabasco. Pour over the\r\n\'sandwiches\'. Cover and let it stand in the fridge overnight.\r\n\r\nIn the morning, preheat oven to 350ÃÂ° F.\r\n\r\nMelt 1/4 lb butter and pour over top. Cover with crushed corn flakes or\r\nSpecial K cereal.  Bake 1 hour in 350ÃÂ° F oven. \r\n\r\nLet stand for 10 minutes before serving.\r\n\r\n                   - - - - - - - - - - - - - - - - - - \r\n\r\n\r\n\r\n', 'Serving Size  : 8    Preparation Time :0:30', 67),
(437, 'brushetta bread', 'Ingredients:\r\n\r\n    * 12 slices French or Italian bread, lightly toasted\r\n    * 3 large tomatoes, chopped\r\n    * 1 tbsp olive oil\r\n    * 3 tbsp fresh basil, chopped\r\n    * 1/4 tsp salt. \r\n\r\nPreparation:\r\nCombine tomatoes, oil, basil and salt in a covered bowl and let marinate at least 4 hours (do not refrigerate; tomatoes will lose their flavor).\r\n\r\nUse a slotted spoon to layer on to bread. Serve immediately.\r\n\r\nServings: 6 - 2 slices each\r\n\r\nCalories/Serving: 213\r\n\r\n', 'n/a', 'Nutrition: One serving (2 slices) provides approximately: 213 calories, 6 g protein, 37 g carbohydrates, 3 g fiber, 5 g fat (1 g saturated), 0 mg cholesterol, 61 mcg folate, 2 mg iron, 489 mg sodium. Source: Wheat Foods Council', 42),
(438, 'Layered Mexican Spread', 'What You Need\r\nBase Ingredients:\r\n1 pkg.  (250 g) PHILADELPHIA Brick Cream Cheese, softened\r\n1/2 cup salsa\r\n1 cup  KRAFT Tex Mex Shredded Cheese\r\n  Topping Choices (pick one or a combination):\r\n1/4 cup chopped cilantro\r\n1/4 cup  sliced green onions\r\n1/2 cup sliced pitted ripe olives\r\n1/2 cup  coarsely chopped avocados\r\n1/2 cup drained canned black beans, rinsed\r\n', 'Make It\r\n\r\nSPREAD cream cheese onto bottom of a 9-inch serving dish or pie plate.\r\n\r\nTOP with salsa, shredded cheese and topping.\r\n\r\nSERVE with Ritz Crackers.\r\n', 'prep Time:\r\n10 min\r\nTotal Time:\r\n10 min\r\nMakes:\r\n16', 34),
(439, 'Orange Glazed Honey Carrots', '1/4 cup orange juice\r\n1/4 tsp salt\r\n1/4 cup honey\r\n2 tsp cornstarch\r\n1/4 cup butter or margarine (melted)\r\ndash of nutmeg\r\n1 lb carrots sliced (1/2 inch thick)', 'In a 4 cup casserole combine juice, honey, butter, salt, nutmeg, stir in cornstarch. Mix until well blended, stir in carrots, cover, co...ok at high in microwave for 5 to 9 minutes, stir once, let stand, covered for 3 minutes before serving.', '', 22),
(440, 'nacho dip', '1 1/2  cup mayonnaise\r\n1 8oz pkg cream cheese\r\n1 jar salsa(8oz)\r\n1 1/2 cup shredded cheese\r\n1 green pepper\r\ni yellow pepper\r\n1 red pepper\r\n2 chopped tomatoes', 'In a bowl blend the mayonnaise and cream cheese \r\nSpread the mayonnaise and cream cheese mixture evenly on the bottom of serving dish.Then layer the salsa ,then the peppers and tomatoes.\r\n\r\nspread the cheese on top of the dish then refrigerate for at least 1 hr before serving.', 'enjoy', 56),
(441, 'Breakfast Parfait', '    * 16 ounce(s) yogurt, fat-free, Greek-style, plain\r\n    * 2 cup(s) cereal, flax, such as Nature\'s Path\r\n    * 1 cup(s) blueberries, fresh or defrosted frozen\r\n    * 1 cup(s) strawberries, fresh or defrosted frozen\r\n    * 4 teaspoon honey\r\n    * 4 teaspoon nuts, almonds, slivers\r\n    * 1 medium orange(s), peeled and thinly sliced\r\n\r\n', 'In 4 small bowls or large cups, place 2 ounces of yogurt to line the bottom. Layer 1/2 cup cereal, 1/4 cup of each berry, and 1 teaspoon of honey. Cover with another layer of yogurt (2 ounces per bowl or cup each), and top each parfait with 1 teaspoon of almonds and 2 to 3 orange slices.\r\n\r\nServe cold. ', '', 67),
(442, 'Butterscotch Pull-aparts', '1/4 cup chopped walnuts\r\n1/4 cup raisins\r\n1/3 cup packed brown sugar\r\n1/3 cup butterscotch pudding powder (not instant)\r\n6 tbsps melted butter or margarine\r\n1 tsp cinnamon\r\n\r\n', 'Thaw bread loaf for 1 1/2 hrs. Cut into 1/2 inch slices. Sprinkle walnuts and raisins in bottom of greased 1...2 cup bundt pan. Overlap pieces of dough in a ring. Sprinkle brown sugar and pudding powder over dough. Pour melted butter over top. Sprinkle with cinnamon. Cover tightly with plastic wrap. Let rise overnight, on kitchen counter, or until doubled in size. Bake in 350 F oven for about 30 minutes. Let cool on rack for 5 minutes. Turn onto serving platter. Serves 6 to 8 people.', '', 40),
(443, 'Garlic Mashed Potatoes', '6 large Yukon Gold Potatoes peeled 1 cup milk\r\n1 tsp salt 1/4 cup butter\r\n5 cloves of garlic, minced\r\n\r\n', 'Cut potatoes in half and place in large saucepan and cover with water. Add salt and bring to a boil. Reduce heat and boil ge...ntly, partially covered, for about 20 to 25 minutes, or until tender. Pour milk into microwave safe measuring cut or dish and add garlic. Microwave on high, stirring once, for about 2 minutes, or until hot. Drain water from cooked potatoes. Mash potatoes, add butter and stir in hot milk mixture. Add salt to taste. Serves well with steak, roast beef or spareribs.', '', 61),
(444, 'Easiest chicken recipe ever', 'Take as many boneless skinless chicken breasts or thighs as you need/want.\r\nSprinkle with chili powder and cinnamon and rub them in with a bit of olive oil.\r\nBake 20-25 minutes at 350.\r\nSounds like an odd flavour combination, but trust me, it is soooo good. And makes the house smell amazing!', 'n/a', 'Used this on pork tonight, also added a bit of ground black pepper and topped with apple slices while cooking in the oven... it turned out fantastic!', 54),
(445, 'Snapple Iced Tea - Copy Cat Recipe', '2 quarts (8 cups) water\r\n4 tea bags\r\n3/4 cup sugar\r\n1/3 cup lemon juice\r\n\r\n', 'In a large pot, bring water to a boil. Turn off heat, add tea bags, cover and let steep for at least one hour. Remove tea bags and add sugar to warm tea, stirring until dissolved. Once dissolved, add lemon juice then chill and enjoy!\r\n\r\n', 'Other Flavours:\r\n\r\nDiet Lemon: Replace sugar with 12-1 gram envelopes of Sweet n\' Low or Equal\r\n\r\nOrange: add 1/4 tsp orange extract to all original ingredients\r\n\r\nStrawberry: add 1 Tbsp strawberry extract to all original ingredients\r\n\r\n     \r\n\r\n', 65),
(446, 'Easy Granola Bars', 'Ã¢â¬Â¢ 3 cups quick-cooking oats\r\nÃ¢â¬Â¢ 1 (14 ounce) can sweetened condensed milk\r\nÃ¢â¬Â¢ 2 tablespoons butter, melted\r\nÃ¢â¬Â¢ 1 cup flaked coconut\r\nÃ¢â¬Â¢ 1 cup sliced almonds\r\nÃ¢â¬Â¢ 1 cup miniature semisweet chocolate chips\r\nÃ¢â¬Â¢ 1/2 cup sweetened dried cranberries\r\n\r\n', '1. Preheat oven to 350 degrees F (175 degrees C). Grease a 9x13 inch pan.\r\n2. In a large bowl, mix together the oats, sweetened condensed milk, butter, coconut, almonds, chocolate chips and cranberries with your hands until well blended. Press flat into the prepared pan.\r\n3. Bake for 20 to 25 minutes in the preheated oven, depending on how crunchy you want them. Lightly browned just around the edges will give you moist, chewy bars. Let cool for 5 minutes, cut into squares then let cool completely before serving.\r\n', '', 9),
(447, 'Mars Bar Squares', '4 regular size Mars bars\r\n1/2 cup butter\r\n2 tbsp. peanut butter\r\n2 cups Rice Krispies\r\n1 cup milk chocolate chip\r\n\r\n', 'Melt butter, Mars bars and peanut butter over medium-low heat in large saucepan until smooth.\r\n\r\nRemove from heat. Stir in Rice Krispies.\r\n\r\nPress into greased 8&quot; x 8&quot; pan.\r\n\r\nTop with chocolate chips and place under broiler for 30 seconds.\r\n\r\nRemove from oven and spread chocolate evenly over square.\r\n\r\nPut in fridge to set chocolate (1/2 hr. to 1 hr.) Cut and serve.', 'This recipe is a big hit with kids and busy parents - so quick, easy and tasty!\r\n', 9);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(652, 'Vegan Chocolate Pudding (Whipped Silken Tofu)', '349 grams silken firm tofu\r\nthe pack used was 349g but this can be rounded to 350g!\r\n40 grams cocoa powder\r\n4 tablespoon maple syrup\r\nOr an alternative syrup such as agave/date/rice\r\n1 tablespoon vanilla extract\r\nOr essence\r\n2 tablespoon water\r\n', '1. Add all ingredients to a food processor/blender and whizz until smooth.\r\n2. Decant into your serving dishes.\r\nSmooth down the top.\r\n3. Place in the fridge to chill and thicken up for at least an hour.\r\n', 'Nutritional information is provided for guidance only and is not a strict calculation as\r\ningredients vary.\r\nChocolate pudding will keep fresh in the fridge for 3-4 days. If keeping in the fridge a\r\nday after preparing do add a cover to the dishes.\r\nFor a mint chocolate pudding variation replace the vanilla with a few drops of\r\npeppermint or almond extract/essence. Add more to taste.\r\nServe these little puddings with your choice of fresh or frozen berries, fresh fruit, vegan\r\ncream, ice-cream or yogurt, crushed nuts, desiccated coconut, vegan grated, drops or\r\nbutton chocolates. Or simply enjoy plain.\r\nFor extra chocolate flavours add some melted chocolate to the food processor or\r\nblender.\r\nEspecially delicious is a wee Scottish shortbread biscuit. Slather the chocolate pudding\r\nover and take an amazing bite!', 60),
(449, 'cleaning from dr oz', 'Mix together\r\n\r\n1 tbsp of Borax powder (find it in the laundry aisle of your supermarket)\r\n\r\n3 tbsps of white vinegar\r\n\r\n2 cups of water\r\n\r\n1 tablespoon of dish soap\r\n\r\n1 drop of essential oil such as peppermint for fragrance (optional)\r\n\r\n \r\n\r\nPour it into a spray bottle you bought at the hardware store, give it a shake, and you are ready to clean. For windows, use white vinegar wiped down with newspapers, and to disinfect toys and other kidsÃ¢â¬â¢ products fill a spray bottle with non-chlorine bleach (3% hydrogen peroxide) and wipe with a paper towel.\r\n\r\n \r\n\r\nBonus: Cleaning out harsh chemicals is not only better for your health, itÃ¢â¬â¢s good for the environment, because you drastically cut back on your plastic use by eliminating all those bottles of mildew cleaner, window washer, bathtub scrub, and more.', 'n/a', '', 51),
(450, 'Blueberry Power Muffins', 'In large bowl mix:\r\n3/4 c all purpose flour\r\n1/2 c whole wheat flour\r\n1/2 c large flake oats\r\n1/2 c granulated sugar\r\n1 1/2 tsp baking powder\r\n1/2 tsp baking soda\r\n\r\nIn smaller bowl, whisk together:\r\n1 c low-fat vanilla yogurt\r\n1/4 c skim milk\r\n1 egg\r\n1 tbsp canola oil\r\n1 tsp vanilla\r\n\r\n', 'Pour wet mixture into dry mixture and s...tir just to combine. Fold in 1 c. blueberries.\r\nSpoon into 12 muffin cups. Coarsely chop 1/4 c. raw almonds and sprinkle on top of each muffin.\r\nBake 20 minutes at 350, until golden brown.', '', 59),
(451, 'Frozen Belini\'s Recipe', '    * 1 tsp fresh lemon juice, 1 oz .\r\n    * 3/4 c sparkling white wine or champagne, chilled &amp; divided .\r\n    * 1/4 c peach schnapps .\r\n    * crushed ice .\r\n    * 1/2 c peach nectar\r\n\r\n    ', '* Step #1 Mix peach nectar, lemon juice, peach schnapps &amp; 1/2 c Champagne in a mixer until smooth.\r\n    * Step #2 Pour into Champagne flutes.\r\n    * Step #3 Top each glass with 1/2 of remaining 1/4 c of champagne.\r\n    * Enjoy the Frozen Belini\'s recipe', '', 65),
(452, 'chocolate avocado mousse', '12 oz good-quality bittersweet chocolate, chopped\r\n\r\n2 tsp ground cinnamon\r\n\r\n1 tsp chili powder\r\n\r\n1 large, ripe Hass avocado, pitted and peeled\r\n\r\n3/4 cup light brown sugar\r\n\r\n6 egg whites\r\n\r\n \r\n\r\n\r\n', 'Melt the chocolate with the cinnamon and chili powder in a double boiler over hot water and set aside. Puree the avocado and brown sugar in a food processor until smooth. With the machine running, pour in the chocolate mixture. Using a stand mixer or whisk, beat the egg whites until they form soft peaks. Fold the chocolate mixture into the egg whites. Pour the mousse into 6 small serving bowls or wineglasses and refrigerate for at least 1 hour or, covered, overnight.', 'Serves 6\r\n', 40),
(453, 'Mom\'s Yeast Rolls', '2 cups hot water\r\n1/2 cup margarine\r\n1/3 cup white sugar\r\n2 tsp salt\r\n1/2cup cold water\r\n2 pkg yeast\r\n5 1/2 cups flour\r\n2 eggs\r\n\r\n\r\n\r\n', 'Dissolve yeast as directed on pkg.\r\nMelt margarine in hot water, add sugar &amp; salt and stir.Add cold water and yeast.Stir and mix well\r\nAdd 3 cups flour and mix.Add eggs and 2 to 3 cups more flour.Mix well then knead \r\nbetween 8 to 1o minutes then cover and let rise till double.\r\nPunch down and let rise another 30 minutes or till doubled,\r\nMake walnut size balls ,place about 2 in apart in Well Buttered 9 x 13 inch pan. Bake in preheated 350 degrees oven for 35 to 40 minutes, Brush top of roll with butter while hot', 'enjoy\r\nBea', 42),
(454, 'Muesli Muffins', '1 1/3 cup old fashioned rolled oats\r\n1 cup(3%) Plain yogurt\r\n1/2 cup liquid honey\r\n1 egg\r\n1 tsp pure vanilla extract\r\n1/4 cup unsalted butter,melted and cooled to room temperature\r\n1/4 cup packed brown sugar\r\n1 cup whole wheat flour\r\n1 1/2 tsp baking powder\r\n1/2 tsp each,baking soda,salt and ground cinnamon\r\n1/2 cup each,walnut pieces,raisins,and dried cranberries\r\n', 'Preheat oven to 350f .Butter a 12 cup nonstick muffin pan or line with paper liners.\r\n\r\nIn a large bowl,stir oats and yogurt together. Stir in honey,egg and vanilla.In a small bowl combine melted butter and brown sugar and stir into oat mixture.In a separate bowl combine flour,baking powder,baking soda,salt and cinnamon and stir in oat,mixture  ADD in nuts,raisin and cranberries\r\nSpoon into prepared muffin pan. Bake for 25 minutes or until center of the muffin springs back when gently pressed. Let cool in pan for 15 minutes. Transfer to rack to cool completely\r\n\r\nenjoy', 'Along with a glass of chocolate milk these muffins make a great post-workout snack.', 59),
(455, 'italian meat Loaf', '2 tbsp olive oil\r\n1 red pepper,seeded,small diced\r\n1 onion diced\r\n2 tsps chopped garlic (about 3 cloves)\r\n1 lb ground beef\r\n2 eggs\r\n3/4 cup bread crumbs\r\n1 cup grated parmesan cheese\r\n1 tbsp worcestershire sauce\r\n1 tbsp balsamic vinegar\r\n2 tbsp chopped basil leaves\r\n1 tbsp chopped parsley leaves\r\n1 tap salt\r\n1/2 tsp black pepper\r\n1 cup marinara sauce\r\n', 'Preheat oven to 350 degrees F\r\n\r\nHeat 1 tbsp of the olive oil in a medium saute pan over medium heat and add the peppers, onion and garlic.  Saute until soft,remove to plate to cool.\r\n\r\nwhile  mixture is cooling combine all the other ingredients together except Marinara sauce in a bowl then add the cooled mixture, Mix well then pack the mixture(meat Loaf) in a oiled loaf pan. Top with Marinara sauce making sure to spread evenly over the top.\r\n\r\nBAKE for approximately 50 to 60 minutes or until the meat thermometer reads 160F in the middle of the loaf.\r\nlet cool for 5 minutes then cut and serve\r\n', 'Enjoy, very moist and tasty\r\n\r\nBea', 17),
(456, 'Roasted Garlic Mashed Potatoes', '3 cloves of garlic,peeled\r\n2 tbsp olive oil\r\n4 baking potatoes.peeled and cubed\r\n1/4 cup milk\r\n2 tbsp grated parmesan cheese\r\n1 tbsp  butter\r\n1/4 tsp salt\r\n1/2 tsp black pepper', 'Preheat oven to 350 degrees F\r\n\r\nPlace garlic cloves in small baking dish,drizzle with olive oil,cover and bake  45 minutes or until golden brown\r\n\r\nBring a large pot of salted water to a boil then add the potatoes and cook till tender but firm.Drain and transfer to mixing bowl or leave in same pot once water is drained.  add roasted garlic,milk,parmesan cheese ,butter salt and pepper to potatoes then mash to your desired consistency and enjoy', 'very tasty\r\n\r\nbea', 61),
(457, 'GARDEN VEGETABLE SOUP', '2/3 CUP SLICED CARROT\r\n1/2 CUP DICED ONION\r\n2 MINCED GARLIC CLOVES\r\n3 CUPS FAT FREE BROTH (BEEF,CHICKEN OR VEGETABLE)\r\n1 1/2 cup diced green cabbage\r\n1/2 cup green beans\r\n1 tbsp tomato paste\r\n1/2 tsp dried basil\r\n1/4 tsp dried oregano\r\n1/4 tsp salt\r\n1/2 cup  diced zucchini\r\n', 'Spray a large saucepan with nonstick cooking spray,heat.  Saute the carrot,onion and garlic over low heat until softened, about 5 minutes..Add broth,cabbage,beans,tomato paste,basil,oregano and salt:bring to a boil.  Reduce heat simmer covered about 15 minutes or until beans are tender. Stir in the zucchini and heat for 3 to 4 minutes/serve hot\r\n\r\nyou can switch the veggies to your favorite\r\n                       \r\n\r\n\r\n', 'This is a weight watcher soup and you can have as much as you want as it NO points\r\nenjoy\r\n\r\nbea\r\nPOINTS   0', 62),
(458, 'pepsi cola bbq recipe', '1 can pepsi\r\n1 1/2 cup ketchup\r\n1 cup onion diced(optional)\r\n1/4 cup apple cider vinegar\r\n1/4 cup heinz 57 sauce\r\n1 tsp chili powder\r\n1 tsp salt\r\nhot pepper sauce to taste\r\n', 'combine all ingredients and boil for 30 to 45 minutes till sauce thickens.I usually use this with cut up italian sausage. very tasty', 'bea', 51),
(459, 'bbq sauce with pepsi', '1 can pepsi\r\n1 cup ketchup\r\n1 tsp bbq seasoning or to taste\r\n1 tsp garlic powder\r\nsalt and pepper', 'mix all ingredients together and use it with cooked cut up sausages\r\n\r\nthat is my original recipe\r\n\r\nbea', '', 51),
(460, 'Vegan Cheesy Mustard Bites', '    * 1 baguette, sliced on the diagonal into 24 pieces\r\n    * 1 large tomato, seeds removed, coarsely chopped\r\n    * 1/2 cup nutritional yeast\r\n    * 2 Tablespoons flour\r\n    * 1/2 teaspoon salt\r\n    * 1 cup water\r\n    * 1 Tablespoon extra-virgin olive oil\r\n    * 1 teaspoon Bragg\'s Liquid Aminos (or Tamari)\r\n    * 2 teaspoons Dijon mustard\r\n\r\n', '1. Preheat oven to 350F. Brush bread with a little extra-virgin olive oil and lightly toast in oven, about 10 minutes.\r\n\r\n2. In the meantime, whisk the nutritional yeast, flour, and salt in a small saucepan. Add the water, oil and Braggs, and stir over medium heat until sauce starts to thicken. Stir in mustard and simmer on low heat until warmed throughout.\r\n\r\n3. When the bread is toasted, spoon sauce onto each slice. Sprinkle with chopped tomatoes, salt and pepper. Arrange slices on a baking sheet and broil for a few minutes until the sauce is warmed and has a few brown spots and the tomatoes are slightly roasted.\r\n\r\n', 'Little morsels of cheesy mustardy heaven.\r\nThis vegan appetizer is the perfect finger food.\r\nYield: 2 dozen\r\n', 60),
(461, 'guacamole', '    * 2 Haas avocados\r\n    * 1-2 Tablespoons lime or lemon juice\r\n    * 1/4 cup onion, chopped\r\n    * 1/4 cup red bell pepper\r\n    * Chopped jalapenos, to taste\r\n    * Cumin, to taste\r\n    * Sea salt and pepper, to taste\r\n\r\n', 'Remove the meat of 2 Haas avocados from their skin. Begin by FIRST removing the little nubby thing that you usually find at the end of your avocado -- this will ensure it doesn\'t accidentally end up in your vegan guacamole!\r\n\r\nCut avocados in half -- do this by cutting from top to bottom on both sides of the avocado. Then holding both halves give it a little twist just before you pull the 2 halves apart. You\'ll be left with the pit on only one side of the avocado. Remove the pit and toss. Using a spoon, scoop out the avocado and place into a bowl, mashing it (with a fork) until desired consistency is reached.\r\n\r\nNext, stir lime or lemon juice into the avocado. This is not only for flavor, but to keep the pretty green color. :O)\r\n\r\nFinally, add chopped bell pepper and jalapenos. Sprinkle with cumin and sea salt, to taste.\r\n\r\nServe with tortilla chips, soft pitas, or pita crisps -- heat oven to 400F, cut pitas in half and lay halves on a baking sheet, bake until crisp, break into bite-sized pieces.\r\n\r\nYield: 1-2 cups, depending on size of your avocados\r\n\r\nVariations:\r\n\r\n    * Add chopped tomato\r\n    * Vary the chiles, depending on your desired level of spice\r\n\r\n\r\n', 'Who doesn\'t love guacamole? The perfect vegan appetizer party food. Delicious and chock full of healthy fats.', 22),
(462, 'fruit cocktail cake', 'Original recipe:\r\n\r\nmix together: (with wooden spoon or whisk, no need for a mixer)\r\n1 cup flour\r\n1 cup sugar\r\n1 egg\r\n1/2 tsp baking soda\r\n1 15 oz canned fruit cocktail drained\r\n\r\n', 'stir together until combined (looks like muffin batter), spread in greased square pan\r\n\r\nmix together about 1/3 up brown and 1 tsp (ish) cinnamon--sprinkle over cake batter\r\n\r\nbake at 350 for 30 minutes\r\n\r\nfor the cherry version, use 2 cups of pitted cherries (either fresh from the bucket, or the canned in liquid --they\'re usually in a jar in the fruit section), strain, but reserve liquid just in case the mix is too dry--if it\'s too dry then add liquid 1 tbsp at a time.\r\n\r\nbake at 350 for 35 minutes.\r\n\r\n', '', 45),
(463, ' Classic Cherry Pie', 'Dough:\r\n\r\n    * 3 cups all-purpose flour\r\n    * 1 tsp. salt\r\n    * 2 Tbsp. sugar\r\n    * 2 1/2 sticks butter\r\n    * 1 large egg\r\n\r\nFilling:\r\n\r\n    * 5 cups fresh sweet cherries, pitted (or frozen cherries, thawed and drained)\r\n    * 3 Tbsp. quick-cooking tapioca\r\n    * 1 1/4 cups sugar\r\n    * 1/8 tsp. salt', 'To make dough: Place flour, salt, and sugar in the bowl of a mixer fitted with a paddle attachment; combine on low speed. Cut butter into small cubes; add to bowl. Mix on low until butter resembles pea-size balls; then, while mixer is running, add 1/4 cup very cold water, 1 tablespoon at a time. Mix until ingredients just come together. If dough won\'t quite combine, add an extra tablespoon water.\r\n\r\nDivide dough in half. Shape each piece into a flat, round disk. Roll each between 2 pieces of parchment or waxed paper until dough is 1/8-inch thick. Chill (in paper), lying flat, for at least 1 hour before using.\r\n\r\nTo make filling: Place cherries in a bowl. Toss with tapioca, sugar, and salt; let sit for 15 minutes.\r\n\r\nPreheat oven to 425ÃÂ°. Remove dough from refrigerator and place on a countertop. Remove top piece of parchment from 1 sheet, and lay it dough side down in a 9-inch pie pan. Pull the other piece of paper off, and let dough sit for a few minutes to soften. When it has become pliable, gently press it into pan. Trim edges, but leave a 1/2-inch overhang.\r\n\r\nWork with other dough sheet to prepare lattice top. Peel off top piece of paper and immediately place it back on dough. Flip dough over; remove and discard the other piece of paper. Cut dough into 1/2-inch strips.\r\n\r\nPour filling into pie shell. Lay half of dough strips evenly across the top, keeping a 1/4- to 1/2-inch gap between strips. Form a lattice by weaving the remaining strips perpendicular to the first layer (again keeping a 1/4- to 1/2-inch gap between strips).\r\n\r\nTrim excess dough around rim so edges of lattice match up with the ÃÂ½-inch overhang of bottom crust. Dust your fingers with flour, then pinch top and bottom layers of dough together to form a ridged crust. Continue crimping dough around entire pie shell, flouring your fingers as needed.\r\n\r\nPlace pie pan on a baking sheet, and set it on a rack in bottom third of oven. Bake for 10 minutes. Meanwhile, beat egg in a bowl. Pull pie out of oven and brush egg on crust. Return to oven and lower heat to 350ÃÂ°; bake for 45 minutes or until crust is golden brown and fruit is bubbling and thickened. Remove from oven. Allow to cool at least 1 hour before serving.\r\n\r\n', 'Servings: Serves 8 or 9', 64),
(464, ' THE 5 MINUTE CHOCOLATE CAKE', '5 MINUTE CHOCOLATE MUG CAKE\r\n4 tablespoons flour \r\n4 tablespoons sugar \r\n2 tablespoons cocoa \r\n1 egg \r\n3 tablespoons milk \r\n3 tablespoons oil \r\n3 tablespoons chocolate chips (optional) \r\nA small splash of vanilla extract \r\n1 large coffee mug (MicroSafe)\r\n\r\n \r\n', 'spray mug with non stick spray like Pam\r\n\r\nAdd dry ingredients to mug, and mix well.  Add the egg and mix thoroughly.\r\n\r\n Pour in the milk and oil and mix well..\r\n\r\nAdd the chocolate chips (if using) and vanilla extract, and mix again. \r\nPut your mug in the microwave and cook for 3 minutes at 1000 watts.\r\n\r\nThe cake will rise over the top of the mug, but don\'t be alarmed!\r\n\r\nAllow to cool a little, and tip out onto a plate if desired.\r\nEAT ! (this can serve 2 if you want to feel slightly more virtuous).\r\n\r\nAnd why is this the most dangerous cake recipe in the world? \r\nBecause now we are all only 5 minutes away from chocolate cake\r\n\r\nat any time of the day or night! \r\n\r\n \r\n\r\n \r\n\r\n\r\n\r\n\r\n', '', 45),
(465, 'blueberry scones', '1ÃÂ¾ cups flour\r\nÃÂ¾ cups quick oats\r\nÃÂ½ teaspoon baking soda\r\n2 teaspoons baking powder\r\n1 dash of salt\r\nÃÂ¾ cup sugar\r\nÃÂ½ cup vegan butter\r\n2 tablespoons lemon juice\r\nÃÂ½ cup soymilk\r\n1 cup frozen blueberries', '1. Preheat the oven to 400 degrees and lightly grease cookie sheet with oil\r\n\r\n2. In a large bowl, combine flour, oats, baking soda, baking powder and a dash of salt. Add in sugar, softened vegan butter, lemon juice and soymilk, just until combined.\r\n\r\n3. Stir in the blueberries! (Careful not to over stir)\r\ndough \r\n\r\n4. Place the dough in 6-7 circular clumps on the cookie sheet and bake for 10-15 minutes.\r\n\r\nThis scone recipe is quick, easy and of course vegan friendly!\r\n\r\n\r\n', '', 58),
(466, 'Baked Sweet Potato Fries', '2 lbs. sweet potatoes, peeled\r\n2-4 T. toasted sesame oil\r\n2 t. ground cumin\r\n2 t. chili powder\r\n1 t. paprika\r\n1 t. salt\r\n \r\n\r\n', 'Lightly oil (or spray with oil) two non-stick cookie sheets and set aside. Cut the peeled sweet potatoes into &quot;french fries&quot; or pieces 1/2-inch wide and 3-4-inches long. Transfer the cut sweet potato fries to the prepared cookie sheets, dividing them evenly between the two sheets, and spread them to a single layer. For each cookie sheet: drizzle the sweet potatoes with 1-2 T. toasted sesame oil, then sprinkle with 1 t. ground cumin, 1 t. chili powder, 1/2 t. paprika, and 1/2 t. salt (or to taste). Bake at 375 degrees for 20 minutes. Remove the cookie sheets from the oven, stir the sweet potatoes, and spread to a single layer again. Switch the placement of the cookie sheets on the racks of the oven and bake the sweet potatoes an additional 20-25 minutes, or until lightly browned and crisp. Transfer to a large platter for service.\r\n\r\n', 'Serves 6-8', 61),
(467, 'Chocolate Strawberry Shortcake Cupcakes Secret Winning Recipe!', '1 ÃÂ½ cups all-purpose flour\r\n1 cup sugar    \r\n1/3 cup unsweetened cocoa powder\r\n1 teaspoon baking soda\r\nÃÂ½ teaspoon salt\r\n1 cup coconut milk\r\nÃÂ½ cup vegetable oil\r\n2 tablespoons apple cider vinegar\r\n2 teaspoons vanilla extract\r\n1 teaspoon instant espresso powder\r\nFrosting, recipe below\r\n1 ÃÂ½ cups hulled and sliced fresh strawberries\r\nConfectionersÃ¢â¬â¢ sugar, for garnish\r\n\r\n', '1.    Preheat oven to 350 degrees F and line a 12-cup cupcake pan with paper liners.\r\n2.    Sift or whisk together the flour, sugar, cocoa, baking soda, and salt into a bowl. In a separate bowl, mix the coconut milk, oil, vinegar, vanilla, and espresso powder until smooth.\r\n3.    Pour the wet mixture into the dry mixture and mix with a fork or small whisk.\r\n4.    Divide the batter evenly among the prepared cupcake liners until each cup is 2/3 full. Bake for about 20 minutes, or until an inserted toothpick comes out clean.\r\n5.    Once the cupcakes are completely cooled, slice off the top 1/3 of each cupcake and slather with frosting and sliced strawberries. Place the top of the cupcake back on top and add an additional bit of frosting and sliced strawberries. Dust with confectionersÃ¢â¬â¢ sugar.\r\n\r\nFrosting\r\nIngredients:\r\n4 cups confectioners\' sugar, preferably organic\r\n1/2 cup refined coconut oil at room temperature OR margarine (recommended: Earth Balance Organic Soy-Free Non-Hydrogenated Buttery Spread)\r\n1 tablespoon vanilla extract\r\nÃÂ¼ cup water\r\n\r\nProcedure:\r\n1.    Combine the confectioners\' sugar, coconut oil, and vanilla extract in the bowl of a stand mixer.\r\n2.    Beat on medium-high speed until combined. With the mixer running, add 1 tablespoon of water at a time, until the desired buttercream consistency.\r\n', 'Makes 12 Cupcakes', 45),
(469, 'make ahead scalloped potatoes', '3 lbs potatoes Peeled\r\n1/4 cup butter\r\n1 large onion chopped\r\n1/4 cup chopped fresh chives\r\n2 tbsp chopped italian parsley\r\n5 tbsp all purpose flour\r\n4 cups whole milk\r\n1 cup shredded old cheddar cheese\r\n1/2 tsp salt\r\n', 'bring potatoes to boil in large pot of boiling salted water and cook for 10 minutes.drain well and let cool\r\nMeanwhile ,in  a saucepan melt butter over medium heat. Cook onion ,chives and parsley for about 5 minutes or until onion is softened. Stir in flour and cook for 2 minutes. Whisk in milk and cook,whisking constantly for about 10 minutes or until it comes to the boil. Remove from heat and stir in cheese and salt.\r\nThinly slice potatoes and layer half in a greased 13x9 inch baking dish and pour half of the milk sauce over top. Top with remaining potato slices and sauce ,cover with foil and refrigerate for up to 1 day\r\nBake in 375f oven for 45 minutes.Uncover and bake for about 30 minutes or until golden and bubbly.let stand for 10 minutes before cutting and serving\r\nmakes 12 to 16 servings', 'I made and cooked it the same day a and it was great\r\n  enjoy\r\n\r\nbea', 61),
(470, 'Malibu Hot Chocolate', '1 oz Malibu Rum, 1/2 oz Kahlua, hot chocolate, whipped cream and shavings! Add Malibu and Kahlua to a heat proof glass, top with hot chocolate, add whipped cream and shavings and warm your soul :)', 'n/a', '', 65),
(471, 'FRUIT CAKE', '2.0 lbs seedless raisins (Thompsons are better than Sultanas in this cake, I think; and yeah, that\'s 2 lbs of raisins.  Bring a wheelbarrow to Bulk Barn.)\r\n\r\n1.5 lbs mixed candied peel\r\n\r\n1 cup diced candied pineapple\r\n\r\n2 cups red and green candied cherries\r\n\r\n1 cup slivered blanched almonds\r\n\r\n1 cup coarsely chopped pecans\r\n\r\n3 cups white flour\r\n\r\n1 tsp baking powder\r\n\r\n0.5 tsp salt\r\n\r\n1 tsp cinnamon\r\n\r\n0.5 tsp nutmeg\r\n\r\n0.5 tsp cloves\r\n\r\n0.5 tsp mace\r\n\r\n1 cup margarine (I use the &quot;Buttery&quot; flavour of Earth Balance)\r\n\r\n1.5 cups brown sugar\r\n\r\n8 eggs equivalent of egg replacer (Ener-G or Kingsmill work well, but you can also use ground flaxseed mixed with warm water and left to sit until it gets gelatinous)\r\n\r\n0.5 cups blackcurrant jam or jelly\r\n\r\n ', 'Mix fruit and nuts together in giant bowl.  In separate bowl, mix the dried ingredients and then add them to the fruit, mixing well so that all of the fruit is dusted with the dry mix.  Cream the butter and sugar together and, when thoroughly creamed, beat in the egg replacer and jam/jelly. \r\n\r\n \r\n\r\nPreheat oven to 275 F (yes 275, not 375).  Put a broiler pan of water on the rack below the cake. Prepare your cake pans.  I use a regular-size bundt pan, plus a small loaf pan.  I pack the batter into the bundt pan and then put the leftover into the loaf pan.  You can also just use three loaf pans, each lined with waxed paper.  The loaf pans make smaller cakes which are easier to remove intact from the pans. The bundt-pan version is pretty, but it often sticks.  This is a very sugary cake, so it WILL stick if you give it a reason to. \r\n\r\n \r\n\r\nBake on the middle rack, above the pan of water, for 3.5-4 hours.  If the top of the cakes start to get too brown, cover the cakes with foil.  You can start them off that way for the first few hours, if you want, then remove the foil later.  They\'re done when they\'re nice and brown, but not blackened.  If the exposed bits of fruit start to burn, you\'ve cooked it too long. \r\n\r\n \r\n\r\nServe at room temperature.  If you want to make it pretty, you can sprinkle it with a little sifted icing sugar.  Because this cake so obviously cries out for more sugar. \r\n\r\n \r\n\r\nIf you like your fruit cakes soaked in rum and then aged, and you try that with this recipe, please let me know how it goes.  I\'ve never tried that.\r\n\r\n \r\n\r\n', 'Enjoy!  And save me a piece.\r\n\r\n \r\n\r\nMike', 45),
(472, 'ice cream sandwich cake', 'ice cream sandwich around 6-8 (depends on the size of pan you are using\r\ncaramel spread ( i use sunday topping)\r\ncool whip\r\nshredded choc (optimal)', 'place ice cream sandwich bottom of pan\r\ntop with caramel spread\r\nthen your cool whip \r\nthen shred some choc on it\r\nkeep in freezer', 'delicious', 45),
(473, 'BLUEBERRY MUFFINS', '2 CUPS FLOUR\r\n2 TSP BAKING POWDER\r\n1/4 TSP SALT\r\n1/2 CUP LIGHT MARGARINE\r\n1/4 CUP HONEY\r\n2 LARGE EGGS\r\n1 CUP SPLENDA\r\n1 TSP VANILLA EXTRACT\r\n1/2 CUP 1% LOW FAT MILK (I USED SKIM\r\n1 CUP FRESH BLUEBERRIES', '1.PLACE OWEN RACK IN TOP 1/3 OF OVEN\r\n2.PREHEAT OVEN 400 DEGREES.LINE 12 MUFFIN CUPS WITH PAPER LINERS SPRAYED WITH PAM I JUST USED THE PAN WITH NO LINERS AND SPRAYED WITH PAM\r\n3.SIFT TOGETHER, FLOUR,BAKING POWDER AND SALT AND SET ASIDE.\r\n4. BEAT MARGARINE@MEDIUM SPEED WITH MIXER,GRADUALLY ADD SPLENDA AND HONEY,THEN ADD EGGS UNTIL BLENDED.STIR IN VANILLA, ALTERNATELY ADD FLOUR MIXTURE AND MILK BEGINNING AND ENDING WITH FLOUR MIXTURE, BEAT AT LOW SPEED ,FOLD IN THE BERRIES THEN FILL MUFFIN CUPS AND BAKE FOR 20  TO 22 MINUTES OR UNTIL GOLDEN', 'ON WEIGHT WATCHERS WITH THIS NEW POINT PLUS.\r\nPER MUFFIN    4 PTS\r\n\r\nJAN 9,2011\r\nENJOY\r\nBEA', 59),
(474, 'SYRIAN bread(cheese bread)', 'recipe to be doubled\r\n\r\n\r\n1 pkg yeast\r\n5 cups flour\r\n1 tsp salt\r\n1/4 cup oil \r\n1 3/4 cup warm water(approx)\r\n\r\nCheese  topping\r\n2 1/2 lb mild shredded cheese\r\n2 1/2 lb medium shredded cheese\r\n4 large chopped onions\r\n3 eggs\r\nMix all cheese ingredients together.', 'Prepare yeast as directed on pkg.Mix flour,salt and oil well adding yeast mixture and warm water last. Knead gently until dough is smooth in texture.Cover and let rise in a warm place for about 1 1/2 hr. Break off pieces the size of a small orange and work with hands until a smooth ball.Let rest on floured board or wax paper for 20 minutes keep it well covered.\r\nThen roll smoothly with rolling pin in circular motion/Add mixture of cheese on top of loaves and bake on flat pans in a 500F oven until golden. Keep loaves covered till cool  enjoy', 'bea', 42),
(475, 'deluxe 3 egg white cake', '2 cups flour\r\n3 tsp baking powder\r\n1/2 tsp salt\r\n1/2 cup shortening\r\n1 1/4 cups sugar\r\n3 eggs separated\r\n1 tsp vanilla\r\n1 cup milk', 'Stir flour,baking powder and salt together. Cream shortening; gradually add sugar, beating between additions. Add egg yolks and beat until fluffy. Add dry ingredients,alternately with milk, blending well after each addition. STIR in vanilla.  BEAT egg whites until stiff but not dry;fold into batter. pour into 2 greased and floured or lined 8&quot; layer cake pans. BAKE in moderate oven 350F 25 to 30 minutes or until done. for cupcakes bake between 15 to 20 minutes', 'enjoy and frost as desired', 45),
(476, 'Mom,s Tomato Vegetable Soup', '1(3lb chicken) cut up\r\n8 cups water\r\n1 celery rib,HALVED\r\n1 medium onion halved\r\n3 medium potatoes,peeled and cut inb 1/2 in cubes\r\n2 cups tomato juice\r\n1 (15oz) can mixed vegetables (I used cauliflower, carrots and broccoli)\r\n1 can 15.5 oz 3 beans medley\r\n1 28 oz canned tomatoes\r\n1/2 cup chopped onion\r\n2 1/2 tsp salt\r\n1 tsp pepper\r\n1/2 lb lean ground beef\r\n1 15 oz can cream style corn', 'DIRECTIONS;1. In a large soup kettle ,place chicken,water, celery and onion. Cover and bring to a boil; skim fat.Reduce heat;cover and simmer for 1 1/2 hr or until chicken falls off the bones. Strain broth and skim fat, return broth to kettle. Add the next 8 ingredients.\\debone the chicken and cut into chunks;return to kettle. Bring to a boil.Meanwhile ,in a medium skillet , brown beef;drain and add soup. Reduce heat;cover and simmer for 1 hr. Stir in corn;uncovered for 30 minutes stirring occasionally', 'enjoy real tasty\r\n\r\nBea', 62),
(477, 'Sweet Potato Chili', '1 medium red onion chopped\r\n1 green pepper, chopped\r\n1 red bell pepper, chopped\r\n1 medium sweet potato, peeled cut into 1/2 pieces.\r\n4 garlic cloves, chopped or 1 heaping tablespoon of minced garlic\r\n1 tablespoon of chili powder\r\n1 teaspoon of ground cumin\r\n1 teaspoon of cayenne pepper (more or less depending on how spicy you like your chili)\r\n2 teaspoons unsweetened cocoa powder\r\n1/4 teaspoon ground cinnamon\r\nground sea salt and black pepper\r\n1 28 oz can diced tomatoes including the liquid\r\n1 can black beans, rinsed and drained\r\n1 can kidney beans rinsed and drained\r\n1 can vegetable broth', 'In a 4 to 6 quart Dutch over or stockpot, saute the chopped vegetables in one to tw, o tablespoon of olive oil on medium-high heat. You\'ll need to stir the ingredients every few minutes so thy can cook evenly. Once the onions start turning translucent, turn the heat down to medium-low.  Add all of the spices and canned ingredients, and stir.  Cover for about two hours, stirring occasionally.  By the time your chili is done, the sweet potatoes should be nice and soft and the liquid should have reduced a bit, producing the hearty chili consistency that we all know and love.', 'very good recipe...a bit spicy so i did not add the cayenne pepper (as i did not have any).  It was perfect for us that way .', 17),
(478, 'cherry cheesecake', '3/4 cup graham cracker crumbs\r\n2 tbsp light butter melted\r\n2/3 cup low-fat cream cheese\r\n6 tbsp fat free cream cheese\r\n3 tbsp lemon juice\r\n2 large egg whites\r\n1 1/2 tsp vanilla\r\n3/4 cup light cherry pie filling', 'Place 12 cupcake liners in cupcake pan.Preheat oven to 375f\r\nIn a small bowl combine graham crackers crums with melted butter,mix well..Sponn 1 tbsp of crumb mixture on the bottom of each cupcake liners then refrigerate till needed,,\r\nin large mixer bowl mix the cream cheeses,with beater till fluffy then add lemon juice,egg whites,vanilla and sugar beat till smooth\r\nSpoon cream cheese mixture evenly into liners,bake until sett about 15 minutes, remove from oven and cool.\r\nwhen cool add 1 tbsp of cherry pie filling to baked cheesecake', 'very good\\\r\n\r\nPOINTS PLUS  is   3\r\n\r\nbea', 45),
(656, 'Fish Chowder Soup', '\r\n\r\n\r\n40g / 3 tbsp butter unsalted\r\n2 garlic cloves minced\r\n1 small onion finely chopped\r\n2 small carrots halved, cut into 0.5cm / 1/5\" slices\r\n1/2 cup (125ml) dry white wine (can skip)\r\n1/4 cup (35g) flour (plain / all purpose)\r\n3 cups (750 ml) milk any fat %\r\n2 cups (500 ml) fish stock, clam juice OR chicken stock, preferably low sodium (Note 1)\r\n2 cups potato 1.5 cm/ 0.5\" cubes (~1 large potato)\r\n1 cup corn frozen or canned (drained)\r\n0.5 tsp salt plus more to taste\r\nFinely ground black pepper\r\n600 g/1.2 lb white fish fillets skinless, cut into 2cm / 4/5\" pieces (Note 2)\r\n1 cup peas frozen\r\n1/4 cup green onions halved and finely sliced (garnish)\r\nCrusty bread for dunking\r\n', '1. Melt butter in a large pot over medium heat.\r\n2. Add garlic and onion, cook for 5 minutes until translucent but not golden.\r\n3. Add carrots and stir through.\r\n4. Turn heat up to high and add wine. Stir then let it simmer rapidly until it\'s mostly evaporated.\r\n5. Add flour and stir for 30 seconds - it will become sludgy!\r\n6. Slow pour in broth while stirring to dissolve paste, then stir in milk.\r\n7. Add potato, corn, salt and pepper. Bring to simmer then turn heat down so it\'s simmering gently.\r\n8. Cook, stirring every now and then, for 8 minutes or until potato is almost cooked.\r\n9. Add fish and peas, simmer for 3 minutes or until fish is just cooked (should flake easily).\r\n10. Adjust salt and pepper to taste. If soup is too thick, add a touch of water or milk.\r\n11. Serve, garnished with green onions and crusty bread on the side for dunking\r\n\r\n\r\n', '1. Broth / liquid stock - in order of preference:\r\na) first choice is homemade or good quality store bought fish stock (I avoid standard supermarket fish\r\nstock like Campbell\'s, good fish stock is sold at fish shops)\r\nb) clam juice (not sold in Australia, it\'s in the US and Canada. Great for seafood soups, pastas, etc, way\r\nbetter than supermarket fish stock)\r\nc) chicken broth - this is what I use for everyday purposes, you still get GREAT flavour in the soup from\r\nthe fish that is poached in the broth.\r\nThis is not a soup suitable to make with stock cubes or bouillon powder - you really need to buy or\r\nmake a liquid stock.\r\n2. Fish - this is ideal made with \"meaty\" firm fish such as: Snapper, barramundi, tilapia, basa, cod, ling,\r\nmonkfish, marlin, latchet (gurnard), leatherjacket, Spanish mackerel, shark (flake), salmon.\r\nAvoid delicate fish such as whiting, garfish, John Dory, flat fish (flounder, sole) and flathead as th', 21),
(483, 'Strawberry-Banana Tofu Smoothie', 'NGREDIENTS\r\n3/4 cup(s) soy milk, may substitute skim, almond, or rice milk\r\n1/2 cup(s) tofu, silken, (quarter of a 16-ounce block)\r\n1/2 medium banana(s), preferably frozen, sliced into rounds\r\n1/2 cup(s) strawberries, frozen', '1. Combine all ingredients in a blender, and blend until smooth and frothy. ', '1 serving = 2 cups Silken tofu gives this smoothie a good dose of vegetarian protein and a thick, creamy texture. If you prefer, substitute Â½ cup nonfat yogurt (plain or vanilla) for the tofu.', 60),
(484, ' FROZEN BANANA BITES ', '- 2 large bananas\r\n- 1/3 cup chocolate chips\r\n- 1/3 cup peanut butter\r\n- Unsweetened coconut flakes\r\n\r\n', '1. Set out a large plate with a piece of Reynolds parchment paper on it\r\n2. Cut up the bananas into good-sized chunks. Each banana should give you around 5 to 6 pieces\r\n3. Heat the peanut butter and chocolate chips in the microwave on high for about a minute. Then stir until smooth\r\n4. Dip the banana pieces in the chocolate-peanut butter mixture. Lay them out leaving some space between them on the parchment paper. Then when you\'ve \"covered\" them all, use the remaining mixture to spoon over the tops (for even more chocolate-y goodness)\r\n5. Then sprinkle the unsweetened coconut flakes on top. Transfer to the freezer uncovered for about an hour until hardened ', 'from Facebook', 9),
(487, 'Purple Dragon Martini', '\r\n3oz vodka\r\n1 1/2oz cranberry juice\r\n1/2oz blue Curacao liqueur\r\n1/2oz sweet and sour mix\r\n1/2oz of 7-Up\r\n2-3 ice cubes\r\n\r\n', 'Directions \r\nin blender or food processor all ingredients and blitz 20 to 30 seconds on high speed.\r\nSalt the rim of your martini glass\r\n\r\n', 'Pour and Enjoy', 65),
(488, 'Slow Cooker Cabbage Rolls', '1 Head of Cabbage\r\n3 Cups Tomato Juice\r\n1 8oz. can tomato sauce\r\n1 egg\r\n1/2 C. uncooked brown or white rice\r\n1 envelope Onion soup mix\r\n1 lb. Ground Turkey or Extra Lean Ground Beef\r\n1/3 Cup Parmesan Cheese\r\n\r\n', 'Directions:\r\n\r\nPeel 8-12 big Leaves off the Cabbage head and place in a microwave safe dish. Cover in about an inch of water and microwave on high for 2 min.\r\n\r\nIn a mixing bowl combine tomato sauce, egg, turkey or beef, rice, onion soup, and cheese, and mix with fingers until well combined.\r\n\r\nGrease your crock pot with some Pam cooking spray', 'from facebook', 41),
(489, 'Maple Mustard Pork Roast', '\r\nINGREDIENTS\r\n\r\n1	 seasoned centre-cut boneless pork loin roast, about 3 lb (1.5 kg)\r\n1/3 cup (75 mL)	PC Dijon Prepared Mustard\r\n1 tbsp (15 mL)	 vegetable oil\r\n1/4 tsp (1 mL) each	 salt & freshly ground black pepper\r\n2/3 cup (150 mL)	PC 100% Pure Maple Syrup\r\n', 'Preheat oven to 400Â°F (200Â°C).\r\nRub pork roast with oil. Sprinkle with salt and pepper. Place in shallow roasting pan. Stir together maple syrup and mustard; pour over roast. Pour 1 cup (250 mL) water into pan.\r\nRoast uncovered in centre of oven for 20 to 25 minutes per lb/ 500 g or until meat thermometer inserted in centre reads 160Â°F (71Â°C), basting every 20 minutes with pan juices. Add more water to pan as needed to keep pan drippings from burning.\r\nLet stand 10 minutes before slicing. Serve with pan drippings.\r\n', 'CHEF\'S TIPS\r\n\r\nServe with mashed potatoes for a real comfort meal.', 17),
(490, ' Cinnamon Roll Swirl Cake Recipe', 'For the batter~\r\n3 cup flour\r\n1/4 tsp salt\r\n1 cup sugar\r\n4 tsp baking powder\r\n1 1/2 cup milk\r\n2 eggs\r\n2 tsp vanilla\r\n1/2 cup butter, melted\r\n\r\nTopping~\r\n1 cup butter, soft to the point of almost melted*\r\n1 cup brown sugar\r\n2 Tbsp flour\r\n2 Tbsp cinnamon', 'n a large bowl, mix all the ingredients together except for the butter.\r\nonce mixed ...slowly pour in the butter.\r\n\r\nPour into a greased 9x13 pan. \r\n\r\nFor the topping, mix all the ingredients together until well combined.\r\n\r\nDrop evenly over the batter and swirl with a knife. \r\nBake at 350 for 30-40 minutes.\r\n\r\nGlaze~\r\n2 cup powdered sugar\r\n5 Tbsp milk\r\n1 tsp vanilla\r\n\r\nWhile the cake is warm ~ drizzle the glaze over the cake. :)\r\nLike Â·  Â· Share Â· 6 hours ago Â· \r\nOptions\r\n', 'from Facebook', 40),
(491, 'Crock-Pot Chicken Teriyaki ', '1 lbs chicken, diced\r\n1 cup chicken broth\r\nÂ½ cup teriyaki sauce\r\n&#8531; cup brown sugar\r\n3 garlic cloves, minced', '1. Combine chicken broth, teriyaki sauce, brown sugar and garlic cloves in large bowl.\r\n\r\n2. Add chicken to sauce, and toss to combine.\r\n\r\n3. Pour chicken mixture into crock-pot.\r\n\r\n4. Cook on low 4-6 hours, or until chicken is cooked through.\r\n\r\n5. Serve over hot cooked rice and spoon extra sauce if desired.', 'from face book', 41),
(492, 'Apple Crisp Pizza', 'Pastry for single-crust pie (9 inches)\r\n2/3 cup sugar\r\n3 tablespoons all-purpose flour\r\n1 teaspoon ground Cinnamon\r\n4 medium apples (like Gala, Fiji, Braeburn, Empire) peeled and diced into 1/4 inch pieces\r\nTOPPING:\r\n1/2 cup all-purpose flour\r\n1/3 cup packed brown sugar\r\n1/2 cup old-fashioned rolled oats\r\n1 teaspoon ground cinnamon\r\n1/4 cup salted butter, softened\r\nDRIZZLE:\r\n1/2 cup caramel topping', 'Preheat oven to 350 degrees.\r\nRoll pastry to fit a 12 inch pizza pan; fold under edges to give the pizza a bit of a raised crust. Combine sugar, flour and cinnamon in a medium bowl. Add peeled, diced apples and toss. Arrange the apples in a single layer over the pie crust to completely cover it. \r\nFor the topping: Combine the flour, brown sugar, oats, cinnamon, and butter in a bowl. Mix well. Sprinkle topping evenly over the apples.\r\nBake at 350 degrees for 35-40 minutes or until apples are tender. Remove from oven and immediately drizzle with caramel topping. Cut into pizza slices and serve warm with ice cream. ', 'Makes 12 servings.\r\n', 40),
(493, 'Weight Watchers Beef and Broccoli ', '	 2 1/2 Tbsp cornstarch, divided   \r\n1/4 tsp table salt   \r\n 	 3/4 pound(s) uncooked lean trimmed sirloin beef, thinly sliced against the grain   \r\n2 tsp canola oil   \r\n 	 1 cup(s) reduced-sodium chicken broth, divided   \r\n 	 5 cup(s) uncooked broccoli, florets (about a 12 oz bag)   \r\n1 Tbsp ginger root, fresh, minced   \r\n2 tsp minced garlic   \r\n1/4 tsp red pepper flakes, or to taste   \r\n1/4 cup(s) water   \r\n1/4 cup(s) low sodium soy sauce   \r\n\r\n', 'On a plate, combine 2 tablespoons cornstarch and salt; add beef and toss to coat.\r\n\r\nHeat oil in a large nonstick wok or large deep skillet over medium-high heat. Add beef and stir-fry until lightly browned and cooked through, about 4 minutes; transfer to a bowl with a slotted spoon.\r\n\r\nAdd 1/2 cup broth to same pan; stir to loosen any bits on food on bottom of pan. Add broccoli; cover and cook, tossing occasionally and sprinkling with a tablespoon water if needed, until broccoli is almost crisp-tender, about 3 minutes. Uncover pan and add ginger, garlic and red pepper flakes; stir-fry until fragrant, about 1 minute.\r\n\r\nIn a cup, stir together water, soy sauce, remaining 1/2 cup broth and remaining 1/2 tablespoon cornstarch until blended; stir into pan. Reduce heat to medium-low and bring to a simmer; simmer until slightly thickened, about 1 minute.\r\n\r\nReturn beef and accumulated juices to pan; toss to coat. Serve. Yields about 1 1/4 cups per serving.\r\n', 'from face book', 66),
(494, 'Crock Pot Scalloped Potatoes With Ham', '3 pounds potatoes, peeled and thinly sliced\r\n 1 cup shredded Cheddar cheese\r\n 1/2 cup chopped onion\r\n 1 cup chopped cooked ham\r\n 1 (10.75 ounce) can condensed cream of mushroom soup\r\n 1/2 cup water\r\n 1/2 teaspoon garlic powder\r\n 1/4 teaspoon salt\r\n 1/4 teaspoon black pepper\r\n', 'Place sliced potatoes in slow cooker. In a medium bowl, mix together shredded cheese, onion and ham. Mix with potatoes in slow cooker. Using the same bowl, mix together condensed soup and water. Season to taste with garlic powder, salt and pepper. Pour evenly over the potato mixture.\r\nCover, and cook on High for 4 hours.', 'from Facebook  ', 61),
(495, 'SALAD IN A JAR', 'THE ARRANGEMENT\r\nFrom BOTTOM to TOP:\r\nDressing\r\nShredded carrots\r\nCherry tomatoes\r\nSunflower seeds\r\nHard boiled eggs\r\nBaby spinach\r\n', '1) Arrange ingredients in a large mason jar\r\n2) Store in fridge for up to a week\r\n3) When ready to eat: shake jar, place on a plate, and eat!\r\n\r\nYou can make any arrangement you wantâ¦ you can add red onion, cucumbers, radishes or peppers. Always remember to put the dressing at the bottom and the lettuce at the topâa MUST.\r\n\r\n****NOTE**** If your making a few salads at a time for the week, you MUST remember to vacuum seal the Mason Jars. (Mason jars can be bought at Wal-mart, and various grocery stores) They must be vacuum sealed to remain fresh and crisp :) Here are two different ways to vacuum seal a mason jar :D\r\n', 'MY NEWEST LUNCH OBSESSION!!!!! Utterly brilliant, people. Not only does  save space in your fridge, it also reduces food waste and gets non-salad eaters (me) to mow down daily. ', 55),
(496, 'Orange Cream Freezer Dessert Recipe ', '\r\n4 cups graham cracker crumbs\r\n3/4 cup sugar\r\n1 cup butter, melted\r\n3-1/2 quarts vanilla ice cream, softened\r\n2 cans (12 ounces each) frozen orange juice concentrate, thawed\r\n', 'n a bowl, combine cracker crumbs and sugar; stir in butter. Set aside 2 cups for topping. Press remaining crumb mixture into two greased 15-in. x 10-in. x 1-in. pans. Cover and freeze for at least 10 minutes.\r\nIn a large bowl, combine ice cream and orange juice concentrate until smooth. Spoon over crusts (pans will be full). Freeze for 10 minutes or until partially firm.\r\nSprinkle with reserved crumb mixture; gently press down. Cover and freeze for up to 2 hours. Remove from the freezer 15 minutes before serving.', ' Yield: 2 desserts (24 servings each).\r\n', 9),
(497, 'SKINNY BROCCOLI SALAD', '\r\n2 stalk(s) uncooked broccoli, Chopped \r\n1 head(s) (medium) uncooked cauliflower, Chopped \r\n1/2 cup(s) sweet red pepper(s), Chopped \r\n1/2 cup(s) green pepper(s), Chopped \r\n1 large fresh tomato(es), chopped \r\n1/2 large uncooked red onion(s), Chopped \r\n1 item(s) (large) large canned ripe black olive(s), 1 cup chopped \r\n1/2 cup(s) low-fat shredded cheddar cheese \r\n1 1/2 cup(s) fat free Ranch dressing (I changed the dressing to Ranch because I liked it better with Ranch.) \r\n\r\n', '\r\nBlanch the broccoli and cauliflower and then chop add everything in a large bowel add the dressing and toss. Place in the frig for four (4) hours and serve. \r\n', '(This recipe came from my Weight Watchers page of healthier recipes.)', 55),
(498, 'Cheesecake Cookies', '\r\n\r\n3 1/2 cups all-purpose flour\r\n2 teaspoons baking powder\r\n1 teaspoon salt\r\n2 (8-ounce) packages cream cheese, softened\r\n2 1/2 sticks butter, softened\r\n1 1/2 cups sugar\r\n2 large eggs\r\n2 teaspoons vanilla extract\r\n1 cup graham cracker crumbs\r\n2 cans (20-ounce) cherry pie filling (or your favorite kind.)\r\n\r\n\r\n', 'Combine the flour, baking powder and salt in a bowl. In another bowl with an electric mixer, beat cream cheese, butter and sugar until smooth and creamy, about 2 minutes. Add eggs and vanilla and mix until incorporated. Reduce speed to low and add the flour mixture and mix until just combined. Refrigerate dough until firm, at least 30 minutes.\r\nPreheat oven to 350 degrees. Line 2 baking sheets with parchment paper or silpat liners. Place graham cracker crumbs in a shallow dish.\r\nRoll the dough into 1 1/2-inch balls, then roll the balls in graham cracker crumbs. Place balls 2 inches apart on prepared baking sheets. Using a tablespoon measure, make an indentation in the center of each ball. Place 3 cherries in the dimple. Bake until golden brown around the edges, 12 to 14 minutes. Cool for five minutes on the sheet and then transfer to a wire rack to cool completely.\r\n\r\nPrep Time: 45 min (including refrigeration time) Cook Time: 14 min ', 'Yield: 3 dozen cookies\r\n\r\nSource: Cook\'s Country', 58),
(499, 'Easiest PB Fudge EVER', '\r\n2 cups sugar,\r\n1/2 cup milk (or use half and half)\r\n1 tsp. vanilla,\r\n3/4 cup peanut butter.\r\n', 'Bring sugar and milk to a boil. Boil two and a half minutes. Remove from heat and stir in PB and vanilla. That\'s it.', 'Easiest PB Fudge EVER', 9),
(500, 'Crispy Cheddar Chicken', '\r\n2 lbs chicken tenders or 4 large chicken breasts\r\n2 sleeves Ritz crackers\r\n1/4 teaspoons salt\r\n1/8 teaspoon pepper\r\n1/2 cup whole milk\r\n3 cups cheddar cheese, grated\r\n1 teaspoon dried parsley\r\n\r\nSauce:\r\n1 10 ounce can cream of chicken soup\r\n2 tablespoon sour cream\r\n2 tablespoon butter\r\n\r\n', 'Crush crackers. If using chicken breasts and not tenders, cut each chicken breast into 3 large pieces. Pour the milk, cheese and cracker crumbs into 3 separate small pans. Toss the salt and pepper into the cracker crumbs and stir the mixture around to combine. Dip each piece of chicken into the milk and then the cheese. Press the cheese into the chicken with your fingers. Then press the cheesy coated chicken into the cracker crumbs and press it in.\r\n\r\nSpray a 9Ã13 pan with cooking spray and lay the chicken inside the pan. Sprinkle the dried parsley over the chicken. Cover the pan with tin foil and bake at 400 degrees for 35 minutes. Remove the tin foil, bake for an additional 10-15 minutes, or until the edges of the chicken are golden brown and crispy.\r\n\r\nIn a medium sized sauce pan combine the cream of chicken soup, sour cream and butter with a whisk. Stir it over medium high heat until the sauce is nice and hot. Serve over the chicken.\r\nÂ· ', 'You may never fry chicken again after tasting this baked crispy chicken.', 54),
(646, 'Cheesy Chicken Fritters', '1 1/2 lbs chicken breasts (3 large)\r\n2 large eggs\r\n1/3 cup mayonnaise\r\n1/3 cup all-purpose flour or cornstarch or potato starch for gluten free\r\n4 oz mozzarella cheese (1 1/3 cups shredded)\r\n1 1/2 Tbsp chopped fresh dill\r\n1/2 tsp salt or to taste\r\n1/8 tsp black pepper\r\n2 Tbsp Extra light olive oil to saute (or any high heat cooking oil)\r\nIngredients for Garlic Aioli Dip (Optional)\r\n1/3 cup mayonnaise\r\n1 garlic clove pressed\r\n1/2 Tbsp lemon juice\r\n1/4 tsp salt\r\n1/8 tsp black pepper\r\n\r\n', 'n/a', '*To test for doneness, cut a fritter in half and the chicken should be completely white inside. If your chicken patty is browning too fast, adjust your heat down.', 54),
(647, 'Air Fryer-Fried Raviolis', '1 package of frozen ravioli\r\n2 cups of flour\r\n3 large eggs\r\n2 cups of breadcrumbs\r\nOther supplies: Non-stick cooking spray, marinara sauce for dipping\r\n\r\n', 'Keep the ravioli frozen, until ready to use\r\nThen dip the ravioli into flour, then beaten egg, then breadcrumbs\r\nThen spray them with non-stick cooking spray and then place them in the air fryer basket.\r\nBake at 380 for 20 minutes.\r\n\r\n', 'n/a', 70),
(648, 'Air Fryer-Mozzarella Sticks', '1 package of mozzarella sticks\r\n1 egg\r\nÂ½ cup of flour\r\nÂ¼ cup of breadcrumbs\r\nOptional: Serve with a side of marinara sauce', 'First. Cut the mozzarella sticks in half.\r\nThen place them on a baking sheet and freeze them for about 20 minutes.\r\nThen get them out, and dip them into the flour, egg and then breadcrumbs.\r\nThen place them back into the baking tray to freeze, for another 1 hour.\r\nThen place them in the fry basket, and fry for 12 minutes on 390 degrees.\r\nServe with marinara sauce.', 'n/a', 70);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(504, '*Fudge Brownie Pie*', '105g of flour\r\n(3/4 cup)\r\n200g of caster sugar\r\n(1 cup)\r\n1 ounce of unsweetened cocoa powder, sifted\r\n(1/4 cup)\r\n1 tsp baking powder\r\n1/4 tsp salt\r\n4 ounces butter, melted\r\n2 large free range eggs, beaten\r\n2 tsp vanilla\r\n60g of chopped toasted pecans (1/2 cup)\r\n2 handfuls of mini marshmallows\r\n \r\nFor the frosting:\r\n2 ounces butter, melted\r\n(1/4 cup)\r\n1 ounce cocoa powder, sifted\r\n(1/4 cup)\r\n2 ounces evaporated milk\r\n(1/4 cup)\r\n8 ounces icing sugar, sifted\r\n \r\n \r\nPreheat the oven to 180*C/350*F/ gas mark 4.  Butter a 9 inch flan pan with a removeable bottom well and then set aside. \r\n ', '\r\nWhisk together the flour, sugar, cocoa powder, baking powder and salt in a bowl.  Beat together the butter, eggs and vanilla.  Add to the dry ingredients and mix until smooth.  Stir in the toasted nuts.  Pour into the prepared pan.  Bake on a middle shelf of the oven for 25 to 30 minutes, or until a toothpick inserted in the centre comes out clean.  Immediately sprinkle the marshmallows on top and return to the oven for a few minutes to melt the marshmallows.  Remove from the oven and carefully spread the chocolate frosting over top.\r\n \r\nTo make the chocolate frosting mix all ingredients together in a bowl, beating with an eletric whisk until smooth and thick.  Spread on the hot marshmallows.\r\n \r\nLet cool completely.  Cut into wedges to serve.\r\n', 'Makes one 9 inch pie  Delicious fudgy brownie bottom topped with marshmallow and a tasty chocolate fudge icing.  Gorgeous!', 40),
(505, 'The best icing!', 'All you do is mix one vanilla pudding packet with half of the milk called for on the package. Whisk until it begins to thicken. Then fold in one container of Cool Whip. A great frosting spread on cakes and piped onto cupcakes, a tasty filling in crepes or on waffles along with some fruit...way less sugar too!!!!', 'The best icing!', 'The best icing!', 44),
(506, 'Two Ingredient Lemon Bars.', '.....\r\nThis is all you need:\r\n1 box angel food cake mix( I use Betty Crocker)\r\n2 cans lemon pie filling\r\nI used two 21 oz cans of Comstock pie filling ( total of 42 oz)\r\nMix dry cake mix and cans of pie filling together in large bowl.\r\nI just mixed it by hand...\r\n', 'Pour into greased 9 x 13&#8243; baking pan.\r\nBake at 350 degrees for 25 minutes or until top is starting to brown.\r\nNOTE...Mine took the full 25 minutes to get done and did not brown on top at all :))\r\nCool on wire rack and sprinkle with powered sugar. It has a melt in your mouth spongy texture.\r\nI have come across this recipe in a few different places so thanks to those who shared this yummy recipe!', '2 Ingredient Lemon Bars\r\nOh yeah you read that right only Two simple ingredients to make these melt in your mouth ( middle of the pie) lemon squares!Yep this is like you cut your self a slice right out of the middle of the pie!', 40),
(507, 'Loaded Potato and Buffalo Chicken Casserole:', '2 pounds boneless chicken breasts, cubed (1\")\r\n8-10 medium potatoes, cut in 1/2\" cubes\r\n1/3 cup olive oil\r\n1&1/2 tsp salt\r\n1 Tbsp. black pepper\r\n1 Tbsp. paprika\r\n2 Tbsp. garlic powder\r\n6 Tbsp. hot sauce\r\n\r\nTopping:\r\n2 cups fiesta blend cheese\r\n1 cup crumbled bacon\r\n1 cup diced green onion\r\n\r\n', 'Preheat oven to 500 degrees. Spray a 9X13\" baking dish with cooking spray. In a large bowl mix together the olive oil, salt, pepper, paprika, garlic powder and hot sauce. Add the cubed potatoes and stir to coat. Carefully scoop the potatoes into the prepared baking dish, leaving behind as much of the olive oil/hot sauce mixture as possible. Bake the potatoes for 45-50 minutes, stirring every 10-15 minutes, until cooked through and crispy and browned on the outside. While the potatoes are cooking, add the cubed chicken to the bowl with the left over olive oil/hot sauce mixture and stir to coat. Once the potatoes are fully cooked, remove from the oven and lower the oven temperature to 400 degrees. Top the cooked potatoes with the raw marinated chicken. In a bowl ix together the cheese, bacon and green onion and top the raw chicken with the cheese mixture. Return the casserole to the oven and bake for 15 minutes or until chicken is cooked through and the topping is bubbly delicious.\r\n', 'Serve with extra hot sauce and/or ranch dressing.\r\n\r\n    ', 54),
(508, 'Fudge Brownie Pie', '3/4 cup flour\r\n1 cup of regular sugar\r\n1/4 cup unsweetened cocoa powder, sifted\r\n1 teaspoon baking powder\r\n1/4 tsp salt\r\n4 ounces butter, melted\r\n2 large free range eggs, beaten\r\n2 teaspoons vanilla\r\n1/2 cup chopped toasted pecans\r\n2 handfuls of mini marshmallows\r\n\r\nFor the frosting:\r\n\r\n2 ounces butter, melted (1/4 cup)\r\n1 ounce cocoa powder, sifted (1/4 cup)\r\n2 ounces evaporated milk (1/4 cup)\r\n1 cup powdered sugar, sifted (8 ounces)\r\n\r\n', 'Preheat the oven to 350 degrees. Butter a 9 inch spring form pan set aside.\r\n\r\nWhisk together the flour, sugar, cocoa powder, baking powder and salt in a bowl. Beat together the butter, eggs and vanilla. Add to the dry ingredients and mix until smooth. Stir in the toasted nuts. Pour into the prepared pan.\r\n\r\nBake on a middle shelf of the oven for 25 to 30 minutes, or until a toothpick inserted in the center comes out clean. Immediately sprinkle the marshmallows on top and return to the oven for a few minutes to melt the marshmallows. Remove from the oven and carefully spread the chocolate frosting over top.\r\n\r\nTo make the chocolate frosting mix all ingredients together in a bowl, beating with an electric whisk until smooth and thick. Spread on the hot marshmallows. Let cool completely. Cut into wedges to serve.\r\n', 'good', 40),
(511, 'Banana Strawberry Pudding Desert', ' 1 cup (approx. 30 vanilla wafers) crumbled into crumbs\r\n1 pkg (3 ounces) cook-and-serve vanilla pudding mix (not instant)\r\n2 medium ripe bananas, divided\r\n1 pkg (3 ounces) strawberry Jello (I used sugar-free)\r\n1 cup whipped topping\r\n\r\n', 'Spread 1/2 of the vanilla crumbs on the bottom of a greased 8x8 pan.\r\n\r\nCook vanilla pudding as directed on package and spoon over crumbs while still hot.\r\n\r\nSlice up one banana over the pudding, and then spread the remaining crumbs over top. Place in the fridge one hour until set.\r\n\r\nMix up jello as directed on package, and let sit in fridge for 30 minutes until partially set.\r\n\r\nPour jello over the crumb layer, and then slice up the remaining banana over top, of the unset jello. Place in the fridge for 2-3 hours until set. Spread on a layer of whipped cream. (I used low sugar/fat Cool Whip)\r\n', 'Makes 9 servings.', 40),
(512, 'Srawberry Cheesecake', '1 Keebler Graham Cracker Crust\r\n1 (8oz) tub coolwhip\r\n1 (8oz) philadelphia cream cheese\r\n1/2 cup of sugar\r\nFor topping:\r\n1 pt. fresh strawberries\r\n\r\nOR\r\n1 Can premade strawberry topping (Comstock brand)\r\n\r\n\r\n', 'Mix softened cream cheese and sugar in medium bowl until fluffy.\r\nFold in cool whip.Pour into crust and garnish with fresh strawberries or strawberry topping. Refridgerate for 1 hour until firm.', 'good', 40),
(513, '\"Quicker than rice krispie treats and tastier than Reese\'s\"', '3 cups corn flakes, crushed\r\n1 cup crunchy peanut butter\r\n1/2 cup sugar\r\n1/2 cup white corn syrup\r\n6 ounces chocolate chips\r\n\r\n\r\n ', 'Directions:\r\n\r\n1\r\nHeat peanut butter, sugar and corn syrup over low heat to melt. Stir in cereal.\r\n2\r\nPat into a 8x8 lightly greased pan. (I line my pan with foil and then lightly spray it. When it is time to cut them, the foil lifts right out.).\r\n3\r\nMelt chocolate chips over low heat or in the microwave and spread over top. Cool until firm\r\n', '   Share', 40),
(514, 'French Toast Bake', '1/2 cup melted butter (1 stick)\r\n1 cup brown sugar\r\n1 loaf Texas toast\r\n4 eggs\r\n1 1/2 cup milk\r\n1 teaspoon vanilla\r\nPowdered sugar for sprinkle\r\n\r\n', '1. Melt butter in microwave & add brown sugar....stir till mixed.\r\n2. Pour butter/sugar mix into bottom of 9 x 13 pan....spread around\r\n3. Beat eggs, milk, & vanlla\r\n4. Lay single layer of Texas Toast in pan\r\n5. Spoon 1/2 of egg mixture on bread layer\r\n6. Add 2nd layer of Texas Toast\r\n7. Spoon on remaining egg mixture\r\n8. Cover & chill in fridge overnight\r\n9. Bake at 350 for 45 minutes (covered for the first 30 minutes)\r\n10. Sprinkle with powdered sugar\r\n11. Serve with warm maple syru', 'good', 67),
(515, 'Two Minute Hawaiian Pie', '1 can(s) crushed pineapples, undrained (20oz)\r\n1 bx instant vanilla pudding mix (6 serving )\r\n8 oz sour cream\r\n1 9 inch graham cracker crust\r\n1 can(s) (8oz) pineapple slices\r\n8 maraschino cherries\r\n1/2 c sweetened flaked, coconut\r\n1 sm container of cool whip for piping\r\n\r\n\r\n\r\n', 'in a large bowl, combine crushed pineapple with its syrup, dry pudding mix, and sour cream; mix until well combined. Spoon into pie crust and decorate top with pineapple slices and cherries; sprinkle with coconut.Pipe with Cool Whip if so desired..Cover and chill at least 2 hours before serving.', 'This pie actually does just take a few minutes to prepare\r\n', 40),
(516, 'Green Spring Cleaning Recipe for the Grout :)', '\r\n7 cups water, 1/2 cup baking soda, 1/3 cup lemon juice and 1/4 cup vinegar - ', 'throw in a spray bottle and spray your floor, let it sit for a minute or two... then scrub :)\r\n\r\n', 'PLEASE, LIKE and SHARE if you loved this tip!!', 51),
(517, 'Greek Yogurt Strawberry Banana Bread', '1.5 cups whole wheat flour\r\n1.5 tsp baking powder\r\n1/2 tsp kosher salt\r\n1/2 cup brown sugar (or 1/4 cup agave)\r\n3 large ripe bananas (I used 2)\r\n2 eggs\r\n6 oz. Chobani Strawberry Banana Greek yogurt (I used Strawberry)\r\n1 cup diced fresh strawberries\r\n', '	\r\nPreheat oven to 375 degrees. Start by combining flour, baking powder, and salt in a large mixing bowl.\r\nIn a separate bowl, mash bananas with a fork until they are gooey and liquid-like.\r\nAdd eggs and sugar and mix thoroughly.\r\nAdd greek yogurt\r\nWhisk until everything is well combined and there are no lumps.\r\nPour the wet ingredients into the dry ingredients, and mix until just combined. At this point, fold in the fresh strawberries!\r\nPour batter into a greased loaf pan and distribute evenly.\r\nPut into the oven and bake for one hour, or until the top is golden brown and a toothpick comes out clean (55 minutes for me).\r\nTransfer to a cooling rack and (try to) let the bread cool for at least ten minutes before slicing.\r\n', '....Healthy and Delicious!', 40),
(518, 'Cabbage Casserole (1/2 cooked)', '\r\nFry ground beef and onion, salt & pepper. Drain. Cut 1 cabbage in small peices and peel & cut about 6-8 carrot in coins. Layer large roaster with aprox 1/2 of the meat mixture, 1/2 of the cabbage and 1/2 of the carrot, then a tin of Alymers petite cut diced tomatoes, & 1 tin tomato soup. Then layer remaining meat mixture, cabbage, carrot and another tomato soup on top. Salt & pepper to taste. Cover and bake at 375 for about 1 1/2 hours. Stir occasionally. Casserole shrinks during baking. ', 'Enjoy!', 'Enjoy!', 17),
(519, ' Strawberry Angel Food Trifle', '(1) angel food cake\r\n24 oz. container frozen strawberries, sliced with sugar added, thawed\r\n3 cups sugar free vanilla pudding\r\n16 oz. container of whipped cream, slightly less than the whole container\r\nFresh strawberries for garnish', 'Tear angel food cake into medium pieces. Begin layering cake, strawberries, pudding and whip cream in a large clear glass bowl.Continue irregular layers, filling the bowl. Top entire dessert with a solid layer of whip cream. Slice a few fresh strawberries for garnish Refrigerate overnight or at least 4 hours before serving. To me it tastes like all the flavors of strawberry shortcake in one big yummy bite! I think it would be GREAT to add blueberries to this mix too.', 'YUMMY! ~ If you want to SAVE this recipe be sure to click SHARE so it will store on your personal page.', 40),
(520, 'Chocolate Peanut Butter Layered Cupcakes...', '1 1/2 cups Pillsbury BESTÂ® All Purpose Flour\r\n1/3 cup HersheyâsÂ® baking cocoa\r\n1 cup packed brown sugar\r\n1 teaspoon baking soda\r\n1/4 teaspoon salt\r\n1/3 cup CriscoÂ® Pure Vegetable Oil\r\n1 cup water\r\n1 tablespoon white vinegar\r\n1/2 teaspoon vanilla\r\n1 EGGLANDâS BEST eggs\r\n1 package (8 oz) cream cheese, softened\r\n3/4 cup JifÂ® Creamy Peanut Butter\r\n1/3 cup granulated sugar\r\n1/3 cup powdered sugar\r\n1/4 cup Reese\'sÂ® peanut butter chips\r\n1/4 cup HersheyâsÂ® semi-sweet chocolate baking chips', 'Heat oven to 350Â°F. Place paper baking cup in each of 18 regular-size muffin cups.\r\nIn large bowl, mix flour, cocoa, brown sugar, baking soda and salt. Add oil, water, vinegar and vanilla to flour mixture, stirring just until smooth (do not overmix).\r\nIn another large bowl, beat egg, cream cheese, peanut butter and granulated sugar with electric mixer on medium speed until smooth. Add powdered sugar; beat until creamy.\r\nSpoon 1 level tablespoon chocolate batter into each cup; evenly spread 1 level tablespoon peanut butter filling on top. Repeat layers. Sprinkle with peanut butter chips and chocolate chips.\r\nBake 25 to 30 minutes or until toothpick inserted in center comes out clean (do not overbake). Cool in pan 15 minutes. Remove from pan to cooling rack; cool 15 minutes.', ' Serve warm or cool', 59),
(521, 'Le meilleur Pouding chÃ´meur', 'PrÃ©chauffer le four Ã  325 F.\r\n\r\nSauce :\r\n1 tasse (250 ml) sirop d\'Ã©rable\r\n1 tasse (250 ml) cassonade\r\n1 tasse (250 ml) eau, bouillante\r\n1/4 de tasse (65 ml) beurre\r\n\r\nGÃ¢teau :\r\n1 1/2 tasse (375 ml) farine\r\n1 c. Ã  thÃ© (5 ml) poudre Ã  pÃ¢te\r\n1/4 de tasse (65 ml) beurre\r\n1 tasse (250 ml) sucre\r\n1 tasse (250 ml) lait\r\n', 'Tamiser ensemble la farine et la poudre Ã  pÃ¢te. Mettre de cÃ´tÃ©.\r\nDans un bol, dÃ©faire le le beurre en crÃ¨me. Incorporer graduellement le sucre jusqu\'Ã  l\'obtention d\'une consistance onctueuse.\r\nVerser le quart du lait et de la farine. MÃ©langer. RÃ©pÃ©ter jusqu\'Ã  Ã©puisement du lait et de la farine.\r\nBeurrer un moule rectangulaire de 13 x 9 pouces (32 x 22 cm). Verser la pÃ¢te. RÃ©server.\r\n\r\nDans une casserole, mÃ©langer tous les ingrÃ©dients de la sauce. Porter Ã  Ã©bullition et laisser bouillir quelques instants.\r\nVerser la sauce sur la pÃ¢te. Ne pas mÃ©langer. ', 'Cuire Ã  325 F pendant 45 minutes.', 40),
(522, 'KFC COLESLAW from All Things Homemade', '1/2 cup mayonnaise\r\n1/3 cup sugar\r\n1/4 cup milk\r\n1/4 cup buttermilk\r\n2 1/2 tablespoons lemon juice\r\n1 1/2 tablespoons white vinegar\r\n1/2 teaspoon salt\r\n1/8 teaspoon pepper\r\n8 cups finely chopped cabbage (approx. 1 head)\r\n1/4 cup shredded carrot (1 medium carrot)\r\n2 tablespoons minced onion\r\n\r\n\r\n', 'Directions:\r\n* Be sure cabbage and carrots are chopped into very fine pieces (a little bigger than rice)\r\n* Combine the mayonnaise, sugar, milk, buttermilk, lemon juice, vinegar, salt and pepper in large bowl. Beat until smooth\r\n* Add cabbage, carrots, and onions. Mix well.\r\n* Cover and refrigerate for at least 2 hours, if you let it sit over night it\'s even better.', 'KFC coleslaw is one of my all-time favorite foods, After doing some research I found this recipe and I have made it in the past and it is absolutely delicious! It tastes exactly like the stuff KFC makes!', 55),
(523, 'BTS CAKE (Better Than Sex...)', '1 pkg. devil\'s food, chocolate, or German chocolate cake mix\r\n1 can sweetened condensed milk\r\ncaramel ice cream topping\r\n1 (8 oz.) container frozen whipped topping, thawed\r\n4-5 Health or Skor bars, chopped up\r\n\r\n\r\n\r\n', 'Bake cake according to package directions for a 9x13 inch pan; cool for about 5 minutes.Using the handle of a wooden spoon, poke holes into the cake. Let the cake cool for a little while.\r\n\r\nSlowly pour sweetened condensed milk over the cake, letting it sink into the holes; then drizzle some of the caramel over the top of the cake.\r\n\r\n(Some people I know heat the milk and caramel together and then pour it over the cake.... I\'ve tried it both ways ... no real preference here)\r\n\r\nLet cake cool completely. Top cake with whipped topping. Decorate the top of the cake with candy bar chunks and swirls of caramel topping. Refrigerate before serving. (Great to make one evening and serve the next.)\r\n - it exceeds all limits, but wonderfully quick dessert for company and delicious with a cup of coffee!', 'DO NOT EVEN MENTION CALORIE  COUNT HERE', 40),
(524, 'Are you kitchen cabinets looking a little tired?', 'Mix 3/4 cup canola oil and 1/4 cup apple cider vinegar, place in a jar and shake, shake, shake. Take a rag (a cotton tee-shirt works best) and rub the oil onto the cabinets, wipe with another clean cloth and you will be amazed with the outcome! ', 'same as ingredients', 'I found a quick and easy formula on Pinterest to restore them. ', 51),
(525, 'Caramel Topping', '5 Tbsp butter\r\n1 cup brown sugar, packed\r\n1/4 cup half and half\r\nPinch salt\r\n1/2 tsp Vanilla extract\r\n\r\n', 'Melt butter and brown sugar in large heavy saucepan over low heat; stir constantly until mixture is smooth. Add half and half, then salt; simmer 4 minutes. Remove from heat; stir in vanilla.\r\n\r\n ', 'Serve over ice cream, desserts, pancakes, wafflesor as a dip for apples or other fruits.\r\nGranny\'s Favorites Cookbooks', 44),
(526, 'insect reppelent  recipe', '\r\nCombine in a 16 oz bottle:\r\n15 drops lavender oil\r\n3-4 Tbsp of vanilla extract\r\n1/4 Cup lemon juice.\r\n\r\n', 'Fill bottle with water. Shake.Ready to use. Make some extra to gift to your family & friends. (Trust me.. it\'ll be appreciated!) Share this on your wall so you\'ll have it handy when it\'s needed.\r\n\r\nHAPPY SPRING Y\'ALL!\r\n', 'Here\'s an easy & pleasant repellent recipe you can make at home:\r\n', 51),
(527, 'Heavenly Delight Chocolate Dream Dessert', 'â¢ CRUST:\r\nâ¢ 1 cup all-purpose flour\r\nâ¢ 1 cup finely chopped pecans\r\nâ¢ 1/2 cup cold butter\r\nâ¢\r\nâ¢ ORâ¦.A pre-made Graham Cracker Crust (My family prefers)\r\nâ¢\r\nâ¢ FILLING:\r\nâ¢ 1 package (8 ounces) cream cheese, softened\r\nâ¢ 1 cup confectioners\' sugar\r\nâ¢ 1 carton (8 ounces) frozen whipped topping, thawed, divided\r\nâ¢ 1 package (3.4 ounces) instant vanilla pudding mix\r\nâ¢ 1 package (3.9 ounces) instant chocolate pudding mix\r\nâ¢ 3 cups cold milk\r\nâ¢ 1 chocolate bar, grated\r\n', 'Directions\r\nâ¢ In a bowl, combine the flour and pecans; cut in butter until mixture resembles fine crumbs. Press into a 13-in. x 9-in. baking pan.\r\nâ¢ Bake at 350Â° for 15-20 minutes or until golden brown. Cool on a wire rack. Place the cream cheese, sugar and half the whipped topping in a large bowl; beat until smooth. Spread over crust.\r\nâ¢ Whisk pudding mixes and milk for 2 minutes or until soft-set. Spread over cream cheese mixture; chill until firm. Spread with remaining whipped topping, then sprinkle with grated chocolate. Refrigerate until serving', '\r\n( This is an ALL time favorite in my home!)', 40),
(528, 'shiny wood floor', '1 c water, 1 c vinegar, 1c alcohol, 2-3 drops dishwashing soap.....for shiny wood floors PLUS stainless steel appliances!', '1 c water, 1 c vinegar, 1c alcohol, 2-3 drops dishwashing soap.....for shiny wood floors PLUS stainless steel appliances!', '1 c water, 1 c vinegar, 1c alcohol, 2-3 drops dishwashing soap.....for shiny wood floors PLUS stainless steel appliances!', 51),
(529, 'SLICED BAKED POTATOES!!! YES!!!!!', 'Preheat oven to 375 degrees F (Can also do in Microwave for 6 plus minutes)\r\nBrush both side of potato slices with butter; place them on a cookie sheet. Bake in the preheated 400 degrees F oven for 30 to 40 minutes or until lightly browned on both sides, turning once.\r\n\r\nWhen potatoes are ready, top with bacon, cheese, green onion; continue baking until the cheese has melted;\r\n\r\n\r\n', 'Add a dollop of sour cream when done and enjoy', 'Yummy! What a clever idea!', 61),
(530, 'TO DIE FOR RICE KRISPY TREATS', '\r\n 3 Tbsp. butter 1 (10 oz.) bag of mini-marshmallows 1/4 cup yellow cake mix (the dry cake mix, not prepared into a batter!) 6 cups crispy rice cereal 1 (1.75 oz.) container of sprinkles Method: Melt butter in a large saucepan over low heat and add marshmallows. ', 'Stir until they begin to melt, adding in (dry) cake mix one spoonful at a time so its combined. Stir in cereal and let set. ', 'Warning: cake batter rice crispy treats.You will probably never make regular rice crispy treats again.', 9),
(531, 'Pizza Puffs of Paradise', '1-1/4 cups water\r\n1/3 cup shortening\r\n1-1/2 cups all-purpose flour\r\n4 eggs\r\n3/4 cup finely chopped pepperoni (3 oz.)\r\n3/4 cup finely shredded Romano or Parmesan cheese (3 oz.)\r\n2 tablespoons chopped fresh parsley\r\n1/8 teaspoon garlic powder\r\n1/8 teaspoon pepper\r\n1 jar pizza sauce\r\n\r\nPreparation:\r\nGrease 2 large baking sheets and set aside. In a large saucepan combine water and shortening. Bring to a boil. Add flour all at once, stirring vigorously. Cook and stir until mixture forms a ball. Remove from heat. Cool for 10 minutes. Add eggs, 1 at a time, beating well after each addition. Stir in pepperoni, cheese, parsley, garlic powder, and pepper.\r\n\r\n', 'Drop dough by rounded teaspoons 2 inches apart onto prepared baking sheets. Bake at 450Â°F for 15 to 17 minutes or until golden brown.\r\n\r\n', 'Serve with pizza sauce for dipping', 2),
(532, 'Amish Broccoli Salad', '1 head broccoli, chopped\r\n\r\n1 head cauliflower, chopped\r\n\r\n1 cup mayonnaise\r\n\r\n1 cup sour cream\r\n\r\n1/2 cup sugar\r\n\r\n1/2 teaspoon salt\r\n\r\n1/2 pound bacon, fried and crumbled\r\n\r\n1 cup shredded Cheddar cheese \r\n\r\nserving.', 'Combine the chopped broccoli and cauliflower in a large bowl. In a separate bowl, combine the mayonnaise, sour cream, sugar, and salt to make a creamy dressing. Add the dressing to the broccoliâcauliflower mix, stirring to evenly coat the vegetables. Stir in the bacon and the cheese, reserving a small amount to sprinkle on top of the salad just before  serving.1', 'Facebook', 55),
(533, 'Caramel Apple Cheesecake Bars', 'Crust:\r\n\r\n2 cups all-purpose flour\r\n\r\n1/2 cup firmly packed brown sugar\r\n\r\n1 cup (2 sticks) butter, softened\r\n\r\n\r\n\r\nCheesecake Filling:\r\n\r\n3 (8-ounce) packages cream cheese, softened\r\n\r\n3/4 cup sugar, plus 2 tablespoons, divided\r\n\r\n3 large eggs\r\n\r\n1 1/2 teaspoons vanilla extract\r\n\r\n\r\n\r\nApples:\r\n\r\n3 Granny Smith apples, peeled, cored and finely chopped\r\n\r\n1/2 teaspoon ground cinnamon\r\n\r\n1/4 teaspoon ground nutmeg\r\n', 'Preheat oven to 350 degrees F.\r\n\r\nIn a medium bowl, combine flour and brown sugar. Cut in butter with a pastry blender (or 2 forks) until mixture is crumbly. Press evenly into a 9x13 baking pan lined with heavy-duty aluminum foil. Bake 15 minutes or until lightly browned.\r\n\r\n\r\n\r\nIn a large bowl, beat cream cheese with 3/4 cup sugar in an electric mixer at medium speed until smooth. Then add eggs, 1 at a time, and vanilla. Stir to combine. Pour over warm crust.\r\n\r\n\r\n\r\nIn a small bowl, stir together chopped apples, remaining 2 tablespoons sugar, cinnamon, and nutmeg. Spoon evenly over cream cheese mixture. Sprinkle evenly with Streusel topping. Bake 40-45 minutes, or until filling is set. Drizzle with caramel topping and let cool. Serve cold and enjoy!', 'Streusel Topping:\r\n\r\n1 cup firmly packed brown sugar\r\n\r\n1 cup all-purpose flour\r\n\r\n1/2 cup quick cooking oats\r\n\r\n1/2 cup (1 stick) butter, softened\r\n\r\n\r\n\r\nIn a small bowl, combine all ingredients. I like to really combine it by using my clean hands to thoroughly combine the butter into the mixture.', 9),
(534, 'Strawberry cream cheese crescent rolls', '    \r\n\r\n    pillsbury crescent rolls\r\n    8 tsp strawberry jam\r\n    4 oz cream cheese, room temperature\r\n    1/4 c sugar\r\n    1/2 tsp lemon juice\r\n    1/2 tsp pure vanilla extract\r\n    1 egg white\r\n    1 tsp water\r\n    1 tbsp sugar to sprinkle on top\r\n\r\n\r\n    ', 'Directions\r\n\r\n    1 Preheat oven to 375. Line cookie sheet with aluminum foil.\r\n    2 Mix together cream cheese, sugar, lemon juice and vanilla extract until creamy and there are no lumps.\r\n    3 Unroll crescent rolls. On fattest part of triangle; spoon on 2 tsp of cream cheese mixture and 1 tsp of strawberry jam. Roll and make sure fattest part of crescent roll is on the bottom of pan so that filling doesn\'t ooze out.\r\n    4 Whisk together egg white and water. Brush over each crescent roll.\r\n    5 Bake for 9-10 minutes until crescent rolls are golden brown. Sprinkle with granulated sugar, if desired (yes...I did). \r\n', 'facebook', 9),
(535, 'Caramel Topping', '5 Tbsp butter\r\n1 cup brown sugar, packed\r\n1/4 cup half and half\r\nPinch salt\r\n1/2 tsp Vanilla extract', 'Melt butter and brown sugar in large heavy saucepan over low heat; stir constantly until mixture is smooth. Add half and half, then salt; simmer 4 minutes. Remove from heat; stir in vanilla.\r\n\r\nServe over ice cream, desserts, pancakes, waffles or as a dip for apples or other fruits.', 'facebook', 40),
(536, 'NEW WAY TO SERVE POTATOES, I LOVE IT ', 'potatoes \r\nbutter or \r\nadd yummy ingredients like\r\ncooked bacon, cheese, parsley, green onion, garlic, etc. \r\n', 'Just mash potatoes plain with butter or you can add yummy ingredients like cooked bacon, cheese, parsley, green onion, garlic, etc. Stuff in to a greased muffin tin, run a fork along the top and brush with melted butter or olive oil. Bake at 375 degrees or until tops are crispy and golden.\r\n\r\n\r\n', 'yes we still need carbs in our diet even when we are trying to lose weight so this is a great way to stick with portion control!!!\r\n\r\nAlso remember there are varying sizes in muffin pans so you can choose the serving size!! Using mini muffin tins you can turn this into a healthy alternative to chips or wedges too. You still get the soft potato centre with the crunch on the outside without all the fat!!!!', 61),
(537, 'Unstuffed Cabbage Rolls', '1 1/2 to 2 pounds lean ground beef\r\n1 tablespoon oil\r\n1 large onion, chopped\r\n1 clove garlic, minced\r\n1 small cabbage, chopped\r\n2 cans (14.5 ounces each) diced tomatoes\r\n1 can (8 ounces) tomato sauce\r\n1/2 cup water\r\n1 teaspoon ground black pepper\r\n1 teaspoon sea salt', 'In a large skillet, heat olive oil over medium heat. Add the ground beef and onion and cook, stirring, until ground beef is no longer pink and onion is tender.\r\nAdd the garlic and continue cooking for 1 minute.\r\n\r\nAdd the chopped cabbage, tomatoes, tomato sauce, pepper, and salt. Bring to a boil. Cover and simmer for 20 to 30 minutes, or until cabbage is tender.', 'Yield: Serves 6 to 8', 17),
(538, 'Another idea to help the feet!!', '\r\nListerine: the BEST way to get your feet ready for summer. Sounds crazy but it works! Mix 1/4c Listerine (any kind but I like the blue), 1/4c vinegar and 1/2c of warm water. Soak feet for 10 minutes and when you take them out the dead skin will practically wipe off!\r\n\r\nFor more great tips, recipes and motivation The New You', 'Another idea to help the feet!!', 'Another idea to help the feet!!', 51),
(539, 'Another idea to help the feet!!', '\r\nListerine: the BEST way to get your feet ready for summer. Sounds crazy but it works! Mix 1/4c Listerine (any kind but I like the blue), 1/4c vinegar and 1/2c of warm water. Soak feet for 10 minutes and when you take them out the dead skin will practically wipe off!\r\n\r\nFor more great tips, recipes and motivation The New You', 'Another idea to help the feet!!', 'Another idea to help the feet!!', 51),
(540, 'Crispy Cheddar Chicken', '2 lbs chicken tenders or 4 large chicken breasts\r\n2 sleeves Ritz crackers\r\n1/4 teaspoons salt\r\n1/8 teaspoon pepper\r\n1/2 cup whole milk\r\n3 cups cheddar cheese, grated\r\n1 teaspoon dried parsley\r\n\r\nSauce:\r\n1 10 ounce can cream of chicken soup\r\n2 tablespoon sour cream\r\n2 tablespoon butter\r\n', 'Crush crackers. If using chicken breasts and not tenders, cut each chicken breast into 3 large pieces. Pour the milk, cheese and cracker crumbs into 3 separate small pans. Toss the salt and pepper into the cracker crumbs and stir the mixture around to combine. Dip each piece of chicken into the milk and then the cheese. Press the cheese into the chicken with your fingers. Then press the cheesy coated chicken into the cracker crumbs and press it in.\r\n\r\nSpray a 9Ã13 pan with cooking spray and lay the chicken inside the pan. Sprinkle the dried parsley over the chicken. Cover the pan with tin foil and bake at 400 degrees for 35 minutes. Remove the tin foil, bake for an additional 10-15 minutes, or until the edges of the chicken are golden brown and crispy.\r\n\r\nIn a medium sized sauce pan combine the cream of chicken soup, sour cream and butter with a whisk. Stir it over medium high heat until the sauce is nice and hot. Serve over the chicken\r\n', 'You may never fry chicken again after tasting this baked crispy chicken. Share this post so it saves to your photos on your timeline', 54),
(541, 'Fruit Salad - Ambrosia Style', 'Mandarin oranges, drained 2 (8 ounce) cans\r\nPineapple tidbits, drained 1 (16 ounce) can\r\nBananas, sliced 3\r\nMiniature marshmallows 1 (12 ounce) bag\r\nSour cream, container 16 ounces\r\nMaraschino cherries, sliced and drained (optional) 1 (6 ounce) can\r\nShredded coconut (optional) to taste\r\nÂ· ', 'Mandarin oranges, drained 2 (8 ounce) cans\r\nPineapple tidbits, drained 1 (16 ounce) can\r\nBananas, sliced 3\r\nMiniature marshmallows 1 (12 ounce) bag\r\nSour cream, container 16 ounces\r\nMaraschino cherries, sliced and drained (optional) 1 (6 ounce) can\r\nShredded coconut (optional) to taste\r\n', 'Mandarin oranges, drained 2 (8 ounce) cans\r\nPineapple tidbits, drained 1 (16 ounce) can\r\nBananas, sliced 3\r\nMiniature marshmallows 1 (12 ounce) bag\r\nSour cream, container 16 ounces\r\nMaraschino cherries, sliced and drained (optional) 1 (6 ounce) can\r\nShredded coconut (optional) to taste\r\n', 55),
(543, 'MELT IN YOUR MOUTH CHICKEN', '1/2 cup parmesan cheese\r\n1 cup Greek yogurt -plain\r\n1 tsp garlic powder\r\n1 1/2 tsp seasoning salt\r\n1/2 tsp pepper ', 'Spread mixture over chicken breasts, bake at 375 degrees for 45 mins--Absolutely Delish!', 'OMG This Chicken is TO DIE FOR!!! You Gotta Try it!!! Sooo Tender & Juicy! And it\'s Healthy...So much better than fried!!!\r\n', 54),
(545, 'Never boil corn again!', ' Throw it in the oven at 350 for 25-30 minutes. Thats it. Leave the husk on, it will trap in the moisture, leaving you with juicy, tender corn. \r\n', 'The husk and silk will peel away easily once its cooked. Cut off the large end and it slides right out with no silk. Bonus - keeps more of the nutrients in the corn (no boiling is best). Who Knew!', 'Want to know the easiest way to cook corn on the cob?', 22),
(546, 'Olive Garden Alfredo Sauce', '1 pkg Pasta (penne or fettuccine)\r\n1 stick of butter\r\n1 clove of minced garlic\r\n1 pint of heavy cream\r\n1 cup of fresh Parmesan cheese\r\n2 tbsp cream cheese\r\n1/4 tsp salt\r\n1/2 tsp white pepper', 'Make Pasta to your liking.\r\nIn a sauce pan over medium heat â melt butter and add garlic and cook for two minutes, then add in heavy cream and cream cheese and heat until bubbling, but do not boil.\r\nAdd in Parmesan Cheese and mix until the cheese melts.\r\nSprinkle in salt and pepper to taste (you don;t need to use all of this, do to your liking).\r\nMix the hot sauce into the noodles and serve. ', 'Just like Olive Garde', 57),
(547, 'Cold Fudge Cake ', 'Â¾ 	cup (1-Â½ sticks) butter, melted\r\n1Â½ 	cups all-purpose flour\r\n1 	cup chopped walnuts, divided\r\n2 	(4-serving-size) packages instant chocolate pudding mix\r\n3 	cups milk\r\n12 	ounces cream cheese, softened\r\n1 	cup confectioners\' sugar\r\n1 	(16-ounce) container frozen whipped topping, thawed, divided', 'Preheat oven to 350 degrees F.\r\n\r\nIn a medium bowl, combine the melted butter, flour, and 3/4 cup nuts. Press mixture into a 9-x 13-inch baking dish.\r\n\r\nBake 10 to 12 minutes, or until a firm crust forms; let cool.\r\n\r\nIn a medium bowl, whisk together pudding mix and milk until thickened; set aside. In another medium bowl, combine cream cheese, confectionersâ sugar, and half the whipped topping; mix well.\r\n\r\nUsing a wet table knife, spread cream cheese mixture over top of cooled crust. Spoon chocolate pudding mixture over top of cream cheese mixture then top with remaining whipped topping. Sprinkle remaining walnuts on top.\r\n\r\nCover and chill overnight, or at least 6 hours. \r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n\r\n  \r\n', 'Refrigerate any leftovers', 45),
(548, 'Clayton\'s Vegan, gluten-free Peanut Sauce for stir-fries', 'Peanut Butter\r\nGluten-free Tamari sauce\r\nSugar\r\nWater\r\nFive Spice (or Chinese Five Spice)\r\nGinger powder\r\nGarlic powder', 'Mix ingredients.  You may want to begin by warming the peanut butter in the microwave to make it sauce.  Add water to get the right consistency.  Keep in mind that aauce will become more liquid when it comes into contact with hot vegetables. Mix well. After cooking vegetables, stir directly into wok or pan.', 'vegan and gluten-free', 60),
(549, '2 ingredients cake', ' 1- 21oz can of apple (or fruit of your choice) pie filling and 1 box of angel food cake ', 'mix.....that\'s it! NOTE: you MUST use the ONE-STEP (the kind that only requires water) cake mix for this to work....but DO NOT add the water!\r\nMix the 2 ingredients together (the dry packet of cake mix and the undrained can of fruit/filling) pour in a greased 9x13 pan or dish and bake for about 20 minutes at 350 (or according to baking directions on the box).\r\nPeople....it can\'t get ANY easier than this! A dollop or 3 of ice cream finishes it off perfectly', 'You\'re going to just DIE over this recipe!...\r\n2 SIMPLE ingredients:', 45),
(550, 'SLOW-COOKER SALSA CHICKEN!', '2 lbs. (32 oz.) chicken breasts, boneless and skinless\r\n1 cup salsa, homemade or purchased\r\n1 cup petite diced canned tomatoes (choose low-sodium)\r\n2 tbsp. taco seasoning\r\n1 cup onions, diced fine\r\n1/2 cup celery diced fine\r\n1/2 cup carrots, shredded\r\n3 tbsp. sour cream, reduced fat\r\n\r\n', 'n/a', 'Makes eight 1 cup servings.\r\nNutrition Info: Calories: 164.9; Fat: 2.5g; Carbohydrates: 7.3g; Protein: 27.6g', 41),
(649, 'Apple Pie Bread', '\r\n1 can apple pie filling, mashed\r\n1 yellow cake mix\r\n4 eggs, slightly beaten\r\n1 cup self rising flour\r\n1 Tbsp cinnamon\r\n1 medium chopped apple\r\n', 'Whisk all dry ingredients , add wet ingredients. Fold in apples. Pour in 2 loaf pans, greased. Sprinkle sugar and cinnamon on top. Bake in 325 oven for 35 to 45 minutes. ', 'Cool and enjoy', 42),
(650, 'LOADED CHICKEN AND POTATO CASSEROLE', '\r\n* 1 Â½ pounds boneless skinless chicken breasts cut in 1 inch pieces\r\n* 5 medium Russet or Idaho potatoes cut in 1 inch pieces\r\n* 3 Tablespoons olive oil\r\n* 1/2 Tablespoon paprika\r\n* 1 Tablespoon garlic powder\r\n* 1 teaspoon salt\r\n* 1 teaspoon black pepper\r\n* 2 cups shredded cheddar cheese\r\n* 1/2 cup cooked, chopped bacon\r\n* 2 green onions sliced thin\r\n', '\r\n* Preheat oven to 400Â° F. Grease a 9Ã13-inch baking dish with non-stick spray.&#8232;\r\n* Spread the diced raw chicken and potatoes evenly into the baking dish.&#8232;\r\n* In a large bowl, whisk together the olive oil, paprika, garlic powder, salt and pepper. Pour mixture evenly over the chicken and potatoes. Stir to coat the chicken and potatoes.\r\n* Bake, uncovered, for 50 to 55 minutes.\r\n* Remove from oven, and sprinkle evenly with the cheddar cheese, chopped bacon, and onion. Bake another 5 minutes, or until cheese is melted. Let stand 5 minutes before serving.', 'Seasoned chicken and potatoes, baked together, then topped with bacon, cheese and green onion. This is a phenomenal dish!\r\nPrep Time 20 minutes\r\nCook Time 50 minutes\r\nTotal Time 1 hour 10 minutes\r\n\r\nServings 4 to 6', 54),
(568, 'ITALIAN BAKE Recipe', '3 pounds chicken breasts (cooked & cut into bite size pieces)\r\n6 Italian sausage links\r\n2 jars or spaghetti sauce (I use Hunt\'s in the can - cheaper & just as good!)\r\n1 pound of pasta, penne, macaroni, shells or what ever you like\r\n1 large package of pizza cheese\r\n1 onion\r\n2 large bell peppers - red & green, cut into chunks\r\n\r\n', 'Cut up chicken, onion, peppers and sausage.\r\nBoil pasta and drain (don\'t over cook)\r\nMix pasta, sausage, onion, peppers, chicken and sauce.\r\nPut in a large deep dish. If it won\'t all fit, make a little side dish to freeze for lunch later.\r\nTop heavily with cheese.\r\nBake at 325 degrees for about 45 minutes or until golden and bubbly.', 'FROM FACEBOOK', 54),
(569, 'Oven Baked Cabbage Rolls ', '12 cabbage leaves\r\n1 pound ground beef\r\n3/4 cup cooked rice\r\n1/2 cup finely chopped onion\r\n2 cloves garlic, minced\r\n1 egg\r\n2 teaspoons salt\r\n1 teaspoon pepper\r\n1/2 cup milk\r\n\r\nSauce:\r\n1 cans (8 ounces ) tomato sauce\r\n1 can (14.5 ounces) diced tomatoes, undrained\r\n3 tablespoons sugar\r\n2 tablespoons vinegar\r\n1/2 cup water\r\n2 tablespoons cornstarch mixed with 1/4 cup cold water\r\n\r\n', 'Drop cabbage leaves into boiling salted water; cover and cook for 3 minutes. Drain well. Combine ground beef, rice, onion, egg, and salt, pepper, and milk. Mix well and divide into 12 portions.\r\nPlace a portion into the center of each cabbage leaf. Roll leaf around filling; fasten with toothpick. Place in a baking dish.\r\n\r\nFor sauce, combine tomato sauce, tomatoes, sugar, vinegar, and 1/2 cup of water and pour over cabbage rolls. Bake covered in a preheated 350 degree oven 40 to 45 minutes. Remove rolls and discard toothpicks. Place pan with juices over medium heat and stir cornstarch and water mixture into the sauce; bring to a boil and cook and whisk until thickened. Pour thickened sauce over cabbage rolls or serve on the side.', 'FROM FACEBOOK', 17),
(553, 'HAMBURGER STEW', '\r\n2 pounds ground beef\r\n2 medium yellow onions, chopped\r\n4 cans (14-1/2 ounces each) stewed tomatoes\r\n8 medium carrots, thinly sliced\r\n4 celery ribs, thinly sliced\r\n2 medium potatoes, peeled and cubed\r\n2 cups water\r\n1/2 cup uncooked long grain rice\r\n1 to 2 tablespoons salt\r\n1 to 2 teaspoons pepper\r\n', 'Cook beef and onions over medium heat; drain. Add tomatoes, carrots, celery, potatoes, water, rice, salt and pepper; bring to a boil. Reduce heat; cover and simmer for 30 minutes until vegetables and rice are tender. Uncover; simmer 20-30 minutes longer or until thickened.', 'Serve with buttered cornbread.', 41),
(554, 'Oven-Baked Zucchini Fries ', '3 zucchini (1 lb.)\r\n1/4 cup Grated Parmesan Cheese\r\n1 packet Shake & Bake Coating Mix\r\n1 small egg', '\r\nHeat oven to 450ÂºF.\r\nTrim the zucchini -cut crosswise in half, then cut each piece into 1/4-inch sticks. Add cheese to coating mix in shaker bag; shake gently to combine.\r\nWhisk egg in medium bowl. Add zucchini; toss to coat. Use tongs to place 1/4 of the zucchini in shaker bag; close bag and shake to evenly coat. Spread onto baking sheet sprayed with cooking spray. Repeat with remaining zucchini.\r\nBake for 12 to 13 min. or until golden brown, turning the baking tray 180 degrees after 7 min to facilitate even baking.\r\n', 'makes approximately 8 servings', 22),
(555, 'Zucchini Pizza Bites', '4 slices large zucchini 1/4\" thick (or 1 medium zucchini cut on diagnal)\r\nSpray olive oil (I used my Misto)\r\n2 tbsp pizza sauce\r\n1/4 cup part skim mozzarella\r\nsalt and pepper', 'Cut zucchini about 1/4 inch thick. Spray both side lightly with oil and season with salt and pepper. Broil or grill for about 2 minute on each side. Top with sauce and cheese and broil for an additional minute or two. (Careful not to burn cheese)', 'Gina\'s Weight Watcher Recipes\r\nServings: 1 â¢ Serving Size: 4 pieces â¢ Old Points: 2 pts â¢ Points+: 3 pts\r\nCalories: 124.8 â¢ Fat: 5.7 g â¢ Protein: 8.2 g â¢ Carb: 10.4 g â¢ Fiber: 3.0 g', 22),
(556, 'ZIP LOCK OMELET', 'his works great when you have a group of people together. No one has to wait for their omelet, everyone gets involved in the process and itâs a great conversation piece.\r\n\r\nHave guests write their name on a quart-size Ziploc freezer bag with permanent marker.\r\n\r\nCrack no more than two eggs (large or x-large) into each bag and shake to combine.\r\n\r\nPut out a variety of ingredients such as cheeses, ham, onion, green pepper, tomato, hash browns, salsa, etc as selection.\r\n\r\nEach guest adds prepared ingredients of their choice to their bag. Shake, carefully press air out of bag and zip it up.\r\n\r\nPlace the bags into rolling, boiling water for exactly 13 minutes. (We suspect that if you only make fewer at a time you might not need to cook them for that long.)\r\n\r\n\r\n\r\n\r\n', 'You can cook 6-8 omelets (bags) in a large pot. For more bags, make another pot of boiling water or cook in shifts.', 'Open the bags and the omelet will roll out easily. Be prepared for everyone to be amazed.', 67),
(557, 'S\'mores dip!', '1 cup of milk chocolate chips\r\n2 tbs of milk\r\n1Â¼ cups mini marshmallows\r\nGraham crackers for dipping\r\n', ' In a medium sauce pan add chocolate chips, milk and 1 cup of your mallows. Mix continuously over medium heat until melted and smooth. Using a rubber spatula, scrape chocolate mixture into a small casserole dish. Top with remaining mallows. Place dish under your oven broiler for approximately 60 seconds or until the top has started to brown. Dip your graham crackers and enjoy!', 'good', 56),
(558, 'Biscuit or Pastry ', '3 cups flour\r\n4 tsp baking powder\r\nÂ¼ cup sugar\r\nÂ½ cup butter (unsalted)\r\nÂ¼ tsp salt\r\nÂ¾ cup milk\r\nÂ½ cup water', 'Rub butter into dry ingredients. Add milk and water to make a soft dough. If the dough is too sticky, add a little flour and grease your hands with butter to knead, or if dough is not soft enough, add a little water.\r\nPress soft dough in a small baking pan.\r\nBake at 350ÂºF for 35-40 minutes until golden brown and not sticky in the middle.\r\nCut in small pieces and serve with butter.\r\n', 'I use this recipe with Beef Stew.\r\n\r\nPreparation time: 20 minutes\r\nBaking time: 35-40 minutes\r\nServings: 6', 42),
(559, 'Layered Pudding Delight', '14 graham crackers	\r\n1 pkg. Instant Vanilla pudding\r\n2 cups cold milk	\r\n1 cup cool whip\r\n1 can cherry pie filling', 'Mix pudding with milk and cool whip. In 9x9 pan layer bottom with crackers, next Â½ of\r\nthe vanilla pudding mixture, next crackers, \r\nnext last Â½ of pudding mixture and top with cherry pie filling. \r\nChill over nightâ¦.serve.', 'Double recipe for 9x13 pan. \r\n\r\nVariations: \r\nuse vanilla wafers in place of graham crackers\r\nuse chocolate pudding in place of vanilla pudding\r\nuse blueberry pie filling in place of cherry', 40),
(560, 'crusty parmesan-herb zucchini bites', '4 medium, fresh zucchini, sliced in half\r\n1/2 cup fresh Parmesan cheese, grated\r\n1-2 tablespoons fresh rosemary & thyme, minced\r\nsmidge of olive oil\r\nsalt & pepper to taste', 'Pre-heat oven to 350F, lightly brush both sizes of the zucchini with olive oil and place on a foil-lined baking sheet. Mix cheese and herbs together in a small bowl and sprinkle over the zucchini along with salt and pepper to taste. Bake for 15 minutes and place under the broiler for the last 3-5 minutes until cheese is crispy and browned.\r\n', '(recipe from nutritionella)', 22),
(561, 'Oven Baked Cabbage Rolls', '\r\n12 cabbage leaves\r\n1 pound ground beef\r\n3/4 cup cooked rice\r\n1/2 cup finely chopped onion\r\n2 cloves garlic, minced\r\n1 egg\r\n2 teaspoons salt\r\n1 teaspoon pepper\r\n1/2 cup milk\r\n\r\nSauce:\r\n1 cans (8 ounces ) tomato sauce\r\n1 can (14.5 ounces) diced tomatoes, undrained\r\n3 tablespoons sugar\r\n2 tablespoons vinegar\r\n1/2 cup water\r\n2 tablespoons cornstarch mixed with 1/4 cup cold water\r\n', 'Drop cabbage leaves into boiling salted water; cover and cook for 3 minutes. Drain well. Combine ground beef, rice, onion, egg, and salt, pepper, and milk. Mix well and divide into 12 portions.\r\nPlace a portion into the center of each cabbage leaf. Roll leaf around filling; fasten with toothpick. Place in a baking dish.\r\n\r\nFor sauce, combine tomato sauce, tomatoes, sugar, vinegar, and 1/2 cup of water and pour over cabbage rolls. Bake covered in a preheated 350 degree oven 40 to 45 minutes. Remove rolls and discard toothpicks. Place pan with juices over medium heat and stir cornstarch and water mixture into the sauce; bring to a boil and cook and whisk until thickened. Pour thickened sauce over cabbage rolls or serve on the side.', 'facebook', 17),
(562, 'Broccoli Cheese Soup Recipe', 'â¢2 cups sliced fresh carrots\r\nâ¢2 cups broccoli florets\r\nâ¢1 cup sliced celery\r\nâ¢1-1/2 cups chopped onion\r\nâ¢1/2 cup butter\r\nâ¢1/4 cup all-purpose flour\r\nâ¢1 can (10-1/2 ounces) condensed chicken broth, undiluted\r\nâ¢4 cups whole milk\r\nâ¢1 cup of cheddar or marble cheese, shredded\r\n\r\n\r\n', 'â¢In a large saucepan, bring 2 quarts water to a boil. Add carrots, broccoli and celery; cover and boil for 5 minutes. Drain and set aside.\r\nâ¢ In the same saucepan, saute onion in butter. Add flour and stir to make smooth paste. Gradually add chicken broth and milk. Cook until mixture thickens, about 8-10 minutes. Add vegetables; heat until tender. Add cheese; heat until cheese is melted. Yield: 6-8 servings (2 quarts).', 'from facebook', 62),
(563, 'Quick black forest cake', '4 cups mini-marshmallows\r\n1 chocolate cake mix\r\n1 can cherry pie filling\r\n1 large container of Cool Whip (or 2 cups whipping cream)', 'Method:\r\nPour four cups of mini-marshmallows into a greased 9x13 inch cake pan.\r\nPrepare chocolate cake mix according to directions on package. Pour over marshmallows.\r\nSpoon cherry pie filling evenly over cake.\r\nBake at 350Â°F for about 50 minutes...or until toothpick inserted comes out clean.\r\nCool.Top with whipped topping. (If using whipping cream, whip 2 cups of cream with 3 Tablespoons sugar and 2 teaspoons vanilla until almost ready to form peaks.)', 'If you need to make a great dessert in a pinch here is a good one that always ends up all gone before you turn around..Serves 15', 45),
(564, 'Slow Cooker Cabbage Rolls', 'â¢1 large head cabbage\r\nâ¢1 can (8 ounces) tomato sauce\r\nâ¢3/4 cup quick-cooking rice\r\nâ¢1/2 cup chopped green pepper\r\nâ¢1/2 cup crushed saltines (about 15 crackers)\r\nâ¢1 egg, lightly beaten\r\nâ¢1 ounce onion soup mix\r\nâ¢1-1/2 pounds lean ground beef (90% lean)\r\nâ¢1 can (46 ounces) V8 juice\r\nâ¢Salt to taste\r\nâ¢Grated Parmesan cheese, optional', 'â¢Cook cabbage in boiling water just until leaves fall off head. Set aside 12 large leaves for rolls; drain well. (Refrigerate remaining cabbage for another use.) Cut out the thick vein from the bottom of each reserved leaf, making a V-shaped cut; set aside.\r\nâ¢In a large bowl, combine the tomato sauce, rice, green pepper, cracker crumbs, egg and soup mix. Crumble beef over mixture and mix well.\r\nâ¢Place about 1/3 cup meat mixture on each cabbage leaf; overlap cut ends of leaf. Fold in sides, beginning from the cut end. Roll up completely to enclose filling. Secure with toothpicks if desired.\r\nâ¢Place cabbage rolls in a 3-qt. slow cooker. Pour V8 juice over rolls. Cover and cook on low for 6-7 hours or until filling reaches 160Â°. Just before serving, sprinkle with salt and cheese if desired', 'from facebook', 41),
(565, 'BETTER-THAN-TAKEOUT-FRIED-RICE', '\r\n4 cups rice, prepared (white or brown) refrigerated & day old is best\r\nÂ½ pound boneless, skinless chicken breasts, cooked or shrimp cooked\r\n1 cup peas & carrots, frozen\r\n1 white onion, chopped\r\n2 cloves garlic, minced\r\n2 eggs\r\n3 tablespoons sesame oil\r\nÂ¼ cup soy sauce\r\n\r\n', '1. Prepare rice according to package instructions to yield 4 cups cooked rice.\r\n2. Heat sesame oil in a large skillet on medium heat.\r\n3. Add onion, garlic, peas, and carrots. Stir fry until tender.\r\n4. Crack eggs into pan and scramble, mixing throughout vegetables.\r\n5. Add rice, chicken, and soy sauce to pan. Stir in soy sauce and remove from heat.\r\n', '\r\nServes: 5-6', 66),
(566, 'Spinach Dip Recipe ', '1 10 oz container of frozen chopped spinach â defrost and squeeze out all the juice 1-2 5 oz cans of sliced water chestnuts â dice into small pieces 1 8 oz container of 1% cottage cheese â blend with a handheld blender or in a traditional blender until smooth and creamy 1 packet ranch dressing ', 'After completing the above tasks, mix well, eat, and enjoy! No baking or cooking needed.', 'from facebook', 56),
(567, 'Beefy Tomato Macaroni Soup.', '1 pound ground beef\r\n1/2 cup onion, diced\r\n2 cloves garlic, minced\r\n6 cups beef broth\r\n1- 26.46 ounce can Chopped Tomatoes\r\n1- 26.46 ounce can Strained Tomatoes\r\n3 teaspoons Worcestershire sauce\r\n2 tablespoons brown sugar\r\n1 teaspoon dried basil\r\n1 1/2 teaspoons steak seasoning\r\n3 cups cooked elbow macaroni\r\nsalt and pepper, as desired\r\n\r\n', 'Directions:\r\nIn a large sauce pan or soup pot, brown ground beef, onion and garlic until ground beef is no longer pink. Season with salt and pepper while browning.\r\n\r\nAdd broth, chopped and strained tomatoes, Worcestershire, brown sugar, basil and steak seasoning. Bring to slight boil over medium high heat, stirring occasionally. Reduce heat and simmer for 10 minutes. Add cooked macaroni and heat through and serve!', 'from facebook', 62);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(570, 'Homemade Salisbury Steaks', '2 lbs uncooked ground beef\r\n3 tablespoons Worcestershire sauce (or more if you desire)\r\n1 teaspoon garlic powder\r\n1 dash salt and pepper\r\n2 cups beef gravy\r\n\r\n', 'Directions:\r\n1.Take a cookie sheet and cover it with foil, pre heat oven to 350-375Â°F.\r\n2.Get your hands dirty! In a large mixing bowl add ground beef, Worcestershire sauce, garlic powder, salt and pepper to taste. Mix well with your hands. Make patties according to the size you want. Place patties on foiled cookie sheet.\r\n3.Bake until done to your preference (for well done-30 minutes or so).\r\n4.When patties are done, make gravy according to package instructions. Pour brown gravy on top and enjoy with some mashed potatoes!', 'FROM FACEBOOK', 17),
(571, 'Loaded Potato Bites', '- 2 cups leftover mashed potatoes\r\n- 2 tablespoons of flour\r\n- 2/3 cup of shredded cheddar cheese\r\n- 3 strips bacon\r\n- 1/3 cup scallions, chopped\r\n- 1 egg\r\n- 1 Â¼ - 1 Â½ cups Italian bread crumbs\r\n- Oil for frying\r\n- Salt and Pepper\r\n- Ranch or Honey Mustard for dipping\r\n', '    1. Take potatoes out of the fridge and let sit for a few minutes to take the chill off a bit. Meanwhile shred the cheese, chop scallions, and cook bacon then dice finely. Add potatoes and flour to a large mixing bowl and stir to combine well, then add cheese, bacon, and scallions. Take about a heaping tablespoon of mixture and roll with hands into a small ball. It if doesnât hold its shape, add a little more flour to make the potatoes sturdy. Repeat until done.\r\n\r\n    2. Heat oil in a medium sauce pan â or use your fryer â over medium/medium high heat to about 350-375 degrees. Whisk egg into a small bowl and season with salt and pepper. Place bread crumbs in an additional bowl. Dip each ball in egg and then roll in bread crumbs until fully coated. Set aside on a sheet pan.\r\n\r\n    3. Test oil with one ball. The oil should bubble when potato is in oil and ball should take about 1-2 minutes to brown and cook through. (If takes longer the oil needs to be hotter, if it browned too quickly on the outside and the inside is still cold, the temperature needs to be lower.) Once oil is ready, add potato balls in small batches and fry for 1-2 minutes â it will depend on size. Remove with slotted spoon and place on paper lined plate to allow excess oil to drain off. Repeat until done.\r\n\r\n    4. Allow to cool for a minute or two and serve with dipping sauce.\r\n\r\n\r\n    ', 'FROM FACE BOOK', 61),
(572, 'Baked Parmesan Fish', '16 ounces fish fillets\r\n1 egg\r\n2 tablespoons milk\r\nBreading\r\n1/3 cup parmesan cheese, grated\r\n2 tablespoons flour\r\n1/2 teaspoon paprika\r\n1/4 teaspoon salt\r\n1/8 teaspoon pepper', '1 Beat egg and milk in a shallow bowl and set aside. In a zipper bag combine breading ingredients.\r\n2 One at a time dip fillets in egg, shake off excess and turn or shake in breading in bag.\r\n3 Bake uncovered on an oiled baking sheet at 350 degrees for about 25 minutes or until fish flakes easily with a fork.\r\n4 Can be served with lemon wedges if desired.', 'Nutritional Facts\r\nServing Size: 1 (146 g)\r\nServings Per Recipe: 4\r\n\r\nCalories 192.8\r\nCholesterol 117.2 mg\r\nSodium 382.8 mg\r\nTotal Carbohydrate 3.9 g\r\nProtein 31.3 g', 21),
(573, ' Spinach Dip Recipe', '1 10 oz container of frozen chopped spinach â defrost and squeeze out all the juice\r\n1-2 5 oz cans of sliced water chestnuts â dice into small pieces\r\n1 8 oz container of 1% cottage cheese â blend with a handheld blender or in a traditional blender until smooth and creamy\r\n1 packet ranch dressing', 'After completing the above tasks, mix well, eat, and enjoy!', 'No baking or cooking needed.', 56),
(574, 'Breakfast Bake', '10 eggs\r\n1/2 cup milk\r\n16 oz refrigerated breakfast biscuits (I used the Pillsbury flakey kind) ***DO NOT COOK FIRST!!!***\r\n4 scallions (green onions, spring onions, whatever you prefer to call them)\r\n1 cup shredded extra sharp cheddar cheese\r\nIf youâre into the meats â cooked center cut bacon or cooked sausage\r\n11Ã17 pan, sprayed with cooking spray (Note: I think a 9Ã13 works better, but it might need to bake a little longer)', '1. Mix your eggs and milk in a large bowl. Cut each biscuit (Iâm all about scissors in the kitchen) into fours and add it to the bowl. I like to do this before I cook the bacon or cut up the scallions â give the biscuits some time to really soak in the eggs.\r\n\r\n2. Cut up your scallions, shred your cheese, cook and break up your bacon (or sausage). Add everything to the bowl.\r\n\r\n3. Mix it all up and pour into your pan. Bake at 350 for 25-30 minutes .. closer to 30 so it isn\'t runny\r\n\r\nBLC Hint/Tip *** - If you want to make this the night before, leave it in the mixing bowl covered with saran and put in fridge overnight. The next morn, give it a good stir and bake as directed!!', 'YUMMY!! Serve with Fresh Fruit Salad and lotsa coffee/tea and assorted juices', 67),
(575, 'Easy Baked Meatballs Recipe', '1 lb lean ground beef\r\n2 eggs, beaten with 1/2 cup milk\r\n1/2 cup grated Parmesan\r\n1 cup panko or bread crumbs\r\n1 small onion, minced\r\n2 cloves garlic, minced\r\n1/2 teaspoon oregano\r\n1 teaspoon salt\r\nfreshly ground pepper to taste\r\n1/4 cup minced fresh basil', 'Mix all ingredients with hands.\r\nForm into golfball sized meatballs.\r\nBake at 350 degrees for 30 minutes.', 'FROM FACEBOOK', 17),
(576, 'Mini Chicken Pot Pies', '2 cups frozen mixed vegetables,\r\nthawed\r\n1 cup diced cooked chicken\r\n1 can (10 3/4 oz) condensed cream of chicken soup\r\n1 can (16.3 oz) Pillsbury Grands! Flaky Layers refrigerated biscuits', '1) Heat oven to 375Â°F. In medium bowl, combine vegetables, chicken and soup; mix well.\r\n2) Press each biscuit into 5 1/2-inch round. Place 1 round in each of 8 greased regular-size muffin cups. Firmly press in bottom and up side, forming 3/4-inch rim. Spoon a generous 1/3 cup chicken mixture into each. Pull edges of dough over filling toward center; pleat and pinch dough gently to hold in place.\r\n3) Bake at 375Â°F 20 to 22 minutes or until biscuits are golden brown. Cool 1 minute; remove from pan.', 'FROM FACEBOOK', 54),
(577, 'Parmesan Meatloaf', '2lbs Ground Beef\r\n1/2 cup Parmesan Cheese\r\n1/4 cup Dijon Mustard\r\n1/2 cup Ketchup\r\n2 tbs Majoram\r\n1 tbs dried basil\r\n1 tbs dried parsley\r\n1 tbs oregano\r\n1 tbs thyme\r\n1 teaspoon salt\r\n2 teaspoon pepper\r\n1/2 cup mozzarella cheese\r\n4 cloves garlic, chopped\r\n1/4 cup green bell pepper\r\n1 small onion, very finely chopped\r\n1/2 cup spaghetti sauce of your choice\r\n1 tbs olive oil\r\n1 large egg, beaten (optional)\r\n', 'In a large bowl, combine the ground beef, egg, seasonings, and dressings in a bowl.\r\n\r\nPut mixed beef, into a sprayed loaf pan.\r\n\r\nTop the meatloaf with pasta sauce and mozzarella cheese.\r\n\r\nPlace filled loaf pan on bottom rack of oven and bake in the preheated oven at 375 degrees for 45 minutes - 1 hour. Remove the meatloaf from the oven and allow to rest for 5-10 minutes before serving/slicing. Garnish with parsley if desired..', 'FROM FACEBOOK', 17),
(578, 'Famous Red Lobster Shrimp Scampi', '1 lb medium shrimp, peeled and deveined\r\n1 tablespoon pure olive oil\r\n... 2 tablespoons garlic, finely chopped\r\n1 1/2 cups white wine, I use chardonnay\r\n1/2 fresh lemon, Juice only\r\n1 teaspoon italian seasoning\r\n1/2 cup softened butter\r\n1 tablespoon parsley\r\n1/2 cup grated parmesan cheese', '1 Heat cast iron skillet and add olive oil.\r\n2 Add shrimp and cook until tender and no longer translucent, reduce heat. Remove Shrimp and set aside.\r\n3 Add garlic and cook 2-3 minutes. Do not allow garlic to brown - it will make it bitter.\r\n4 Add white wine, and lemon juice.\r\n5 Cook until wine is reduced by half. After it is reduced, add Italian seasoning.\r\n6 Reduce heat to low, and add butter. If pan is too hot, the butter will separate.\r\n7 Add shrimp back into sauce, add parsley, and season to taste with salt and pepper.\r\n8 Sprinkle with grated Parmesan Cheese\r\n', 'FROM FACEBOOK', 21),
(579, 'Famous Red Lobster Shrimp Scampi', '1 lb medium shrimp, peeled and deveined\r\n1 tablespoon pure olive oil\r\n... 2 tablespoons garlic, finely chopped\r\n1 1/2 cups white wine, I use chardonnay\r\n1/2 fresh lemon, Juice only\r\n1 teaspoon italian seasoning\r\n1/2 cup softened butter\r\n1 tablespoon parsley\r\n1/2 cup grated parmesan cheese', '1 Heat cast iron skillet and add olive oil.\r\n2 Add shrimp and cook until tender and no longer translucent, reduce heat. Remove Shrimp and set aside.\r\n3 Add garlic and cook 2-3 minutes. Do not allow garlic to brown - it will make it bitter.\r\n4 Add white wine, and lemon juice.\r\n5 Cook until wine is reduced by half. After it is reduced, add Italian seasoning.\r\n6 Reduce heat to low, and add butter. If pan is too hot, the butter will separate.\r\n7 Add shrimp back into sauce, add parsley, and season to taste with salt and pepper.\r\n8 Sprinkle with grated Parmesan Cheese\r\n', 'FROM FACEBOOK', 21),
(580, 'CINNAMON ROLL CAKE', '3 c. flour\r\n1/4 tsp. salt\r\n1 c. sugar\r\n4 tsp. baking powder\r\n1 1/2 c. milk\r\n2 eggs\r\n2 tsp. vanilla\r\n1/2 c. butter, melted\r\nTopping:\r\n1 c. butter, softened\r\n1 c. brown sugar\r\n2 Tbsp. flour\r\n1 Tbsp. cinnamon', 'Directions:\r\nMix everything together except for the butter. Slowly stir in the melted butter and pour into a greased 9x13 pan. For the topping, mix all the ingredients together until well combined. Drop evenly over the batter and swirl with a knife. Bake at 350 for 28-32 minutes.\r\nGlaze:\r\n2 c. powdered sugar\r\nenough milk to make a runny glaze about 6 or 7 tablespoons\r\n1 tsp. vanilla\r\n\r\nWhile warm drizzle the glaze over the cake.', 'FROM FACE BOOK', 45),
(581, 'Loaded Baked Potato & Chicken Casserole', '2lbs chicken breast\r\n8 potatoes\r\n1/3 cup Olive Oil\r\n1 1/2 tsp salt\r\n1 TBS fresh Ground Pepper\r\n1 TBS Paprika\r\n2 TBS Garlic Powder\r\n6 TBS Hot Sauce\r\n{Toppings}\r\n2 cups Shredded Cheese\r\n1 cup crumbled Bacon\r\n1 cup diced Green Onion', 'Preheat oven 500F\r\nIn a large bowl mix Olive Oil, Salt, Pepper, Paprika, Garlic Powder & Hot Sauce\r\nCube the potatoes & add to the bowl\r\nCoat a 9x13 dish with cooking spray\r\nAdd potatoes, allow for excess sauce in the bowl\r\nBake the potatoes for 45 minutes, stir every 15 minutes\r\nCube the chicken & add it to the bowl with the left over sauce\r\nMix together cheese, bacon & green onion in a small separate bowl\r\nOnce potatoes are done, add the uncooked marinated chicken\r\nThen layer the toppings over the chicken\r\nBake for 15 minutes or until the chicken is cooked', 'FROM FACEBOOK', 54),
(582, 'Peanut Butter Cornflake Clusters', '1 cup sugar\r\n1 cup corn syrup\r\n1 jar (18 oz ounce) peanut butter, crunchy or smooth (I used creamy)\r\n6 cups corn flakes\r\n3 oz good quality chocolate of your choice', '1. In a saucepan, combine the sugar and corn syrup over medium-high heat until it comes to a full boil. Remove from heat and add the peanut butter, stirring until smooth and incorporated.\r\n2. In a large bowl, mix the corn flakes and the peanut butter mixture together, gently stirring very well until all of the cereal is coated.\r\n3. Drop spoonfuls of the cornflake mixture onto wax paper.\r\n4. Heat the chocolate in the microwave, stirring every 30 seconds, until melted and smooth. Drizzle over cornflake clusters and let cool. Serve when they have cooled.', 'Sticky, Gooey, Creamy, Chewy', 58),
(583, ' SLICED BAKED POTATOES', '4-5 potatoes\r\n4 Tbs butter, melted\r\n4-5 green onions, chopped\r\n1 cup grated cheese of your choice\r\n4 strips of cooked bacon', '1. Preheat oven to 400 degrees\r\n2. Slice potatoes about Â¼â thick and brush both sides of potato slices with butter; place them on a cookie sheet.\r\n3. Bake in the preheated oven for 30 to 40 minutes or until lightly browned on both sides, turning once.\r\n\r\nWhen potatoes are ready, top with bacon, cheese, green onion; continue baking until the cheese has melted;\r\n\r\nAdd some sour cream and enjoy!!\r\n', 'FROM FACEBOOK', 61),
(584, 'BROCCOLI QUICHE ', ' 10 ounces frozen chopped broccoli, cooked and well drained 8 ounces cheddar cheese, shredded 2 ounces onion, chopped, about 1/3 cup 6 eggs 1 cup heavy cream 1 teaspoon salt Dash pepper', 'Spray a large glass pie plate. Put the broccoli, onion and cheese in the bottom of the plate. Beat the eggs, then whisk in the cream, salt and pepper. Pour evenly over the cheese. Bake at 350Âº for 35-45 minutes, until a knife inserted in the center comes out clean. Let stand 10 minutes before cutting. ', ' Makes 6 servings Can be frozen Per Serving: 379 Calories; 32g Fat; 18g Protein; 5g Carbohydrate; 2g Dietary Fiber; 3g Net Carbs', 64),
(585, 'CHICKEN APPLE WRAPS', ' 1/2 c cooked chopped skinless chicken breast - 3 Tbsp chopped apple - 2 Tbsp. chopped grapes - 2 Tbsp. Natural Peanut butter - 1 Tbsp Greek yogurt - 2 Tbsp Honey ( optional ) - Romaine lettuce ', ' Mix all chopped ingredients in a bowl, add the rest of the ingredients and mix well. Spoon into lettuce leaf, roll & serve. ', 'FACEBOOK', 54),
(586, 'Apple Cinnamon Bread', ' 1/3 cup brown sugar (not packed) 1 teaspoon ground cinnamon 2/3 cup white sugar 1/2 cup butter, softened 2 eggs 1 1/2 teaspoons vanilla extract 1 1/2 cups all-purpose flour 1 3/4 teaspoons baking powder 1/2 cup milk 1 apple, peeled and chopped.', 'Preheat oven to 350 degrees. Grease and flour a 9 x 5-inch loaf pan. Mix brown sugar and cinnamon together in a bowl and set aside. Beat white sugar and butter together in a bowl using an electric mixer until smooth and creamy. Beat in eggs, 1 at a time, until incorporated; add vanilla extract. Combine flour and baking powder together in another bowl; stir into creamed butter mixture. Mix milk into batter until smooth. Pour half the batter into the prepared loaf pan. Next add half the apples and half the brown sugar cinnamon mixture. Lightly pat apple mixture into batter. Pour the remaining batter over apple layer; top with remaining apples and add more brown sugar/cinnamon mixture. Lightly pat apples into batter; swirl brown sugar mixture through apples using a finger or spoon. Bake in the preheated oven until a toothpick inserted in the center of the loaf comes out clean, 30 to 40 minutes.', ' http://allrecipes.com/recipe/apple-cinnamon-white-cake/photo-gallery.aspx', 45),
(587, '{Baked Fried Chicken}', '  Place thawed chicken breast tenderloin strips in a bowl of milk. Let soak for 20-30 min. Mix in a Gallon Size Ziploc or Large Bowl: 1/2 tsp. Salt 1 T Season All 3/4 tsp Pepper 1 c. Flour 2 tsp. Paprika Preheat oven to 400 degrees. Cut 1/2 stick of butter into a few pieces and place in a 9x13 pan.', ' Melt butter in pre-heated oven. Spread melted butter around the bottom of the pan. Lightly spray the pan, if needed, to make sure that there are no dry spots. Shake excess milk off of chicken and completely coat each piece with the seasoning mix. You can either shake the chicken in the bag, until coated, or dip each piece in the bowl until coated. Place each piece of chicken in the pan. Cook for 20 min. Turn each piece of chicken and continue cooking for 20 more minutes, or until cooked through. ENJOY! ', ' ENJOY! ', 54),
(588, 'POTATO PUFFS', '3 cups of mashed potatoes\r\n2 eggs\r\n1/3 cup sour cream (optional extra for serving)\r\n1 heaping cup shredded sharp cheddar cheese\r\n2 tablespoons grated Parmesan\r\n2 tablespoons chopped chives or parsley\r\nSalt and black pepper, to taste\r\n', 'Directions Preheat oven to 400 degrees F. Lightly grease with butter 8 - 9 of the wells of a nonstick muffin pan. In a medium mixing bowl whisk the eggs then mix in the sour cream. Stir in both cheeses and the chives. Add potatoes and mix well. Spoon them into the pan filling the cups to slightly below the top. Bake 25- 35 minutes until they pull away from the sides of the cup and are golden brown. Remove from oven and let them cool 5 minutes in pan. Serve with sour cream if desired.', 'from facebook', 61),
(589, 'Easy Triple Bake', '\r\n\r\n\r\n\r\nPut refrigerated cookie dough into the bottom of each well. Place Reese cup upside down on top of cookie dough (or an Oreo!).\r\nTop with prepared box brownie mix, filling 3/4 full.\r\nBake for 18 minutes.', 'Preheat oven to 350', 'from facebook', 58),
(590, 'Crash Hot Potatoes', 'baby potatoes\r\nolive oil\r\nsalt & pepper\r\nfresh herbs and garlic\r\ngrated parmesan cheese', 'boil some baby potatoes (I used red) until fork tender. Preheat oven to 450 degrees. Drizzle olive oil on a baking sheet, set potatoes on sheet and using a potato masher, gently smash each potato down, rotating masher both ways (so it looks like a thick cookie). Drizzle with olive oil, season with salt/pepper and sprinkle cut fresh herbs and garlic over each. THEN top with some lovely grated Parmesan cheese. Bake for 20 minutes. OMG...crispy on the outside, soft in the middle, salty, garlicky, herby and cheesy goodness.', 'from facebook', 61),
(591, ' ROASTED GARLIC MUSHROOMS', '16 even-sized open cup mushrooms, stalks cut level\r\n\r\n3 tbsp corn or vegetable oil\r\n\r\n1/4 c unsalted butter, softened\r\n\r\n3 cloves garlic, chopped very finely\r\n\r\n2 tbsp fresh thyme, chopped\r\n\r\n1 1/2 tbsp lemon juice\r\n\r\nsalt and freshly ground black pepper to taste\r\n\r\n1/4 c fresh breadcrumbs', 'Preheat the oven to 200C/400F/gas mark 6. Lightly fry the mushrooms, cap-side down, in hot oil for 20 seconds.\r\n\r\nArrange the mushrooms in a shallow roasting tin with the stalks facing upwards.\r\n\r\nMix together the butter, garlic, thyme, lemon juice and seasoning. Spoon a little garlic butter on to each mushroom, then lightly press the breadcrumbs on top. Either refrigerate for later use, or cook immediately in the oven for 10 minutes.\r\n', 'from facebook', 22),
(592, 'Skinny Shake', '3/4 cup Almond Milk\r\nabout 15 ice cubes\r\n1/2 tsp Vanilla\r\n1-2 Tbsp unsweetened Cocoa powder\r\n1/3 of a Banana\r\n', 'Blend.', 'it tastes like a Wendy\'s frosty', 65),
(593, 'Roasted Asparagus', '1 bunch of Asparagus, washed and ends trimmed\r\nolive oil\r\nfresh squeezed lemon juice\r\nkosher salt\r\nblack pepper\r\nfreshly grated Parmesan cheese', 'Place Asparagus on large baking sheet. Drizzle with olive oil and lemon juice. Sprinkle with kosher salt and black pepper. Place in a 350 degree oven and roast for 10 minutes. Remove from oven and sprinkle with freshly ground Parmesan cheese. Return to the oven and roast for 5 more minutes until tender.', 'from facebook', 22),
(594, 'Crispy Cheddar Chicken', '2 lbs chicken tenders or 4 large chicken breasts\r\n2 sleeves Ritz crackers\r\n1/4 teaspoons salt\r\n1/8 teaspoon pepper\r\n1/2 cup whole milk\r\n3 cups cheddar cheese, grated\r\n1 teaspoon dried parsley \r\nSauce:\r\n1 10 ounce can cream of chicken soup\r\n2 tablespoon sour cream\r\n2 tablespoon butter', 'Crush crackers. If using chicken breasts and not tenders, cut each chicken breast into 3 large pieces. Pour the milk, cheese and cracker crumbs into 3 separate small pans. Toss the salt and pepper into the cracker crumbs and stir the mixture around to combine. Dip each piece of chicken into the milk and then the cheese. Press the cheese into the chicken with your fingers. Then press the cheesy coated chicken into the cracker crumbs and press it in.\r\n\r\nSpray a 9Ã13 pan with cooking spray and lay the chicken inside the pan. Sprinkle the dried parsley over the chicken. Cover the pan with tin foil and bake at 400 degrees for 35 minutes. Remove the tin foil, bake for an additional 10-15 minutes, or until the edges of the chicken are golden brown and crispy.\r\n\r\nIn a medium sized sauce pan combine the cream of chicken soup, sour cream and butter with a whisk. Stir it over medium high heat until the sauce is nice and hot. Serve over the chicken.\r\nPhoto: Crispy Cheddar Chicken 2 lbs chicken tenders or 4 large chicken breasts 2 sleeves Ritz crackers 1/4 teaspoons salt 1/8 teaspoon pepper 1/2 cup whole milk 3 cups cheddar cheese, grated 1 teaspoon dried parsley Sauce: 1 10 ounce can cream of chicken soup 2 tablespoon sour cream 2 tablespoon butter Crush crackers. If using chicken breasts and not tenders, cut each chicken breast into 3 large pieces. Pour the milk, cheese and cracker crumbs into 3 separate small pans. Toss the salt and pepper into the cracker crumbs and stir the mixture around to combine. Dip each piece of chicken into the milk and then the cheese. Press the cheese into the chicken with your fingers. Then press the cheesy coated chicken into the cracker crumbs and press it in. Spray a 9Ã13 pan with cooking spray and lay the chicken inside the pan. Sprinkle the dried parsley over the chicken. Cover the pan with tin foil and bake at 400 degrees for 35 minutes. Remove the tin foil, bake for an additional 10-15 minutes, or until the edges of the chicken are golden brown and crispy. In a medium sized sauce pan combine the cream of chicken soup, sour cream and butter with a whisk. Stir it over medium high heat until the sauce is nice and hot. Serve over the chicken.', 'from facebook', 54),
(595, 'Loaded Chicken & Potatoes', '1 lb boneless chicken breasts, cubed (1&#8243;)\r\n6-8 medium skin on red potatoes, cut in 1/2&#8243; cubes\r\n1/3 c olive oil\r\n1 1/2 tsp salt\r\n1 tsp black pepper\r\n1 Tbsp paprika\r\n2 Tbsp garlic powder\r\n2 Tbsp hot sauce (more if you like it HOT)\r\n\r\nTopping:\r\n\r\n2 c fiesta blend cheese\r\n1 c crumbled bacon\r\n1 c diced green onion', '1. Preheat oven to 400 degrees. Spray a 9X13&#8243; baking dish with cooking spray.\r\n2. In a large bowl, mix together the olive oil, salt, pepper, paprika, garlic powder, and hot sauce. Add the cubed potatoes and chicken and stir to coat. Carefully scoop the potatoes and chicken into the prepared baking dish..\r\n3. Bake the potatoes and chicken for 55-60 minutes, stirring every 20 minutes, until cooked through, crispy, and browned on the outside. While the potatoes are cooking, fry your bacon (about half a pound).\r\n4. Once the potatoes and chicken are fully cooked, remove from the oven. Top the cooked potatoes with the the cheese, bacon, and green onion. Return the casserole to the oven and bake for 5 minutes or until cheese is melted.\r\n\r\nServe With: extra hot sauce and/or ranch dressing or sour cream!', 'from facebook', 54),
(596, 'Baked Margarita Spaghetti Squash', '1 large spaghetti squash\r\n2 tbsp. olive oil\r\n1 large Roma tomato, finely chopped\r\n2 tbsp. finely chopped fresh basil\r\n1/4 cup shredded mozzarella cheese\r\n1 tsp. each salt & pepper\r\n1 tsp. garlic powder', 'Preheat the oven to 400 degrees. Using a large knife or a cleaver, slice the spaghetti squash in half lengthwise down the middle. Use a spoon to remove the seeds and center strings. Drizzle the two halves with olive oil and then sprinkle with salt, pepper and garlic powder. Place the squash, open side down on a cookie sheet and bake for 30 minutes. Remove from the oven, check to see if the squash is soft and easily comes up with a fork into a spaghetti like texture. If itâs too hard to remove, cook for another 10 minutes. Remove from the oven, scrape and fluff the stringy squash with a fork. Leave the squash in the skin. Turn the oven up to broil. Add the tomatoes and fresh basil into the squash, stir and top with the mozzarella cheese. Place in the broiler for 3-4 minutes, until the cheese is melted and slightly browned. Allow to cool for 5 minutes before serving the squash.\r\nShare to help us spread the cool recipes:', 'from fACEBOOK', 57),
(597, 'Lemon Blueberry Bread', '1/3 cup melted butter\r\n1 cup sugar\r\n3 tablespoons lemon juice\r\n2 eggs\r\n1 1/2 cups all-purpose flour\r\n1 teaspoon baking powder\r\n1 teaspoon salt\r\n1/2 cup milk\r\n2 tablespoons grated lemon zest\r\n1/2 cup chopped walnuts optional\r\n1 cup fresh or frozen blueberries\r\nGLAZE\r\n2 tablespoons lemon juice\r\n1 tablespoon butter melted\r\n1 cup confectioners sugar\r\n\r\n', 'In a mixing bowl, beat together butter, 1 cup sugar, juice and eggs. Combine flour, baking powder and salt; stir into egg mixture alternately with milk. Fold in lemon zest, nuts, and blueberries. Pour batter into greased loaf pan. Bake at 350 for 60 to 70 minutes.\r\nGLAZE\r\nCombine all ingredients mix well. Drizzle over bread.', 'from facebook', 42),
(598, ' A Classic Hummus', '2 cups Chickpeas\r\n2 tablespoons of tahini\r\nHalf the juice of a lemon\r\n2 table spoons of olive oil\r\n1 tsp of ground cumin\r\nSprinkle  sea salt', 'Place everything in a blender until smooth consistency. If hummus is too thick, add a splash of water.', 'must try', 56),
(599, 'Roasted Garlic Hummus', '2 cups chickpeas, cooked (or 1 15oz can)\r\n1/2 lemon, juiced\r\n1/2 cup extra virgin olive oil\r\n1/2 tsp ground cumin\r\n1/4 tsp sea salt\r\nroasted garlic, from one bulb', 'Pre-heat oven to 400 degrees.\r\nCut about 1/2 inch off the top of the bulb of garlic, exposing the top of each garlic clove.\r\nRemove the excess outside layers of the bulb by peeling them away.\r\nBrush the top with extra virgin olive oil and sprinkle with sea salt.\r\nCover with foil and roast for about 30 minutes until the garlic feels \'soft\'.\r\nLet cool then squeeze out individual cloves.\r\nAdd all ingredients into blender or food process well and blend until smooth.\r\n\r\n', 'hummus', 56),
(600, 'Avocado Hummus', '2 cups chickpeas, cooked (or one 15oz can)\r\n1/2 lemon, juiced\r\n1/3 cup extra virgin olive oil\r\n1/4 tsp sea salt\r\n1 clove garlic\r\n1/2 tsp ground cumin\r\n1/2 lime, juiced\r\n2 small ripe avocados \r\nCayenne pepper to taste ', ' Add all ingredients into food processor and blend until smooth', 'hummus', 56),
(601, 'Roasted Red Pepper Chipotle Hummus', '\r\n\r\n2 cups chickpeas, cooked (or one 15oz can)\r\n1/2 lemon, juiced\r\n1/3 cup extra virgin olive oil\r\n1/4 tsp sea salt\r\n1 clove garlic\r\n1/2 cup roasted red peppers\r\n1 chipotle pepper in adobo sauce', '\r\n Add all ingredients into food processor and blend until smooth.\r\n', 'hummus', 56),
(602, 'Cheesy Baked Cauiflower Tots ', '1/2 large head caulflower, coarsely chopped\r\n1/3 cup reduced-fat sharp cheddar\r\n1/4 cup coarsely grated Parmesan cheese\r\n2 T almond flour\r\n1/2 tsp. Vege-Sal (or a slightly smaller amount of salt)\r\n1/2 tsp. Spike Seasoning (Probably optional, but it does add flavor. You can substitute another all-purpose seasoning blend that tastes good with cauliflower)\r\nfresh-ground black pepper to taste\r\n1 egg', 'Preheat oven to 400F/200C. Spray a Mini Muffin Pan with non-stick spray.\r\n\r\nCut away the leaves of the cauliflower, but use most of the inner core part. Coarsely chop the cauliflower, place in a micro-wave proof bowl, cover with cling wrap, and microwave 2 minutes on high. (Microwaves can vary so you may need to experiment with the time, but the cauliflower should be just slightly soft.) Quickly take off the cling-wrap and let the steam escape, and if you see any water in the bottom of the bowl, put the cauliflower into a colander and let the water drain off.\r\n\r\nPut the steel blade in the food processor, add the cauliflower, and pulse until the cauliflower is finely chopped but still slightly chunky. (Be careful not to over process so you don\'t end up with cauliflower puree!) If there is any water in the food processor bowl, drain the cauliflower again in the colander.\r\n\r\nPut finely chopped cauliflower into a bowl and add the reduced-fat sharp cheddar, coarsely grated Parmesan, almond flour, Vege-Sal or salt, Spike Seasoning (if using), and fresh-ground black pepper. Stir until ingredients are well-combined. Add the egg and stir until the ingredients are mostly coated with egg. (You might be tempted to add another egg, but don\'t. You\'ll be surprised how well this sticks together.)\r\n\r\nUse a One Tablespoon Cookie Scoop or a steel one-tablespoon measuring spoon to scoop out rounded spoonfuls of the mixture and place it in the mini muffin pan. Bake 15 minutes. Carefully turn each cauliflower tot over in the muffin tin and bake 15 minutes more, or until tots are nicely browned on both sides. Serve hot; these are best served right out of the oven.', 'from face book', 22),
(603, 'Bacon & Onion Foil Packet Potatoes', '2 to 3 sheets of heavy-duty foil\r\n1 packet onion soup powder\r\n10-12 baby red potatoes, thinly sliced\r\n12 slices of cooked and crumbled bacon\r\n1 small onion thinly sliced and diced\r\n1 cup cheese (optional)\r\nSalt and pepper to taste\r\n3 tablespoons butter\r\nSour cream for serving (optional)', ' Spray each sheet of foil with cooking spray. Top each piece with equal portions of potatoes, bacon, 1 packet onion soup powder and mix. Add salt and pepper to taste. Add 1 tablespoon of butter to each serving. Wrap securely.\r\n\r\nGrill for 20 to 30 minutes. Or you can bake it in the oven, at 350Â° for about 35 minutes or till done. Let stand 10 minutes before serving. Serve in foil, topped with sour cream if desired', 'from facebook', 61),
(604, 'healthy cookies', '3 mashed bananas ripe\r\n1/3 cup apple sauce\r\n2 cups oats\r\n1/4 cup almond milk\r\n1/2 cup raisins (optional)\r\n1 tsp vanilla\r\n1 tsp cinnamon\r\n', 'bake at 350 for 15-20 minutes', 'from facebook', 58),
(605, ' Luscious Chocolate Smoothies', '    4 ounces melted bittersweet dark chocolate\r\n    2 cups soy milk\r\n    1 banana\r\n    12 ounces silken style soft tofu\r\n    1/2 tablespoon flax seed oil\r\n    1 teaspoon cinnamon powder', 'Place ingredients in blender and mix things up for 1 minute on medium.\r\n\r\n', 'Pour into tall cups, serve and do the samba or tango with your love.', 65),
(606, 'Blueberry Tofu Smoothie', '    6 ounces silken tofu\r\n    1 medium banana\r\n    2/3 cup soy milk\r\n    1 cup frozen or fresh blueberries\r\n    1 tablespoon honey\r\n    2 -3 ice cubes, optional', 'Drain the silken tofu to remove excess water (silken tofu has a high water content).\r\nPeel and slice the banana. Place on a baking sheet and freeze for about 15 minutes (this helps make the smoothie thicker).\r\nBlend the banana, tofu and soy milk for 30 seconds. Add 1/2 cup of the frozen blueberries and process until smooth. Add the remaining blueberries, honey and ice cubes if using and process again until smooth.', ' Enjoy!', 65),
(607, 'Sweet and Spicy Vegan Tofu Nuggets', ' block firm or extra firm tofu, cubed\r\n3 tbsp soy sauce\r\n3 tbsp maple syrup\r\n3 tbsp barbecue sauce\r\n2 tbsp ketchup\r\n2 tsp apple cider vinegar\r\n2 tsp hot sauce', 'In a baking dish, whisk together all ingredients and add tofu, coating well. Marinate at least one hour.\r\n\r\nBake at 375 degreed for 35 minutes, tossing occasionally to bake tofu evenly.', 'must try', 60),
(608, 'Crock Pot Balsamic Chicken', '1 teaspoon garlic powder\r\n1 teaspoon dried basil\r\n1/2 teaspoon salt\r\n1/2 teaspoon pepper\r\n2 teaspoons dried minced onion\r\n4 garlic cloves, minced\r\n1 tablespoon extra virgin olive oil\r\n1/2 cup balsamic vinegar\r\n8 boneless, skinless chicken thighs (about 24 ounces) or breasts\r\nsprinkle of fresh chopped parsley', 'Combine the first five dry spices in a small bowl and spread over chicken on both sides. Set aside. Pour olive oil and garlic on the bottom of the crock pot. Place chicken on top. Pour balsamic vinegar over the chicken. Cover and cook on high for 4 hours. Sprinkle with fresh parsley on top to serve.\r\n', 'from claire on facebook', 54),
(609, 'SHIPWRECK CASSEROLE', '\r\n4 Onions (sliced)\r\n4 Potatoes (sliced)\r\n1 lbs Hamburger (cooked)\r\n1 cup Rice (uncooked)\r\n2 cups Celery (sliced)\r\n2 cups Carrots (sliced)\r\n2 cans of Tomato Soup\r\n2 cups of boiling water\r\nsalt\r\npepper\r\n\r\n\r\n', 'Spray a large casserole dish (I use a medium sized roaster) with pam cooking spray. Layer onions, potatoes, hamburger, rice, celery, then carrots. In a separate bowl, mix soup, water, and salt and pepper as desired. Pour over vegetable mixture. Cover and bake in a slow oven at 250 - 300 degrees for 3 - 5 hours.\r\n\r\nYou can also substitute the tomato soup with mushroom soup, and it\'s just as yummy!\r\n\r\n', 'For more great recipes, motivation, tips, and more join our awesome FREE online support group: click on --->\r\nhttps://www.facebook.com/groups/sonyasweightloss/', 17),
(610, 'incredible detox drink', 'This  helps you burn fat, boost metabolism, lose weight, fight diabetes and lower blood pressure.\r\n\r\n1 glass of water (12-16 oz.)\r\n2 Tbsp. Apple Cider Vinegar\r\n2 Tbsp. lemon juice\r\n1 tsp. cinnamon\r\n1 dash cayenne pepper (optional)\r\n1 packet White Stevia Powder (Optional)\r\n\r\n\r\n', 'Blend all ingredients together', 'Secret Recipe Detox Drink will help your body burn fat, lose weight, fight diabetes.\r\nApple Cider Vinegar is full of enzymes and good bacteria. It contains acetic acid which has been shown to lower blood pressure up to 6%. It can also help eat up the starches if you do eat grains in your diet. (I use Bragg â Apple Cider Vinegar)\r\nLemon juice helps balance blood sugar and has an alkaline effect on your body helping to regulate ph. It contains, Vitamin C. (I use Lakewood Organic PURE Lemon Juice)\r\nCinnamon is one of the best anti-oxidants on the planet. It is the number one herb/spice for balancing blood sugar.\r\nCayenne Pepper has been shown to drop blood pressure, increase metabolism.\r\nStevia is an all natural sweetener made from the stevia plant and it is a great replacement for any artificial sweeteners.', 65),
(611, 'Metabolism boosting drink', 'For Recipe. You Need:\r\n2 tsp Honey\r\n1 tsp Cinnamon\r\n1cup/ 8oz/ 237 ml Water\r\n\r\n', '1) Use 1 part of cinnamon to 2 parts of raw honey. 1 tsp cinnamon to 2 tsp honey is recommended.\r\n2) Boil 1 cup/8oz/237 ml of water.\r\n3) Pour the boiling water on cinnamon. Cover it and let it steep until it is warm enough to drink.\r\n4) Add honey when the water is cool/warm. Never add honey when it is hot as the heat will destroy the enzymes and other nutrients in the raw honey.\r\n5) Drink 1/2 of this before going to bed. The other half should be covered and refrigerated and drink it in the morning. Do not re-heat it in the morning.\r\n', 'Do not add any flavors in this mixture. And this recipe only works if you drink it on empty stomach.', 65),
(612, 'PERFECT PEANUT BUTTER COOKIES Healthier version!!!! Sugar-free!', '\r\n1 cup peanut butter\r\n1/3 cup truvia or desired sweetener to taste\r\n1 egg\r\n1/2 cup almond flour\r\n1/4 tsp salt\r\n1 tsp baking soda\r\n1/2 tsp vanilla extract\r\n', 'Preheat oven to 375.\r\nMix all ingredients till thoroughly mixed. Scoop onto cookie sheet lined with parchment paper. Press down with fork. Bake for 12 min or until slightly browned.\r\n', 'Do not over-bake. Let cool before removing from cookie sheet.\r\nEnjoy!', 63),
(613, 'Cheese & Rice Stuffed Peppers', '\r\nYou will Need:\r\n6 med. peppers\r\n1 1/2 lbs of ground beef\r\n1 med. onion\r\n1/2 tsp salt\r\n2 cups of shredded cheddar cheese\r\n2 1/2 c. of chopped tomatoes\r\n1 1/2 cup of cooked rice\r\n', 'What you do:\r\n*Cut tops of peppers and remove seeds, rinse well...cook in boiling water for 8 min.\r\n*Meanwhile cook your ground beef with your onions and salt...drain.. then add your cheese, chopped tomatoes and rice.. stir well\r\n*drain your peppers and then stuff with meat mixture... ', 'place in a baking dish and bake at 350degrees for 20 min.\r\nEnjoy~', 22),
(614, 'METABOLISM BOOSTER', '\r\n*This burns hundreds of calories even if you are just sitting down on your computer. It also increases your metabolism which helps in weight loss\r\nYou Need:\r\n2 tsp Honey\r\n1 tsp Cinnamon\r\n1cup/ 8oz/ 237 ml Water\r\n', 'Directions:\r\n1) Use 1 part of cinnamon to 2 parts of raw honey. 1 tsp cinnamon to 2 tsp honey is recommended.\r\n2) Boil 1 cup/8oz/237 ml of water.\r\n3) Pour the boiling water on cinnamon. Cover it and let it steep until it is warm enough to drink.\r\n4) Add honey when the water is cool/warm. Never add honey when it is hot as the heat will destroy the enzymes and other nutrients in the raw honey.\r\n5) Drink 1/2 of this before going to bed. The other half should be covered and refrigerated and drink it in the morning. Do not re-heat it in the morning.\r\n', 'Do not add any flavours in this mixture. And this recipe only works if you drink it on empty stomach', 65),
(615, 'Caulifower Ranch Chips', '1 cup grated parmesan cheese\r\n1 cup grated raw cauliflower\r\n1/2 tsp parsley\r\n1/2 tsp basil\r\n1/2 tsp dill\r\n1/2 tsp chives\r\n1/2 tsp garlic powder\r\n1/2 tsp onion powder\r\n1/2 tsp pepper\r\n', 'Preheat oven to 450 degrees.\r\n\r\n', 'Add all ingredients to a bowl. Stir\r\nLine a baking sheet or stone with parchment paper.\r\nPlace about 1 TBSP of mixture on prepared baking sheets, about 1 inch apart.\r\nBake at 450 degrees for 5- 7 minutes.\r\nRemove and turn cauliflower chips over.\r\nBake for another 5 -7 minutes.\r\n', 22),
(616, 'easy-roast-chicken', '1 whole free-range or corn fed chicken, broken down into 8 pieces\r\n\r\n(or 8 of your favorite chicken pieces, skin on and bone- in preferable)\r\n\r\n2 tbsp soy sauce\r\n\r\n1 tbsp light brown sugar\r\n\r\n2 tbsp red wine vinegar\r\n\r\n3 tbsp olive oil\r\n\r\n4 shallots, chopped\r\n\r\n2 cloves of garlic, minced\r\n\r\nHandful of fresh parsley\r\n\r\nSalt and Pepper\r\n', '1. Preheat oven to 425 (220)\r\n\r\n2. In a large baking dish, combine marinade and toss with chicken. Season well.\r\n\r\n3. Place chicken pieces skin side up and roast for 30 minutes until it begins to brown. Remove and baste with marinade. Flip pieces and bake a remaining 10 minutes or until chicken is cooked.\r\n\r\n4. Garnish with lots of fresh parsley\r\n', 'from facebook', 54),
(617, 'Coconut Orange Cake', '\r\n1 orange cake mix\r\n1 cup flaked, sweetened coconut\r\n\r\nFrosting\r\n1 15 oz. can mandarin oranges, do not drain and crushed\r\n1 large instant vanilla pudding mix\r\n1 cup flaked, sweetened coconut\r\n1 8 oz. frozen whipped topping, thawed\r\n\r\n', 'Prepare cake mix according to package directions adding in 1 cup coconut and put in 9 X 13 pan - bake at 350 as cake directions instruct.\r\n\r\nWhen the cake has cooled, make the frosting. In a mixing bowl, crush the mandarin oranges with their juices with an electric mixer. Stir in the instant pudding mix and coconut. Fold in the whipped topping. Mix well. Frost the cake\r\n\r\nIf you want to garnish the top with the 5-6 of the mandarin orange slices, remove them before you crush the rest.\r\n\r\nRefrigerate for at least a couple of hours', 'from face book', 45),
(618, 'Garlic Rubbed Roasted Cabbage Steaks', '1 (approx 2lb) head of organic green cabbage, cut into 1&#8243; thick slices\r\n1.5 tablespoons olive oil\r\n2 to 3 large garlic cloves, smashed\r\nkosher salt\r\nfreshly ground black pepper\r\nspray olive oil OR non-stick cooking spray', '1. Preheat oven to 400F and spray a baking sheet with non-stick cooking spray. Pull outer leaf off cabbage (itâs usually dirty and nasty looking), cut cabbage from top to bottom (bottom being root) into 1&#8243; thick slices.\r\n2. Rub both sides of cabbage with smashed garlic.\r\n3. Use a pastry brush to evenly spread the olive oil over both sides of the cabbage slices.\r\n4. Finally, sprinkle each side with a bit of kosher salt and freshly cracked black pepper.\r\n5. Roast on the middle rack for 30 minutes. Carefully flip the cabbage steaks and roast for an additional 30 minutes until edges are brown and crispy.\r\nServe hot and Enjoy!', 'facebook', 22),
(619, 'GARLIC & LEMON CHICKEN WITH RED POTATOES & GREEN BEANS !', '\r\n6 tablespoons olive oil\r\n2 lemons, 1 thinly sliced, 1 juiced - ( 1 lemon if not a fan of lemon )\r\n4 cloves garlic, minced\r\n1 teaspoon salt\r\n1/2 teaspoon freshly ground black pepper\r\n3/4 pound trimmed green beans\r\n8 small red potatoes, quartered\r\n4 chicken breasts\r\n\r\n', 'DIRECTIONS\r\nPreheat oven to 400Â°F ( 180). Coat a large baking dish or cast-iron skillet with 1 tablespoon of the olive oil. Arrange the lemon slices in a single layer in the bottom of the dish or skillet.\r\n\r\nIn a large bowl, combine the remaining oil, lemon juice, garlic, salt, and pepper; add the chicken, green beans and potatoes and toss to coat. Pour this mix into the pan and spread around evenly.\r\n\r\nRoast for 50 minutes or until cooked through. Serve warm.\r\n', '(Gluten free. Low Carb, Diabetic Friendly and so simple to make)\r\n', 54),
(620, 'Dreamsicle Cake', '\r\n1 (18 1/4 ounce) box white cake mix\r\n1 cup water\r\n1&#8260;3 cup vegetable oil...\r\n3 eggs\r\n2 teaspoons orange extract\r\n1 (3 ounce) box orange Jell-O\r\n1 cup boiling water\r\n1 cup cold water\r\n1 (8 ounce) package cream cheese, at room temperature\r\n1 (3 1/2 ounce) box instant vanilla pudding\r\n1 (3 ounce) box orange Jell-O\r\n1 cup milk\r\n1 teaspoon vanilla\r\n1 (8 ounce) container Cool Whip, thawed\r\n', 'Place cake mix in a bowl.\r\nAdd water, oil, eggs and extract; beat on medium low speed two minutes.\r\nPlace batter evenly into a greased and floured 9x13 inch baking pan.\r\nBake in a 350 degree oven for 30-35 minutes.\r\nWhile cake is warm, poke holes evenly over cake with a fork.\r\nPour boiling water over jello in a bowl, stir and dissolve for 2 minutes. Then add cold water into jello and stir till combined.\r\nPour evenly over cake, when cooled; chill 2-4 hours.\r\nFor frosting, beat softened cream cheese till creamy and smooth.\r\nAdd pudding, orange jello, milk and vanilla; beat 1-2 minutes, or till smooth.\r\nFold in Cool Whip till combined.\r\nFrost evenly over cooled cake.\r\nCover and chill till ready to serve.', 'from Facebook', 45),
(621, 'Potato and bacon bake', '\r\n3 lbs (1.5 kg) potatoes, peeled and halved (the short way)\r\n1 lb (500 gr) bacon, diced\r\n2.5 cups (500 gr) shredded cheddar cheese, divided\r\n1 medium brown onion, sliced\r\n2 tablespoons butter\r\n3 tablespoons all-purpose flour\r\n2 cups milk\r\n1/2 teaspoon salt, plus more to taste\r\n1/2 teaspoon pepper, plus more to taste\r\n2-3 garlic cloves, minced\r\n1/2 cup green onion, chopped\r\n\r\n', '1. Parboil potatoes: Boil the potatoes partially (about 10 minutes) so the time they have to cook in the oven will be reduced. Drain water and let cool.\r\n2. While the potatoes are boiling, sautÃ© the diced bacon, onion and garlic until the bacon is browned and the onions soft. Remove bacon and onion into a bowl, but do not get rid of the grease in the pan.\r\n3. When the potatoes have sufficiently cooled, carefully slice them into disks.\r\n4. In the same pan used for cooking bacon and onion, melt butter. Mix in flour and salt, stirring constantly to avoid burning the flour. As soon as the flour is mixed in, begin pouring in the milk, still stirring. Continue to cook until slightly thick, then add 2 cups of cheese and pepper, stirring until melted. Remove from heat.\r\n5. Spoon and spread some sauce in the bottom of a 9 x 13 casserole dish. Make a single layer of potato. Sprinkle 1/2 of the bacon and onion mixture, then pour over half of the sauce. Then make a second layer of potato followed by the remaining bacon and onion mixture followed by more sauce. Sprinkle remaining 1/2 cup of shredded cheese.\r\n6. Place the dish into an oven preheated to 350Â° F (175Â° C) and bake for 45 minutes or until the top is bubbling and golden. Let cool for 15 minutes before serving.\r\nTop with chopped green onion. Salt and pepper to taste.\r\n', '\r\nPreparation time: 20 minutes\r\nTotal time: 45 minutes\r\nServes: 4-6\r\n', 61),
(622, 'Mayonnaise Cake', '3 cups flour\r\n1 1/2 cup sugar\r\n1/3 cup cocoa\r\n2 1/4 tsp baking powder \r\n1 1/2 tsp baking soda\r\n1 1/2 cups Hellmann\' s Real Mayonaise\r\n1 1/2 cups water\r\n1 1/2 tsp vanilla\r\n', 'Grease 2 (9 x 1 1/2-inch) layer pans; line bottoms with wax paper.  Sift together dry Ingredients  into large bowl. Stir in Real Mayonnaise.  Gradually stir in water and vanilla until smooth and blended. Pour into prepared pans.  Bake in 350 f. About 30 minutes, or until cake springs back when touched. Cool. Remove from pans. Makes 2 layers.\r\n', 'from facebook', 45),
(623, 'MeatLoaf', '2 eggs, beaten&#8232;\r\n3/4 cup milk&#8232;\r\n3/4 cup dry breadcrumbs&#8232;\r\n1 (1 ounce) envelope dry onion soup\r\n mix&#8232;2 lbs lean ground beef\r\n', 'o remove loaf when done, line crock with wide strip of aluminum foil, coming up sides of crock.&#8232;2 In a large bowl combine eggs, milk, bread crumbs, and soup mix. Mix well, then add meat. Mix thoroughly, then shape into a rectangle or oval that wonât touch sides of crock. Place in crock. Cover and cook on low for 6 hours or high for 3 hours.\r\n', 'from facebook', 17),
(624, 'mini doughnuts', '1 can of buscuits&#8232;\r\n1/2 cup white sugar&#8232;\r\n1/3 cinnamon \r\n&#8232;1 cup confection sugar. \r\n&#8232;Grease for frying', 'Mix sugars & cinnamon in paper bag or bowl then set aside. (If making a lot use paper bag)\r\nOpen can of buscuits, cut in fourths then drop in grease. &#8232;Flip every two minutes (careful not to fry too long) once brown on both sides put on paper towel.\r\nPlace donuts in bowl or bag and apply your sugar mixture. If using bowl get a spoon and bury donut with mixture or flip it around 1 or 2 at a time, if using a bag place donuts in bag and shake until well coated. A serve!!!\r\n', 'from facebook', 40),
(625, 'mini potatoes in cheese', '* 1/2 cup finely grated Parmesan cheese with a sand consistency (donât use shredded or Microplaned Parmesan cheese)\r\n* 1/2 teaspoon garlic powder\r\n* 1/4 teaspoon paprika\r\n* 1/2 teaspoon dried oregano\r\n* 3/4 teaspoon kosher salt\r\n* 3/4 teaspoon freshly ground black pepper\r\n* 2 tablespoons olive oil\r\n* 1 1/2 lbs baby potatoes, halved (1.5-2 inch diameter; approx 20-22 potatoes)\r\n* FOR DIPPING (optional)\r\n* sour cream or Greek yogurt (or a half-and-half mixture)\r\n* chopped scallions or chives\r\n', 'Preheat oven to 400 degrees F.In small bowl, combine grated cheese, garlic powder, paprika, oregano, salt, and pepper, stirring with fork until mixed.\r\n\r\nPour olive oil into 9Ã13 glass baking dish. Tilt dish around until olive oil evenly coats entire bottom.\r\nCarefully and evenly sprinkle cheese mixture over bottom of pan. (Donât dump it in and then try to spread it out. Once it touches the olive oil, it becomes almost impossible to spread the cheese out evenlyâit will clump. It works better to sprinkle slowly and evenly over the entire surface so that no spreading is necessary.)\r\nArrange potatoes in a single layer, cut side down, on top of cheese mixture. Press down to insure potatoes are flat and in contact with cheese layer.\r\nBake for 30-40 minutes, or until cheese is browned and potatoes are soft when pressed or pierced with fork. Remove from oven and leave potatoes to rest in pan for 5 minutes. Remove potatoes from pan using a small spatula, being careful to keep the cheese layer intact on the cut side of potato. (Use a paring knife to cut cheese between the potatoes, if necessary.)\r\nArrange on serving platter cheese side up. Serve with sour cream or Greek yogurt, (or a half-and-half mixture) sprinkled with chopped scallions or chives, if desired.\r\nTO REHEAT LEFTOVERS: Â Place potatoes cheese side up in a med-hot non-stick skillet to heat the bottom side. In 1-2 minutes, flip them over with tongsâcheesy side downâand cook another 1-2 minutes until heated and crispiness is restored. Be careful not to let them burn; they reheat quickly.\r\nNUTRITIONAL INFORMATION for one prepared potato (2 halves): 45 calories, 2.0g fat, .6g sat.fat, 2mg cholesterol, 118mg sodum, 142mg potassium, 5.6g carbs, .9g fiber, 1.5g protein.\r\n', 'from facebook', 61),
(626, 'overnight french toast', 'Â½ CUP Melted butter (1 stick)\r\n1 CUP Brown sugar + 3 tablespoons brown sugar\r\n1 Loaf of Kings Hawaiian bread\r\n4 Eggs\r\n1Â½ CUP Milk\r\n1 tsp Vanilla\r\n2 tsp of Cinnamon\r\n1 Tbsp of powdered sugar plus more for sprinkling\r\nMaple syrup for topping\r\n', 'Bake it until the top is crispy and golden brown and the inside is soft.\r\nSprinkle with powdered sugar.\r\nPut the butter in a microwave safe bowl, melt it in the microwave and add 1 cup of brown sugar. Stir until combined. Pour the mixture evenly over the bottom of 9 x 13 baking pan.\r\n\r\nIn a large bowl, whisk eggs, milk, 1 tablespoon of powdered sugar and vanilla.\r\n\r\nPlace toast bread in a single layer in the pan so that it covers the whole area.\r\nYou can leav\r\nPour half the egg-milk mixture over the entire layer of toast bread.\r\nIn a small bowl, combine the 3 tablespoons of brown sugar and 2 teaspoons of cinnamon.\r\n\r\nSprinkle half the mixture on a layer of toast bread.\r\n\r\nThen arrange the second layer of bread and pour the rest of the mixture of eggs and milk.\r\n\r\nRepeat with the rest of the sugar and cinnamon.\r\n\r\nCover with aluminum foil and leave to cool in the fridge overnight.\r\n\r\nCooking instructions:\r\n\r\nPreheat oven to 350Â°F.\r\n\r\nLeave chilled toast bread at room temperature for a few minutes.\r\n\r\nPut it in the oven and bake for 45 minutes, so that the first 30 minutes it is baked with aluminum foil.\r\n\r\n\r\nServe with maple syrup.\r\n\r\n', 'Notes: e it for a couple of hours in the refrigerator, but the best effect is achieved if you leave it overnight.', 67);
INSERT INTO `recipe` (`recipeID`, `recipe_title`, `recipe_ingredients`, `recipe_method`, `recipe_note`, `catID`) VALUES
(627, 'Pirogies', '\r\n10-20 lbs of potatoes velveeta cheese Dough........ 2 cups flour 1 cup mashed potatoes 2 eggs pinch saltÂ 	Peel and boil potatoes. Mash until very smooth and add in velveeta cheese and whip until melted and to desired flavor. ', 'Dough...... Mix the flour, mashed potatoes, eggs and salt together. Knead until smooth. Let relax for 30 minutes. Either use a perogy maker or cut squares of desired size and put the potato mixture in the middle and seal shut. To cook...bring water to a boil and gently add in perogies. Cook until they float on the top and are soft to touch.Â 	This is bushkas recipe. When I make the dough I use the mashed potatoes that have the cheese in them..I find it makes a more tender dough and of course makes it tastier. The amount of cheese that you put in depends on your. Taste the potatoes as you add the cheese until you get the taste you want. We like our cheesy so I put in quite a bit of cheese. If they aren\'t cheesy enough they are pretty tasteless. You can also fry them after they are boiled if you like them a little crispy. Fry up either onions and butter or some bacon and put on the top of them to serve.Â 	\r\nÂ Â ', 'Side DishesÂ ', 61),
(628, 'A simple dessert that\'s great served with ice cream.\"', '\r\n* 		10 cups all-purpose apples, peeled, cored and sliced\r\n* 		1 cup white sugar\r\n* 		1 tablespoon all-purpose flour\r\n* 		1 teaspoon ground cinnamon\r\n* 		1/2 cup water\r\n* 		1 cup quick-cooking oats\r\n \r\n* 1 cup all-purpose flour\r\n* 1 cup packed brown sugar\r\n* 1/4 teaspoon baking powder\r\n* 1/4 teaspoon baking soda\r\n* 1/2 cup butter, melted\r\n', '* Preheat oven to 350 degrees F (175 degree C).\r\n* Place the sliced apples in a 9x13 inch pan. Mix the white sugar, 1 tablespoon flour and ground cinnamon together, and sprinkle over apples. Pour water evenly over all.\r\n* Combine the oats, 1 cup flour, brown sugar, baking powder, baking soda and melted butter together. Crumble evenly over the apple mixture.\r\n* Bake at 350 degrees F (175 degrees C) for about 45 minutes.\r\n', 'from facebook', 40),
(629, 'Apple Cake', '1 cup vegetable oil&#8232;\r\n2 cups Sugar..\r\n.&#8232;3 eggs&#8232;\r\n3 cups flour&#8232;\r\n1 teaspoon baking Soda&#8232;\r\n2 teaspoons Vanilla extract&#8232;\r\n1 cup Chopped Pecans&#8232;\r\n3 cups peeled and chopped apples', 'Preheat oven to 350. grease a 9x13 pan. In a mixing bowl ix all above except for pecan and apples. The batter will be stiff, mix well then add pecans and apples and mix. Spread into your pan. Bake for 45 min. The apples moisten this cake while cooking, its delicious.&#8232;', 'Enjoy', 45),
(630, 'Banana Cake', '1 1/2 cups bananas, mashed, ripe\r\n2 teaspoons lemon juice\r\n3 cups flour\r\n1 1/2 teaspoons baking soda\r\n1/4 teaspoon salt\r\n3/4 cup butter, softened\r\n2 1/8 cups sugar\r\n3 large eggs\r\n2 teaspoons vanilla\r\n1 1/2 cups buttermilk\r\nFrosting\r\n1/2 cup butter, softened\r\n1 (8 ounce) packages cream cheese, softened\r\n1 teaspoon vanilla\r\n3 1/2 cups icing sugar\r\nGarnish\r\nchopped walnuts&#65532;', '&#65532;not sure', '&#65532;from facebook', 45),
(631, 'beef barley soup', 'Beef Barley Soup\r\n1 chopped onion\r\n1 lrg pkg ground beef\r\n(Brown together in large pot)\r\n\r\nAdd:\r\n1 cup chopped onions\r\n1 cup chopped carrots\r\n11 cups water\r\n5 bouillon cubes (beef)\r\nI use envelopes of knorr beef bouillon in 1 cup water (boiling)\r\n2 cans beef consommÃ© \r\n1 small can tomato juice\r\n8 tbsp pearl barley\r\n1/2 tbsp thyme\r\n\r\n\r\n', 'mix all together', 'Simmer for 2 hrs.', 62),
(632, 'Hasselback Potatoes in a Slow Cooker', '5 medium potatoes, scrubbed\r\n1 stick of very cold butter\r\n5 slices pepper jack cheese\r\nsalt for seasoning (as desired)\r\nchopped parsley (optional)\r\nbacon bites (optional)\r\n\r\n', '1. Slice potatoes about 1/4-inch thick, but do not cut all the way.\r\n&#65532;\r\n2. Thinly slice butter about 1/8-inch thick. This is easiest with cold butter.\r\n3. Cut each slice of cheese into 8 pieces, ending up with 40 slices.\r\n4. Insert butter and sliced cheese into the potato, in this pattern: butter, cheese, cheese, butter, cheese, cheese, etc.\r\n5. Melt remaining butter and brush on top of each potato.\r\n6. Place parchment paper on bottom of slow cooker then place potatoes on top. Be careful not to disturb slices.\r\n7. Sprinkle with salt if desired.\r\n8. Cover and cook on high 4 hours.\r\n9. Sprinkle with chopped parsley and bacon bites before serving if desired.\r\n', 'from facebook', 61),
(633, 'Ice Cream Cake', '1Â box Betty Crockerâ¢ fudge brownie mix\r\nWater, vegetable oil and eggs called for on brownie mix box\r\n1/2Â gallon (8 cups) vanilla ice cream, slightly softened\r\n1Â cup HersheyâsÂ® hot fudge topping, warmed if desired\r\n2Â tablespoons Betty Crockerâ¢ Decorating Decors candy sprinkles\r\n16Â red maraschino cherries with stems, drained\r\n', '* Heat oven to 350Â°F. Line 2 (9-inch) round cake pans with foil; grease bottoms only with shortening or cooking spray.&#8232;\r\n* Follow the box instructions to make the brownie batter. Divide batter evenly between pans. Bake 19 to 22 minutes or until toothpick inserted 2 inches from side of pan comes out almost clean. Cool completely, about 1 hour. Do not remove from pans.&#8232;\r\n* Spread slightly softened ice cream evenly on brownies in pans. Freeze at least 2 hours or until ice cream is firm.&#8232;\r\n* Remove from pans and also remove the foil. Place on serving plates. Cut each dessert into 8 wedges. Drizzle each wedge with hot fudge topping. Decorate with candy sprinkles and cherries. Store covered in freezer.&#8232;', 'from facebook', 45),
(634, 'Italian crock pot chicken cacciatore', '1 whole chicken; or equivalent chicken pieces\r\n1 can stewed tomatoes; drained\r\n1 can tomato paste\r\n4 cloves garlic; chopped\r\n1 medium Onion; chopped\r\n3 carrots; cut into 3/4&#8243; wide pieces\r\n2 bay leaves\r\n1 tbsp italian seasoning\r\n1 tbsp dried oregano\r\n2 tsp Salt\r\n2 tsp pepper\r\n1/4 cup white wine\r\n1 tsp celery seed\r\n1 tbsp mild curry powder\r\n', 'Place chicken in theÂ crock pot. Mix ingredients in a bowl. Pour mixture over chicken. Cook on high until dish begins to boil. Reduce heat to low and continue cooking until dinner (up to 10 hours).\r\nIf the chicken is frozen or you get a late start, do not reduce heat to low. Leave on high and cook at least six hours.\r\nServe over white rice.\r\n', 'from facebook or bea', 54),
(635, 'Sangria', '\r\n\r\n2 bottles of red wine Triple sec about 1-1.5 cups Simple syrup ... To your desired sweetness I would say 1/2 cup 7 up .....add some taste and see if the flavor is right...keep adding to desired taste ', 'Cut up fruits of your choice, I like lemons, limes, apples more citrucy tasting.Â 	Put wine in jug. Add triple sec, simple syrup and muddle with fruit. Put in fridge to cool. Just before serving add 7 up and ice.Â 	There are no specific portions to this. Put. Some in give it a taste and adjust til you like it.Â 		Â Â \r\n', 'Punches and cocktailsÂ  from Randi', 65),
(636, 'Pirogies', '10-20 lbs of potatoes velveeta cheese Dough........ 2 cups flour 1 cup mashed potatoes 2 eggs pinch saltÂ ', 'Peel and boil potatoes. Mash until very smooth and add in velveeta cheese and whip until melted and to desired flavor. Dough...... Mix the flour, mashed potatoes, eggs and salt together. Knead until smooth. Let relax for 30 minutes. Either use a perogy maker or cut squares of desired size and put the potato mixture in the middle and seal shut. To cook...bring water to a boil and gently add in perogies. Cook until they float on the top and are soft to touch.Â 	This is bushkas recipe. When I make the dough I use the mashed potatoes that have the cheese in them..I find it makes a more tender dough and of course makes it tastier. The amount of cheese that you put in depends on your. Taste the potatoes as you add the cheese until you get the taste you want. We like our cheesy so I put in quite a bit of cheese. If they aren\'t cheesy enough they are pretty tasteless. You can also fry them after they are boiled if you like them a little crispy. Fry up either onions and butter or some bacon and put on the top of them to serve.Â ', 'Side DishesÂ \r\n', 61),
(637, 'Potato and bacon bake', '3 lbs (1.5 kg) potatoes, peeled and halved (the short way)\r\n1 lb (500 gr) bacon, diced\r\n2.5 cups (500 gr) shredded cheddar cheese, divided\r\n1 medium brown onion, sliced\r\n2 tablespoons butter\r\n3 tablespoons all-purpose flour\r\n2 cups milk\r\n1/2 teaspoon salt, plus more to taste\r\n1/2 teaspoon pepper, plus more to taste\r\n2-3 garlic cloves, minced\r\n1/2 cup green onion, chopped\r\n', ' Parboil potatoes: Boil the potatoes partially (about 10 minutes) so the time they have to cook in the oven will be reduced. Drain water and let cool.\r\n2. While the potatoes are boiling, sautÃ© the diced bacon, onion and garlic until the bacon is browned and the onions soft. Remove bacon and onion into a bowl, but do not get rid of the grease in the pan.\r\n3. When the potatoes have sufficiently cooled, carefully slice them into disks.\r\n4. In the same pan used for cooking bacon and onion, melt butter. Mix in flour and salt, stirring constantly to avoid burning the flour. As soon as the flour is mixed in, begin pouring in the milk, still stirring. Continue to cook until slightly thick, then add 2 cups of cheese and pepper, stirring until melted. Remove from heat.\r\n5. Spoon and spread some sauce in the bottom of a 9 x 13 casserole dish. Make a single layer of potato. Sprinkle 1/2 of the bacon and onion mixture, then pour over half of the sauce. Then make a second layer of potato followed by the remaining bacon and onion mixture followed by more sauce. Sprinkle remaining 1/2 cup of shredded cheese.\r\n6. Place the dish into an oven preheated to 350Â° F (175Â° C) and bake for 45 minutes or until the top is bubbling and golden. Let cool for 15 minutes before serving.\r\nTop with chopped green onion. Salt and pepper to taste.', 'Preparation time: 20 minutes\r\nTotal time: 45 minutes\r\nServes: 4-6\r\n', 61),
(638, 'Janet\'s Rich Banana Bread', '1/2 cup butter, melted\r\n* 1 cup white sugar\r\n* 2 eggs\r\n* 1 teaspoon vanilla extract\r\n* 1 1/2 cups all-purpose flour\r\n* 1 teaspoon baking soda\r\n* 1/2 teaspoon salt\r\n* 1/2 cup sour cream\r\n* 1/2 cup chopped walnuts\r\n* 2 medium bananas, sliced', '* Preheat oven to 350 degrees F (175 degrees C). Grease a 9x5 inch loaf pan.\r\n* In a large bowl, stir together the melted butter and sugar. Add the eggs and vanilla, mix well. Combine the flour, baking soda and salt, stir into the butter mixture until smooth. Finally, fold in the sour cream, walnuts and bananas. Spread evenly into the prepared pan.\r\n* Bake at 350 degrees F (175 degrees C) for 60 minutes, or until a toothpick inserted into the center of the loaf comes out clean. Cool loaf in the pan for 10 minutes before removing to a wire rack to cool completely.\r\n', '\"This is the moistest banana bread that I have ever tasted. It\'s also very easy to make!\"\r\n', 42),
(639, 'mini potatoes in cheese', '* 1/2 cup finely grated Parmesan cheese with a sand consistency (donât use shredded or Microplaned Parmesan cheese)\r\n* 1/2 teaspoon garlic powder\r\n* 1/4 teaspoon paprika\r\n* 1/2 teaspoon dried oregano\r\n* 3/4 teaspoon kosher salt\r\n* 3/4 teaspoon freshly ground black pepper\r\n* 2 tablespoons olive oil\r\n* 1 1/2 lbs baby potatoes, halved (1.5-2 inch diameter; approx 20-22 potatoes)\r\n* FOR DIPPING (optional)\r\n* sour cream or Greek yogurt (or a half-and-half mixture)\r\n* chopped scallions or chives\r\n', 'Preheat oven to 400 degrees F.In small bowl, combine grated cheese, garlic powder, paprika, oregano, salt, and pepper, stirring with fork until mixed.\r\n\r\nPour olive oil into 9Ã13 glass baking dish. Tilt dish around until olive oil evenly coats entire bottom.\r\nCarefully and evenly sprinkle cheese mixture over bottom of pan. (Donât dump it in and then try to spread it out. Once it touches the olive oil, it becomes almost impossible to spread the cheese out evenlyâit will clump. It works better to sprinkle slowly and evenly over the entire surface so that no spreading is necessary.)\r\nArrange potatoes in a single layer, cut side down, on top of cheese mixture. Press down to insure potatoes are flat and in contact with cheese layer.\r\nBake for 30-40 minutes, or until cheese is browned and potatoes are soft when pressed or pierced with fork. Remove from oven and leave potatoes to rest in pan for 5 minutes. Remove potatoes from pan using a small spatula, being careful to keep the cheese layer intact on the cut side of potato. (Use a paring knife to cut cheese between the potatoes, if necessary.)\r\nArrange on serving platter cheese side up. Serve with sour cream or Greek yogurt, (or a half-and-half mixture) sprinkled with chopped scallions or chives, if desired.\r\n', 'TO REHEAT LEFTOVERS: Â Place potatoes cheese side up in a med-hot non-stick skillet to heat the bottom side. In 1-2 minutes, flip them over with tongsâcheesy side downâand cook another 1-2 minutes until heated and crispiness is restored. Be careful not to let them burn; they reheat quickly.\r\nNUTRITIONAL INFORMATION for one prepared potato (2 halves): 45 calories, 2.0g fat, .6g sat.fat, 2mg cholesterol, 118mg sodum, 142mg potassium, 5.6g carbs, .9g fiber, 1.5g protein.\r\n', 61),
(640, 'INSTANT POT SHRIMP BOIL ', '1 1/2 pounds baby red potatoes\r\n1 (12.8-ounce) package smoked andouille sausage, thinly sliced\r\n1/2 medium sweet onion, chopped\r\n4 teaspoons Old Bay seasoning, divided\r\n1 tablespoon hot sauce\r\n3 ears corn, halved\r\n1 (16-ounce) pilsner or lager beer\r\n1 1/2 pounds medium shrimp, shell-on\r\n1/4 cup unsalted butter\r\n3 cloves garlic, minced\r\n2 tablespoons chopped fresh parsley leaves\r\n1 lemon, cut into wedges', 'Place potatoes, sausage, onion, 3 teaspoons Old Bay seasoning and hot sauce into a 6-qt Instant PotÂ®. Stir until well combined. Top with corn and beer.\r\nSelect manual setting; adjust pressure to high, and set time for 5 minutes. When finished cooking, quick-release pressure according to manufacturerâs directions.\r\nAdd shrimp. Select manual setting; adjust pressure to high, and set time for 1 minute. When finished cooking, quick-release pressure according to manufacturerâs directions.\r\nMelt butter in a small skillet over medium low heat. Stir in garlic and remaining 1 teaspoon Old Bay seasoning until fragrant, about 1-2 minutes.\r\nServe shrimp mixture immediately, drizzled with butter mixture, garnished with parsley and lemon, if desired.\r\n', 'This was fabulous! I read all your comments about the âshrimp cooking or over cooking issuesâ I came up with an idea that I didnât see posted yet,\r\nand it was SO Good. OMGoshâ¦..\r\nI used 1/2cup of butter vs 1/4, and I upped the Old Bay another tsp. Then I cooked the shrimp in the butter sauce. I started it when the IP started the 5minute count down. The shrimp and IP were done at almost the same time.\r\nI poured the shrimp and sauce all over the rest. Then I mixed it all up so the shrimp werenât the first things gone off the top.\r\nDefinitely a go to dinner.\r\nBTW it cost about $27 and there is No way a family of 5 can eat this in a restaurant for under $150-$200.\r\nThanks for the info. It was wonderful!  ', 69),
(641, 'choc chips cookies', '2 tbsp light butter softened\r\n2 tsp canola oil\r\n1/2 cup packed brown sugar, dark variety\r\n1 tsp vanilla\r\n1/8 tsp table salt\r\n1 large egg white\r\n3/4 cup flour\r\n1/4 tsp baking soda\r\n3 oz semi-sweet chocolate chips about 1/2 cup', 'preheat oven to 375 f.\r\nin a medium bowl, crea, together butter,oil and sugar.  Add vanilla, salt and egg white; mix thoroughly to combine.\r\nin a small bowl, mix together flour and baking soda; stir in batter.  Add chocolate chips to batter; stir to distribute evenly throughout.\r\nDrop rounded half teaspoons of dough onto one or two large nonsstick baking sheets,leavinga small amount of space between each cookie.\r\nBake cookies until golden around edges, about 4-6 minutes; cool on a wire rack.', 'makes 24 servings. serving size is 2 cookies\r\neach serving = 1 weight watchers smart points.', 63),
(642, 'Apple Cinnamon Muffin', '1/4 cup ground walnuts\r\n3/4 cup granulated sugar\r\n1-2 tsp ground cinnamon\r\n1/4 cup butter - melted & cooled\r\n1 large egg - beaten\r\n1/2 cup milk\r\n1-1/2 cups flour\r\n1 tbsp baking powder\r\n1/2 tsp salt\r\n1 cup peeled and grated apples\r\n', 'Preheat oven to 375 Bake 15 to 20 minutes Mix walnuts, 1/4 sugar and 1 tsp cinnamon and set aside. Combine butter, sugar, and egg. Stir in milk. Combine flour, baking powder,1 tsp cinnamon and salt. Add to butter mixture. Stir together, should be lumpy. Fold in apples. Put a little batter in the tins. Sprinkle with most of the sugar and nut mix. Fill tins. Sprinkle with remaining sugar and nut mix.', 'from Randi', 59),
(643, 'Banana Muffins', '1/2 cup margarine\r\n1/2 cup white sugar \r\n1 egg \r\n1-3/4 cups flour \r\n1/2 tsp salt \r\n1 tsp baking powder \r\n1 tsp baking soda \r\n1/4 cup milk \r\n1 cup mashed bananas', 'Beat margarine and sugar well. Add eggs. Add dry insgredients and milk. Lastly add bananas', '350 for 30 minute Makes 12 large muffins.  I usually put in approx. 2 cups of bananas. The muffins are moister. I also put a little brown sugar on the top of each muffin. You can add nuts if you want or chocolate chips.', 59),
(644, 'Blueberry Strudel Muffins', '2-1/2 cups flour \r\n1-1/4 cup sugar \r\n1 tbsp baking powder \r\n1 cup butter \r\n1/2 tsp cinnamon \r\n3/4 cup milk \r\n2 eggs \r\n1-1/2 tsp vanilla \r\n2 cups blueberries', '350 for 30 minutes Mix together the first 5 ingredients and set aside 3/4 of a cup. Combine the next 3 ingredients and add to the flour mixture. Add the berries last. Put in muffin tins and put the reserved mixture on the top', 'I don\'t usually use butter I use margarine. You can mix it half and half to make the muffins richer. I also put a little more than 2 cups of berries. It depends on how fruity you want them to be.  From Randi', 59),
(645, 'peanut butter cookies', '2 Tbsp butter softened *I used Gay Leah light butter 7SP for 2Tbsp 3 Tbsp brown sugar &#8531; cup peanut butter 1 egg 1 tsp vanilla 1 tsp baking powder 1 cup flour\r\n\r\n', 'Preheat oven to 350F and line a baking sheet with parchment paper, I also lightly spray it.\r\nIn a bowl using an electric mixer cream together your butter and sugar, add in peanut butter, egg and vanilla and beat for 2 minutes.\r\nStir in flour and baking powder till well mixed.\r\nUsing your hands roll dough into small balls, each one approximately 1 tsp of dough, these are mini cookies, if you donât get 36 or close to then you are making them too big.\r\nPlace rolled balls of dough on cookie sheet and press down with a fork.\r\nBake in the oven for 8-10 minutes, let cool 5 minutes.\r\nStore in a sealed container, you can freeze these cookies if you wish.\r\nMakes 36 mini cookies\r\n\r\n', 'Author: Drizzle Recipe type: Baking Prep time:  5 mins Cook time:  10 mins Total time:  15 mins Serves: 36 1 Freestyle SP, 1SP/1PP per cookie', 58),
(657, 'Vegan honey garlic sauce', '* 		1 tbsp minced garlic\r\n* 		1/3 cup ketchup\r\n* 		1/4 cup brown sugar\r\n* 		1/4 cup maple syrup\r\n* 		2 tbsp soy sauce\r\n* 		optional: sliced green onion, for garnish', 'N/A', 'N/A', 60);
